const dom = require("../../templates/SystemFormControl.ejs");
import { FormControl } from "../../../../baseControls";
import { isSupportDataPost } from '../../../../core/postDecorator';
import { map } from '../../../../decorator/controlmap';

@map('系统时间', 'dsf.systemtime', 'systemtime')
@isSupportDataPost(false)
export class SystemTime extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$format = "yyyy-mm-dd hh:ii";
  }

  initTemplate() {
    return dom(this);
  }

  set value(value) {
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(dsf.date.format(value, this.$format))
    }
    super.value = value;
  }
  get value() {
    return super.value;
  }

  getTextString() {
    if (this.value) {
      return dsf.date.format(this.value, this.$format);
    }
    return "";
  }
  getValueString() {
    if (this.value) {
      return dsf.date.format(this.value, this.$format);
    }
    return "";
  }
}