const dom = require("../../templates/AutoComplete.ejs");

import { relyFiles } from '../../../../core/relyfiles';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControl } from "../../../../baseControls";
import { TextMetaData } from "../../../../core/metadata";
import { Action } from '../../../../core/pageAction';
import {express} from '../../../../core/express';
import {map} from  '../../../../decorator/controlmap';

@map('自动完成','dsf.autocomplete','AutoComplete')
@relyFiles([
    'res/libs/jquery-ui/jquery-ui.min.js'
])
@isSupportDataPost(true)
export class AutoComplete extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$source = "";
        this.$placeholder = "请输入";
        this.$metadata = TextMetaData.call(this,200);
        this.$maxItemsNumber = 100;
        this.$value = "";
        this.$metaDataType = 0;
		this.chooseMetaData = {};
		this.delay = 300;
    }

    set placeholder(value) {
        this.$placeholder = value;
        if (this._handlers.input) {
            this._handlers.input.attr("placeholder", value);
        }
    }
    get placeholder() {
        return this.$placeholder;
    }

    initTemplate() {
        return dom(this);
    }

    set value(value) {
        this.$value = value;
        if (this._handlers.input) {
            this._handlers.input.val(this.value);
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString());
        }
    }

    get value() {
        return this.$value;
    }

    set readOnly(value) {
        if (value) {
            if (this.element&&this.element.input) {
                this.element.input.autocomplete("destroy")
            }
        }
        super.readOnly = value;

    }
    get readOnly() {
        return super.readOnly;
    }

    renderContext(){
        super.renderContext();
        if (this._handlers.input) {
            this._handlers.input.val(this.value);
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString());
        }
    }
    renderComplete() {
        super.renderComplete();
        if (this._handlers.input) {
            setAutoComplete.call(this);
        }

    }
    getTextString() {
        return this.$value;
    }
    response(arr) {
        return arr;
    }
}



function setAutoComplete() {
    let _this = this;
    let cache = {};

    function trigger() {
        _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
    }
    this.element.off("input.textChange");
    this.element.on("input.textChange", "input", evt => {
        _this.$value = this._handlers.input.val();
        trigger();
    })

    this.element.on("change.textChange","input",evt=>{
        this.commitAudit();
    })

    this._handlers.input.autocomplete({
		delay: _this.delay,
        source: function(request, response) {
			let exp = dsf.Express;
            if (_this.$source || _this.$metaDataType == "0") {
				let v = exp.replace(_this.$source);
                let url = dsf.url.getAbsolutePath(v);
                dsf.http.request(url, { "q": request.term }, "GET")
                    .done(function(result) {
                        if (result.success) {
                            let arr = result.data.slice(0, parseInt(_this.$maxItemsNumber));
                            arr = _this.response(arr) || [];
                            response(arr);
                        }
                    })
                    .error(function() {})
                    .exec();
            }else if(_this.$metaDataType == "1" && _this.chooseMetaData.id){
				// 开发中
				return;
				Action['getTreeByName']({id:_this.chooseMetaData.id}, (err, data) => {
				    if (err) {
				        
				    } else {
				        let arr = data.slice(0, parseInt(_this.$maxItemsNumber));
				        arr = _this.response(arr) || [];
				        response(arr);
				    }
				});
			}
        }, 
        change: function(event, ui) {
            // 值变化且失去焦点
        },
        response: function(event, ui) {
            // 搜索后的返回的值
            cache = {};
            for (let i = 0; i < ui.content.length; i++) {
                if (ui.content[i]["_id"]) {
                    cache[ui.content[i]["_id"]] = ui.content[i];
                }
            }
        },
        open: function(event, ui) {
            // 展开数据框
            setWidgetContentStyle.call(_this, true);
        },
        select: function(event, ui) {
            // 选中值
            _this.value = ui.item.value
            trigger();
            _this.event.trigger(AutoCompleteEvent.SELECT, { "ui": _this, "data": ui.item });
            _this.commitAudit();
        },
        close: function(event, ui) {
            // 关闭数据框
            setWidgetContentStyle.call(_this);
        }
    });



}

function setWidgetContentStyle(set) {
    $(".ui-autocomplete.ui-widget-content").css('marginTop', set ? '5px' : 0);
    $(".ui-autocomplete.ui-widget-content").css('width', this._handlers.input.outerWidth());
}