import { orderMetaData } from '../../../../core/metadata';
import { TextBox } from '../Form/TextBox';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { map } from '../../../../decorator/controlmap';

@map('排序', 'dsf.order', 'Order')
@isSupportDataPost(true)
export class Order extends TextBox {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "排序码";
    this.$placeholder = "请输入排序编号"
    this.value = "";
    this.$metadata = orderMetaData.call(this);
  }

  init() {
    super.init();
    this.caption = dsf.config.kw.order;
  }

}