import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from "../../../../editor/ControlEditor";
import { ChartControl } from '../../../../baseControls/controls/ChartControl';

@map("折线图", 'dsf.linechart', 'LineChart')
export class LineChart extends ChartControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.height = '319px';
    this.label = "折线图";
    this.chartType='line'
  }

  get label() {
    return super.label;
  }
  set label(value) {
    super.label = value;
  }

  renderContext() {
    super.renderContext();
  }
  setOption() {
    super.setOption();
    let customerOption = {
      xAxis: {
        data:this.chartData.xAxis
      }
    }
    let option  = $.extend(true, {}, this.defalutOption, customerOption)
    console.log(option)
    this.chart.setOption(option)
  }
}


