const dom = require("../../templates/SubTableVertical.ejs");
const subtitleDom = require("../../templates/SubTitle.ejs");
const headDom = require("../../templates/SubTableVerticalHead.ejs");
import { ChildrenList } from "../../../../baseControls";
import { SubTableEditor } from '../../../../editor/SubTableEditor';
import { SubMetaData } from '../../../../core/metadata';
import * as ButtonPlugin from '../../../../pulgins/buttons';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { SubTableEvent, PageEvent } from '../../../../core/ControlEvent';
import { Template } from '../../../../core/template'
import { oneToMany } from "../../../../decorator/oneToMany";
import { map } from '../../../../decorator/controlmap';
let columnMinWidth = 100;

@map('纵向子表', 'dsf.subtablevertical', 'SubTableVertical')
@isSupportDataPost(true)
@oneToMany
export class SubTableVertical extends ChildrenList {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = SubTableEditor;
        this._rows = [];
        this.$metadata = SubMetaData.call(this);
        //按钮栏
        this.$buttonBar = ButtonPlugin.ButtonBar();
        this.$columns = [];
        this.$templates = [];
        this.$mainColumnsSetting = [];
        this.$logic = [];
        this._htmlCtrl = dsf.getControlClassForCode("dsf.htmlelement");
    }

    get dataKey() {
        return dsf.config.kw.id;
    }

    get scope() {
        return this.root.scope + "_" + this.metadata.code;
    }

    set readOnly(value) {
        this.$readOnly = value;
        if (value) {
            this.addClass("readonly");
        } else {
            this.removeClass("readonly")
        }
    }

    get readOnly() {
        return this.$readOnly;
    }

    set showLabel(value) {
        this.$showLabel = value;
        if (value) {
            this.addClass("hasTitle");
        } else {
            this.removeClass("hasTitle");
        }
    }
    get showLabel() {
        return this.$showLabel;
    }

    set label(value) {
        this.$label = value;
        if (this.element) {
            let dom = this.renderTitle();
            this._handlers.title.html(dom);
        }
    }
    get label() {
        return this.$label;
    }

    get value() {
        return this.$value;
    }
    set value(value) {
        value = value || [];
        this.$value = value;
        if (this._isRender) {
            this.reload(true);
        }
    }

    set showIndex(value) {
        this.$showIndex = value;
        if (value) {
            this.removeClass("hideIndex");
        } else {
            this.addClass("hideIndex");
        }
    }
    get showIndex() {
        return this.$showIndex;
    }

    get rows() {
        return this._rows;
    }

    set metadata(value) {
        super.metadata = value;
        this.label = value.name;
    }
    get metadata() {
        return super.metadata;
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
    }

    analysisRow() {
        let _this = this;
        let temp = this.$mainColumnsSetting;
        let matrix = [];
        for (let i = 0; i < temp.length; i++) {
            for (let n = 0; n < this.$columns.length - 1; n++) {
                let col = this.$columns[n];
                let row = matrix[i];
                if (!row) {
                    row = matrix[i] = { "id": temp[i].id, "columns": [] };
                }
                let setting = $.extend({}, temp[i].columns[col.id]);
                setting.rowSpan = 1;
                setting.colSpan = 1;
                setting.align = col.bodyAilgn;
                row.columns.push(setting);
            }
        }
        for (let i = 0; i < matrix.length; i++) {
            let m = matrix[i];
            let old = _.find(_this.$templates, o => o.id == m.id);
            if (old) {
                m.template = old.template;
            }
            // else{
            //     m.template=new Template(this);
            //     m.template.control=new HtmlElement("<DIV></DIV>")
            // }
        }
        this.$templates = matrix;
        //优先计算行合并
        for (let i = 0; i < matrix.length; i++) {
            let row = matrix[i];
            for (let n = 0; n < row.columns.length; n++) {
                if (row.columns[n].text) {
                    setRowSpan(row.columns[n], matrix, i, n)
                }
            }
        }

        function setRowSpan(cell, matrix, x, y) {
            let count = x + 1;
            let rowSpan = 1;
            while (matrix[count] && matrix[count].columns[y] && !matrix[count].columns[y].text) {
                rowSpan++;
                matrix[count].columns[y].isShow = false;
                count++;
            }
            cell.rowSpan = rowSpan;
        }
        this.render();

    }

    render() {
        super.render();
    }

    renderHead() {
        let html = headDom(this);
        this._handlers.thead.html(html)
    }

    renderContext() {
        super.renderContext();
        this.renderHead();
        this.setColumnsWidth();
        if (this.isDesign) {
            this.renderTemplate();
        } else {
            this.renderRows();
        }
        if (this.root._isDesign) {
            ButtonPlugin.renderButtons(this, this._handlers.buttonsbar, this.$buttonBar, null, null, "small");
        } else {
            this.root.event.on(PageEvent.READY, evt => {
                ButtonPlugin.renderButtons(this, this._handlers.buttonsbar, this.$buttonBar, null, null, "small");
            });
        }
    }

    renderComplete() {
        super.renderComplete();
        createFtx.call(this);
    }

    resize() {
        this.setColumnsWidth();
    }

    renderTemplate() {
        for (let i = 0; i < this.$templates.length; i++) {
            let row = this.$templates[i];
            let t = new Template(this, "template_row_" + i);
            if (!row.template) {
                t.control = new this._htmlCtrl("<DIV></DIV>", true);
                t.control.addClass("no_padding");
            } else {
                t.control = row.template.control;
            }
            let arr = t.control.$classList;
            let index = _.findIndex(arr, o => {
                return o.startsWith("subtable-" + this.id + "-column-");
            });
            if (index >= 0) {
                t.control.removeClass(arr[index]);
            }
            t.control.addClass("subtable-" + this.id + "-column-" + (this.$columns.length - 1));
            row.template = t;
            row.template.control.render();
        }
    }

    renderRows() {
        let _this = this;
        for (let i = 0; i < this.$templates.length; i++) {
            var r = this.$templates[i];
            var tr = new this._htmlCtrl("<TR></TR>", null);
            tr.id = r.id;
            for (var n = 0; n < r.columns.length; n++) {
                let col = r.columns[n];
                if (col.isShow != false) {
                    var cell = new this._htmlCtrl("<TD class='ds_sub_table_cell' style='text-align:" + col.align + ";padding:0px 9px;'></TD>", null);
                    cell.addClass("no_padding");
                    cell.addAttrs("rowspan", col.rowSpan);
                    cell.addAttrs("colspan", col.colSpan);

                    var content = new this._htmlCtrl("<DIV>" + (col.text || "") + "</DIV>", null);
                    let index = _.findIndex(content.$classList, o => o.startsWith("subtable-" + this.id + '-column-'))
                    if (index >= 0) {
                        content.removeClass(content.$classList[index]);
                    }
                    if (col.colSpan <= 1) {
                        content.addClass("subtable-" + this.id + '-column-' + n)
                    }
                    cell._addChild(content);
                    tr._addChild(cell);
                }
            }
            this.rows.push(tr);
            this._addChild(tr, null, "tbody");
        }
    }

    initEvent() {
        let _this = this;
        let clearId = null;
        this.element.on("mouseenter", "TD[data=1]", function(evt) {
            if (!_this.readOnly) {
                if (evt.target) {
                    var target = $(evt.target).closest("TD[data=1]");
                    if (target.length > 0) {
                        $(".operation_tips").remove();
                        clearId = window.setTimeout(function() {
                            let tips = createOperationTips.call(_this, target);
                            target.append(tips);
                        }, 500);
                    }
                }
                return false;
            }

        });
        this.element.on("mouseleave", "TD[data=1],.ds_sub_table", function(evt) {
            if (!_this.readOnly) {
                $(".operation_tips").remove();
                if (clearId) {
                    window.clearTimeout(clearId);
                }
            }
        });
    }


    reload(isTriggerValueChange) {
        for (let i = 0; i < this.rows.length; i++) {
            var row = this.rows[i];
            var cells = row.element.find("[data=1]");
            cells.each(function() {
                var td = $(this);
                var cell = td.data("Object");
                if (cell) {
                    cell.remove();
                }
            });
        }
        for (let n = 0; n < this.value.length; n++) {
            let d = this.value[n];
            if (d[this.dataKey]) {
                if (this._deleteData[d[this.dataKey]]) {
                    delete this._deleteData[this.dataKey];
                }
            }
            let result = renderDataRow.call(this, this.value[n], n);
            addToTable.call(this, n, result);
        }
        if (isTriggerValueChange) {
            this.event.trigger(SubTableEvent.VALUECHANGE, { ui: this, "type": "reload", "data": this.value });
        }
        this.renderHead();
        createFtx.call(this);
    }


    addData(index, data) {
        data = data || {};
        let result = null;
        let q = new dsf.queue();
        q.step((def, v) => {
            if (this.event.has(SubTableEvent.ADDROWBEFORE)) {
                this.event.trigger(SubTableEvent.ADDROWBEFORE, {
                    ui: this,
                    data: data,
                    next: function(r) {
                        r === false ? def.reject() : def.resolve();
                    }
                });
            } else {
                def.resolve()
            }
        })
        q.step((def, v) => {
            result = renderDataRow.call(this, data);
            index = index == undefined ? this.value.length : index;
            addToTable.call(this, index, result);
            this.value.push(data);
            this.renderHead();
            createFtx.call(this);
            this.event.trigger(SubTableEvent.ADDROW, { ui: this, data: data, index: index });
            this.event.trigger(SubTableEvent.VALUECHANGE, { ui: this, data: data, "type": "addNew" });
            def.resolve();
        });
        q.exec();
        return result;

    }

    renderTitle() {
        return subtitleDom({ title: this.$label });
    }

    beginEditor() {

    }

    deleteRow(index) {
        let d = this.value[index];
        if (d[this.dataKey]) {
            this._deleteData[d[this.dataKey]] = d;
        }
        this.value.splice(index, 1);
        // if (this.value.length <= 0) {
        //     this.value.push({});
        // }
        this.reload();
        this.event.trigger(SubTableEvent.DELETEDATA, { ui: this, data: d });
        this.event.trigger(SubTableEvent.VALUECHANGE, { ui: this, data: d, "type": "delete" });
    }


    exchangeRow(index, newIndex) {
        if (newIndex < 0) {
            return;
        } else if (newIndex > this.value.length - 1) {
            return;
        }
        let d1 = this.value[index];
        let d2 = this.value[newIndex];
        this.value[newIndex] = d1;
        this.value[index] = d2;
        this.reload();

        this.event.trigger(SubTableEvent.VALUECHANGE, { ui: this, "type": "exchange", "data": [d1, d2] });
    }

    setColumnsWidth() {
        let autoWidthCols = [],
            sumSize = 0,
            totalWidth = this._handlers.wrap.innerWidth() - 1;
        let size = totalWidth;

        //计算出所有已知的尺寸和未设置尺寸的单元
        for (let i = 0; i < this.$columns.length; i++) {
            let c = this.$columns[i];
            delete c._width;
            if (c.width) {
                if (c.width.indexOf("%") < 0) {
                    if (this.isDesign) {
                        sumSize += parseFloat(c.width);
                    } else {
                        sumSize += (c.hide != "1") ? parseFloat(c.width) : 0;
                    }

                } else {
                    if (this.isDesign) {
                        sumSize += parseFloat(c.width) / 100;
                    } else {
                        sumSize += (c.hide != "1") ? totalWidth * (parseFloat(c.width) / 100) : 0;
                    }

                }
            } else {
                if (this.isDesign) {
                    autoWidthCols.push(c)
                } else {
                    (c.hide != "1") ? autoWidthCols.push(c): dsf.noop();
                }

            }
        }

        //平均分配没有填写尺寸的单元格
        let residueWidth = totalWidth - sumSize;
        if (residueWidth > 0) {
            //如果容器还有空间则平均分配剩余空间
            let avgWidth = residueWidth / autoWidthCols.length;
            if (avgWidth < columnMinWidth) {
                autoWidthCols.forEach(o => {
                    o._width = columnMinWidth;
                });
            } else {
                autoWidthCols.forEach(o => {
                    o._width = (avgWidth / totalWidth * 100) + "%";
                });
            }
        } else {
            //如果尺寸已知尺寸已经超出容器则已最小尺寸作为当前单元格的宽度
            autoWidthCols.forEach(o => {
                o._width = columnMinWidth;
            });
        }

        let s = 0;
        for (let i = 0; i < this.$columns.length; i++) {
            let c = this.$columns[i];
            if (i == this.$columns.length - 1) {
                if (!c.width && s < totalWidth) {
                    c._width = totalWidth - s;
                }
            }
            let w = setColumnWidth.call(this, i, (c._width || c.width));
            s += w;
        }
        // console.log(temp);

    }

    createMetaData() {
        try {
            let _this = this;
            let key = this.root.scope;
            let ns = key;
            this.metadata.code = this.$caption;
            key += "_" + this.metadata.code;
            this.metadata.id = ns.replace(/\_/g, '.') + "." + this.metadata.code;
            let path = this.metadata.id.split(".");
            path = path.slice(0, path.length - 1);
            this.metadata.at = path.join(".");
            this.metadata.name = this.metadata.name || this.label;
            this.metadata.level = 1;
            this.metadata_fullcode = key;
            let children = [],
                metaControls = [],
                temp = [],
                mm = [];

            var template = this.$templates;
            for (var i = 0; i < template.length; i++) {
                var row = template[i].template;
                row.control.ControlsForEach(control => {
                    if (control.metadata) {
                        control.metadata.level = 1;
                        if (control.$isFromMetaData) {
                            metaControls.push(control)
                            if (temp.indexOf(control.metadata.at) < 0) {
                                temp.push(control.metadata.at);
                            }
                        } else {
                            children.push(control);
                        }
                    }
                }, false);
            }


            if (temp.length > 1) {
                throw "子表中不可以存在不同来源的元数据控件";
            }
            //如果子表中有元数据控件，则表示子表用了已有元数据
            for (let i = 0; i < metaControls.length; i++) {
                let ctrl = metaControls[i];
                if (ctrl) {
                    let key = ctrl.metadata.id.substring(0, ctrl.metadata.id.lastIndexOf(".")).replace(/\./g, "_") + "." + ctrl.metadata.code;
                    ctrl.metadata_fullcode = key;
                    mm.push({ "key": key, "md": ctrl.metadata });
                    //根据子控件元数据信息生成将子表元数据信息
                    let arr = ctrl.metadata.id.split(".");
                    let at = arr.splice(0, arr.length - 1);
                    _this.metadata.code = at[at.length - 1];
                    _this.metadata.at = at.join(".");
                    _this.metadata.id = at.join(".");
                    _this.metadata_fullcode = _this.metadata.id.replace(/\./g, "_");
                }
            }
            for (let i = 0; i < children.length; i++) {
                let ctrl = children[i];
                if (ctrl.createMetaData) {
                    ctrl.createMetaData();
                }
                let controlCode = ctrl.$caption;
                ctrl.metadata.level = 1;
                ctrl.metadata.code = controlCode;
                ctrl.metadata.name = ctrl.metadata.name || ctrl.label;
                ctrl.metadata.id = _this.metadata.id + "." + ctrl.$caption;
                ctrl.metadata.at = _this.metadata.id;
                ctrl.metadata_fullcode = _this.metadata_fullcode + "." + ctrl.$caption;
                mm.push({ "key": ctrl.metadata_fullcode, "md": ctrl.metadata });
            }

            //如果页面中存在auditinfo组件,则子表需要同步审核状态字段
            let auditMetaData = _this.root.getAuditMetaData()
            if (auditMetaData) {
                let ameta = $.extend(true, {}, auditMetaData);
                ameta.at = _this.metadata.id;
                ameta.level = _this.metadata.level;
                ameta.id = ameta.at + "." + ameta.code;
                let ametakey = _this.metadata_fullcode + ".auditinfo";
                mm.push({ "key": ametakey, "md": ameta });
            }

            mm.splice(0, 0, { "key": _this.metadata_fullcode, "md": _this.metadata });
            return mm;
        } catch (ex) {
            throw ex;
        }
    }

    execLogic() {

    }
}

function renderDataRow(rowData, index) {
    let _this = this;
    rowData = rowData || {};
    dsf.props.definePrivateProp(rowData, "$$checked", rowData["$$checked"]);
    index = index == undefined ? _this.value.length : index;
    dsf.props.definePrivateProp(rowData, dsf.hashKey, rowData[dsf.hashKey] || dsf.uuid());
    let result = [];
    for (let n = 0; n < this.$templates.length; n++) {
        let row = this.$templates[n];
        let t = new Template(this, "template_row_" + n);
        t.control = row.template.control;
        let cellLayout = t.createControlByTemplate(rowData, index, function(ctrl) {
            if (ctrl.metadata_fullcode) {
                rowData[ctrl.metadata_fullcode] = ctrl.value;
            }
            ctrl.event.on(FormControlEvent.VALUECHANGE, function(evt) {
                rowData[ctrl.metadata_fullcode] = ctrl.value;
                _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this, data: rowData });
            });
            if (_this.readOnly) {
                ('readOnly' in ctrl) ? ctrl.readOnly = true: dsf.noop();
            }
            if (!ctrl._caption) {
                ctrl._caption = ctrl.caption;
            }
            _this.defineControlSetValue(ctrl);
            ctrl.caption = _this.caption + "_" + index + "_" + ctrl._caption;
        });
        result.push(cellLayout);
    }
    return result;
}

function addToTable(index, cells, addToValue) {
    for (let i = 0; i < this.rows.length; i++) {
        var row = this.rows[i];
        let td = new this._htmlCtrl("<TD data='1'></TD>", true);
        td.addClass("ds_sub_table_cell");
        td.addClass("no_padding");
        td.addClass("children_small_padding")
        td._addChild(cells[i]);
        td.addAttrs("index", index);
        row.addChild(td);
    }
}

function setColumnWidth(index, width, callback) {
    var style = this._handlers.colStyle.get(0);
    var sheet = style.sheet || style.styleSheet || {};
    var rules = sheet.cssRules || sheet.rules;
    var cssName = ".subtable-" + this.id + "-column-" + index;
    // var total=this._handlers.outer.width() - 3;
    for (var i = 0; i < rules.length; i++) {
        var rule = rules[i];
        if (rule.selectorText == cssName) {
            if (width.toString().indexOf("%") > 0) {
                let w = (this._handlers.wrap.innerWidth() - 1) * (parseFloat(width) / 100);
                w = parseInt(w)
                rule.style.width = (w - 1) + "px";
                return w;
            } else {
                let w = parseInt(width)
                rule.style.width = (w - 1) + "px";
                return w;
            }
        }
    }
}

function createOperationTips(cell) {
    let _this = this;
    let div = $("<div class='operation_tips'>\
                <div>\
                    <i class='iconfont icon-delete ds_font_4' title='删除' event='delete'></i>\
                    <i class='iconfont icon-zuojiantou ds_font_4' title='前移' event='up'></i>\
                    <i class='iconfont icon-youjiantou ds_font_4' title='后移' event='down'></i>\
                </div>\
            </div>");
    div.on("click", function(evt) {
        let target = $(evt.target);
        let command = target.attr("event");
        let colIndex = parseInt(cell.attr("index"));
        if (command == "delete") {
            dsf.layer.confirm("确定要删除数据?", ['是', '否'], function(index, layero) {
                _this.deleteRow(colIndex);
            })
        } else if (command == "up") {
            _this.exchangeRow(colIndex, colIndex - 1)
        } else if (command == "down") {
            _this.exchangeRow(colIndex, colIndex + 1)
        }
    })
    return div;
}



function createFtx() {
    if (this.isDesign) {
        return;
    }
    var ftx = this.element.find(".ftx");
    var source = this._handlers.table;
    if (ftx.length <= 0) {
        ftx = $("<div id='ftx_" + this.id + "' class='ftx'></div>");
        // ftx.css("position", "absolute");
        // ftx.css({ "top": "0px", "left": "0px" })
        var table = $("<table cellspacing='0' cellpadding='0' border='0' class='ds_sub_table'></table>").appendTo(ftx);
        var thead = $("<thead></thead>").appendTo(table);
        var tbody = $("<tbody></tbody>").appendTo(table);

        var sourceHead = source.find("THEAD").find("TR");
        var sourceRows = source.find("TBODY").find("TR");

        for (let i = 0; i < sourceHead.length; i++) {
            var tr = sourceHead.eq(i).clone();
            tr.find("td[data=1]").remove();
            thead.append(tr);
        }

        for (let i = 0; i < sourceRows.length; i++) {
            var tr = sourceRows.eq(i).clone();
            tr.find("td[data=1]").remove();
            tbody.append(tr);
        }
        // this._handlers.wrap.append(ftx);
        this._handlers.box.append(ftx);
    }
    let trlist_1 = source.find("TR");
    let trlist_2 = ftx.find("TR");
    trlist_1.each(function(i) {
        var tr = $(this);
        var h = tr.outerHeight();
        if (trlist_1.eq(i).outerHeight() > trlist_2.eq(i).outerHeight()) {
            h = trlist_1.eq(i).outerHeight();
        } else {
            h = trlist_2.eq(i).outerHeight();
        }
        $(trlist_2.eq(i)).css("height", h);
        $(trlist_2.eq(i)).css("height", h);
    });
}