import { TabControl } from "../../../../baseControls";

import { map } from '../../../../decorator/controlmap';

@map('选项卡', 'dsf.navtab', 'NavTab')
export class NavTab extends TabControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.tabHeight = '100%'
    this.enableDelete = false;
    this.tabPosition = "";
    this.$showPadding = true;
  }

  render() {
    super.render();
    !this.$showPadding ? this.addClass("no_padding") : this.removeClass("no_padding");
    if (this.tabStyle == "customer-tab-pad") {
      $('.layui-tab-title').find('li').html(" ")
    }
  }

  changeDeleteStyle() {
    if (this.enableDelete) {
      $('.ds_tabcontainer .layui-tab').attr("lay-allowClose", true);
      this._handlers["layui-tab-title"].removeClass("cancelDeleteTab").addClass("enableDeleteTab")
    } else {
      $('.ds_tabcontainer .layui-tab').removeAttr("lay-allowClose");
      this._handlers["layui-tab-title"].removeClass("enableDeleteTab").addClass("cancelDeleteTab");
    }
    layui.element.render(this.id);
  }
  changeStyle() {
    super.changeStyle()
    if (Boolean(this.tabPosition)) {
      if (this._handlers.tabContainer.hasClass("tabContainer")) {
        this._handlers.tabContainer.removeClass().addClass(this.tabPosition)
      } else {
        this._handlers.tabContainer.addClass(this.tabPosition)
      }
      if (this._handlers.tabContainer.hasClass("bottom_container")) {
        this._handlers["layui-tab-title"].css({ top: 'unset', bottom: '16px' });
      } else if (this._handlers.tabContainer.hasClass("tabSideContainer")) {
        this._handlers["layui-tab-title"].css({ top: 0, bottom: 0 });
      }
    } else {
      this._handlers.tabContainer.removeClass().addClass("container")
      this._handlers["layui-tab-title"].css({ top: 0, bottom: 0 });
    }

  }
  resizeHeight() {
    super.resizeHeight()
    if (this._handlers.tabContainer.hasClass("tabSideContainer")) {
      this._handlers["layui-tab-title"].css({ top: 0, bottom: 0 });
    }
  }
}