const dom = require("../../templates/Title.ejs");
import { Text } from '../../../../baseControls'
import { map } from '../../../../decorator/controlmap';

@map('标题基类', 'dsf.title', 'Title')

export class Title extends Text {
  constructor(id, isPart) {
    super(id, isPart);
    this.$htmlFor = "";
    this.$useVdom = true;
    this.showColorLump = false;
    this.showUnderline = false;
    this.showWeight = false;
    this.textAlign = "";
    this.fontFamily = "";
    this.remake = ''
  }
  initTemplate() {
    return dom(this);
  }
  get htmlFor() {
    return this.$htmlFor;
  }
  set htmlFor(value) {
    this.$htmlFor = value;
    this.domUpdate();
  }
  set colorLump(v) {
    this.showColorLump = v;
    this.domUpdate();
  }
  get colorLump() {
    return this.showColorLump;
  }
  set value(v) {
    super.value = v;
    this.domUpdate();
  }
  get value() {
    return this.$value;
  }

  beginEdit() {
    if (this.isDesign) {
      this._editting = true;
      this.domUpdate();
      this.element.find(".contenteditable").focus();
    }
  }
  endEdit(evt) {
    if (this.isDesign) {
      this._editting = false;
      this.value = evt.target.innerHTML;
    }
  }
}