const dom = require("../../templates/TextBox.ejs");
// const test = require("../../templates/testcode.ejs");
import { FormControl } from '../../../../baseControls'
import { TextMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControlEvent } from '../../../../core/ControlEvent';
import { map } from '../../../../decorator/controlmap';

@map('文本框', 'dsf.textbox', 'TextBox')
@isSupportDataPost(true)
export class TextBox extends FormControl {
   constructor(id, isPart) {
      super(id, isPart);
      this.$placeholder = "请输入";
      this.label = "输入框";
      this.value = "";
      this.$metadata = TextMetaData.call(this, 200);
      this.openInputGrade = false;
      this.$encrypt = false;
      this._inputGrade = {}
   }

   get label() {
      return super.label;
   }
   set label(value) {
      super.label = value;
   }

   set value(value) {
      value = (value == null || value == undefined) ? "" : value;
      super.value = value;
      if (this._handlers.input) {
         this._handlers.input.val(this.value);
      }
      if (this._handlers.readOnlyLabel) {
         this._handlers.readOnlyLabel.text(this.value);
      }
   }
   get value() {
      return super.value;
   }

   set placeholder(value) {
      this.$placeholder = value;
      if (this._handlers.input) {
         this._handlers.input.attr("placeholder", value);
      }
   }
   get placeholder() {
      return this.$placeholder;
   }


   set encrypt(value) {
      this.$encrypt = value;
   }

   get encrypt() {
      return this.$encrypt
   }

   initTemplate() {
      return dom(this);
   }

   renderContext() {
      super.renderContext();
      if (this.$encrypt === undefined) this.$encrypt = false;
      if (this.disabled) {
         if (this._handlers.input) {
            this._handlers.input.prop("disabled", true);
         }
      }
      if (this.ishideCon) {
         if (this._handlers.input) {
            this._handlers.input.prop("type", 'password');
         }
      }
   }

   renderReady() {
      // let d1 = new Date();
      let _this = this;
      super.renderReady();
      this.element.off("input.textChange");
      this.element.off("change.textChange");

      function fn() {
         _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
      }
      let trigger = _.debounce(fn, 100);
      // this.element.on("input.textChange", "input", _.debounce(fn, 200));
      this.element.on("input.textChange", "input", evt => {
         let val = $(evt.target).val();
         if (_this.$metadata && this.$metadata.valueAttributes[0].type.value == "number") {
            let reg = /^[\-]?\d*?\.?\d*?$/;
            let check = val.match(reg);
            if (!check) {
               let newVal = val.replace(/[^0-9\.-]/g, "");
               $(evt.target).val(newVal);
            }
         }
         let isChange = $(evt.target).val() != _this.value;
         _this.value = _this.$value = $(evt.target).val();

         if (isChange) {
            trigger();
         }
      });
      this.element.on("change.textChange", "input", evt => {
         this.commitAudit();
      });
   }
   renderComplete() {
      super.renderComplete();
      this.changeInputGrade();
   }


   changeInputGrade() {
      let _this = this;
      if (this.openInputGrade) {
         this._inputGrade = new dsf.inputGrade.init({
            inputJqDom: _this.element.find('input').eq(0),
            value: _this.value
         })
      } else if (this._inputGrade.destroy) {
         this._inputGrade.destroy();
      }
   }

}