function returnSelectedValue(returnFn, SelectedFn) {
    return function (target) {
        target.prototype._allowReturnValue = true;
        target.prototype._getSelectedValue = function (returnType) {
            if (this instanceof dsf.Controls.DataGrid) {
                return DataGridReturnValueHanler.call(this, returnType);
            }
            if (this instanceof dsf.Controls.CheckNode) {
                return CheckNodeReturnValueHanler.call(this, returnType);
            }
        };
        target.prototype._setSelectedValue = function (data, returnType) {
            if (this instanceof dsf.Controls.DataGrid) {
                return DataGridSetCheckedHandler.call(this, data, returnType)
            }
            if (this instanceof dsf.Controls.CheckNode) {
                return CheckNodeSetCheckedHanler.call(this, data, returnType);
            }
        }
    }
}

//DataGrid控件处理选中值
function DataGridSetCheckedHandler(data, returnType) {
    if (returnType == "TextValue") {
        let checked = [];
        let firstColumn = this.$dataRowsColumns[0];
        for (let i = 0; i < data.length; i++) {
            let obj = {
                "_id": data[i].value
            }
            obj[firstColumn] = data[i].text;
            checked.push(obj);
        }
        this.setCheckedData(checked);
    }else if(returnType == "object"){

    }else {
        this.setCheckedData(data);
    }
}
//DataGrid控件返回值处理
function DataGridReturnValueHanler(returnType) {
    if (returnType == "TextValue") {
        let rows = this.getCheckedData();
        let result = [];
        for (let i = 0; i < rows.length; i++) {
            let row = rows[i];
            let firstColumn = this.$dataRowsColumns[0];
            let returnVal = { "value": row["_id"] };
            if (typeof (row[firstColumn]) == "string") {
                returnVal.text = row[firstColumn];
            } else if (typeof (row[firstColumn]) == "object" && row[firstColumn].text != undefined) {
                if (row[firstColumn].text != undefined) {
                    returnVal.text = row[firstColumn].text;
                } else if (row[firstColumn].name != undefined) {
                    returnVal.text = row[firstColumn].name;
                } else if (row[firstColumn]._name != undefined) {
                    returnVal.text = row[firstColumn]._name;
                }
            }
            if (returnVal.text == undefined) {
                returnVal.text = "无文本内容";
            }
            result.push(returnVal);
        }
        return result;
    } else {
        let rows = this.getCheckedData();
        return rows;
    }
}

//CheckNode控件处理选中值
function CheckNodeSetCheckedHanler(data, returnType) {
    if (returnType == "TextValue") {
        for (let i in data) {
            data[i]._name = data[i].text;
            data[i]._id = data[i].value;
        }
    }
    this.value = data;
}
//CheckNode控件返回值处理
function CheckNodeReturnValueHanler(returnType) {
    if (returnType == "TextValue") {
        let result = this.value;
        for (let i = 0; i < result.length; i++) {
            result[i].text = result[i]._name;
            result[i].value = result[i]._id;
        }
        return result;
    } else {
        let rows = this.getCheckedData();
        return rows;
    }
}

export {
    returnSelectedValue
}