import dom from '../templates/RankControl.ejs'
import {
  FormControl
} from './FormControl'
import {
  ControlEditor
} from '../../editor/ControlEditor'
import {
  isSupportDataPost
} from '../../core/postDecorator'
import {
  map
} from '../../decorator/controlmap'

@map('评分基类', 'dsf.rankcontrol', 'RankControl')
@isSupportDataPost(true)
export class RankControl extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = '评分';
    this._desingerClass = ControlEditor;
    /**
     * styleType:评分模式
     * 1：混合模式
     * 2：滑块模式
     * 3：文本模式
     * 4：选项模式
     * 5：下拉模式
     * 6：五角星模式
     */
    this.styleType = 1;

    /**
     * chooseType:选项模式
     * 1：5分制
     * 2：10分制
     * 3：等级制1
     * 4：等级制2
     * 5：等级制3
     * 6：等级制4
     * 7：等级制5
     * 8：等级制6
     * 9：自定义
     */
    this.chooseType = 1;

    this.chooseTypeData = [
      [{ //5分制
          text: '1分',
          value: '1'
        },
        {
          text: '2分',
          value: '2'
        },
        {
          text: '3分',
          value: '3'
        },
        {
          text: '4分',
          value: '4'
        },
        {
          text: '5分',
          value: '5'
        }
      ],
      [{ //10分制
          text: '1分',
          value: '1',
        },
        {
          text: '2分',
          value: '2',
        },
        {
          text: '3分',
          value: '3',
        },
        {
          text: '4分',
          value: '4',
        },
        {
          text: '5分',
          value: '5',
        },
        {
          text: '6分',
          value: '6',
        },
        {
          text: '7分',
          value: '7',
        },
        {
          text: '8分',
          value: '8',
        },
        {
          text: '9分',
          value: '9',
        },
        {
          text: '10分',
          value: '10',
        },
      ],
      [{ //等级制1
          text: '满意',
          value: '100',
        },
        {
          text: '不满意',
          value: '0',
        },
      ],
      [{ //等级制2
          text: '满意',
          value: '100',
        },
        {
          text: '基本满意',
          value: '50',
        },
        {
          text: '不满意',
          value: '0',
        },
      ],
      [{ //等级制3
          text: '满意',
          value: '100',
        },
        {
          text: '基本满意',
          value: '66',
        },
        {
          text: '一般',
          value: '33',
        },
        {
          text: '不满意',
          value: '0',
        },
      ],
      [{ //等级制4
          text: '优秀',
          value: '100',
        },
        {
          text: '良好',
          value: '66',
        },
        {
          text: '一般',
          value: '33',
        },
        {
          text: '差',
          value: '0',
        },
      ],
      [{ //等级制5
          text: '是',
          value: '100',
        },
        {
          text: '否',
          value: '0',
        },
      ],
      [{ //等级制6
          text: '优秀',
          value: '100',
        },
        {
          text: '良好',
          value: '75',
        },
        {
          text: '一般',
          value: '50',
        },
        {
          text: '较差',
          value: '25',
        },
        {
          text: '很差',
          value: '0',
        },
      ],
      [] //自定义
    ]

    //下拉模式最大值
    this.selectMaxV = 10;

    // 文本分制 5:5分制、10:10分制、30:30分制
    this.chooseTypeInput = 5;

    // 评分项
    this.rowSet = {
      level: '1',
      weight: '0',
      norm: '1',
      rows: [],
      total: 0,
    }

    // 是否必评
    this.$required = false;

    // 总分
    this.total = 0;

    // 自定义内容设置
    this.scoringOptions = []

    // 星星默认配置
    this.rateOptions = {
      length: 5,
      value: 0,
      theme: '#FFB800',
      half: false,
      text: true,
      readonly: false,
      textArray: ['极差|20', '差|40', '中等|60', '好|80', '极好|100'],
    }

    // 滑块默认配置
    this.sliderConfig = {
      min: 0,
      max: 100,
      step: 1,
      showstep: false
    }
    
    // 默认权重总和
    this.totalWeight = 100
  }
  initTemplate() {
    return dom(this)
  }
  renderContext() {
    super.renderContext();
    if(!this.totalWeight){
      this.totalWeight = 100
    }

    this.element.off('input.textChange')
    let _this = this,
      form = layui.form

    function fn(dom) {
      changeSelectValue.call(_this, dom, true, true)
    }

    if (_this.root._isDesign) {
      _this.metadata_fullcode = ''
    }
    form.on('select(select_' + _this.id + ')', function(data) {
      changeSelectValue.call(_this, data)
    })
    form.render('select')

    _this.element.on('click', '.ds_button', function() {
      $(this)
        .parent()
        .find('.selected')
        .removeClass('selected')
        .addClass('ds_button_auxiliary')
      $(this)
        .addClass('selected')
        .removeClass('ds_button_auxiliary')
      changeSelectValue.call(_this, $(this), true)
    })

    let trigger = _.debounce(fn, 200)
    this.element.on('input.textChange', 'input', (evt) => {
      let val = $(evt.target).val()
      let reg = /^\d*?\.?\d{0,2}?$/
      let check = val.match(reg)
      if (!check) {
        let index = $(evt.target).attr('index')
        index = index.split('_')
        if (index.length == 1) {
          $(evt.target).val(_this.rowSet.rows[index[0]].score || '')
        } else {
          $(evt.target).val(
            _this.rowSet.rows[index[0]].children[index[1]].score || ''
          )
        }
      }
      trigger($(evt.target))
    })

    _.forEach(_this.rowSet.rows, function(val, key) {
      if (val.children && val.children.length > 0) {
        _.forEach(val.children, function(_val, _key) {
          let _id = '#' + _this.id + '_hk_' + key + '_' + _key;
          let sliderConfig = _val.sliderConfig || _this.sliderConfig;
          //渲染滑块
          layui.slider.render({
            elem: _id, //绑定元素
            value: _val.score || sliderConfig.min || 0,
            min: sliderConfig.min,
            max: sliderConfig.max,
            step: sliderConfig.step,
            showstep: sliderConfig.showstep,
            change: function(value) {
              console.log(value)
              $(_id).attr('value', value)
              changeSelectValue.call(_this, $(_id), true)
            },
          })
          
        })
      } else {
        let _id = '#' + _this.id + '_hk_' + key;
        let sliderConfig = val.sliderConfig || _this.sliderConfig;
        //渲染滑块
        layui.slider.render({
          elem: _id, //绑定元素
          value: val.score || sliderConfig.min || 0,
          min: sliderConfig.min,
          max: sliderConfig.max,
          step: sliderConfig.step,
          showstep: sliderConfig.showstep,
          change: function(value) {
            $(_id).attr('value', value)
            changeSelectValue.call(_this, $(_id), true)
          },
        })
        // 星星模式
        let _rate = '#' + _this.id + '_rate_' + key
        let matchRate = parseFloat(val.score || _this.rateOptions.value)
        let rateValue = 0
        _(_this.rateOptions.textArray).forEach(function(item, index) {
          var v = item.split('|')
          if (v.indexOf(matchRate + '') == 1) {
            rateValue = ++index
          }
        })

        layui.rate.render({
          elem: _rate,
          length: _this.rateOptions.length,
          value: rateValue,
          text: _this.rateOptions.text,
          half: _this.rateOptions.half,
          readonly: _this.rateOptions.readonly,
          setText: function(value) {
            var newArr = {}
            _(_this.rateOptions.textArray).forEach(function(item, index) {
              var v = item.split('|')
              Object.assign(newArr, {
                [v[1]]: v[0]
              })
            })
            this.span.text(newArr[matchRate] || '')
          },
          choose: function(value) {
            $(_rate).attr('value', value)
            let elm = $(_rate)
            let _i = value
            if (this.half) {
              _i = value * 2
            }
            if (_this.rateOptions.textArray[_i - 1]) {
              let val = _this.rateOptions.textArray[_i - 1].split('|')[1]
              matchRate = val
              elm.val = function() {
                return val
              }
            }
            changeSelectValue.call(_this, elm, true, true)
          },
        })
      }
    })
  }
  showTips(message, selector, pos, time) {
    let _this = this
    if (selector && !selector.data('isShow')) {
      let index = layui.layer.tips(message, selector, {
        tips: pos,
        time: time == undefined ? 2000 : time,
        tipsMore: true,
        end: function() {
          selector.data('tipsIndex', null)
          selector.data('isShow', false)
        },
      })
      selector.data('isShow', true)
      selector.data('tipsIndex', index)
    }
  }
  validateError() {
    let errors = this.vaildateData()
    let _this = this

    $(_this.element)
      .find('.ds_error')
      .removeClass('ds_error')

    if (this._validator) {
      _.forEach(errors, function(obj, index) {
        let errorPostElement = $(
          $(_this.element).find('tbody tr')[obj.index]
        ).find('td:last-child')
        errorPostElement.addClass('ds_error')
        _this.showTips(obj.errorMsg, errorPostElement, 2)
      })
    }
  }
  customerValidate() {
    let errors = this.vaildateData()
    if (!errors || errors.length == 0) {
      return null
    } else {
      return '评分验证'
    }
  }
  changeTotal(t) {
    this.event.trigger(FormControlEvent.VALUECHANGE, {
      ui: this,
      total: t,
    })
  }
  changeSelectValue() {
    changeSelectValue.call(this)
  }
}

function destroyToolTips() {
  $(this).off('mouseenter.tooltips')
  $(this).off('mouseleave.tooltips')
  $(this).removeClass('ds_error')
}

function changeSelectValue(data, chooseType, isInput, noTrigger, type) {
  let _this = this;
  if (data) {
    let index = chooseType ? data.attr('index') : data.elem.getAttribute('index');
    let value = chooseType ? (isInput ? data.val() : data.attr('value')) : data.value;
    value = (value * 1).toFixed('2');
    index = index.split('_');
    if (index.length == 1) {
      _this.rowSet.rows[index[0]].score = value
    } else {
      _this.rowSet.rows[index[0]].children[index[1]].score = value
    }
  }
  let total = 0
  let length = 0

  for (let i in _this.rowSet.rows) {
    let obj = _this.rowSet.rows[i]
    if (obj.weight) {
      total += (obj.score || 0) * (obj.weight / 100) * (_this.totalWeight / 100)
    } else {
      total += (obj.score || 0) * (_this.totalWeight /100)
    }
    if (!obj.children) {
      length++
    }
    _.forEach(obj.children, function(_val, _key) {
      length++
      if (_val.weight) {
        total += (_val.score || 0) * (_val.weight / 100) * (_this.totalWeight /100)
      } else {
        total += (_val.score || 0) * (_this.totalWeight /100)
      }
    })
  }
  if (!noTrigger) {
    _this.changeTotal(total)
  }
  _this.total = total
  if (_this.rowSet.weight == '0') {
    total = total / length
  }
  _this.rowSet.total = total.toFixed(2)
  
  if (!chooseType) {
    _this.render()
  } 
}
