import dome from '../templates/Chart.ejs';
import { ControlEditor } from "../../editor/ControlEditor";
import { relyFiles } from "../../core/relyfiles";
import { Control } from './Control';
import { map } from '../../decorator/controlmap';

@map('图表基类', 'dsf.ChartControl', 'ChartControl')
@relyFiles([
  'res/libs/echarts/echarts.min.js',
])
export class ChartControl extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.height = '519px';
    this.$label = "";
    this.url = '/teas/jwgl/bjxygl/statistics';
    this.busniessType = "";
    this.chartData = { series: [], xAxis: [] };
    this.chartType = 'bar';
    this.chartColor = '#D7DA8B';
    this.isShowYSplitLine = false;
    this.isShowLegend = false;
    this.orient = "horizontal";
    this.position='right';
    this.isShowYAxisLine=true;
    this.isShowXAxisLine = true
    console.log(1)
  }

  set label(value) {
    this.$label = value;
    if (this.element && this._handlers.label) {
      this._handlers.label.html(value);
    }
    this.updateLabel();
  }

  get label() {
    return this.$label;
  }


  initTemplate() {
    return dome(this);
  }

  updateLabel() {
    if (this.root && this.root._isDesign) {
      let text = ($("[ctrl_type=Label][htmlfor=" + this.id + "]"));
      if (text.length > 0) {
        let textCtrl = text.data("Object");
        if (textCtrl) {
          textCtrl.$required = this.$required;
          textCtrl.value = this.label;
        }
      }
    }
  }
  renderContext() {
    super.renderContext();
    this.getChartData()
    this.renderChart();
    this.renderEvent();
  }

  renderEvent() {
    window.addEventListener('resize', () => {
      this.chart && this.chart.resize();
    })
  }

  renderReady() {
    super.renderReady();
    setTimeout(() => {
      this.chart && this.chart.resize();
    }, 0)
  }

  renderChart() {
    this.rigialOption = {
        grid: {
          left: 30,
          top: 20,
          bottom: 20,
          right: 30,
        },
        tooltip: {
          trigger: 'axis',
          backgroundColor: 'rgba(255,255,255,.8)',
          borderColor: '#6ca6cd',
          borderWidth: 1,
          padding: [5, 10],
          textStyle: {
            color: '#333'
          },
          axisPointer: {
            type: 'cross',
            label: {
              backgroundColor: this.chartColor
            }
          }
        },
        color: [ this.chartColor],
        xAxis: {
          show:true,
          type: 'category',
          data: [],
          splitLine: {
            show:false
          },
          splitArea: {
            show: false
          },
          axisLine: {
            lineStyle: {
              color: '#999'
            },
            show:this.isShowXAxisLine
          },
          axisLabel: {
            color: '#999'
          },
          axisTick: {
            show: false,
          }
        },
        yAxis: {
          show:true,
          type: 'value',
          splitLine: {
            show: this.isShowYSplitLine,
          },
          splitArea: {
            show: false
          },
          axisLine: {
            lineStyle: {
              color: '#999'
            },
            show:this.isShowYAxisLine
          },
          axisLabel: {
            color: '#999',
            inside:true,
            textStyle:{
              color: '#fff'
            }
          },
          axisTick: {
            show: false,
          }
        },
        legend:{
          right:'5%'
        },
        series: [{
          data: [],
          type: 'line',
          symbolSize: 2,
          label: {
            show: true,
            position: 'top'
          },
        }]
      }
    this.chart = echarts.init(this._handlers['chart'][0]);
    if(this._root._isDesign){
      this.chart.setOption( this.rigialOption)
    }
  }

  getChartData() {
    let param = {
      classId: dsf.url.queryString('classid') || '5e4a9e79c605479186218651bf159843',
      type: this.busniessType
    }
    dsf.http.request(dsf.url.getWebPath(this.url), param, "get")
      .done(({ success, data }) => {
        if (success) {
          this.chartData.series =  data.series
          this.chartData.xAxis = data.xaxis
          this.setOption()
        }
      }).error(err => {
        dsf.layer.message(err.message || '接口出错');
      }).exec();
  }

  setOption() {
    this.defalutOption = {
      legend:{
        show:this.isShowLegend,
        orient:this.orient,
        left:this.position,
      },
      series: this.setChartType( this.chartData.series)
    }
   this.defalutOption  = $.extend(true, {}, this.rigialOption,this.defalutOption)
  }

  setChartType(series){
    _(series).forEach( item =>{
      item.type = this.chartType;
      if(this.isShowArea){
        item.areaStyle = {
          color: this.areaColor
        }
      }
    })
    console.log('series',series)
    return series
  }
}


