const dom = require("../../templates/Tree.ejs");
import { express } from '../../../../core/express';
import { ControlEditor } from '../../../../editor/ControlEditor'
import { LayoutControl } from '../../../../baseControls';
import { map } from '../../../../decorator/controlmap';

@map('树基类', 'dsf.tree', 'Tree')
export class Tree extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
	this._desingerClass = ControlEditor;
    // 配置树的设置
    this.setting = {
      view: {
        showLine: true,
        showIcon: true
      },
      data: {
        key: {
          name: "_name",
          url: ""
        },
        simpleData: {
          enable: true,
          idKey: "_id",
          pIdKey: "treeinfo_pid",
          rootPId: ""
        }
      },
      async: {
        enable: false
      },
      check: {
        enable: false,
        chkboxType: { "Y": "ps", "N": "ps" }
      },
      callback: {}
    };
    // 初始化树需要的节点数据
    this._zNodes = [];
    // 存放treeObj(生成树的返回值)
    this.zTreeObj = null;

    // 默认展开至第几级
    this.defaultOpenSeries = 1;
    // 是否正在展开设定的级数
    this._openingSeries = true;

    // 目标iframe地址、name属性
    this.targetIframe = {
      src: "",
      name: ""
    };

    /**
     * @desc 树的样式
     * 原始风格 "" (加号减号)
     * 箭头风格 arrowsTree
     */
    this.ztreeClass = "";

    // 是否关闭搜索功能，默认开启搜索
    this.closeSearch = false;

    this.searchNode = [];

    // 启用虚拟根目录
    this.open_webRoot = false;
    // 虚拟目录的名字
    this.webRoot_name = null;

  }

  get showLine() {
    return this.setting.view.showLine;
  }
  set showLine(value) {
    this.setting.view.showLine = value;
  }

  get showIcon() {
    return this.setting.view.showIcon;
  }
  set showIcon(value) {
    this.setting.view.showIcon = value;
  }

  get targetFrameSrc() {
    return this.targetIframe.src;
  }
  set targetFrameSrc(value) {
    this.targetIframe.src = value;
  }

  get targetFrameName() {
    return this.targetIframe.name;
  }
  set targetFrameName(value) {
    this.targetIframe.name = value;
  }

  init() {
	super.init();
    if (!this.root._isDesign) {
      this.setting.callback = {
        onClick: this.zTreeOnClick.bind(this),
        beforeAsync: this.asyncBefore.bind(this),
        onAsyncSuccess: this.asyncSuccess.bind(this),
        onRightClick: this.rightClick.bind(this)
      }
    }
    if (!this.metaDataType) {
      this.metaDataType = 1;
    }
  }
  initTemplate() {
    return dom(this);
  }
  initDesign() {
    // 设计器模式加载的数据
    this._zNodes = [{
      id: 1,
      pId: 0,
      _name: "父节点1",
      children: [{
        id: 11,
        pId: 1,
        name: "子节点1.1",
        children: [{
          id: 111,
          pId: 11,
          _name: "子节点1.1.1"
        }]
      }, {
        id: 12,
        pId: 1,
        _name: "子节点1.2"
      }]
    }, {
      id: 2,
      pId: 0,
      _name: "父节点2",
      children: [{
        id: 21,
        pId: 2,
        _name: "子节点2.1"
      }]
    }];
  }
  createElement() {
    super.createElement();
    if (this.root._isDesign) {
      this.initTree();
    }

    // 渲染搜索的Dom节点
    this.renderSearchDom();
  }
  initEvent() {
    if (this._handlers.search_box) {
      let _this = this;
      this._handlers.search.on('click', function(e) {
        // 搜索
        _this.search();
      });
      this._handlers.search_input.on('keyup', function(e) {
        // 回车搜索
        let keycode = window.event ? e.keyCode : e.which;
        if (keycode == 13) {
          _this.search();
        }
      });
    }
  }
  renderReady() {
	super.renderReady();
    this.initEvent();
  }
  initTree() {
    let _node = null;
    if (this.zTreeObj && this.zTreeObj.getSelectedNodes) {
      _node = this.zTreeObj.getSelectedNodes();
      console.log(_node);
    }

    //如果开启了异步请求，那在初始化前需要把所有节点都置成父节点标识
    if (!this.root._isDesign && this.setting.async.enable) {
      this.addIsParent(this._zNodes);
    }
    let _d = this._zNodes;

    // 启用虚拟路径
    if (this.open_webRoot && this.webRoot_name) {
      _d = {
        id: '',
        pid: '',
        name: this.webRoot_name,
        children: this._zNodes
      }
    }
    this.setting.data.key.name = "_name";
    //初始化树
    this.setting.view.fontCss = this.getFontCss.bind(this);
    this.zTreeObj = $.fn.zTree.init(this._handlers.tree, this.setting, _d);
    let nodes = this.zTreeObj.getNodes();

    /**
     * 展开层级处理
     * if 不是异步的时候，没有设置展开级数，就默认展开全部
     * else 展开对应级数
     */
    if (this.root._isDesign || (!this.setting.async.enable && !this.defaultOpenSeries)) {
      this.zTreeObj.expandAll(true);
    } else if (this.defaultOpenSeries && (parseInt(this.defaultOpenSeries) > 1)) {
      this.defaultExpandNodes(nodes);
    }

    /**
     * iframe处理
     * 初始化完成后，默认选中第一个节点，加载其iframe
     */
    if (!this.root._isDesign) {
      if (_node && _node[0] && _node[0]._id) {
        _node = this.zTreeObj.getNodeByParam("_id", _node[0]._id);
        this.zTreeObj.expandNode(_node, true, true, true);
        setTimeout(() => {
          this.zTreeObj.selectNode(_node, false, false);
        }, 300)
      } else {
        this.selectNodeLoadIframe(_node || nodes[0]);
      }
    }

  }

  //右键菜单
  rightClick() {}

  search() {
    if (this.zTreeObj) {
      const v = this._handlers.search_input.val().replace(/\s|\n/m, '');
      const nodes = this.zTreeObj.transformToArray(this.zTreeObj.getNodes());
      const treeId = this.zTreeObj.setting.treeId;
      if (v) {
        this.updateNodes(false);
        this.searchNode = this.zTreeObj.getNodesByParamFuzzy('_name', v);
        const temp = [];
        const fn = node => {
          temp.push(node);
          const pn = node.getParentNode();
          pn && fn(pn);
        }
        this.searchNode.forEach(n => fn(n));
        this.updateNodes(true);
        this.zTreeObj.hideNodes(nodes);
        this.zTreeObj.showNodes(temp);
        if (!this.searchNode.length) {
          if($("#" + treeId).find('div').hasClass('tips')){
            $(".tips").remove()
          }
          $("#" + treeId).append($("<div class='tips' style='text-align:center;padding:20px'><img style='width:40%;max-width:162px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"));        
        } else {
          $("#" + treeId).find('.tips').remove();
          this.zTreeObj.selectNode(this.searchNode[0], false, false);
        }
      } else if(!v) {
        this.zTreeObj.showNodes(this.zTreeObj.transformToArray(this.zTreeObj.getNodes()));
        this.updateNodes(false);
        $("#" + treeId).find('.tips').remove();
      } 
    }
  }
  getFontCss(treeId, treeNode) {
    return (!!treeNode.highlight) ? { color: "#EB6025", "font-weight": "bold" } : { color: "#333", "font-weight": "normal" };
  }
  updateNodes(highlight) {
    for (let i in this.searchNode) {
      this.searchNode[i].highlight = highlight;
      this.zTreeObj.updateNode(this.searchNode[i]);
    }
  }
  addIsParent(nodes) {
    for (let i in nodes) {

      if ((nodes[i].treeinfo_level * 1 < this.maxLevel * 1) || !this.maxLevel) {
        nodes[i].isParent = true;
      }

      if (nodes[i].children) {
        this.addIsParent(nodes[i].children)
      }
    }
  }
  defaultExpandNodes(nodes) {
    for (let i in nodes) {
      if (nodes[i].level >= (parseInt(this.defaultOpenSeries || 0) - 1)) {
        this._openingSeries = false;
        return;
      }
      this.zTreeObj.expandNode(nodes[i], true);
      if (nodes[i].isParent && nodes[i].zAsync) {
        this.defaultExpandNodes(nodes[i].children, true);
      }
    }
  }
  selectNodeLoadIframe(treeNode) {
    this.zTreeObj.selectNode(treeNode);
    this.loadIframe(treeNode);
  }
  loadIframe(treeNode) {
    let iframeDom = this._root.element.find("iframe[name='" + this.targetIframe.name + "']")[0];
    if (iframeDom) {
      let url = dsf.Express.replace(this.targetIframe.src, treeNode);
      url = dsf.url.analysis(url);
      iframeDom.src = url;
    }
  }
  zTreeOnClick(event, treeId, treeNode) {
    this.loadIframe(treeNode);
  }
  changeStyle() {
    let treeDom = this._handlers.tree;
    treeDom.removeClass("arrowsTree");
    if (this.ztreeClass != "") {
      treeDom.addClass("arrowsTree");
    }
  }


  // 异步加载处理
  asyncBefore(treeId, treeNode) {
    // 异步请求前
  }
  asyncDataFilter(treeId, parentNode, responseData) {
    // 异步请求数据过滤
    if (responseData.state == "20000") {
      for (let i in responseData.data) {
        if ((responseData.data[i].treeinfo_level * 1 < this.maxLevel * 1) || !this.maxLevel) {
          responseData.data[i].isParent = true;
        }
      }
      return responseData.data;
    } else {
      return [];
    }
  }
  asyncSuccess(event, treeId, treeNode, msg) {
    // 异步请求成功
  }
  renderSearchDom() {
    if (this.closeSearch) {
      this._handlers.search_box.hide();
      this._handlers.navTree_body.removeClass('hasPaddingTop');
    } else {
      this._handlers.search_box.show();
      this._handlers.navTree_body.addClass('hasPaddingTop');
    }
  }
}