const dom = require("../../templates/stepsNav.ejs");
import { TabControl } from "../../../../baseControls";
import { isSupportDataPost } from '../../../../core/postDecorator';
// import { format } from "url";
import { map } from '../../../../decorator/controlmap';

@map('步骤导航', 'dsf.stepsnav', 'StepsNav')
@isSupportDataPost(true)
export class StepsNav extends TabControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.tabTitles = [];
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    super.createElement();

  }

  init() {
    if (this.tabTitles.length == 0) {
      this.tabTitles = [
        { num: "1", name: "step1", id: dsf.uuid() },
        { num: "2", name: "step2", id: dsf.uuid() },
        { num: "3", name: "step3", id: dsf.uuid() },
        { num: "4", name: "step4", id: dsf.uuid() }
      ]
    }

  }
  renderDom() {
    this.renderContext(true);
  }

  renderContext(isUpdate) {
    super.renderContext(isUpdate)

  }

  renderTabTitles() {
    this._tabTitleBox.html("");
    let len = this.tabTitles.length;
    let li = null
    for (let i = 0; i < len; i++) {
      if (i == 0) {
        li = $("<li class='layui-this' lay-id='" + i + "'>")
      } else if (i == len - 1) {
        li = $("<li id='last' lay-id='" + i + "'>")
      } else {
        li = $("<li lay-id='" + i + "'>")
      }
      li.html(this.tabTitles[i].name);
      this._tabTitleBox.append(li)

    }
  }
  resizeHeight() {
    super.resizeHeight()
  }
  initEvent() {
    let lis = this._tabTitleBox.find('li')
    for (let i = 0; i < lis.length; i++) {
      // if (i != 0) {
      $(lis[i]).css("pointer-events", "none")
      // }
    }
  }
  render() {
    super.render();
  }
  renderReady() {
    super.renderReady()
    let operateDomIndex = window.location.search.replace("stepIndex", "");
    if (operateDomIndex) {
      let obj = getCurrentTabIndex.call(this, this);
      this.operateDom(this, obj.tabs, operateDomIndex)
    }
  }
  nextStep(dom) {
    let obj = getCurrentTabIndex.call(this, dom);
    let operateDomIndex = obj.currentIndex + 1;
    // window.location.hash="#stepIndex"+operateDomIndex;
    window.localStorage.setItem("stepIndex", operateDomIndex)
    if (obj.currentIndex == obj.tabArray.length - 1) {
      operateDomIndex = obj.currentIndex
    }
    this.operateDom(dom, obj.tabs, operateDomIndex)
  }
  preStep(dom) {
    let obj = getCurrentTabIndex.call(this, dom);
    let operateDomIndex = obj.currentIndex - 1;
    window.localStorage.setItem("stepIndex", operateDomIndex)
    // window.location.hash="#stepIndex"+operateDomIndex;
    if (operateDomIndex < 0) {
      operateDomIndex = 0
    }
    this.operateDom(dom, obj.tabs, operateDomIndex)
  }
  chooseStep(e, index) {
    let dom = e.data.dom;
    let obj = getCurrentTabIndex.call(this, dom);
    if (index > obj.tabArray.length - 1) {
      index = obj.tabArray.length - 1
    }
    if (index < 0) {
      index = 0
    }
    this.operateDom(dom, obj.tabs, index)
  }
  operateDom(dom, tabs, operateDomIndex) {
    let operateTab = tabs.children[operateDomIndex];
    $(operateTab).addClass("layui-this").siblings().removeClass("layui-this");
    let operateContent = dom._handlers['layui-tab-content'][0].children[operateDomIndex]
    $(operateContent).addClass("layui-show").siblings().removeClass("layui-show")
  }
}

function getCurrentTabIndex(dom) {
  let tabs = dom._handlers['layui-tab-title'][0];
  let tabArray = tabs.children;
  let tabClassArr = [];
  for (let i = 0; i < tabArray.length; i++) {
    tabClassArr.push(tabArray[i].className)
  }
  let currentTabIndex = $.inArray("layui-this", tabClassArr);
  let obj = {
    tabs: tabs,
    currentIndex: currentTabIndex,
    tabArray: tabArray
  }
  return obj
}

