import { express } from "../core/express";

//点击页面任意位置，隐藏更多按钮气泡
$(document).on("click.hidemenu", function (evt) {
  let target = $(evt.target);
  let isInBubble = false;
  if (target.hasClass("ds_bubble") || target.get(0).tagName == "TD") {
    isInBubble = true;
  }
  if (!isInBubble) {
    hiddenBubble($(".ds_bubble_buttons"));
  }
});

function hiddenBubble(bubbles) {
  bubbles.each(function (i, el) {
    let bubble = $(el);
    let mbutton = bubble.data("morebutton");
    mbutton.removeClass("open");
    bubble.hide();
  });
}

function ButtonBar() {
  return {
    buttons: [],
  };
}

function createButton(text, actionName, icon, buttonType, style, show, isSystem, actionArgs, uploadFile) {
  return {
    text: text,
    actionName: actionName,
    alias: "",
    icon: icon,
    buttonType: buttonType,
    style: style,
    show: show || "default",
    isSystem: isSystem,
    actionArgs: actionArgs,
    uploadFile: uploadFile || null,
    isRender: true,
    isView: false,
  };
}

function renderButtons(control, box, buttonBar, data, eventType, styleType) {
  let showButtons = [];
  let more = [];
  box.html("");
  box.off("click");
  let isPreView = control.root.preview;
  let isDebug = control.root._isDebug;
  let buttons = buttonBar.buttons;
  _.each(buttons, button => {
    if (!control.root._isDesign) {
      //页面只读状态下是否显示
      if (button.isView && control.root._isView) {
        button.isRender = !control.root._isView;
      }
      if (button["if"]) {
        let d = data || control.root._data;
        let ifExpress = true;
        try {
          ifExpress = express.eval(button["if"], d);
        } catch (ex) {
          dsf.error("运算按钮显示表达式存在错误");
          throw ex;
        }
        ifExpress ? (button.isRender = true) : (button.isRender = false);
      }
    }
    let _eventType = eventType ? eventType + "_" : "";
    let eventName = _eventType + "buttonbar_render";
    control.event.trigger(eventName, {
      ui: control,
      args: {
        button: button,
        data: data,
      },
    });
    // if (button.isRender != false) {
    //     if (button.show == "default") {
    //         showButtons.push(button);
    //     } else {
    //         more.push(button);
    //     }
    // }
    if (button.show == "default") {
      showButtons.push(button);
    } else if (button.isRender == undefined || button.isRender) {
      more.push(button);
    }
  });
  let showButtonDiv = $("<div/>");
  showButtons.forEach(v => {
    let btn = createButton(v, styleType);
    btn && showButtonDiv.append(btn);
  });
  if (more.length > 0) {
    let moreButton = null;
    let mouseIn = false;
    //更多按钮取未折叠的最后一个按钮的样式
    let last_btn = showButtons[showButtons.length - 1];
    let last_btn_style = last_btn ? last_btn.style : 0;
    if (last_btn_style == "0") {
      moreButton = $(
        "<a class='ds_button ds_button_auxiliary ds_more_button " +
        (styleType == "small" ? "ds_button_md" : "") +
        "'>更多" +
        "<i class='iconfont layui-icon icon-xiangxiazhanhang collapse'></i>" +
        "<i class='iconfont layui-icon icon-xiangshangzhanhang expand'></i>" +
        "</a>"
      );
    } else if (last_btn_style == "2") {
      moreButton = $(
        "<a class='ds_button ds_icon_button ds_more_button " +
        (styleType == "small" ? "ds_button_md" : "") +
        "' ><i class='iconfont layui-icon icon-gengduo'></i></a>"
      );
    } else {
      moreButton = $(
        "<a class='ds_button ds_icon_button_text " +
        (styleType == "small" ? "ds_button_md" : "") +
        "'><i class='iconfont icon-gengduo' ></i><div>更多</div></a>"
      );
    }

    // if (styleType == "small") {
    //     moreButton = $("<a class='ds_button ds_icon_button ds_button_md ds_more_button' title='更多'><i class='iconfont layui-icon icon-gengduo'></i></a>");
    // } else {
    //     moreButton = $("<a class='ds_button ds_button_auxiliary ds_more_button'>更多" +
    //         "<i class='iconfont layui-icon icon-xiangxiazhanhang collapse'></i>" +
    //         "<i class='iconfont layui-icon icon-xiangshangzhanhang expand'></i>" +
    //         "</a>");
    // }
    // debugger;
    if (dsf.config.moreButtonOpenForClick) {
      moreButton.on("click.changemenu", evt => {
        if (control.root._isDesign) {
          return false;
        }
        mouseIn = !mouseIn;
        mouseIn ? showMenu() : hideMenu();
        return false;
      });
    } else {
      moreButton.on("mouseenter.showmenu", evt => {
        if (control.root._isDesign) {
          return false;
        }
        mouseIn = true;
        showMenu();
        return false;
      });
      moreButton.on("mouseleave.hidemenu", evt => {
        mouseIn = false;
        window.setTimeout(() => {
          !mouseIn && hideMenu();
        }, 500);
        return false;
      });
    }

    function showMenu() {
      hiddenBubble($(".ds_bubble_buttons"));
      let bubble = createBubble(more, moreButton);
      bubble.show();
      bubble.on("mouseenter.showmenu", function () {
        mouseIn = true;
        return false;
      });
      bubble.on("mouseleave.hidemenu", function () {
        mouseIn = false;
        window.setTimeout(() => {
          !mouseIn && hideMenu();
        }, 500);
        return false;
      });
      moreButton.attr("bubble_id", bubble.attr("id"));
      let top = moreButton.offset().top + (moreButton.outerHeight() + 13);
      let left = moreButton.offset().left + (moreButton.outerWidth() - bubble.outerWidth()) / 2;
      //判断下方尺寸是否够显示浮动层
      if (top + bubble.outerHeight() < $("body").get(0).clientHeight) {
        bubble.removeClass("bottom").addClass("top");
      } else {
        bubble.removeClass("top").addClass("bottom");
        top = moreButton.offset().top - (bubble.outerHeight() + 13);
      }
      //浮动层大于窗体可视宽度，浮动层偏移
      if (left + bubble.outerWidth() > $("body").get(0).clientWidth - 10) {
        let offsetLeft = bubble.outerWidth() + left - $("body").get(0).clientWidth;
        let arrowborder = bubble.children(".arrowborder");
        let arrow = bubble.children(".arrow");
        arrowborder.css("left", bubble.outerWidth() / 2 + offsetLeft + 10);
        arrow.css("left", bubble.outerWidth() / 2 + offsetLeft + 10);
        left = left - offsetLeft - 10;
      } else if (left < 10) {
        let offsetLeft = 0 - left;
        let arrowborder = bubble.children(".arrowborder");
        let arrow = bubble.children(".arrow");
        arrowborder.css("left", bubble.outerWidth() / 2 - offsetLeft - 10);
        arrow.css("left", bubble.outerWidth() / 2 - offsetLeft - 10);
        left = left + offsetLeft + 10;
      }
      moreButton.addClass("open");
      bubble.css({
        top: top,
        left: left,
      });
    }

    function hideMenu() {
      if (moreButton.hasClass("open")) {
        moreButton.removeClass("open");
        let bubble = $("#" + moreButton.attr("bubble_id"));
        bubble.length && bubble.hide();
      }
    }
    showButtonDiv.append(moreButton);
  }
  if (showButtonDiv.children().length <= 0) {
    showButtonDiv.hide();
  }
  box.append(showButtonDiv);

  box.on("click", ".ds_button", barClick);

  if (!control._root.isDesign) {
    for (var i = 0, len = buttons.length; i < len; i++) {
      let userargs = getButtonArgs(buttons[i].actionArgs);
      let evt = {
        target: box.find(".ds_button")[i],
      };
      if (userargs[2] == "render") {
        let actionName = buttons[i].actionName;
        if (actionName == "system_count_down") {
          countdown(control, buttons[i], evt);
        } else if (actionName == "system_comment_like") {
          comment_like(control, buttons[i], evt);
        } else if (actionName == "system_comment_attention") {
          comment_attention(control, buttons[i], evt);
        } else if (actionName == "system_collection") {
          collectionFn(control, buttons[i], evt);
        } else if (actionName == "system_subscriptionFn") {
          subscriptionFn(control, buttons[i], evt);
        }
      }
    }
  }

  function barClick(evt) {
    if (control.root.isDesign) {
      return;
    }
    if (isPreView && !isDebug) {
      dsf.layer.message("预览界面不支持该操作", false);
      return;
    }
    let target = $(evt.currentTarget);
    let button = target.data("data");
    if (button) {
      // console.log(button)
      if (button.isSystem) {
        evt._data = data;
        sysButtonHandler(control, button, evt);
        evt.stopPropagation();
      } else {
        let args = getButtonArgs(button.actionArgs, control);
        let _eventType = eventType ? eventType + "_" : "";
        let eventName = _eventType + "buttonbar_click";
        control.event.trigger(eventName, {
          actionName: button.actionName,
          actionArgs: args,
          ui: control,
          data: data,
        });
      }
    }
  }

  //创建浮动气泡
  function createBubble(moreButtons, mbutton) {
    let bubble = $("#" + control.id + "_buttonmore");
    if (bubble.length <= 0) {
      bubble = $("<div id='" + control.id + "_buttonmore' class='ds_bubble ds_bubble_buttons top'></div>");
      bubble.html("<div class='arrow'/><div class='arrowborder'/>");
      bubble.appendTo($("body"));
    } else {
      bubble.html("<div class='arrow'/><div class='arrowborder'/>");
    }
    bubble.hide();
    if (moreButtons.length <= 5) {
      let table = $("<table class='ds_gridbuttonbar'/>").appendTo(bubble);
      for (let i = 0; i < moreButtons.length; i++) {
        let btn = createButton(moreButtons[i]);
        //如果是图标文字按钮强制尺寸变为大号
        if (btn) {
          if (moreButtons[i].style == "4") {
            btn.removeClass("ds_button_md");
          }
          let tr = $("<tr/>");
          let td = $("<td>");
          td.append(btn);
          tr.append(td);
          table.append(tr);
        }
      }
    } else if (moreButtons.length <= 9) {
      renderButtonBubble(3);
    } else {
      renderButtonBubble(4);
    }
    bubble.off("click");
    bubble.on("click", ".ds_button", barClick);
    bubble.data("morebutton", mbutton);

    function renderButtonBubble(size) {
      let count = moreButtons.length % size;
      if (count > 0) {
        count = parseInt(moreButtons.length / size) + 1;
      } else {
        count = moreButtons.length / size;
      }
      let index = 0;
      let table = $("<table class='ds_gridbuttonbar'/>").appendTo(bubble);
      for (let i = 0; i < count; i++) {
        let tr = $("<tr></tr>");
        for (let n = 0; n < size; n++) {
          let cell = $("<td></td>");
          if (moreButtons[index]) {
            let btn = createButton(moreButtons[index]);
            //如果是图标文字按钮强制尺寸变为大号
            if (moreButtons[index].style == "4") {
              btn.removeClass("ds_button_md");
            }
            cell.append(btn);
          }
          tr.append(cell);
          index++;
        }
        table.append(tr);
      }
    }
    return bubble;
  }

  //创建按钮元素
  function createButton(button, styleType) {
    // debugger;
    if (button.isRender != false) {
      let html = "";
      let buttonType = button.buttonType == "auxiliary" ? "ds_button_auxiliary" : "";
      if (button.style == "0" || button.style == "1") {
        html =
          "<a class='ds_button " +
          (styleType == "small" ? "ds_button_md" : "") +
          " " +
          buttonType +
          "'  ds-event='" +
          button.actionName +
          "'><i class='iconfont " +
          button.icon +
          "'></i>" +
          button.text +
          "</a>";
      } else if (button.style == "2") {
        html =
          "<a class='ds_button ds_icon_button " +
          (styleType == "small" ? "ds_button_md" : "") +
          " " +
          buttonType +
          "' title='" +
          button.text +
          "' ds-event='" +
          button.actionName +
          "'><i class='iconfont " +
          button.icon +
          " ' ></i></a>";
      } else if (button.style == "4") {
        html =
          "<a class='ds_button ds_icon_button_text " +
          (styleType == "small" ? "ds_button_md" : "") +
          "' dsevent='" +
          button.actionName +
          "'><i class='iconfont " +
          button.icon +
          "' ></i><div>" +
          button.text +
          "</div></a>";
      } else if (button.style == "5") {
        html =
          "<a class='ds_button ds_icon_button_text " +
          (styleType == "small" ? "ds_button_md" : "") +
          "' dsevent='" +
          button.actionName +
          "' style='color:" +
          button.color +
          "' dstag='" +
          button.cate +
          "' title='" +
          button.text +
          "'><i class='iconfont " +
          button.icon +
          "'></i><span></span></a>";
      }
      html = $(html);
      html.data("data", button);
      button.hasHide && html.addClass("ds_hide");
      button.style == "2" && html.attr("title", button.text);
      return html;
    }
    return null;
  }
  return showButtonDiv;
}

//打开新窗口
let windowOpen = function (control, button, evt) {
  _windowOpen(button.actionArgs, evt._data || control);
};

function _windowOpen(args, data) {
  let _args = getButtonArgs(args, data);
  let url = dsf.url.getAbsolutePath(_args[0]);
  window.itemIsRead && window.itemIsRead(_args, data);
  dsf.layer.openWindow(url);
}
window["windowOpen"] = _windowOpen;

//层打开窗口
let layerOpen = function (control, button, evt) {
  _layerOpen(button.actionArgs, evt._data || control);
};

function _layerOpen(args, data) {
  let _args = getButtonArgs(args, data);
  let url = dsf.url.getAbsolutePath(_args[0]);
  let title = _args[1];
  let area = [_args[2] || "500px", _args[3] || "500px"];
  let closeBtn = _args[4] == "0" ? 0 : 1;
  // let currentWindow = window;
  dsf.layer.openDialog({
    title: title,
    area: area,
    content: url,
    closeBtn: closeBtn,
  });
}
window["layerOpen"] = layerOpen;

//倒计时按钮
let iscountdown = true;

let countdown = function (control, button, evt) {
  let args = getButtonArgs(button.actionArgs, evt._data || control);
  let _evt = evt;
  let countdowndata = {
    time: args[1] || 60,
    isclick: args[2] || "click",
    isdoingclick: args[3] || "false", //是否进行中可以点击
    textafter: args[4] || "重新获取",
    isagain: args[5] || "false",
    timebefore: function () {
      control.event.trigger("countdownbefore", {
        ui: control,
        args: button,
      });
    },
    timestart: function () {
      control.event.trigger("countdownstart", {
        ui: control,
        args: button,
      });
    },
    timeend: function () {
      control.event.trigger("countdownend", {
        ui: control,
        args: button,
      }); //触发
    },
    timeendcl: function () {
      //			control.event.trigger("countdownendcl", { "ui": control, "args": button});
      $(_evt.target).click(function () {
        control.event.trigger("countdownendcl", {
          ui: control,
          args: button,
        });
      });

      //			page.getControl("buttonbar1").event.on(ButtonBar.COUNTDOWNENDCL,function(obj){
      //				console.log(1);
      //				console.log(obj);
      //			})
    },
  };
  //  if (!iscountdown) {//第一次可以点击，如果用户配置为false,则第一次结束后就不可点击了
  //      return false;
  //  }
  countdowndata.timebefore();
  var isclick = $(_evt.target).attr("isdoingcl");
  if (isclick) {
    //已经点击过

    iscountdown = args[5] == "true" ? true : false; //用配置的值
    if (iscountdown) {
      let _btnattr = countdowndata.isdoingclick;
      let num = $(_evt.target).attr("num");

      if (countdowndata.isdoingclick == "false" && (num == 0 || num == undefined)) {
        countdowndata.timestart();
        _countdown(countdowndata, args, _evt);
      } else if (countdowndata.isdoingclick == "true" && (num == 0 || num == undefined)) {
        countdowndata.timestart();
        _countdown(countdowndata, args, _evt);
      }
    }
  } else {
    //第一次点击
    let _btnattr = countdowndata.isdoingclick;
    let num = $(_evt.target).attr("num");

    if (countdowndata.isdoingclick == "false" && (num == 0 || num == undefined)) {
      countdowndata.timestart();
      _countdown(countdowndata, args, _evt);
    } else if (countdowndata.isdoingclick == "true" && (num == 0 || num == undefined)) {
      countdowndata.timestart();
      _countdown(countdowndata, args, _evt);
    }
  }
};

function _countdown(countdowndata, args, _evt) {
  if (countdowndata.time == 0) {
    $(_evt.target).attr("num", countdowndata.time);
    countdowndata.timeend();
    countdowndata.timeendcl();
    $(_evt.target).attr("isdoingcl", true);
    //  $(_evt.target).attr("isclick", true);
    $(_evt.target).removeClass("layui-btn layui-btn-disabled ds_button_auxiliary");
    $(_evt.target).text(countdowndata.textafter);
    countdowndata.time = args[1];
  } else {
    $(_evt.target).attr("num", countdowndata.time);
    $(_evt.target).attr("isdoingcl", countdowndata.isdoingclick);
    $(_evt.target).addClass("layui-btn layui-btn-disabled ds_button_auxiliary");
    $(_evt.target).text(countdowndata.time);
    countdowndata.time--;
    setTimeout(function () {
      _countdown(countdowndata, args, _evt);
    }, 1000);
  }
}
window["countdown"] = countdown;
