//表单关闭
let form_close = function (control, button, evt) {
  let targetWin = null;
  if (button.actionArgs) {
    if (window.frameElement && window.frameElement.dialogIndex) {
      targetWin = window.frameElement.opener;
      // window.frameElement.opener.page.event.trigger(PageEvent.READY);
    } else {
      targetWin = window[button.actionArgs];
      // window[button.actionArgs].page.event.trigger(PageEvent.READY);
    }
  }
  if (targetWin && targetWin.page) {
    targetWin.page.event.trigger(PageEvent.READY);
  }
  control.root.event.trigger(PageEvent.CLOSE);
  control.root.close();
};

//步骤导航保存
let form_save_steps = function (control, button, evt) {
  let args = getButtonArgs(button.actionArgs, control);
  console.log(button.actionArgs);
  args[0] = args[0] || "self";
  args[1] = args[1] || null;
  args[2] = args[2] || "next";
  args[3] = args[3] || "";
  args[4] = args[4] || "opener";
  args[5] = args[5] || "false";
  let saveOption = {
    refreshTarget: args[4],
    info: args[2],
    message: args[3],
    isCloseWindow: false,
    isSilent: args[5] == "true" ? true : false,
  };
  control.root.formSave(saveOption, function (result) {
    if (result) {
      let stepsNav = "";
      if (window[args[0]]) {
        stepsNav = window[args[0]].page.getControl(args[1]);
      }

      if (args[2] == "next") {
        stepsNav.nextStep(stepsNav);
      } else if (args[2] == "pre") {
        stepsNav.preStep(stepsNav);
      }
    }
  });
};
