//datagrid批量删除
let datagrid_delete = function (control, button, evt) {
  let args = getButtonArgs(button.actionArgs, control);
  let url = dsf.Express.replace(args[0], control);
  // url = dsf.url.getWebPath(url);
  let rows = control.getCheckedData();

  if (rows.length > 0) {
    dsf.layer.confirm("您选择了" + rows.length + "条数据，确定要删除吗?", () => {
      control.deleteRow(rows, url);
    });
  } else {
    dsf.layer.message("请选择要删除的数据", false);
  }
};

