//列表数据选择对话框
let datachoice_list_dialog = function (control, button, evt) {
  if (!control.disabled) {
    let args = getButtonArgs(button.actionArgs, control);
    let a = {
      url: dsf.url.getAbsolutePath(args[0]),
      title: args[1],
      area: [args[2] || "1000px", args[3] || "500px"],
    };
    let q = dsf.queue();
    q.step((def, v) => {
      if (control.event.has(DataChoiceEvent.OPENBEFORE)) {
        control.event.trigger(
          DataChoiceEvent.OPENBEFORE,
          {
            ui: control,
            args: a,
          },
          def
        );
      } else {
        def.resolve(true);
      }
    });
    q.step((def, v) => {
      if (v !== false) {
        let opener = window.self;
        if (window.frameElement && window.frameElement.dialogIndex) {
          opener = window.parent;
        }
        opener.dsf.layer.openDialog({
          // type: 2,
          title: a.title,
          area: a.area,
          content: a.url,
          dialogLoaded: function (layero, index, win) {
            let data = $.extend(true, [], control.value);
            // let result = null;
            if (win.setCheckedData) {
              win.setCheckedData(data, control);
            } else if (win && win.page) {
              win.page.dialogInitCheckedValue(data, "TextValue");
            }
          },
          btn: [
            {
              text: "确定",
              handler: function (index, layero, win) {
                let max = null;
                control.maxTags && (max = parseInt(control.maxTags));
                let result = null;
                if (win.getCheckedData) {
                  result = win.getCheckedData();
                } else if (win && win.page) {
                  result = win.page.dialogCheckedReturnValue("TextValue");
                }
                if (control.getWin) {
                  control.getWin(win)//获取当前弹窗window对象
                }
                if (dsf.isDef(result)) {
                  result = dsf.type(result) == "array" ? result : [result];
                  if (max && result.length > max) {
                    opener.dsf.layer.message("最多只能选择" + max + "个", false);
                    return false;
                  }
                  control.clearTags(false);
                  _.each(result, row => {
                    control.addTag({
                      value: row.value,
                      text: row.text,
                    },row);
                  });
                  !result.length && control.clearTags();
                }
                control.event.trigger(DataChoiceEvent.CHOICECOMPLETE, {
                  ui: control,
                });
              },
            },
            {
              text: "取消",
              handler: function (index, layero, win) {
                return true;
              },
            },
          ],
        });
      }
    });
    q.catch(ex => {
      dsf.error(ex);
    });
    q.exec();
  }
};

//部门人员的选择框
let selector_list_dialog = function (control, button, evt) {
  if (!control.disabled) {
    let args = getButtonArgs(button.actionArgs, control);
    let url = dsf.url.getAbsolutePath(args[0]);
    let title = args[1];
    let area = [args[2] || "1000px", args[3] || "500px"];

    function getSelector(win) {
      let _page = win.page;
      let selector = [];
      console.log(_page);
      _page.ControlsForEach(v => {
        if (v instanceof win.dsf.Controls.CheckNode) {
          selector.push(v);
        }
      }, false);
      if (selector.length <= 0) {
        return null;
      } else {
        let st = selector[0];
        return st;
      }
    }

    dsf.layer.openDialog({
      title: title,
      area: area,
      content: url,
      dialogLoaded: function (layero, index, win) {
        let data = $.extend(true, [], control.value);
        // if (win.setCheckedData) {
        //     win.setCheckedData();
        // } else if (win && win.page) {
        //     win.page.dialogInitCheckedValue(data,"TextValue");
        // }
        let st = getSelector(win);
        if (st) {
          st._showSubDept = control.showSubDept;
          st._showType = control.showType;
          st._sort = control.canSort;
          st._types = control.types;
          st._tabs = control.tabs;
          st._chkboxType = control.chkboxType;
          // st.renderDom();
          for (let i in data) {
            data[i]._name = data[i].text;
            data[i]._id = data[i].value;
          }
          st.value = data;
        }
      },
      btn: [
        {
          text: "确定",
          handler: function (index, layero, win) {
            let max = null;
            if (control.maxTags) {
              max = parseInt(control.maxTags);
            }
            let st = getSelector(win);
            let checkedRows = st.value;
            if (max && checkedRows.length > max) {
              dsf.layer.message("最多只能选择" + max + "个", false);
              return false;
            } else {
              control.clearTags();
              _.each(checkedRows, row => {
                row.text = row._name;
                row.value = row._id;
                control.addTag(row);
              });
            }
          },
        },
        {
          text: "取消",
          handler: function (index, layero, win) {
            return true;
          },
        },
      ],
    });
  }
};

// layui的导入
let layuiUpload = function (control, button, evt) {
  let args = getButtonArgs(button.actionArgs, evt._data);
  let headersParam = dsf.getCookie("XSRF-TOKEN") || "";
  let dom = $(evt.target).closest(".ds_button");
  let q = dsf.queue();
  q.step((def, v) => {
    if (control.event.has(PageEvent.UPLOADBEFORE)) {
      control.event.trigger(
        PageEvent.UPLOADBEFORE,
        {
          ui: control,
          args: args,
          actionName: button.actionName,
          data: evt._data || {}
        },
        def
      );
    } else {
      def.resolve(true);
    }
  });
  q.step((def, v) => {
    if (v !== false) {
      if (!dom.attr("upload_rended")) {
        let layuiUploadLoadingIdx = null;
        layui.upload.render({
          elem: dom,
          headers: {
            "X-XSRF-TOKEN": headersParam,
          },
          url: dsf.url.getWebPath(args[0] || ""),
          multiple: args[8] == "true" ? true : false,
          number: parseInt(args[9]) || 0,
          accept: args[1] || "",
          acceptMime: args[2] || "",
          data: JSON.parse(args[4] || "{}"),
          exts: args[6],
          size: args[7] || 0,
          before: function (obj) {
            layuiUploadLoadingIdx = dsf.layer.loadding();
          },
          done: function (res, index, upload) {
            dsf.layer.close(layuiUploadLoadingIdx);
            if (res.success) {
              if (args[3]) {
                control.event.trigger(args[3], {
                  actionName: button.actionName,
                  actionArgs: args,
                  ui: control,
                  data: res.data,
                });
              }
            } else {
              if (args[10]) {
                control.event.trigger(args[10], {
                  actionName: button.actionName,
                  actionArgs: args,
                  ui: control,
                  data: res.data,
                });
              } else {
                dsf.layer.message(dsf.prompt.uploadfail, false);
              }
            }
          },
          error: function (errmsg) {
            dsf.layer.close(layuiUploadLoadingIdx);
            if (args[10]) {
              control.event.trigger(args[10], {
                actionName: button.actionName,
                actionArgs: args,
                ui: control,
                data: errmsg,
              });
            } else {
              dsf.layer.message(dsf.prompt.uploadfail, false);
            }
          },
        });
        dom.attr("upload_rended", true);
        setTimeout(function () {
          dom[0].click();
        }, 300);
      }
    }
  });
  q.catch(ex => {
    dsf.error(ex);
  });
  q.exec();
};

