let execInterface = function (control, button, evt) {
  let args = getButtonArgs(button.actionArgs, evt._data || control);
  if (dsf.isNaN(args[0] * 1)) {
    args.shift()
    args.unshift(0)
  }
  let url = dsf.url.analysis(args[1]);
  let method = args[2];
  let isRefresh = args[0] || 0//是否刷新页面 0 不刷新，1：刷新
  let arrs = {};
  for (let i = 3; i < args.length; i += 2) {
    arrs[args[i]] = args[i + 1];
  }
  let loadingIndex = dsf.layer.loadding();
  url = dsf.url.getAbsolutePath(url);
  dsf.http
    .request(url, arrs, method)
    .done(function (response) {
      if (response.success) {
        dsf.layer.message("操作成功", true);
        // 是否刷新本页面
        if (isRefresh * 1) {
          window.location.reload()
        }
      } else {
        let message = response.state == "20001" ? "操作失败" : response.message;
        dsf.layer.message(message, false);
      }
    })
    .error(function (response) {
      dsf.layer.message("操作失败", false);
    })
    .always(function () {
      dsf.layer.close(loadingIndex);
    })
    .exec();
};
