let sysButtonHandler = function (control, button, evt, data) {
  if (handler[button.actionName]) {
    handler[button.actionName](control, button, evt, data);
  }
};

function getButtonArgs(argsStr, data) {
  let arr = argsStr.split(";");
  let newArr = [];
  for (var i = 0; i < arr.length; i++) {
    newArr.push(dsf.Express.replace(arr[i], data || {}));
  }
  return newArr;
}
/**
 * desc 系统通用业务按钮请求方式
 * @param {Array} args 用户手填参数
 * @param {Object} button 按钮配置信息
 * @param {jqueryObj} $target 按钮元素
 * @param {String} queryUrl 按钮请求接口地址
 */
function teas_sysBtn_qureyFn(args, button, $target, queryUrl, _id) {
  let id = "";
  let parentIDStr =
    $target.parent().parent() &&
    $target
      .parent()
      .parent()
      .attr("id"); //获取评论item 单条ID
  if (parentIDStr) {
    let index = parentIDStr.lastIndexOf("_");
    id = parentIDStr.substring(index + 1, parentIDStr.length);
  } else if (_id) {
    id = _id
  } else {
    id = dsf.url.queryString("id"); //获取浏览器url 参数ID
  }

  let num = $target.find("span").text();
  let param = {
    ywlxValue: args[0].split(";")[0],
    ywlxText: args[0].split(";")[1],
    ywid: id,
  };
  let url = dsf.url.getWebPath(queryUrl);
  dsf.http
    .request(url, param, "post")
    .done(function (response) {
      console.log(response);
      if (response.success) {
        if (response.data.isDo) {
          num++;
          $target.find("span").text(num);
          $target
            .find("i")
            .removeClass()
            .addClass("iconfont " + button.activeIcon);
        } else {
          if (num > 0) {
            num--;
            $target.find("span").text(num);
          }
          $target
            .find("i")
            .removeClass()
            .addClass("iconfont " + button.icon);
        }
      } else {
        dsf.layer.message("请求失败,请稍后再试", false);
      }
    })
    .error(function (err) {
      dsf.layer.message("请求失败,请稍后再试", false);
    })
    .always(function () {
      // dsf.layer.close(loadding);
    })
    .exec();
}
/**
 * desc 系统通用业务按钮加载数据
 * @param {Array} args 用户手填参数
 * @param {Object} button 按钮配置信息
 * @param {jqueryObj} $target 按钮元素
 * @param {String} queryUrl 按钮请求接口地址
 */
function teas_sysBtn_getData(args, button, $target, queryUrl, _id) {
  let id = "";
  let parentIDStr =
    $target.parent().parent() &&
    $target
      .parent()
      .parent()
      .attr("id"); //获取item 单条ID
  if (parentIDStr) {
    let index = parentIDStr.lastIndexOf("_");
    id = parentIDStr.substring(index + 1, parentIDStr.length);
  } else if (_id) {
    id = _id
  } else {
    id = dsf.url.queryString("id"); //获取浏览器url 参数ID
  }

  let num = $target.find("span").text();
  let param = {
    ywlxValue: args[0].split(";")[0],
    ywid: id,
  };
  let url = dsf.url.getWebPath(queryUrl);
  dsf.http
    .request(url, param, "GET")
    .done(function (response) {
      console.log(response);
      if (response.success) {
        num = response.data.total;
        let isDo = response.data.isDo; //点过 是true ，没点过 false
        let $target = $('[dsevent="' + button.actionName + '"]');
        $target.find("span").text(num);
        if (isDo) {
          $target
            .find("i")
            .removeClass()
            .addClass("iconfont " + button.activeIcon);
        }
        // if (num > 0) {
        //     $target.find("i").removeClass().addClass("iconfont " + button.activeIcon)
        // }
      } else {
        dsf.layer.message("请求失败,请稍后再试", false);
      }
    })
    .error(function (err) {
      dsf.layer.message("请求失败,请稍后再试哦", false);
    })
    .always(function () {
      // dsf.layer.close(loadding);
    })
    .exec();
}

