import { ControlEditor } from "./ControlEditor";
import { ContextMenu } from './ContextMenu';
// import dom from "../templates/SetCellSize.ejs";

export class TableLayoutEditor extends ControlEditor {
    constructor(control) {
        super(control);
        if (control.root._isDesign) {
            this.table = control._handlers.table;
            this.selectedList = [];
            this.menuItems = [
                { name: "合并单元格", handler: this.cellSpan },
                { name: "拆分单元格", handler: this.cancelCellSpan },
                { split: true },
                { name: "插入行(前)", handler: this.addRowBefore },
                { name: "插入行(后)", handler: this.addRowAfter },
                { name: "插入列(前)", handler: this.addColumnBefore },
                { name: "插入列(后)", handler: this.addColumnAfter },
                { split: true },
                { name: "删除整行", handler: this.removeRow },
                { name: "删除整列", handler: this.removeColumn },
                { split: true },
                { name: "列宽平均分配", handler: this.columnWidthIdenticalI },
                { name: "单元格设置", handler: this.settingCells }
            ];
        }

    }
    init() {
        super.init();
        this.cellResize();

    }

    /**
     * 编辑状态下触发鼠标按下后触发
     */
    mouseDown(evt) {
        let _this = this;
        ContextMenu.removeAll();
        super.mouseDown(evt);
        if (this.control.root._isDesign) {
            let target = $(evt.target);
            if (!target.hasClass("th_td")) {
                if (target.get(0).tagName != "TD") {
                    target = target.closest("TD");
                }
                if (target.length > 0 && target.get(0).tagName == "TD") {
                    let isSelfTable = target.closest("TABLE").get(0) == this.table.get(0);
                    if (isSelfTable) {
                        let cell = target;
                        cancelEdit.call(this);
                        CellSelected.call(_this, cell);
                        this.selectedList = [];
                        this.selectedList[0] = cell.get(0);
                    }
                }
            }
        }
    }

    /**
     * 编辑状态下触发了mouseDown后启动的鼠标弹起事件
     */
    moouseUp(evt) {
        super.moouseUp(evt);
    }

    /**
     * 编辑状态下触发了mouseDown后启动的鼠标移动事件
     */
    mouseMove(evt) {
        if (this.mouseDown) {
            let cell = $(evt.target);
            //先路由到同一个TABLE下，避免table嵌套的判断错误
            while (!isSelfTable.call(this, cell)) {
                let p = cell.parent();
                if (p.length > 0) {
                    cell = p;
                } else {
                    break;
                }
            }
            if (cell.get(0).tagName != "TD") {
                cell = cell.closest("TD");
            }
            if (cell.length > 0 && cell.get(0).tagName == "TD") {
                delete this.selectedList[1];
                this.selectedList[1] = cell.get(0);
                if (this.selectedList.length >= 2) {
                    let c1 = $(this.selectedList[0]),
                        c2 = $(this.selectedList[1]);
                    var result = getCellMarquee.call(this, [c1, c2]);
                    CellSelected.call(this, result);
                }
            }
        }

    }

    /**
     * 右键菜单
     */
    contextMenu(evt) {
        let _this = this;
        if (this.control.root._isDesign) {
            let target = $(evt.target);
            if (!target.hasClass("th_td")) {
                if (target.get(0).tagName != "TD") {
                    target = target.closest("TD");
                }
                if (target.length > 0 && target.get(0).tagName == "TD") {
                    let isSelfTable = target.closest("TABLE").get(0) == _this.control._handlers.table.get(0);
                    if (isSelfTable) {
                        let cell = target;
                        if (!cell.hasClass("selected")) {
                            cancelEdit.call(this);
                            CellSelected.call(_this, cell);
                            // cell.addClass("selected");
                        }
                        ContextMenu.show.call(this, this.menuItems, evt.pageX, evt.pageY);
                    }
                }
            } else {
                ContextMenu.show.call(this, this.headMenuItem, evt.pageX, evt.pageY);
            }
        }
        evt.preventDefault();
        evt.stopPropagation();
    }

    /**
     * 添加列(后)
     */
    addColumnAfter() {
            let cells = getSelectedCells.call(this);
            let colindex = -1;
            for (let i = 0; i < cells.length; i++) {
                let cell = $(cells[i])
                let colSpan = parseInt(cell.attr("colspan")) || 1;
                let mIndex = cell.attr("matrix_idx").split(",");
                // let rowIndex=parseInt(mIndex[0]);
                let cellIndex = parseInt(mIndex[1]) + colSpan;
                if (colindex < cellIndex) {
                    colindex = cellIndex;
                }
            }
            this.control.addColumn(colindex, true);
            this.control.refreshTableHead();
            refreshMarquee.call(this, cells);
        }
        /**
         * 添加列(前)
         */
    addColumnBefore() {
        let cells = getSelectedCells.call(this);
        let colindex = Number.MAX_VALUE;
        for (let i = 0; i < cells.length; i++) {
            let cell = $(cells[i])
            let mIndex = cell.attr("matrix_idx").split(",");
            let cellIndex = parseInt(mIndex[1]);
            if (colindex > cellIndex) {
                colindex = cellIndex;
            }
        }
        this.control.addColumn(colindex, true);
        this.control.refreshTableHead();
        refreshMarquee.call(this, cells);
    }

    /**
     * 添加行(后)
     */
    addRowAfter() {
        let cells = getSelectedCells.call(this);
        let rindex = -1;
        for (let i = 0; i < cells.length; i++) {
            let cell = $(cells[i])
            let rowSpan = parseInt(cell.attr("rowspan")) || 1;
            let mIndex = cell.attr("matrix_idx").split(",");
            let rowIndex = parseInt(mIndex[0]) + rowSpan;
            if (rindex < rowIndex) {
                rindex = rowIndex;
            }
        }
        this.control.addRow(rindex, false);
        this.control.execParser();
        refreshMarquee.call(this, cells);
    }

    /**
     * 添加行(前)
     */
    addRowBefore() {
        let cells = getSelectedCells.call(this);
        let rindex = Number.MAX_VALUE;
        for (let i = 0; i < cells.length; i++) {
            let cell = $(cells[i])
                // let rowSpan=parseInt(cell.attr("rowspan"))||1;
            let mIndex = cell.attr("matrix_idx").split(",");
            let rowIndex = parseInt(mIndex[0])
            if (rindex > rowIndex) {
                rindex = rowIndex;
            }
        }
        this.control.addRow(rindex, false);
        this.control.execParser();
        refreshMarquee.call(this, cells);
    }

    /**
     * 删除行
     */
    removeRow() {
        let cells = getSelectedCells.call(this);
        let deleteRowIndex = [];
        for (let n = 0; n < cells.length; n++) {
            let cell = $(cells[n]);
            let mIndex = cell.attr("matrix_idx").split(",");
            let rowSpan = parseInt(cell.attr("rowspan")) || 1;
            let rowIndex = parseInt(mIndex[0]);
            let i = rowIndex;
            while (i < (rowIndex + rowSpan)) {
                if (deleteRowIndex.indexOf(i) < 0) {
                    deleteRowIndex.push(i);
                }
                i++;
            }
        }
        for (let n = deleteRowIndex.length - 1; n >= 0; n--) {
            this.control.removeRow(deleteRowIndex[n]);
        }
        cancelEdit.call(this);
    }

    /**
     * 删除列
     */
    removeColumn() {
        let cells = getSelectedCells.call(this);
        let deleteColumnIndex = [];
        for (let n = 0; n < cells.length; n++) {
            let cell = $(cells[n]);
            let mIndex = cell.attr("matrix_idx").split(",");
            let colSpan = parseInt(cell.attr("colspan")) || 1;
            let colIndex = parseInt(mIndex[1]);
            let i = colIndex;
            while (i < (colIndex + colSpan)) {
                if (deleteColumnIndex.indexOf(i) < 0) {
                    deleteColumnIndex.push(i);
                }
                i++;
            }
        }
        for (let n = deleteColumnIndex.length - 1; n >= 0; n--) {
            this.control.removeColumn(deleteColumnIndex[n]);
        }
        cancelEdit.call(this);
    }


    /**
     * 取消编辑
     */
    cancelEdit() {
        super.cancelEdit();
        cancelEdit.call(this);
    }


    /**
     * 附加行列拖动大小的事件
     */
    cellResize() {
        let _this = this;
        this.control._handlers.table.children("TBODY").on("mousedown.cellResize", evt => {
            if (evt.which != 1 || evt.target.tagName != "TD") {
                return;
            }
            let size = 5;
            var td = $(evt.target);
            var w = td.width();
            var h = td.height();
            let isDown = false;
            let downPointX = evt.pageX;
            let downPointY = evt.pageY;
            let lr = false;
            let tb = false;
            let line = null;
            let s_offsetX = 0,
                s_offsetY = 0;
            let offsetSize = 0;
            let index = null;
            let box = _this.control.root.element; //_this.control._handlers.box;
            let colspan = 1,
                rowspan = 1;
            //距离单元格最右侧5像素可以左右拖动宽度
            if (Math.abs(w - evt.offsetX) <= size) {
                isDown = true;
                line = $("<div class='resize-baseline-v'>").appendTo(box);
                s_offsetX = (td.offset().left + td.width()) - box.offset().left;
                line.css("left", s_offsetX);
                lr = true;
            }
            // 距离单元格最下方5像素可以上下拖动宽度
            else if (Math.abs(h - evt.offsetY) <= size) {
                isDown = true;
                line = $("<div class='resize-baseline-h'>").appendTo(box);
                s_offsetY = (td.offset().top + td.height()) - box.offset().top;
                line.css("top", s_offsetY);
                tb = true;
            }
            if (isDown) {
                index = null;
                let m_index = td.attr("matrix_idx");
                colspan = parseInt(td.attr("colspan")) || 1;
                rowspan = parseInt(td.attr("rowspan")) || 1;
                let minWidth = 10;
                //拖动列宽度使用的变量
                let thead, head_tr, head_td, cell, nextCell, isLastCell = false,
                    offsetXLimit = null
                if (lr) {
                    index = parseInt(m_index.split(",")[1]);
                    thead = _this.control._handlers.table.children("THEAD");
                    head_tr = thead.children("TR");
                    head_td = head_tr.children("TD");
                    index = index + colspan - 1;
                    cell = head_td.eq(index);
                    nextCell = cell.next();
                    if (nextCell.length <= 0) {
                        isLastCell = true;
                    }
                    offsetXLimit = {
                        min: td.offset().left - box.offset().left + minWidth,
                        max: nextCell.length > 0 ? (nextCell.offset().left + nextCell.width()) - box.offset().left - minWidth : (td.offset().left + td.width()) - box.offset().left
                    }
                }
                if (tb) {
                    index = parseInt(m_index.split(",")[0]);
                }
                $(document).bind("mousemove.cellResize", evt => {
                    if (lr) {
                        let movePointX = evt.pageX;
                        offsetSize = movePointX - downPointX;
                        let offsetX = s_offsetX + offsetSize;
                        // console.log(offsetX)
                        if (offsetX >= offsetXLimit.max) {
                            offsetX = offsetXLimit.max;
                        }
                        if (offsetX <= offsetXLimit.min) {
                            offsetX = offsetXLimit.min;
                        }
                        offsetSize = offsetX - s_offsetX;
                        line.css({
                            "left": offsetX
                        });
                    }
                    if (tb) {
                        let movePointY = evt.pageY;
                        offsetSize = movePointY - downPointY;
                        let offsetY = s_offsetY + offsetSize;
                        line.css({
                            "top": offsetY
                        });
                    }

                });
                $(document).one("mouseup.cellResize", evt => {
                    try {
                        if (lr) {
                            if (isLastCell) {
                                return;
                            }
                            let tableWidth = this.control._handlers.table.width();
                            let thead = _this.control._handlers.table.children("THEAD");
                            let head_tr = thead.children("TR");
                            let head_td = head_tr.children("TD");
                            let widthList = [];
                            head_td.each(function(i, e) {
                                widthList.push($(this).width());
                            });

                            //获取拖动单元格尺寸
                            let oldSize = cell.width();
                            let newSize;
                            if (offsetSize < 0 && Math.abs(offsetSize) > oldSize) {
                                let count = index;
                                //如果是合并的单元格需要向前借尺寸
                                let offsetSize1 = Math.abs(offsetSize);
                                while (offsetSize1 > 0 && count >= 0) {
                                    var c = head_td.eq(count);
                                    var size = c.width();
                                    if (size - offsetSize1 >= 0) {
                                        widthList[count] = size - offsetSize1;
                                        break;
                                    } else {
                                        widthList[count] = 0;
                                        offsetSize1 -= size;
                                    }
                                    count--;
                                }
                            } else {
                                newSize = oldSize + offsetSize;
                                widthList[index] = newSize;
                            }
                            if (widthList[index + 1]) {
                                widthList[index + 1] = widthList[index + 1] + (offsetSize * -1);
                                _this.control.columns[index + 1].fixed = true;
                            }
                            for (let i = 0; i < widthList.length; i++) {
                                _this.control.columns[i].width = (widthList[i] / tableWidth) * 100;
                                _this.control.columns[index + 1].fixed = true;
                            }
                        } else if (tb) {
                            index = index + rowspan - 1;
                            let tbody = _this.control._handlers.table.children("TBODY");
                            let rows = tbody.children("TR");
                            let tr = rows.eq(index);
                            let oldSize = tr.height();
                            let newSize = oldSize + offsetSize;
                            let tableRowControl = tr.data("Object");
                            if (tableRowControl) {
                                tableRowControl.setHeight(newSize);
                            }
                        }
                        // this.control.execParser();
                        this.control.refreshTableHead();
                    } catch (ex) {
                        throw ex;
                    } finally {
                        $(document).off("mousemove.cellResize");
                        line.remove();
                        refreshMarquee.call(_this);
                    }
                });
                return false;
            }
        })
    }

    /**
     * 合并单元格算法
     */
    cellSpan() {
        let cells = getSelectedCells.call(this); // this.control._handlers.table.children("TBODY").children("TR").children("TD.selected");
        let arr = [];
        for (let i = 0; i < cells.length; i++) {
            arr.push(cells.eq(i));
        }
        this.control.mergeCells(arr);
        unSelected.call(this);
        ContextMenu.removeAll();
    }

    /**
     * 拆分单元格
     */
    cancelCellSpan() {
        let _this = this;
        let cells = getSelectedCells.call(this); // this.control._handlers.table.children("TBODY").children("TR").children("TD.selected");
        let arr = [];
        for (let i = 0; i < cells.length; i++) {
            arr.push(cells.eq(i));
        }
        this.control.splitCells(arr);
        unSelected.call(this);
        ContextMenu.removeAll();
    }

    /**
     * 列宽自动分配
     */
    columnWidthIdenticalI() {
        let columns = this.control.columns;
        let width = 100 / columns.length;
        let cells = this.control._handlers.table.children("THEAD").children("TR").children("TD");
        for (var i = 0; i < columns.length; i++) {
            let col = columns[i];
            let td = cells.eq(i);
            col.width = width;
            td.width(width + "%");
            col.fixed = true;
        }
        this.control.execParser();
        refreshMarquee.call(this)
    }

    settingCells() {
        let _this = this;
        let cells = getSelectedCells.call(_this);
        dsf.layer.openDialog({
            title: "单元格设置",
            content: "../views/settingCells.html",
            args: cells,
            area: ['450px', '300px'],
            btn: [{
                "text": "确定",
                "handler": function(index, layero) {
                    let frame = layero.find("iframe");
                    let win = frame.get(0).contentWindow;
                    let result = win.getDialogResult();
                    if (result) {
                        for (let i = 0; i < cells.length; i++) {
                            let c = cells.eq(i);
                            let cell = c.data("Object");
                            if (cell) {
                                cell.align = result.align;
                                cell.vAlign = result.valign;
                                cell.renderContext();
                            }
                        }
                    }
                }
            }]
        });
    }
}

//获取单元格选取
function getCellMarquee(cells) {
    // console.log(cells)
    let result = getMarqueeSize.call(this, cells);
    // console.log(result)
    let cellArr = [];
    for (let i = result.minRow; i <= result.maxRow; i++) {
        let r = this.control._matrix[i];
        for (let n = result.minCell; n <= result.maxCell; n++) {
            let c = r[n];
            cellArr.push(c);
        }
    }
    // console.log(cellArr)
    let result2 = getMarqueeSize.call(this, cellArr);
    // console.log(result2)
    if (result2.minRow != result.minRow || result2.maxRow != result.maxRow || result2.minCell != result.minCell || result2.maxCell != result.maxCell) {
        cellArr = getCellMarquee.call(this, cellArr)
    }
    return cellArr;
}

/**
 * 获取单元格集合所设计的左右坐标系
 */
function getMarqueeSize(cells) {
    let minRow = Number.MAX_VALUE;
    let maxRow = Number.MIN_VALUE;
    let minCell = Number.MAX_VALUE;
    let maxCell = Number.MIN_VALUE;
    for (var i = 0; i < cells.length; i++) {
        let cell = $(cells[i]);
        let mindex = cell.attr("matrix_idx").split(",");
        let rIndex = parseInt(mindex[0]);
        let rIndex1 = parseInt(mindex[0]) + (parseInt(cell.attr("rowspan")) || 1) - 1;
        let cIndex = parseInt(mindex[1]);
        let cIndex1 = parseInt(mindex[1]) + (parseInt(cell.attr("colspan")) || 1) - 1;
        if (rIndex < minRow) {
            minRow = rIndex;
        }
        if (rIndex1 > maxRow) {
            maxRow = rIndex1;
        }
        if (cIndex < minCell) {
            minCell = cIndex;
        }
        if (cIndex1 > maxCell) {
            maxCell = cIndex1;
        }
    }
    return {
        minRow: minRow,
        maxRow: maxRow,
        minCell: minCell,
        maxCell: maxCell
    };
}

/**
 * 刷新选中框大小
 */
function refreshMarquee(cells) {
    let cellList = getSelectedCells.call(this, cells);
    let arr = [];
    cellList.each((i, el) => {
        arr.push(cellList.eq(i));
    })
    CellSelected.call(this, arr);
}

/**
 * 判断获取的单元格是否是当前表格里的直系单元格，防止表格嵌套使用
 */
function isSelfTable(cell) {
    return cell.closest("TABLE").get(0) == this.table.get(0);
}

/**
 * 取消编辑
 */
function cancelEdit() {
    // console.log("cancelEdit")
    unSelected.call(this);
    ContextMenu.removeAll();
}

/**
 * 单元格选中
 */
function CellSelected(cells) {
    unSelected.call(this)
    if (cells.length <= 0) {
        return false;
    }
    if (!$.isArray(cells)) {
        cells = [cells];
    }
    let box = this.control._handlers.box;
    let proxy = box.children(".selectedProxy");
    if (proxy.length <= 0) {
        box.append("<div class='selectedProxy'></div>");
        proxy = box.children(".selectedProxy");
    }
    proxy.show();
    // console.log(cells)
    let left = Number.MAX_VALUE;
    let top = Number.MAX_VALUE;
    let right = Number.MIN_VALUE;
    let bottom = Number.MIN_VALUE;
    for (var i = 0; i < cells.length; i++) {
        let cell = $(cells[i]);
        let row = cell.parent(); //position()
        let t = row.position().top;
        let l = cell.position().left;
        let b = t + cell.height();
        let r = l + cell.width();
        if (top > t) {
            top = t;
        }
        if (left > l) {
            left = l;
        }
        if (right < r) {
            right = r;
        }
        if (bottom < b) {
            bottom = b;
        }
        cell.addClass("selected");
    }
    proxy.css("top", top - 2).css("left", left - 2);
    proxy.width(right - left - 2).height(bottom - top - 2);
}

/**
 * 取消单元格选中
 */
function unSelected() {
    // console.log("unSelected")
    let box = this.control._handlers.box;
    let proxy = box.children(".selectedProxy");
    if (proxy.length > 0) {
        proxy.hide();
    }
    let cells = this.control._handlers.table.children("TBODY").children("TR").children("TD");
    cells.removeClass("selected");
}

function getSelectedCells() {
    let cells = this.control._handlers.table.children("TBODY").children("TR").children("TD.selected");
    return cells;
}

