const dom = require("../../templates/RadioBox.ejs");
import { ItemsControl } from '../../../../baseControls';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControlEvent } from '../../../../core/ControlEvent';
import { map } from '../../../../decorator/controlmap';

@map('单选', 'dsf.radiobox', 'RadioBox')
@isSupportDataPost(true)
export class RadioBox extends ItemsControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.label = "单选框";
        this.$allowMulti = false;
        this.$showModel = "none";
        this.$placeholder = "请输入";
        this.$readOnlyShowText = "text"
    }

    get value() {
        let val = super.value;
        if (val == "") {
            this.$value = { "text": "", "value": "", "attach_text": "" };
        }
        if (this.$value.value == "else") {
            if (this._itemsBox) {
                this.$value['attach_text'] = this._itemsBox.find("div.q_other>input").val();
            }
        }
        return val;
    }

    set value(value) {
        super.value = value;
        if (!this.$value) {
            this.$value = this.isOther ? { "text": "", "value": "", "attach_text": "" } : { "text": "", "value": "" };
        }

        if (this.itemsBox) {
            if (this.$value) {
                if (this.$value.value == "else") {
                    let attachInput = this._itemsBox.find("div.q_other>input")
                    attachInput && attachInput.val(this.$value['attach_text']);
                } else {
                    let attachInput = this._itemsBox.find("div.q_other>input")
                    attachInput && attachInput.val("");
                }
            }

            let val = (this.value == null || this.value == undefined) ? "" : this.value.value;
            this.itemsBox.find("input[value='" + val + "']").prop("checked", true);
            renderRadio.call(this);
        }
        if (this._handlers.readOnlyLabel) {
            if(this.$readOnlyShowText=="text"){
                this._handlers.readOnlyLabel.text(this.getTextString(","));
            }else{
                this._handlers.readOnlyLabel.text(this.getValueString(","));
            }
            
        }
        if (this.showModel == "text" && this._handlers.input) {
            let result = _.find(this.items, o => o.value == this.$value.value);
            if (result) {
                this._handlers.input.val(result.value);
            }
        }
    }

    set showModel(val) {
        this.$showModel = val;
        if (this.element) {
            this.render();
        }
    }
    get showModel() {
        return this.$showModel;
    }

    set placeholder(value) {
        this.$placeholder = value;
        if (this._handlers.input) {
            this._handlers.input.attr("placeholder", value);
        }
    }
    get placeholder() {
        return this.$placeholder;
    }

    set readOnlyShowText(val) {
        this.$readOnlyShowText = val;
        if (this.element) {
            this.render();
        }
    }
    get readOnlyShowText() {
        return this.$readOnlyShowText;

    }


    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
        this._itemsBox = this._handlers.inputbox;
    }

    initEvent() {
        let _this = this;
        if (this.showModel == "text") {
            if (this._handlers.input) {
                this._handlers.input.off("change");
                this._handlers.input.on("change", function(evt) {
                    var val = _this._handlers.input.val();
                    var newVal = syncItemsChecked.call(_this, val);
                    _this._handlers.input.val(newVal);
                    _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                    _this.commitAudit();
                });
            }
        } else {
            layui.form.on('radio(' + this.id + ')', function(data) {
                $(data.elem).val(data.value);
                let isChange = data.value != _this.value;
                _this.value = data.value;
                if (isChange) {
                    _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                    _this.commitAudit();
                }
            });
        }
        this.element.off("input", ".q_other>input[type=text]");
        this.element.off("change", ".q_other>input[type=text]");

        this.element.on("input", ".q_other>input[type=text]", evt => {
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });

        this.element.on("change", ".q_other>input[type=text]", evt => {
            _this.commitAudit();
        });
    }

    renderContext() {
        super.renderContext();
        this._handlers.label.html(this.label);
        if (this.showModel == "text" && this._handlers.input) {
            let v = syncItemsChecked.call(this, this.value.value);
            this._handlers.input.val(v);
        }
    }

    renderReady() {
        let _this = this;
        super.renderReady();
        renderRadio.call(this);
    }

    renderItems() {
        super.renderItems();
        if (this.element) {
            if (this.root._isDesign && this.items.length <= 0) {
                for (let i = 0; i < 2; i++) {
                    let value = (i + 1);
                    let name = this.name || this.id;
                    let op = $("<input type='radio' " + (this.disabled ? "disabled" : "") + " lay-filter='" + this.id + "' title='选项" + value + "' name='" + (name) + "' value='" + value + "'/>");
                    this._itemsBox.append(op);
                }
                if (this.isOther) {
                    this._itemsBox.append("<input type='radio' " + (this.disabled ? "disabled" : "") + " lay-filter='" + this.id + "' title='其他' />");
                }
            } else {
                //判断items中是否已经存在其他如果没有则追加一个
                let otherItem = null;
                let index = _.findIndex(this.items, { "value": "else" });
                if (index >= 0) {
                    otherItem = this.items[index];
                    this.items.splice(index, 1);
                }
                if (this.isOther) {
                    this.items.push(otherItem || {
                        "text": "其他",
                        "value": "else",
                        "attach_text": ""
                    });
                }

                let isExist = false;
                for (let i = 0; i < this.items.length; i++) {
                    let item = this.items[i];
                    let name = this.name || this.id;
                    let checked = false;
                    if (this.value && (this.value.value == item.value)) {
                        isExist = true;
                        checked = true;
                    }
                    let op = $("<input type='radio' " + (this.disabled ? "disabled" : "") + " lay-filter='" + this.id + "' title='" + item.text + "' name='" + (name) + "' value='" + (item.value) + "' " + (checked ? "checked" : "") + "/>");
                    this._itemsBox.append(op);

                    if (item.value == "else") {
                        this._itemsBox.append('<div class="q_other"><input type="text"></div>');
                        if (this.value.value == "else") {
                            this._itemsBox.find(".q_other>input").val(this.value.attach_text || "")
                        }
                    }
                }
            }
            renderRadio.call(this);
        }
    }
}

function syncItemsChecked(val) {
    var arr = [];
    if (val != "") {
        let oldValue = this.value;
        let result = _.find(this.items, o => o.value == val);
        if (result) {
            if (arr.indexOf(result.value) < 0) {
                arr.push(result.value);
                this.value = result.value;
            }
        } else {
            arr.push(oldValue.value);
        }
    } else {
        this.value = ""
    }
    return arr.join("");
}

function renderRadio() {
    if (this.showModel != "text") {
        dsf.UI.render("radio", true);
    }
}