import dom from '../../templates/Browser.ejs';
import {isSupportDataPost} from '../../../../core/postDecorator';
import {ControlEditor} from "../../../../editor/ControlEditor";
import {map} from '../../../../decorator/controlmap';
import {LayoutControl} from "../../../../baseControls";
import {relyFiles} from "../../../../core/relyfiles";

@map("浏览器升级", 'dsf.browser', 'Browser')
@relyFiles(["res/libs/check-browser.js"])
@isSupportDataPost(true)

export class Browser extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;    //添加控件 拖动/移除 的功能
    this.versionSupport = 11;
    this.downlink = "";
    this.msg = "您的浏览器版本过低，部分功能将无法正常使用";
  }
  
  renderContext() {
    super.renderContext();
    const _this = this;
    //设计器模式
    if (_this.isDesign){
      $('.ds_browser').css("display", "block");
      return false;
    }
    //运行模式
    const ieVersion = $.browser.rv;
    if (!ieVersion) return; //不是IE浏览器或者控件已经显示了直接返回
    const browser = dsf.checkBrowser();
    if (ieVersion < _this.versionSupport || browser.version < _this.versionSupport){
      $(".ds_browser").slideDown(600, function () {
        $(".ds_browser i").off('click').on('click', function () {
          $(".ds_browser").slideUp();
        })
      })
    }
    
  }
  
  setMsg(){
    $("#msg").text(this.msg);
  }
  
  initTemplate() {
    return dom(this);
  }
  
  renderReady() {
    super.renderReady();    //这里要继承一下renderReady(), ControlEditor的拖动/移除功能才有效
    const self = this;
    
  }
}