import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from "../../../../editor/ControlEditor";
import { ChartControl } from '../../../../baseControls/controls/ChartControl';

@map("柱状图", 'dsf.barchart', 'BarChart')
export class BarChart extends ChartControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.height = '319px';
    this.label = "柱状图";
    this.isrevseXY = true;
    this.chartType='bar'
  }

  get label() {
    return super.label;
  }
  set label(value) {
    super.label = value;
  }

  renderContext() {
    super.renderContext();
  }
  setOption() {
    super.setOption();
    let customerOption = {
      xAxis: {},
      yAxis:{},
     
    }
    if(this.isrevseXY){
      customerOption.xAxis.type='value';
      customerOption.yAxis.type='category';
      customerOption.yAxis.data = this.chartData.xAxis
    }else{
       customerOption.xAxis.data=this.chartData.xAxis
       customerOption.yAxis.type='value';
       customerOption.xAxis.type='category'
    }
    let option  = $.extend(true, {}, this.defalutOption, customerOption)
    console.log(option)
    this.chart.setOption(option)
  }
}


