const dom = require("../../templates/AreaSelect.ejs");
import { ItemsControl } from "../../../../baseControls";
import { isSupportDataPost } from "../../../../core/postDecorator";
import { Action } from "../../../../core/pageAction";
import { map } from "../../../../decorator/controlmap";

@map("行政区划", "dsf.areaselect", "AreaSelect")
@isSupportDataPost(true)
export class AreaSelect extends ItemsControl {
  constructor(id, isPart) {
    super(id, isPart);

    this.label = "行政区划";

    // 级别范围
    this.range = [0, 4];

    // 上级编码（2/2/2/3/3  == 省/市/区/街道/村居）
    this.superCode = "";

    // 选中的globalid数据[{text:"",value:""}]
    this.selectData = [{}, {}, {}, {}, {}];

    // 显示模式: 内联模式/块级模式
    this.selectBoxClass = "layui-input-inline";

    this.$value = {
      text: "", //00 00 00 000 000
      value: "", //xx省-xx市-xx区-xx街道-xx村居
    };
    // 固定编码（比如固定要是某某市）
    this.fixedCode = "";
  }

  set value(v) {
    this.$value = v;
    if(this.element){
      if (this.readOnly) {
        if (this._handlers.readOnlyLabel) {
          this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
      } else if (!$.isEmptyObject(this.$value)) {
        this.uploadSelectData();
      }
    }
  }
  get value() {
    return this.$value;
  }

  initTemplate() {
    return dom(this);
  }
  renderContextDisplay() {
    for (let i = 0; i < 5; i++) {
      let _dom = this._handlers[i];
      if (i >= this.range[0] && i <= this.range[1]) {
        _dom.show();
      } else {
        _dom.hide();
      }
    }
    dsf.UI.render("select", true);
  }
  renderReady() {
    super.renderReady();
    if (!this._root._isDesign) {
      if (!!this.superCode) this.superCode = dsf.Express.eval(this.superCode);
      if (!!this.fixedCode) {
        let fixedCode = String(dsf.Express.eval(this.fixedCode)),
          _reg = [2, 4, 6, 9, 12];
        this.fixedCode = fixedCode;
        for (let i = 0; i < _reg.length; i++) {
          let s = i == 0 ? 0 : _reg[i - 1];
          let e = _reg[i];
          let code = fixedCode.slice(s, e);
          if (code * 1 != 0 && this._handlers[i]) {
            this._handlers[i].addClass("readOnly");
            if (this.superCode) {
              this.superCode = fixedCode.substring(0, e) + (this.superCode + "").substring(e);
            }
          }
        }
        if (!this.superCode) this.superCode = this.fixedCode;
      }
    }
    if (!this.readOnly) {
      if (!this.root._isDesign) {
        this.uploadSelectData();
      } else {
        this.renderContextDisplay();
      }
    }
    if (!this.$value.value && (this.superCode || this.fixedCode)) {
      this.uploadValue(1, this.superCode || this.fixedCode);
    }
  }
  uploadSelectData() {
    /**
     * @method	处理值格式
     */
    let _this = this;

    /**
     * _reg 区分省/市/区/街道/村居的结构
     * _globalid 国家编码代表中国用于查询省
     */
    let _value = (_this.$value.value || _this.superCode) + '',
      _textArray = _this.$value.text ? _this.$value.text.split("-") : [],
      _reg = [2, 4, 6, 9, 12],
      _globalid = "000000000000";

    if (!_value && _this.disabled) {
      return;
    }

    // 根据this.value 同步 this.selectData
    for (let i = 0; i < _reg.length; i++) {
      if (_value && _value.length >= 12) {
        _globalid += "." + (_value.slice(0, _reg[i]) + "000000000000".slice(_reg[i], 12));
      } else {
        _globalid = "";
      }
      this.selectData[i] = {
        text: _textArray[i] || "",
        value: _globalid,
      };
    }

    // 重新渲染select
    for (let j = 0; j < 5; j++) {
      let _dom = _this._handlers[j].html("");
      if (j >= _this.range[0] && j <= this.range[1]) {
        _this.loadOption(j + 2, j + 2, true);
      } else {
        _dom.hide();
      }
    }

    this.event.trigger(FormControlEvent.VALUECHANGE, {
      ui: this,
    });
    _this.commitAudit();
    layui.form.on("select(" + _this.id + ")", function(data) {
      let startI = parseInt(data.elem.getAttribute("attr"));

      let text = data.othis.find(".layui-this").html() || "";
      let value = data.value || "";

      _this.selectData[startI] = {
        text: text,
        value: value,
      };

      _this.renderItems(startI, value);
    });

    dsf.UI.render("select", true);
  }

  renderItems(startI, value) {
    /**
     * @method 下拉框数据被切换时，下级的下拉框都需要刷新
     * @param 要刷新的开始层级
     */
    let endI = this.range[1];
    if (startI != endI) {
      for (let i = startI + 1; i <= endI; i++) {
        this.loadOption(i + 2, i + 2);
      }
      dsf.UI.render("select", true);
    }
    this.uploadValue(startI, value);
  }
  renderReset(i) {
    this._handlers[i].html("");

    let _selectDom = $("<select lay-filter='" + this.id + "' attr='" + i + "'>");
    this._handlers[i].append(_selectDom);

    this.selectData[i] = {
      text: "",
      value: "",
    };

    if (this.disabled) {
      _selectDom.prop("disabled", true);
    }
  }

  loadOption(startI, endI, isInit) {
    /**
         * @method 获取下级地区数据，渲染选项
         * @param1 startI 开始层级 
         * @param2 endI 结束层级
			1是国家 2是省[0] 3是市[1] 4是区[2] 5是街道[3] 6是村居[4]
         * @param3 是否是初始化加载
         */

    let param = {
      globalid: startI <= 2 ? "000000000000" : this.selectData[startI - 2 - 1].value,
      startI: startI,
      endI: endI,
    };

    if (param.globalid == "") {
      // 没有数据，比如上一级是直辖区
      this.renderReset(startI - 2);
    } else {
      let _this = this;
      Action.area_load(param, (err, data) => {
        if (err) {
          _this.renderReset(startI - 2);
          dsf.layer.message(dsf.prompt.loaddatafail, false);
        } else {
          let options = data || [];
          for (let i = startI - 2; i <= endI - 2; i++) {
            let _dom = _this._handlers[i].html("");
            let _selectDom = $("<select lay-filter='" + _this.id + "' attr='" + i + "' handlers = 'select'>");

            if (options.length == 0) {
              _this.selectData[i] = {
                text: "",
                value: "",
              };
            } else {
              let _html = "";
              let noValue = true;
              for (let j = 0; j < options.length; j++) {
                let _option = options[j];
                if (j == 0) {
                  _html += "<option value=''>请选择</option>";
                }
                if (isInit && _this.selectData[i].value == _option.treeinfo_globalid) {
                  _this.selectData[i] = {
                    text: _option.name,
                    value: _option.treeinfo_globalid,
                  };
                  noValue = false;
                }
                _html += "<option value='" + _option.treeinfo_globalid + "'>" + _option.name + "</option>";
              }
              _selectDom.append(_html);
              if (!noValue) {
                _selectDom.val(_this.selectData[i].value);
              }
            }
            if (_this.disabled) _selectDom.prop("disabled", true);
            _dom.append(_selectDom);
          }
        }
      });
    }
  }
  completeCode(code) {
    if (code.length < 12) {
      for (let i = code.length; i < 12; i++) {
        code = code + "0";
      }
    }
    return code;
  }
  uploadValue(index, value) {
    let value_Array = (value+'').split(".");
    value = value_Array[value_Array.length - 1];

    if (value == "" && index > 0) {
      // 向上找值
      for (let i = index - 1; i >= 0; i--) {
        value_Array = this.selectData[i].value.split(".");
        value = value_Array[value_Array.length - 1];
        if (value) {
          break;
        }
      }
    }

    this.$value = {
      value: value,
      text: "",
    };
    for (let i = 0; i <= index; i++) {
      if (this.$value.text == "") {
        this.$value.text = this.selectData[i].text;
      } else if (this.selectData[i].value) {
        if (this.selectData[i].text) {
          this.$value.text += "-" + this.selectData[i].text;
        }
      }
    }
    this.event.trigger(FormControlEvent.VALUECHANGE, {
      ui: this,
    });
    this.commitAudit();
  }
  changeStyle() {
    for (var i = 0; i < 5; i++) {
      let _dom = this._handlers[i];
      _dom.attr("class", this.selectBoxClass);
    }
  }
}
