import { RankControl } from '../../../../baseControls'
import { FormFillMetaData, SubRankMetaData } from '../../../../core/metadata'
import { map } from '../../../../decorator/controlmap'

@map('评分', 'dsf.grade', 'Grade')
export class Grade extends RankControl {
  constructor(id, isPart) {
    super(id, isPart)
    this.$metadata = FormFillMetaData.call(this)
    this.tableName = 'grade'
    this._submetadata = SubRankMetaData.call(this)
    this._isreaded = false
    this.keys = {};
  }
  set value(v) {
    let _this = this
    let key = _this.metadata_fullcode
    _.forEach(v, (row, i) => {
      let caption = row[key + '.item'].split('_')[0]
      if (caption == _this.caption) {
        _this._isreaded = true
        let idx = row[key + '.item'].split('_')
        let score = row[key + '.score']
        if (score || score === 0) {
          
          if(_this.keys && JSON.stringify(_this.keys) != "{}"){
            if(_this.keys[idx[1]]){
              idx = _this.keys[idx[1]].split('_');
              idx.unshift(0)
            }else{
              idx = [];
            }
          }
          if (idx.length > 2) {
            if(_this.rowSet.rows[idx[1]] && _this.rowSet.rows[idx[1]].children[idx[2]]){
              _this.rowSet.rows[idx[1]].children[idx[2]].score = score
              _this.rowSet.rows[idx[1]].children[idx[2]]['_id'] = row['_id']
            }
          } else if(idx[1] && _this.rowSet.rows[idx[1]]) {
            _this.rowSet.rows[idx[1]].score = score
            _this.rowSet.rows[idx[1]]['_id'] = row['_id']
          }
        }
      } else if (_this.root.getControl(caption) && !_this.root.getControl(caption)._isreaded) {
        _this.root.getControl(caption).value = v
      }
    })
    this.changeSelectValue()
  }
  get value() {
    let v = []
    let _ri = 0
    let _this = this
    let page = _this.metadata_fullcode
    _.forEach(this.rowSet.rows || [], (row, i) => {
      if (row.children) {
        _.forEach(row.children, function(_val, _i) {
          let index = i + '_' + _i;
          let obj = {
            [_this.metadata_fullcode + '.score']: _val.score,
            [_this.metadata_fullcode + '.item']:
              _this.$caption + '_' + (_val.sourceId || index),
            [_this.metadata_fullcode + '.weight']: _val.weight,
            [_this.metadata_fullcode + '.total_weight']: _this.totalWeight,
          }
          let _id = _val._id || null
          if (_id) {
            obj[
              _this.metadata_fullcode + '.' + _this.metadata_fullcode + '_id'
            ] = _id
            obj['_id'] = _id
          }
          v.push(obj)
        })
      } else {
        let index = i;
        let obj = {
          [_this.metadata_fullcode + '.score']: row.score,
          [_this.metadata_fullcode + '.item']: _this.$caption + '_' + (row.sourceId || index),
          [_this.metadata_fullcode + '.page']: page,
          [_this.metadata_fullcode + '.weight']: row.weight,
          [_this.metadata_fullcode + '.total_weight']: _this.totalWeight,
        }
        let _id = row._id || null
        if (_id) {
          obj[
            _this.metadata_fullcode + '.' + _this.metadata_fullcode + '_id'
          ] = _id
          obj['_id'] = _id
        }
        v.push(obj)
      }
    })
    return v
  }
  vaildateData() {
    let errors = []
    if (this.$required || this.styleType == '3') {
      let index = 0
      let _this = this
      _.forEach(_this.rowSet.rows, function(val, key) {
        if (val.children && val.children.length > 0) {
          // 二级
          _.forEach(val.children, function(c_val, c_key) {
            if (_this.$required && c_val.score == null) {
              errors.push({
                errorMsg: '此项必评',
                index: index,
              })
            } else if (
              _this.styleType == '3' &&
              c_val.score * 1 > _this.chooseTypeInput * 1
            ) {
              errors.push({
                errorMsg:
                  '此项评分为' + _this.chooseTypeInput + '分制,请正确评分',
                index: index,
              })
            }
            index++
          })
        } else {
          // 一级
          if (_this.$required && val.score == null) {
            errors.push({
              errorMsg: '此项必评',
              index: index,
            })
          } else if (
            _this.styleType == '3' &&
            val.score * 1 > _this.chooseTypeInput * 1
          ) {
            errors.push({
              errorMsg:
                '此项评分为' + _this.chooseTypeInput + '分制,请正确评分',
              index: index,
            })
          }
          index++
        }
      })
    }
    return errors
  }
  createMetaData() {
    try {
      let _this = this
      let key = this.root.scope
      let ns = key
      this.metadata.code = this.tableName
      key += '_' + this.metadata.code
      this.metadata.id = ns.replace(/\_/g, '.') + '.' + this.metadata.code
      let path = this.metadata.id.split('.')
      path = path.slice(0, path.length - 1)
      this.metadata.at = path.join('.')
      this.metadata.name = this.metadata.name || this.label
      this.metadata.level = 1
      this.metadata_fullcode = key

      let mm = []
      mm.splice(0, 0, {
        key: _this.metadata_fullcode,
        md: this.metadata,
      })

      let keys = ['item', 'score', 'page','weight','totalWeight']
      _.forEach(keys, (key, i) => {
        let sub_md = _this._submetadata[i]
        sub_md.id = _this.metadata.id + '.' + key
        sub_md.at = _this.metadata.id
        sub_md.level = 1
        mm.push({
          key: _this.metadata_fullcode + '.' + key,
          md: sub_md,
        })
      })
      return mm
    } catch (ex) {
      throw ex
    }
  }
}
