const dom = require("../../templates/TimePicker.ejs");
import { FormControl } from '../../../../baseControls'
import { TimePickerMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';

import {map} from  '../../../../decorator/controlmap';

@map('时间','dsf.timepicker','TimePicker')
@isSupportDataPost(true)
export class TimePicker extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        let d = new Date();
        this.$label = "";
        this.$showLabel = true;
        this.$metadata = TimePickerMetaData.call(this, 100);
        this.label = "时间选择";
        this.$hourStep = "5" //显示小时步长
    }
    set disabled(value) {
        this.$disabled = value;
        super.renderContext();
        this._handlers.picker.prop("disabled", this.$disabled);
      }
      get disabled() {
        return this.$disabled;
      }
    set value(val) {
        super.value = val;
        let lastCommIndex = ""
        if (val) {
            lastCommIndex = val.lastIndexOf(":")
        }
        if (this._handlers.picker) {
            this._handlers.picker[0].value = val.substring(0, lastCommIndex)
        }
        if (this._handlers.readonlyBlock) {
            this._handlers.readonlyBlock.text(this.getTextString(""));
        }

    }
    get value() {
        return super.value
    }
    set label(value) {
        this.$label = value;
    }
    get label() {
        return this.$label;
    }


    set showLabel(value) {
        this.$showLabel = value;
        if (!value) {
            this.addClass("hideLabel")
        } else {
            this.removeClass("hideLabel")
        }
    }
    get showLabel() {
        return this.$showLabel;
    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
    }

    renderContext() {
        super.renderContext();
        if (this._handlers.label) {
            this._handlers.label.html(this.$label)
        }
    }
    initEvent() {
        let minHour = "00:00:00",
            maxHour = "24:00:00"
        if (this.$timeInter) {
            let timeInterval = this.$timeInter
            minHour = $.trim(timeInterval.split("-")[0]) + ":00";
            maxHour = $.trim(timeInterval.split("-")[1]) + ":00"
        }

        let _this = this;
        layui.use('laydate', function() {
            var laydate = layui.laydate;
            laydate.render({
                elem: '#t_' + _this.id,
                type: 'time',
                format: 'HH:mm',
                min: minHour,
                max: maxHour,
                trigger: 'click',
                ready: function() {
                    var showtime = $($(".laydate-time-list li ol")[1]).find("li");
                    for (var i = 0; i < showtime.length; i++) {
                        var t00 = parseInt(showtime[i].innerText);
                        var step = parseInt(_this.$hourStep)
                        if (t00 % step != 0) {
                            showtime[i].remove()
                        }
                    }
                    $($(".laydate-time-list li ol")[2]).find("li").remove();
                },
                change: (value, date, endDate) => {
                    valueChange.call(_this, value, date, endDate)
                },
                done: (value, date, endDate) => {
                    valueChange.call(_this, value, date, endDate)
                }
            });
        })
    }
    renderReady() {
        super.renderReady();
    }

    getTextString(split) {
        let value = this.value
        let val = ""
        if (this.value) {
            let lastCommIndex = value.lastIndexOf(":")
            val = value.substring(0, lastCommIndex)
        }
        return val
    }
    setControlId() {
        return this.id
    }
}

function valueChange(value, date, endDate) {
    this.value = value ? $.trim(value) + ":00" : "";
    this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
    this.commitAudit();
}