export class Ev {
    constructor() {
        this.evList = [];
        this.evResult = [];
        this.ruleCompile = {};
        this._evData = null;
        this.auditting = false;
        this._oldEvData = null;
    }
    addRule(options, getter) {
        let evObj = {
            key: options.key || dsf.uuid(),
            getter: getter || dsf.noop,
            scope: options.scope || options.prop || "",
            prop: options.scope || options.prop || "",
            level: (options.level === undefined || options.level === null) ? 0 : options.level,
            errorMsg: options.errorMsg || "",
            rel: options.rel || []
        }
        let index = _.findIndex(this.evList, o => o.key == evObj.key);
        if (index >= 0) {
            this.evList[index] = evObj;
            evObj.sort = index;
        } else {
            evObj.sort = this.evList.length;
            this.evList.push(evObj);
        }
    }

    filter(filterFn) {
        return _.filter(this.evList, (item) => {
            return filterFn(item)
        });
    }

    /** 
     * args未一个验证器对象数组
     * evItem为过滤器对象
     * options:为校验时的设置，index:用于子表审核时指定审核指定的行
     * [
     *  {
     *      evItem:null,
     *      options:{
     *          index:undefind
     *      }
     *  }
     * ]
     */
    exec(args) {
        try {
            if (!this.auditting) {
                this.auditting = true;
                let result = [];
                //args为否时执行全部审核
                !args && (args = getAllEvListRule.call(this));
                run.call(this, args, (evResult, level) => {
                    result.push(evResult);
                });
                let str = JSON.stringify(this._evData);
                this._oldEvData = JSON.parse(str);
                result = result.sort((v1, v2) => {
                    if (v1.evIndex > v2.evIndex) {
                        return 1;
                    } else if (v1.evIndex < v2.evIndex) {
                        return -1;
                    } else {
                        if (v1.index > v2.index) {
                            return 1;
                        } else {
                            return -1;
                        }
                    }
                });
                return result;
            }
        } catch (ex) {

        } finally {
            this.auditting = false;
        }

    }

    init() {
        createRootData(this);
    }

    compile() {
        let scope = createRootData(this);
        for (let i = 0; i < this.evList.length; i++) {
            let accessor = new Acsessor(this.evList[i], scope);
            this.evList[i].accessor = accessor;
        }
    }

}

function getAllEvListRule() {
    return _.map(this.evList, (item) => {
        return {
            evItem: item,
            options: {
                index: null
            }
        }
    })
}


function simplify(data, control, index) {
    let r = {};
    Object.defineProperties(r, {
        'control': {
            writable: false,
            value: control || page,
            enumerable: false,
            configurable: true
        },
        'isScope': {
            value: true,
            writable: false,
            enumerable: false,
            configurable: true
        },
        '$index': {
            value: index,
            writable: false,
            enumerable: false,
            configurable: true
        }
    });

    //k表示元数据代码,sk表示元数据代码去掉前缀
    for (let k in data) {
        let ctrl = control.element.find(".ds_control[ds-data-bind='" + k + "']");
        if (r.$index != null || r.$index != undefined) {
            ctrl = ctrl.eq(r.$index);
        }
        ctrl = ctrl.data("Object");
        if (ctrl) {
            if (ctrl.oneToMany) {
                _defSubList(r, k, ctrl, null);
            } else {
                _def(r, k, ctrl, null);
            }
        } else {
            _def(r, k, null, data);
        }
    }
    return r;
}

function _def(obj, key, control, data) {
    let sk = getMCode(key);
    let old_val;

    function getValue() {
        if (control) {
            let v = control.value;
            if (control.$metadata && control.$metadata.validate && control.$metadata.validate.config && control.$metadata.validate.config.isNumber == "1") {
                if ($.type(v) == "string" && v != '' && !isNaN(v)) {
                    v = parseFloat(v);
                }
            }
            old_val = v;
            return v;
        } else {
            old_val = data[key];
            return data[key];
        }
    }

    function setValue(v) {
        if (control) {
            control.value = v;
        } else {
            data[key] = v;
        }
    }
    if (sk) {
        Object.defineProperty(obj, sk, {
            get() {
                return getValue();
            },
            set(val) {
                setValue(val);
            },
            enumerable: true,
            configurable: true
        });
        old_val = getValue();
        return sk;
    }
    return null;

}

function _defSubList(obj, key, conrol) {
    let sk = getMCode(conrol.metadata_fullcode);
    let list = null;
    Object.defineProperty(obj, sk, {
        get() {
            if (!list) {
                list = []
                let arr = conrol.value;
                for (let i = 0; i < arr.length; i++) {
                    let local = {};
                    for (let k in arr[i]) {
                        local[k] = arr[i][k];
                    }
                    let child = simplify(local, conrol, i);
                    list.push(child);
                }
            }
            return list;
        },
        set: function(v) {
            list = v;
        },
        enumerable: true,
        configurable: true
    });
}

function getMCode(code) {
    let arr = code.split("."),
        sk = "";
    //子表的元数据编码没有.所以取最后一个下划线后续的字符作为sk
    arr.length > 1 ? sk = arr[arr.length - 1] : sk = code.substr(code.lastIndexOf("_") + 1);
    return sk;
}

function codeRun(variable, ev, index) {
    let result = true;
    try {
        result = ev.accessor.getValue(variable, index)
    } catch (ex) {
        dsf.error("执行规则" + ev.key + "出现错误："+ex)
        // console.log("执行规则" + ev.key + "出现错误");
    }
    return result;
}

function compileRule(ev) {
    let code = [
        'var result=true;',
        'with(__local__||{}){',
        '\tvar getter=(' + ev.getter.toString() + ');',
        '\tresult=getter(__index__);',
        '}',
        'return result;'
    ]
    let Fn = new Function('__local__', '__index__', code.join("\n"));
    return Fn;
}

function createRootData(ev) {
    let root = null;
    if (!ev._evData) {
        let ctrls = page.getPostControls();
        let d = {};
        for (let i = 0; i < ctrls.length; i++) {
            let c = ctrls[i];
            d[c.metadata_fullcode] = null;
        }
        root = simplify(d, page, null);
        for (let k in dsf.validate) {
            Object.defineProperty(root, k, {
                enumerable: false,
                configurable: false,
                writable: false,
                value: dsf.validate[k]
            });
        }
        ev._evData = root;

    } else {
        root = ev._evData;
    }
    return root;
}

function run(evList, callback) {
    let root = createRootData(this);
    let variable = root;
    //作用域归类
    let evMap = {},
        evArr = [];
    _.each(evList, (ev) => {
        let evItem = ev.evItem;
        let scope = evItem.scope;
        scope = scope || "__main__";
        if (evArr.indexOf(scope) < 0) {
            evArr.push(scope)
        }
        if (!evMap[scope]) {
            evMap[scope] = [];
        }
        evMap[scope].push(ev);
    });
    for (let kk = 0; kk < evArr.length; kk++) {
        let scopeKey = evArr[kk]
        let ev_list = evMap[scopeKey];
        let s;
        if (scopeKey == "__main__") {
            s = root;
        }
        else{
            root[scopeKey]=null;
            s=root[scopeKey];
            
        }
        if (!s) {
            dsf.error("审核规则指定的作用域[" + scope + "]无效")
            return;
        }
        //说明是子表
        if (scopeKey != "__main__") {
            //子表审核将指定行号的和未指定行号的审核分开
            let isEach = false;
            _.each(ev_list, (e) => {
                if (!dsf.isDef(e.options.index)) {
                    isEach = true;
                }
            });
            //子表是否要进行循环读取
            if (isEach) {
                for (let n = 0; n < s.length; n++) {
                    let cs = s[n];
                    if (cs && cs.isScope) {
                        _.each(ev_list, (ev) => {
                            let evItem = ev.evItem;
                            let currIndex = (ev.options && dsf.isDef(ev.options.index)) ? ev.options.index : null;
                            let result;
                            if (dsf.isDef(currIndex)) {
                                if (currIndex == n) {
                                    result = codeRun.call(this, variable, evItem, n);
                                }
                            } else {
                                result = codeRun.call(this, variable, evItem, n);
                            }
                            if (dsf.isDef(result)) {
                                callback && callback({
                                    "id": evItem.accessor.id,
                                    "scope": cs,
                                    "rel": evItem.rel,
                                    "index": n,
                                    "errorMsg": evItem.errorMsg,
                                    "level": evItem.level,
                                    "key": evItem.key,
                                    "result": result,
                                    "evIndex": evItem.sort
                                }, 1);
                            }
                        });
                    }
                }
            } else {
                _.each(ev_list, (ev) => {
                    let evItem = ev.evItem;
                    let currIndex = (ev.options && dsf.isDef(ev.options.index)) ? ev.options.index : null;
                    let cs = s[currIndex];
                    let result;
                    if (cs && cs.isScope) {
                        result = codeRun.call(this, variable, evItem, currIndex);
                        if (dsf.isDef(result)) {
                            callback && callback({
                                "id": evItem.accessor.id,
                                "scope": cs,
                                "rel": evItem.rel,
                                "index": currIndex,
                                "errorMsg": evItem.errorMsg,
                                "level": evItem.level,
                                "key": evItem.key,
                                "result": result,
                                "evIndex": evItem.sort
                            }, 1);
                        }
                    }
                })

            }
        }
        //主表审核
        else {
            for (let i = 0; i < ev_list.length; i++) {
                let evItem = ev_list[i].evItem;
                let currIndex = (ev_list[i].options && dsf.isDef(ev_list[i].options.index)) ? ev_list[i].options.index : null;
                let scope = evItem.scope;
                if (s && s.isScope) {
                    var result = codeRun.call(this, variable, evItem, null);
                    // let controls = getRelControlsCaption(evItem, null);
                    callback && callback({
                        "id": evItem.accessor.id,
                        "scope": s,
                        "rel": evItem.rel,
                        "index": null,
                        "errorMsg": evItem.errorMsg,
                        "level": evItem.level,
                        "key": evItem.key,
                        "result": result,
                        "evIndex": evItem.sort
                    });
                }
            }
        }
    }
}


function Acsessor(evItem, vm) {
    this.id = dsf.uuid();
    this.evItem = evItem;
    this.getValue = compileRule(evItem);
    this.rel = [];
    if (evItem.scope) {
        if (vm[evItem.scope]) {
            for (let i = 0; i < evItem.rel.length; i++) {
                let str = evItem.rel[i];
                this.rel.push(str);
            }
        }
    } else {
        for (let i = 0; i < evItem.rel.length; i++) {
            let str = evItem.rel[i];
            this.rel.push("@" + str);
        }
    }
}

function getRelControlsCaption(evItem, index) {
    let controls = [];
    for (let i = 0; i < evItem.rel.length; i++) {
        let ctrl = getCaption(evItem.rel[i], evItem.scope || "", index);
        controls.push(ctrl);
    }
    return controls;
}

function getCaption(caption, scope, i) {
    if (caption.startsWith("@")) {
        return caption.substr(1);
    } else {
        if (!scope) {
            return caption;
        } else {
            return scope + "_" + i + "_" + caption;
        }
    }
}