import { Control } from './Control';
import { ControlEditor } from '../../editor/ControlEditor';
import { FormControlEvent } from '../../core/ControlEvent';
import { map } from '../../decorator/controlmap';

@map('表单组件基类', 'dsf.formcontrol', 'FormControl')
export class FormControl extends Control {
   constructor(id, isPart) {
      super(id, isPart);
      this.$value = "";
      this.$name = "";
      this.$label = "";
      //是否只读
      this.$readOnly = false;
      //是否失效
      this.$disabled = false;
      this.$showLabel = true;
      this._desingerClass = ControlEditor;
      this.$required = false;
      this.$allowPost = true;
      this.$scopeLevel = 0;
      this.$error_tipsPosition = "left";
      this._invalid = false;
      this._errorMsg = "";

      // 移动端提示文字
      this.dataCapion = null;
      // 移动端语音地址
      this.dataAudioUrl = null;
      // 移动端视频地址
      this.dataVideoUrl = null;

      this._isFormControl = true;

      this.$immediatelyAudit = false;

      this._validator = null;


   }

   set label(value) {
      this.$label = value;
      if (this.element && this._handlers.label) {
         this._handlers.label.html(value);
      }
      this.updateLabel();
   }
   get label() {
      return this.$label;
   }
   set name(value) {
      this.$name = value;
   }
   get name() {
      return this.$name;
   }

   set value(value) {
      this.oldValue = this.$value;
      this.$value = value;
   }
   get value() {
      return this.$value;
   }

   set showLabel(value) {
      this.$showLabel = value;
      if (value) {
         this.removeClass("hideLabel");
      } else {
         this.addClass("hideLabel");
      }
   }
   get showLabel() {
      return this.$showLabel;
   }

   set readOnly(value) {
      this.$readOnly = value;
      if (this._isRender) {
         this.render();
      }
   }

   set required(val) {
      this.$required = val;
      if (this.element) {
         val ? this.element.addClass("ds_required") : this.element.removeClass("ds_required");
      }
   }
   get required() {
      return this.$required;
   }

   get readOnly() {
      return this.$readOnly;
   }

   set disabled(value) {
      this.$disabled = value;
      this.renderContext();
   }
   get disabled() {
      return this.$disabled;
   }

   set metadata(value) {
      super.metadata = value;
      this.label = value.name;
   }
   get metadata() {
      return super.metadata;
   }

   get scopeControl() {
      if (!this._scopeCtrl) {
         if (this.$scopeLevel == 0) {
            this._scopeCtrl = this.root;
         } else {
            let p = this,
               isMark = true;
            do {
               p = p.parent;
               if (p.oneToMany || p == this.root) {
                  isMark = false;
               }
            } while (isMark)
            this._scopeCtrl = p;
         }
      }
      return this._scopeCtrl;
   }

   updateLabel() {
      if (this.root && this.root._isDesign) {
         let text = ($("[ctrl_type=Label][htmlfor=" + this.id + "]"));
         if (text.length > 0) {
            let textCtrl = text.data("Object");
            if (textCtrl) {
               textCtrl.$required = this.$required;
               textCtrl.value = this.label;
            }
         }
      }
   }

   renderContext() {
      super.renderContext();
      this.readOnly ? this.element.addClass("ds_readonly") : this.element.removeClass("ds_readonly");
      this.$required ? this.element.addClass("ds_required") : this.element.removeClass("ds_required");

   }

   renderComplete() {
      super.renderComplete();
   }

   initEvent() { }

   createElement() {
      super.createElement();
      if (this.metadata) {
         this.$scopeLevel = this.metadata.level;
         this.element.attr("meta-level", this.$scopeLevel)
      }
   }

   renderReady() {
      super.renderReady();
   }

   render() {
      super.render();
      let _this = this;
      if (!this.isDesign) {
         this.event.top(FormControlEvent.VALUECHANGE, args => {
            if (this._validator) {
               let result = this._validator.exec();
               if (result) {
                  if (result.errorMsg) {
                     this.addError(result, 'validate')
                  } else {
                     this.removeError(result, 'validate');
                  }
                  this.validateError();
               }
            }
         });
         let errorPostElement = this.getErrorPostElement();
         //鼠标悬浮显示错误信息
         errorPostElement.on("mouseenter.tooltips", evt => {
            this.validateError()
         });
         errorPostElement.on("mouseleave.tooltips", evt => {
            _this.hideTips();
         });
      }
   }

   getTextString(split) {
      return this.value;
   }

   getValueString(split) {
      return this.value;
   }


   createMetaData() {
      if (this.metadata) {

         if (this.$encrypt) {
            this.metadata.valueAttributes[0].encrypt = true
         } else {
            this.metadata.valueAttributes[0].encrypt = false
         }

         //来自于已有的元数据
         if (!this.$isFromMetaData) {
            let key = this.root.scope;
            let controlCode = this.$caption;
            let ns = key;
            key += "." + controlCode;
            this.metadata.code = controlCode;
            this.metadata.id = ns.replace(/\_/g, '.') + "." + controlCode;
            let path = ns.replace(/\_/g, '.');
            this.metadata.at = path;
            this.metadata.name = this.metadata.name || this.label;
            this.metadata_fullcode = key;
            this.metadata.level = 0;
            return { "key": this.metadata_fullcode, "md": this.metadata };
         } else {
            let index = this.metadata.id.lastIndexOf(".");
            let key = this.metadata.id.substring(0, index).replace(/\./g, "_") + "." + this.metadata.id.substr(index + 1);
            this.metadata_fullcode = key;
            this.metadata.level = 0;
            return { "key": this.metadata_fullcode, "md": this.metadata };
         }
      }
      return null;
   }

   validateError(value, errorMsg) {
      let errorPostElement = this.element.find(this.validateInfo().tipsElement); //this.element.find(".errorpos");
      if (errorPostElement.length <= 0) {
         errorPostElement = this.element;
      }
      if (this._errors && this._errors.length) {
         this.addClass("ds_error");
         let emsg = this._errors[0].errorMsg;
         this.showTips(emsg, errorPostElement, this.$error_tipsPosition);
      } else {
         this.removeClass("ds_error");
         this.hideTips();
      }
   }

   emitDataChange() {

   }

   //描述组件的验证信息
   validateInfo() {
      return {
         tipsElement: ".layui-input-block"
      }
   }

   addError(error, type) {
      if (!this._errors) {
         this._errors = [];
      }
      error.type = type;
      let index = _.findIndex(this._errors, err => err.id == error.id);
      if (index >= 0) {
         this._errors.splice(index, 1, error);
      } else {
         this._errors.push(error);
      }
      this._invalid = this._errors.length > 0 ? true : false;
   }
   removeError(error, type) {
      if (this._errors) {
         let index = _.findIndex(this._errors, err => err.id == error.id);
         if (index >= 0) {
            this._errors.splice(index, 1);
         }
         this._invalid = this._errors.length > 0 ? true : false;
      }
   }

   //提交审核
   commitAudit() {
      if (this.$immediatelyAudit) {
         if (this.root._auditInfo) {
            this.root._auditInfo.exec(this);
         }
      }
   }

   getErrorPostElement() {
      let errorPostElement = this.element.find(this.validateInfo().tipsElement); //this.element.find(".errorpos");
      if (errorPostElement.length <= 0) {
         errorPostElement = this.element;
      }
      return errorPostElement;
   }
}