const dom = require("../../templates/AuditInfo.ejs");
const detailDom = require("../../templates/AuditInfoDetail.ejs");
import { FormControl } from '../../../../baseControls'
import { AuditInfoMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { PageEvent, FormControlEvent } from "../../../../core/ControlEvent";
import { map } from '../../../../decorator/controlmap';


@map('审核信息', 'dsf.auditinfo', 'AuditInfo')
@isSupportDataPost(true)
export class AuditInfo extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$placeholder = "请输入";
        this.label = "审核结果";
        //state 1为通过 -1未通过 0未审核

        this.$metadata = AuditInfoMetaData.call(this);
        this.$caption = "auditinfo";
        this.$requireRemark = false;
        this.$errorLevels = [{
            num: 0,
            type: "warning"
        }, {
            num: 1,
            type: "error"
        }];
        this._evResult = [];
        this._errorIcon = null;
        this.$isSyncChildList = true;

    }

    get value() {
        if (!this.$value) {
            this.$value = {
                "state": 0,
                "num0": 0,
                "num1": 0,
                "detail": "[]"
            };
        }
        return this.$value;
    }

    set value(val) {
        this.$value = val;
        if (this.element) {
            let arr = JSON.parse(this.$value.detail || '[]');
            arr.length > 0 ? this.showErrorIcon() : this.hideErrorIcon();
        }
    }


    get isSyncChildList() {
        return this.$isSyncChildList;
    }
    set isSyncChildList(val) {
        this.$isSyncChildList = val;
    }

    init() {
        this._ev = this.root._ev;
        this.root._auditInfo = this;
        // this._ev.addRule({
        //     "key": "t1>0",
        //     "errorMsg": "t1输入内容必须大于0",
        //     "level": 0,
        //     "rel": ["t1", "t2"]
        // }, (index) => {
        //     return t1 + t2 > 0
        // });
        // this._ev.addRule({
        //     "key": "t2>0",
        //     "errorMsg": "t2输入内容必须大于0",
        //     "level": 1,
        //     "rel": ["t2"]
        // }, (index) => {
        //     return t2 > 0;
        // });

        // this._ev.addRule({
        //     "key": "sb.t2>0",
        //     "errorMsg": "子表t3输入内容必须是数字且大于0",
        //     "prop": 'sb',
        //     "level": 0,
        //     "rel": ["t3"]
        // }, (index) => {
        //     return sb[index].t3 > 0;
        // });
    }

    createElement() {
        super.createElement();
        this.visible = false;
    }

    initTemplate() {
        return dom(this);
    }

    renderContext() {
        super.renderContext();
    }

    renderComplete() {
        super.renderComplete();
        let _this = this;
        //编译注册的规则

        if (!this.isDesign) {
            this._errorIcon = $("<div class='error_detail' title='查看审核信息'><i class='iconfont icon-jinggao'></i></div>");
            this._errorIcon.hide();
            this._errorIcon.click(function() {
                _this.showDetail();
            });
            this.root.element.append(this._errorIcon);
        }
        //如果有警告或者错误显示小图标
        let arr = JSON.parse(this.$value.detail || '[]');
        arr.length > 0 ? this.showErrorIcon() : this.hideErrorIcon();
    }

    initEvent() {
        this.root.event.on(PageEvent.INITED, () => {
            let sublist = [];
            //提取所有子表控件
            this.root.ControlsForEach(control => {
                if (control.oneToMany) {
                    sublist.push(control);
                }
            });

            //监听子表删除数据功能更新审核结果
            for (let i = 0; i < sublist.length; i++) {
                let sub = sublist[i]
                sub.event.off(SubTableEvent.VALUECHANGE, subrowdelete.bind(this));
                sub.event.last(SubTableEvent.VALUECHANGE, subrowdelete.bind(this));
            }
        })
    }

    updateAduitResult() {
        if (this._ev) {
            let list = JSON.parse(this.value.detail || "[]");
            let keys = [];
            for (let i = 0; i < list.length; i++) {
                let c = list[i];
                let evItem = _.find(this._ev.evList, (item) => {
                    return item.key == c.key;
                });
                if (evItem) {
                    keys.push({
                        evItem: evItem,
                        options: {
                            index: c.index
                        }
                    });
                }
            }
            this._evResult = this._ev.exec(keys);
            execResultHanlder.call(this);
        }
    }

    compile() {
        this._ev && this._ev.compile()
    }

    exec(args) {
        let result = _exec(this, args);
        this._evResult = result || [];
        execResultHanlder.call(this);
    }

    test(args) {
        let returnValue = {
            result: true,
            errorList: [],
            successList: []
        }
        let result = _exec(this, args);
        let errorList = [];
        let successList = [];
        if (result) {
            _.each(result, function(ev) {
                ev.result ? successList.push(ev) : errorList.push(ev);
            });
        }
        returnValue.errorList = errorList;
        returnValue.successList = successList;
        if (errorList.length > 0) {
            returnValue.result = false;
        }
        return returnValue;
    }

    getTextString() {
        let text = ""
        switch (this.value.state) {
            case 0:
                text = "未审核";
                break;
            case -1:
                text = "不通过";
                break;
            case 1:
                text = "通过";
                break;
        }
        return text;
    }

    showErrorIcon() {
        this._errorIcon && this._errorIcon.show();
        // window.setTimeout(()=>{
        //     this._errorIcon.addClass("buzz_out");
        //     window.setTimeout(()=>{
        //         this._errorIcon.removeClass("buzz_out");
        //     },1000)
        // },100);
    }
    hideErrorIcon() {
        this._errorIcon && this._errorIcon.hide();
    }
    showDetail() {
        let _this = this;
        let list = JSON.parse(_this.value.detail || "[]")
        _.each(list, (ev) => {
            let key = ev.key;
            let index = ev.index;
            let evItem = _.find(_this._ev.evList, o => o.key == key);
            let relControls = getRelControls(evItem, index);
            let control = evItem.scope ? _this.root.getControl(evItem.scope) : _this.root;
            if (control) {
                _.each(relControls, function(ctrl) {
                    if (ctrl) {
                        createRuleToControl(ctrl, evItem);
                    }
                })
            }
        })

        layui.layer.open({
            type: 0,
            anim: 2,
            title: "审核结果明细",
            area: ["700px", "60%"],
            content: detailDom({ "list": list }),
            btn: ['确定', '取消'],
            success: function(layero, index) {
                layero.on("change", "textarea", evt => {
                    let textarea = $(evt.target);
                    let key = textarea.attr("key");
                    let result = _.find(list, o => o.key == key);
                    result ? result.remark = textarea.val() : dsf.noop();
                    result ? result.userName = window.decodeURI(dsf.getCookie("user_name") || "") : dsf.noop();
                    result ? result.userId = dsf.getCookie("user_id") || "" : dsf.noop();
                });
                layero.on("click", '.errorRow', evt => {
                    let target = $(evt.target);
                    let key = target.closest("TR").attr("key");
                    let subtable_index = target.closest("TR").attr("subtableindex");
                    let result = _.find(_this._ev.evList, o => o.key == key);
                    if (result) {
                        let relControls = getRelControls(result, subtable_index);
                        let control = result.scope ? _this.root.getControl(result.scope) : _this.root; //result.scope.control;
                        //先移除掉审核错误
                        let errControls = _this.root.element.find(".ds_error");
                        errControls.each(function() {
                            let errctrl = dsf.Dom.getControlByElem(this);
                            if (errctrl) {
                                clearAuditError(errctrl);
                                errctrl.validateError()
                            }
                        });
                        if (control) {
                            _.each(relControls, function(ctrl) {
                                if (ctrl) {
                                    ctrl.addError({
                                        id: result.key,
                                        errorMsg: result.errorMsg
                                    }, 'audit');
                                    ctrl.validateError();
                                }
                            });
                            if (relControls[0]) {
                                relControls[0].element.get(0).scrollIntoView({ behavior: "smooth" });
                            }
                        }
                    }
                });
            },
            yes: function(index, layero) {
                _this.value.detail = JSON.stringify(list);
                layer.close(index);
            }
        });
    }
}


function _exec(auditInfo, args) {
    let returnValue = null;
    let evFilter = getEvItem.call(auditInfo, args);
    //执行逻辑审核规则
    if (auditInfo._ev) {
        if (evFilter) {
            let currReuleRules = getEvItemByCurrentResult.call(auditInfo);
            for (let i = 0; i < evFilter.length; i++) {
                let evf = evFilter[i]
                let index = _.findIndex(currReuleRules, (item) => {
                    if (dsf.isUnDef(item.options.index)) {
                        return item.evItem.key == evf.evItem.key;
                    } else {
                        return item.evItem.key == evf.evItem.key && item.options.index == evf.options.index;
                    }
                });
                if (index >= 0) {
                    currReuleRules.splice(index, 1, evf);
                } else {
                    currReuleRules.push(evf);
                }
            }
            evFilter = currReuleRules;
        }
        returnValue = auditInfo._ev.exec(evFilter);
    }
    return returnValue;
}


function getEvItemByCurrentResult() {
    let result = [];
    let oldArr = JSON.parse(this.$value.detail || "[]");
    //遍历旧的结果集
    _.each(oldArr, (item, i) => {
        let evItem = _.find(this._ev.evList, (rule) => rule.key == item.key);
        if (evItem) {
            if (evItem.scope) {
                let index = item.index;
                let list = this._ev._evData[evItem.scope];
                if (list && $.type(list) == 'array' && list[index]) {
                    result.push({
                        "evItem": evItem,
                        "options": {
                            index: index
                        }
                    });
                }
            } else {
                result.push({
                    "evItem": evItem,
                    "options": {
                        index: undefined
                    }
                });
            }
        }
    });
    result = _.uniqWith(result, (item1, item2) => {
        let key1 = item1.key;
        let key2 = item2.key;
        let index1 = dsf.isDef(item1.options.index) ? item1.options.index : "";
        let index2 = dsf.isDef(item2.options.index) ? item2.options.index : "";
        if (key1 === key2 && index1 === index2) {
            return true;
        }
        return false;
    })
    return result;
}

function getEvItem(args) {
    let evFilter;
    if (!args) {
        return null;
    }
    if (isControl(args)) {
        let ctrl = args;
        let nameAndPos = getControlNameAndPos(ctrl);
        let scope = ctrl.scopeControl == ctrl.root ? "" : ctrl.scopeControl.caption;
        //当组件的中没有规则_auditRules属性不存在是表示第一次执行规则,从规则表中检索一次规则
        if (dsf.isUnDef(ctrl._auditor)) {
            //获取审核规则中和他有关的项目，且只和他有关的项目
            let result = this._ev.filter(function(evItem) {
                if (scope === evItem.scope) {
                    if (evItem.accessor.rel.indexOf(nameAndPos.caption) >= 0 && evItem.accessor.rel.length == 1) {
                        return true;
                    }
                }
                return false;
            });
            if (result && result.length) {
                evFilter = _.map(result, (item) => {
                    return {
                        evItem: item,
                        options: {
                            index: nameAndPos.index
                        }
                    }
                });
            } else {
                evFilter = [];
            }
        } else {
            evFilter = ctrl._auditor.rules;
        }
    } else if ($.type(args) == "function") {
        let result = this._ev.filter(args);
        if (result && result.length) {
            evFilter = _.map(result, (item) => {
                return {
                    evItem: item,
                    options: {
                        index: undefined
                    }
                }
            });
        } else {
            evFilter = [];
        }
    } else {
        evFilter = args;
    }
    return evFilter;
}

function isControl(obj) {
    if (obj) {
        return ('element' in obj) && ('ctrl_type' in obj)
    } else {
        return false;
    }
}

//将规则缓存到组件内部，下次再次验证时，不再重新查找规则
function createRuleToControl(args, evItem) {
    let control;
    if (isControl(args)) {
        control = args;
    } else if ($.type(args) == "string") {
        control = page.getControl(args);
    }
    if (control) {
        if (!control._auditor) {
            control._auditor = {
                rules: [],
                id: dsf.uuid()
            }
        }
        let index = _.findIndex(control._auditor.rules, (rule) => {
            return rule.evItem.key == evItem.key
        });
        if (index < 0) {
            let rule = {
                evItem: evItem,
                options: {}
            }
            Object.defineProperty(rule.options, "index", {
                get() {
                    return dsf.Dom.getRowIndexByContrl(control)
                },
                enumerable: true,
                configurable: true
            });
            control._auditor.rules.push(rule);
        }
    }
}

//获取组件名称及组件所在子表的行，如果不在子表中index为undefind
function getControlNameAndPos(ctrl) {
    if (ctrl) {
        let index = undefined;
        let ctrlCaption = ctrl.caption;
        if (ctrl.scopeControl == ctrl.root) {
            ctrlCaption = "@" + ctrlCaption;
        } else {
            //获取控件的名称
            ctrlCaption = dsf.Dom.getControlSimpleCaption(ctrl)
                //获取控件数据所在子表的行
            index = dsf.Dom.getRowIndexByContrl(ctrl)
        }
        return {
            caption: ctrlCaption,
            index: index
        }
    }
    return null;

}

function getRelControls(evItem, index) {
    let controls = [];
    for (let i = 0; i < evItem.rel.length; i++) {
        let ctrl = getControl(evItem.rel[i], evItem.scope || "", index);
        controls.push(ctrl);
    }
    return controls;
}

//将执行结果写入到组件的value属性中
function execResultHanlder(showError) {
    let arr = [];
    // total = {};
    let oldArr = JSON.parse(this.$value.detail || "[]");
    this.$value.num0 = 0;
    this.$value.num1 = 0;

    //逻辑审核结果处理
    if (this._evResult && this._evResult.length >= 0) {
        let errorResult = [];
        let successResult = [];
        //先置空结果相关组件的审核错误信息,并将审核规则与组件绑定
        _.each(this._evResult, (ev) => {
            _.each(ev.rel, (rel) => {
                let scopeControl = ev.scope.control;
                let ctrl = getControl(rel, (scopeControl == page ? '' : scopeControl.caption), ev.index);
                let evItem = this._ev.filter((item) => item.key == ev.key);
                if (evItem && evItem.length) {
                    evItem = evItem[0];
                    createRuleToControl(ctrl, evItem);
                }
                if (ev.result) {
                    let err = {
                        "id": ev.key,
                        "errorMsg": ""
                    }
                    try {
                        ctrl.removeError(err, 'audit');
                        ctrl.validateError()
                    } catch (ex) {
                        dsf.error(ctrl.caption + "未找到removeError函数或validateError函数")
                    }
                }
            })
            if (!ev.result) {
                errorResult.push(ev);
            }
        });

        //将审核错误的信息生成到列表中去
        _.each(errorResult, ev => {
            let obj = {
                "key": ev.key,
                "errorMsg": ev.errorMsg,
                "remark": "",
                "level": ev.level,
                "index": dsf.isDef(ev.index) ? ev.index : undefined,
                "updateUserName": "",
                "updateUserId": ""
            };
            //如果是警告，且用户已经填写过备注则继承备注,修改人，修改人ID
            if (oldArr && obj.level == "0") {
                let oldErr = _.find(oldArr, o => o.key == obj.key);
                if (oldErr) {
                    obj.remark = oldErr.remark;
                    obj.userName = oldErr.userName; // window.decodeURI(dsf.getCookie("user_name") || "");
                    obj.userId = oldErr.userId; // dsf.getCookie("user_id") || "";
                }
            };
            //统计警告和错误的数量
            if (this.value["num" + ev.level] == undefined) {
                this.value["num" + ev.level] = 0;
            };
            this.value["num" + ev.level]++;
            arr.push(obj);
        });

    }
    //将错误信息的数组转换成JSON存放
    this.value.detail = JSON.stringify(arr);
    if (arr.length > 0) {
        if (this.value.num1 > 0) {
            //存在错误项就是审核不通过
            this.value.state = -1;
        } else {
            if (this.value.num0 > 0 && this.$requireRemark) {
                let isRemark_null = _.filter(arr, o => o.remark == "");
                //查找是否有没有填写备注的警告项目
                isRemark_null.length > 0 ? this.value.state = -1 : this.value.state = 1;
            } else {
                this.value.state = 1;
            }
        }
        this.showErrorIcon();
    } else {
        this.value.state = 1;
        this.hideErrorIcon();
    }
}

function getControl(caption, scope, i) {
    if (caption.startsWith("@")) {
        return page.getControl(caption.substr(1));
    } else {
        if (!scope) {
            return page.getControl(caption);
        } else {
            return page.getControl(scope + "_" + i + "_" + caption);
        }
    }
}

function subrowdelete(args) {
    if (args.type != "addNew") {
        this.updateAduitResult()
    }
}

function clearAuditError(ctrl) {
    if (ctrl._errors) {
        for (let i = ctrl._errors.length - 1; i >= 0; i--) {
            let err = ctrl._errors[i];
            if (err.type == "audit") {
                ctrl._errors.splice(i, 1);
            }
        }
    }

}