const dom = require("../../templates/DateIntervalPicker.ejs");
import { FormControl } from '../../../../baseControls'
import { DateIntervalMetaData } from '../../../../core/metadata'
import { isSupportDataPost } from '../../../../core/postDecorator';

import {map} from  '../../../../decorator/controlmap';

@map('日期区间','dsf.dateintervalpicker','DateIntervalPicker')

@isSupportDataPost(true)
export class DateIntervalPicker extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$showLabel = true;
        this.$showBottom = true;
        this.$timeFormat = '1';
        this.$metadata = DateIntervalMetaData.call(this);
        this.$chooseType = "2";
        this.chooseTypeDir={
            1:'year',
            2:'date',
            3:'month',
            4:'datetime'
        }
        this.$value = { edate: "", sdate: "" };
        this.count = null;
        this.lable = "日期区间选择";
        this.$hourStep = "10"//显示小时步长
        this.completionTime = "00:00:00"
    }

    set value(val) {
        this.$value = val;
        let timeFormat = this.timeFormat.toLowerCase()
        if (this._handlers.readonlyBlock) {
            this._handlers.readonlyBlock.text(this.getTextString("至"));
        }
        if (val) {
            if (this.$chooseType == (dsf.isNaN(this.$chooseType *1 )?'datetime':'4')) {
                timeFormat = timeFormat + ' hh:ii'
            }
            if (this._handlers["starttime-picker"]) {
                if (val.sdate) {
                    this._handlers["starttime-picker"][0].value = dsf.date.format(val.sdate, timeFormat)
                }
                if (val.edate) {
                    if (new Date(val.sdate.replace(new RegExp(/-/gm) ,"/")) <= new Date(val.edate.replace(new RegExp(/-/gm) ,"/"))) {
                        this._handlers["endtime-picker"][0].value = dsf.date.format(val.edate, timeFormat)
                    } else {
                        this._handlers["endtime-picker"][0].value = ""
                    }
                }
            }
        }
       
    }
    get value() {
        return this.$value;
    }
    set label(value) {
        this.$label = value;
    }
    get label() {
        return this.$label;
    }

    get timeFormat() {
        let formatDir = {
            1: 'yyyy-MM-dd',
            2: 'yyyy年MM月dd日',
            3: 'yyyy年MM月',
            4: 'M月d日'
        }
        let format = formatDir[this.$timeFormat]
        return format
    }

    set showLabel(value) {
        this.$showLabel = value;
        if (!value) {
            this.addClass("hideLabel")
        } else {
            this.removeClass("hideLabel")
        }
    }
    get showLabel() {
        return this.$showLabel;
    }

    get defaultStarttime() {
        let d = new Date();
        let month = null;
        let date = d.getDate();

        if (parseInt(d.getMonth()) < 9) {
            month = "0" + parseInt(d.getMonth() + 1)
        } else {
            month = parseInt(d.getMonth() + 1)
        }

        if (parseInt(d.getDate()) < 9) {
            date = "0" + parseInt(d.getDate())
        }

        if (this.$chooseType == (dsf.isNaN(this.$chooseType *1 )?'month':'3')) {
            this.$showBottom = true;
            if (this.$timeFormat == 2 || this.$timeFormat == 4) {
                this.$timeFormat = 3;
            }
            this.$defaultStarttime = d.getFullYear() + '-' + month
        } else {
            this.$defaultStarttime = d.getFullYear() + '-' + month + '-' + date;
        }
        return this.$defaultStarttime
    }



    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
    }

    renderContext() {
        super.renderContext();
        // this.completionTime='00:00:00'
        if(this._toolRight && this._toolRight.find('.isShowTime')){
            this._toolRight.find('.isShowTime>input').val(this.completionTime)
        }
       
        if (this._handlers.label) {
            this._handlers.label.html(this.$label)
        }
        if (this._handlers['starttime-picker']) {
            if (this.readOnly) {
                $(this._handlers['starttime-picker'][0]).attr("disabled", 'disabled')
                $(this._handlers['endtime-picker'][0]).attr("disabled", 'disabled')
            } else {
                $(this._handlers['starttime-picker'][0]).removeAttr("disabled");
                $(this._handlers['endtime-picker'][0]).removeAttr("disabled");
                this._handlers['starttime-picker'][0].value= getFormatDateVal.call(this, this.value.sdate, this.timeFormat)
                this._handlers['endtime-picker'][0].value= getFormatDateVal.call(this, this.value.edate, this.timeFormat)
            }
        }
    }
    initEvent() {
        let _this = this; 
        changeDateTimeStyle.call(_this)//“日期时间”类型时，修改时间样式，根据定时器找到dom
        var d = "", year = "", month = "", hours = "", minutes = "", seconds = "";
        if (!_this.$metadata.defaultValue) _this.$metadata.defaultValue = _this.defaultStarttime
        if (!this.readOnly) {
            console.log(_this.value.sdate)
            let format_sd = getFormatDateVal.call(_this, _this.value.sdate, _this.timeFormat)
            var sdate = layui.laydate.render({
                elem: '#s_' + _this.id,
                value: format_sd,
                isInitValue: true,
                type:dsf.isNaN(_this.$chooseType *1 )?_this.$chooseType: _this.chooseTypeDir[_this.$chooseType],
                calendar: _this.$calendar,
                showBottom: _this.$showBottom,
                trigger: 'click',
                format: (dsf.isNaN(_this.$chooseType *1 )?_this.$chooseType: _this.chooseTypeDir[_this.$chooseType]) == 'datetime' ? _this.timeFormat + ' HH:mm' : _this.timeFormat,
                position: 'fixed',
                ready: function (date) {
                    d = new Date(date.year, date.month, 0)
                    console.log(d.getDate()); //得到初始的日期时间对象：{year: 2017, month: 8, date: 18, hours: 0, minutes: 0, seconds: 0}；
                    changeDateTimeStyle.call(_this)
                },

                done: function (value, date) {
                    if (!$.isEmptyObject(date)) {
                        let time = '';
                        
                        // if(_this.$chooseType== (dsf.isNaN(_this.$chooseType *1 )?'datetime':'4') && _this.completionTime!=='00:00:00'){
                        //     time = _this.completionTime
                        // }else{
                            date.month = timestrformat(date.month)
                            date.date = timestrformat(date.date)
                            date.hours = timestrformat(date.hours)
                            date.minutes = timestrformat(date.minutes)
                            time = date.hours + ":" + date.minutes + ":00"
                        // }
                        
                        _this.value.sdate = date.year + '-' + date.month + '-' + date.date + " " + time
                        if (_this.value.edate && _this.value.sdate) {
                            if (new Date(value.replace(new RegExp(/-/gm) ,"/")) > new Date(_this.value.edate.replace(new RegExp(/-/gm) ,"/"))) {
                              setTimeout(()=>{
                                $('#e_' + _this.id).val("");
                              },300)  
                              
                                _this.value.edate = ""
                            }
                            if(_this.$chooseType == (dsf.isNaN(_this.$chooseType *1 )?'datetime':'4')){
                                window.clearInterval(_this.count)
                            }
                           
                        }
                    }else{
                        _this.value.sdate= value
                    }
                    _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                    _this.commitAudit();
                }
            });
            let format_ed = getFormatDateVal.call(_this,_this.value.edate, _this.timeFormat)

            var edate = layui.laydate.render({
                elem: '#e_' + _this.id,
                value: format_ed,
                isInitValue: true,
                type: (dsf.isNaN(_this.$chooseType *1 )?_this.$chooseType: _this.chooseTypeDir[_this.$chooseType]),
                calendar: _this.$calendar,
                showBottom: _this.$showBottom,
                format: (dsf.isNaN(_this.$chooseType *1 )?_this.$chooseType: _this.chooseTypeDir[_this.$chooseType]) == 'datetime' ? _this.timeFormat + ' HH:mm' : _this.timeFormat,
                position: 'fixed',
                ready: function (date) {
                    year = date.year;
                    month = date.month;
                    hours = date.hours;
                    minutes = date.minutes;
                    seconds = date.seconds
                    d = new Date(date.year, date.month, 0).getDate()
                    console.log(d); //得到初始的日期时间对象：{year: 2017, month: 8, date: 18, hours: 0, minutes: 0, seconds: 0}
                    changeDateTimeStyle.call(_this)
                },
                done: function (value, date) {
                    if (!$.isEmptyObject(date)) {
                        // date.month = timestrformat(date.month)
                        // date.date = timestrformat(date.date)
                        // date.hours = timestrformat(date.hours)
                        // date.minutes = timestrformat(date.minutes)
                        // _this.value.edate = date.year + '-' + date.month + '-' + date.date + " " + date.hours + ":" + date.minutes + ":00";
                        let time = '';
                        if(_this.$chooseType!=(dsf.isNaN(_this.$chooseType *1 )?'datetime':'4') && _this.completionTime!=='00:00:00'){
                            time = _this.completionTime
                        }else{
                            date.hours = timestrformat(date.hours)
                            date.minutes = timestrformat(date.minutes)
                            time = date.hours + ":" + date.minutes + ":00"
                        }
                        date.month = timestrformat(date.month)
                        date.date = timestrformat(date.date)
                        _this.value.edate = date.year + '-' + date.month + '-' + date.date + " " + time
                        
                        _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                        if (_this.value.sdate) {
                            if (new Date(_this.value.sdate.replace(new RegExp(/-/gm) ,"/")) > new Date(value.replace(new RegExp(/-/gm) ,"/"))) {
                                dsf.layer.message("结束时间不能小于开始时间")
                                setTimeout(()=>{
                                  $('#e_' + _this.id).val("");
                                },300)
                               
                                _this.value.edate = ""
                            }
                            if(_this.$chooseType == (dsf.isNaN(_this.$chooseType *1 )?'datetime':'4')){
                                window.clearInterval(_this.count)
                            }
                            return ;
                        }
                    }else{
                        _this.value.edate = value;
                    }
                    _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                    _this.commitAudit();
                }
            });
        }
    }
    renderReady() {
        super.renderReady();
    }
    getTextString() {   
        let str = '';
        let sdate = "";
        let edate = "";
        let sday = "";
        let eday = "";
        let timeFormat = this.timeFormat.toLowerCase()

        if (this.value.sdate) {
            sdate = this.value.sdate;
            edate = this.value.edate;
            if (this.$chooseType == (dsf.isNaN(this.$chooseType *1 )?'datetime':'4')) {
                sday = new Date(sdate.split(" ")[0]);
                eday = new Date(edate.split(" ")[0]);
            }
            sdate = getFormatDateVal.call(this,sdate,timeFormat);
            edate = getFormatDateVal.call(this,edate,timeFormat);
            if (sday) {
                if (!(sday > eday || sday < eday)) {
                    str = sdate.split(" ")[0] + " " + sdate.split(" ")[1] + " 至 " + edate.split(" ")[1];
                } else {
                    str = sdate + " 至 " + edate
                }
            } else {
                str = sdate + " 至 " + edate
            }
        }
        return str
    }
    setControlId() {
        return this.id
    }
}
function timestrformat(n) {
    n = n.toString();
    return n[1] ? n : '0' + n
}
function getFormatDateVal(d,timeFormat){
    let _timeFormat = timeFormat.toLowerCase();
    if (this.$chooseType == (dsf.isNaN(this.$chooseType *1 )?'datetime':'4')) {
        _timeFormat = _timeFormat + ' hh:ii';
    }
    if(d){
        return dsf.date.format(d, _timeFormat)
    }
    return d
}
function changeDateTimeStyle(){
    let _this = this;
    if(_this.$chooseType == (dsf.isNaN(_this.$chooseType *1 )?'datetime':'4')){
        if (this.$timeInter) {
            let timeInterval = this.$timeInter
            var minHour = $.trim(timeInterval.split("-")[0])
            var maxHour = $.trim(timeInterval.split("-")[1]) 
        }
        _this.count = window.setInterval(function(){
            if($("body").find(".laydate-time-show").length>0){
                // console.log(count)
                var showtime = $($(".laydate-time-list li ol")[1]).find("li");
                var showhour = $($(".laydate-time-list li ol")[0]).find("li")
                for (var i = 0; i < showtime.length; i++) {
                    var t00 = parseInt(showtime[i].innerText);
                    var step = parseInt(_this.$hourStep)
                    if (t00 % step != 0) {
                        showtime[i].remove()
                    }
                }
                for(var k=0;k<showhour.length;k++){
                    var h00 = parseInt(showhour[k].innerText);
                    minHour = parseInt(minHour);
                    maxHour= parseInt(maxHour);
                    if(h00<minHour || h00>maxHour){
                        // showhour[k].remove()
                        $(showhour[k]).css({"pointer-events":"none","color":"#ddd"})
                    }
                }
                $($(".laydate-time-list li ol")[2]).find("li").remove();  //清空秒
            }
        },800)
    }
}