function addToTable(index, row, addToValue) {
  // console.time("添加行到表格")
  let _this = this;
  let data = row._data;
  if (data && data[this.dataKey]) {
    //如果新的值有主键并且在删除数组中存在从删除数组中清除掉
    if (this._deleteData[data[this.dataKey]]) {
      delete this._deleteData[data[this.dataKey]];
    }
  }
  if (index == undefined || index == null) {
    this.rows.push(row);
    if (addToValue != false) {
      this.value.push(data);
    }
    index = this.rows.length;
  } else if (index >= 0) {
    this.rows.splice(index, 0, row);
    if (addToValue != false) {
      this.value.splice(index, 0, data);
    }
  }
  // console.time("添加到表格")
  if (this.rows[index + 1]) {
    let childIndex = this.children.indexOf(this.rows[index + 1]);
    this.addChild(row, childIndex, "tbody");
  } else {
    this.addChild(row, null, "tbody");
  }
  //将额外按钮加入row
  let td = row.element.find(".ds_sub_table_row_tools");
  let div = td.find(".extra-btn-box").eq(0);
  let buttons = ButtonPlugin.renderButtons(this, div, this.$rowbuttonBar, row._data, "row", "small");
  buttons.addClass("nowrap");
  // div.parent().css("text-align", this.$operateColumn.bodyAilgn);
  div.parent().attr("align", this.$operateColumn.bodyAilgn);
  div.parent().css("text-align","initial");
  // console.timeEnd("添加到表格")
  row.element.attr("data", 1);
  let filter = "check_" + row._data[dsf.hashKey];
  let firstCell = row.element.get(0).childNodes[0];
  let checkbox = firstCell.childNodes[0];
  checkbox.value = row._data[dsf.hashKey];
  $(checkbox).attr("lay-filter", filter);

  // let checkbox = row.element.children(".ds_subtable_check_cell ").find("INPUT[type=checkbox]").attr("lay-filter", filter).val(row._data[dsf.hashKey]);
  if (row._data.$$checked) {
    checkbox.setAttribute("checked", true);
  }
  this.refreshRowIndex(() => {
    this.event.trigger(SubTableEvent.VALUECHANGE, {
      ui: this,
      data: data,
      type: "addNew",
    });
    this.event.trigger(SubTableEvent.ADDROW, {
      rowId: row.id,
      index: index,
      data: data,
      ui: row,
    });
  });

  dsf.UI.render("checkbox", true);
  layui.form.on("checkbox(" + filter + ")", function(data) {
    watchCheckBox.call(_this);
    row._data["$$checked"] = data.elem.checked;
    _this.event.trigger(SubTableEvent.CHECKROW, {
      data: _this.getCheckedData(),
      ui: _this,
    });
  });
}

function exchangeRow(index, newIndex) {
  let _this = this;
  let cRow = this.rows[index];
  let newRow = this.rows[newIndex];

  this.rows[index] = newRow;
  this.rows[newIndex] = cRow;
  this.rows[index].index = index;
  this.rows[newIndex].index = newIndex;
  // this.rows[index].element.attr("row-index", this.rows[index].index);
  // this.rows[newIndex].element.attr("row-index", this.rows[newIndex].index);

  this.children[index] = this.rows[index];
  this.children[newIndex] = this.rows[newIndex];

  this.value[index] = this.rows[index]._data;
  this.value[newIndex] = this.rows[newIndex]._data;

  let newPos = newRow.element.index();
  let oldPos = cRow.element.index();
  // oldPos.insertBefore(newRow.element);
  // newPos.insertBefore(cRow.element);
  let tbody = newRow.element.parent();
  let newPosElement = tbody.children("tr:eq(" + newPos + ")");
  cRow.element.insertBefore(newPosElement);
  let oldPoElement = tbody.children("tr:eq(" + oldPos + ")");
  newRow.element.insertBefore(oldPoElement);
  this.refreshRowIndex(function() {
    _this.event.trigger(SubTableEvent.VALUECHANGE, {
      ui: this,
      type: "exchange",
      data: [cRow, newRow],
    });
  });
}

function readArrayData(rows, isAppend) {
  let _this = this;
  if (!_this.readOnly) {
    if (isAppend == false) {
      let rowIndex = _this._editorRow;
      for (let i = 0; i < rows.length; i++) {
        let rowCtrl = null;
        if (i == 0) {
          rowCtrl = _this.rows[rowIndex];
        } else {
          if (_this.rows[rowIndex]) {
            rowCtrl = _this.rows[rowIndex];
          } else {
            rowCtrl = _this.addRow(rowIndex, {});
          }
          _this.beginEditor(rowIndex);
        }
        let index = 0;
        rowCtrl.ControlsForEach(function(v) {
          if (v.isPostSupport == true) {
            if (!v.disabled && !v.readOnly) {
              v.value = rows[i][index];
              index++;
            }
          }
        }, false);
        rowIndex++;
      }
      _this.endEditor();
    } else {
      let rowIndex = this.value.length;
      for (let i = 0; i < rows.length; i++) {
        let rowCtrl = null;
        rowCtrl = _this.addRow(rowIndex, {});
        _this.beginEditor(rowIndex);
        let index = 0;
        rowCtrl.ControlsForEach(function(v) {
          if (v.isPostSupport == true) {
            if (!v.disabled && !v.readOnly) {
              v.value = rows[i][index];
              index++;
            }
          }
        }, false);
        _this.endEditor();
        rowIndex++;
      }
    }
    _this.reload();
  }
}

function showErrorRow(rowIndex, error) {
  if (this.rows[rowIndex] && error) {
    let row = this.rows[rowIndex];
    row.element.addClass("ds_row_error");
    let errorrow = this.element.find("tr[target_row_id='" + row.id + "']");
    let colspan = row.element.children("TD:visible").length;
    if (errorrow.length <= 0) {
      let tr = $(
        "<tr class='error_row' target_row_id='" +
          row.id +
          "'><td class='ds_sub_table_cell' colspan='" +
          colspan +
          "'><div>" +
          error.errorMsg +
          "</div></td></tr>"
      );
      row.element.after(tr);
    } else {
      errorrow
        .find(".ds_sub_table_cell")
        .children("div")
        .html(error.errorMsg);
    }
  }
}

function hiddenErrorRow(rowIndex) {
  if (this.rows[rowIndex]) {
    let row = this.rows[rowIndex];
    row.element.removeClass("ds_row_error");
    let errorrow = this.element.find("tr[target_row_id='" + row.id + "']");
    if (errorrow.length > 0) {
      errorrow.remove();
    }
  }
}

