const dom = require("../../templates/UploadThirdFile.ejs");
import {
  FormControl
} from '../../../../baseControls'
import {
  fileMetaData
} from '../../../../core/metadata';
import {
  isSupportDataPost
} from '../../../../core/postDecorator';

import {
  map
} from '../../../../decorator/controlmap';

import * as wangsu from 'wcs-js-sdk'; // 文档地址 https://github.com/Wangsu-Cloud-Storage/wcs-js-sdk

@map('第三方文件上传', 'dsf.uploadthirdfile', 'UploadThirdFile')
@isSupportDataPost(true)
export class UploadThirdFile extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$btnName = "文件上传"; //按钮内部文字
    this.$showBtnName = true; //是否显示按钮内部文字
    this.label = "文件上传"
    this.$showLabel = true; //是否显示按钮标签
    this.$multiple = true; //是否支持多张上传
    this.$metadata = fileMetaData.call(this, 500);
    this.multipleFiles = []; //上传文件数组
    this.$uploadFileNum = "2" //允许上传文件数量
    this.isdeltbn = false; //是否点击删除
    this.$maxFileSize = ""; //允许上传文件大小
    this.$isShowDownloadBtn = true;
    this.$zipFileName = ""; //打包文件名
    this.hasSameName = true;
    this.$error_tipsPosition = "right";

    this.$uploadFileType = 'file'; //默认上传类型
    this.$uploadFileExts = "" //允许上传后缀名
    this.$acceptMime = "" //弹窗筛选条件MiMe类型
    this.$isDragable = false;
    this._flowUploadClass = 'ds_disposeIdea_uploadFile';
    this.requestUrl = "";
    this.backUrl = "";
    this.preview = true;
    this.token = "";
    this.askUrl = "";
    this.percent = 0;
    this.hasUpload = 0;
    this.failed = 0;
  }

  set btnName(value) {
    this.$btnName = value
  }

  get btnName() {
    return this.$btnName
  }
  set isDragable(value) {
    this.$isDragable = value;
    if (this._isRender) {
      this.render();
    }
  }

  get isDragable() {
    return this.$isDragable
  }

  set showBtnName(value) {
    this.$showBtnName = value
    if (!value) {
      this.addClass("hideName")
    } else {
      this.removeClass("hideName")
    }
  }
  get showBtnName() {
    return this.$showBtnName
  }
  set value(val) {
    super.value = val;
    !val && (val = '');
    if (val !== '' && dsf.isDef(val) && typeof val === 'string') {
      val = JSON.parse(val);
      this.multipleFiles = val;
    } else {
      this.multipleFiles = [];
    }
    if ($.isArray(val)) {
      if (this._handlers.uploadMainBtn) {
        if (val.length == 0) {
          if (this.notDisposeIdea()) {
            this.element.find(".uploadMainBtn").show();
          }
          return;
        } else {
          if (this.element.find(".fileContainer")) {
            this.element.find(".fileContainer").remove();
          }
          this.createFileBox(val)
        }
      }
      if (this._handlers.readonlyBlock) {
        if (this.element.find(".fileContainer")) {
          this.element.find(".fileContainer").remove()
        }
        this.getTextString()
      }
      if (this.visible && this.$multiple && this.notDisposeIdea()) {
        this.createDownLoadBtn()
      }
      this.btnBindFn()
    }

  }
  get value() {
    return super.value
  }

  initTemplate() {
    return dom(this);
  }
  createElement() {
    super.createElement();
  }
  // 判断上传的视频是否切片
  videoIsCut(fileId) {
    let url = dsf.url.getAbsolutePath('/slice/video');
    let isCut = null;
    dsf.http.request_sync(url + '/' + fileId, {}, "GET")
      .done(function (result) {
        if (result.success) {
          // 获取标清切片文件
          let sdName = result.data.sd.name;
          let suffixIdx = sdName.lastIndexOf('.');
          let suffix = sdName.substring(suffixIdx + 1); //后缀
          if (suffix.toLowerCase() != 'm3u8') { //不等于m3u8,则表示后台自动切片失败
            isCut = false
          } else {
            isCut = true
          }
        }
        return isCut
      })
      .error(function () { })
      .exec();
    return isCut
  }

  renderContext() {
    super.renderContext();
    if (this._handlers.btnName) {
      this._handlers.btnName.html(this.btnName);
    }
    if (this._handlers.label) {
      this._handlers.label.html(this.$label);
    }

    if (this.$uploadFileNum == 1) {
      this.$multiple = false;
    }

    if (this.backUrl) {
      let reg = /(^[\/\\].*)|(.*:.*)/;
      if (!reg.test(this.backUrl)) {
        this.backUrl = dsf.url.getWebPath(this.backUrl)
      }
    } else {
      this.backUrl = dsf.url.getWebPath('ncFile/backFileUpload')
    }
  }
  initEvent() {
    rebuildDialogData.call(this)
    this.initUploader("#fil_uf_" + this.id);
    return;
  }
  initUploader(dom, reloadId) {
    var _this = this;
    $(".uploadfileBtn").on("change", dom, function () {
      if ($(this).val() == '') {//如果没有选择文件则不触发
        return false;
      }
      let files = this.files; //将每次选择的文件追加到文件队列
      if (!_this.$multiple && files.length > 1) {
        dsf.layer.message("最多只能上传一份文件", false);
        $(this).val('');//操作结束清空input中的内容
        return false
      }
      if (_this.$uploadFileNum == "0") {
        _this.$uploadFileNum = 1000000;
      }
      if (_this.$multiple && files.length > _this.$uploadFileNum) {
        dsf.layer.message(`同时最多只能上传的数量为：${_this.$uploadFileNum}`, false);
        $(this).val('');//操作结束清空input中的内容
        return false
      }
      _this.hasSameName = false; //是否有重名
      let repeateName = ""
      //上传的文件与已上传的文件名对比
      _.forEach(_this.multipleFiles, function (val, index) {
        for (var key in files) {
          if (val.originalFileName == files[key].name) {
            _this.hasSameName = true;
            repeateName += files[key].name + " ";
          }
        }
      })
      if (_this.hasSameName) {
        dsf.layer.message("已存在文件" + repeateName + "，请修改后重新上传", false);
        layer.closeAll('loading');
        $(this).val('');
        return false;
      }
      const allLength = files.length;
      _this.hasUpload = 0;
      _this.failed = 0;
      let allfiles = {}
      Array.from(files).forEach(file => {
        let fileNameStr = file.name;
        let fileSuffixIndex = fileNameStr.lastIndexOf('.');
        let suffix = fileNameStr.substring(fileSuffixIndex + 1, fileNameStr.length);
        suffix = suffix.toLowerCase();
        if (!$.isEmptyObject(_this.$extsSetting) && _this.$uploadFileExts.indexOf(suffix) < 0) {
          // 选择文件中包含不支持的文件格式
          if (_this.$uploadFileExts.split("|").length >= 3) {
            dsf.layer.alert("选择文件中包含不支持的文件格式,请选择包含这些格式的文件：" + _this.$uploadFileExts.split('|').join(','), {
              icon: 5
            }, function (index) {
              dsf.layer.close(index);
            })
          } else {
            dsf.layer.message("选择文件中包含不支持的文件格式,请选择包含这些格式的文件：" + _this.$uploadFileExts.split('|').join(','), false);
          }
          $(this).val('');
          return false
        }
        const uuid = dsf.uuid(32).toLocaleLowerCase();
        const obj = {
          uuid: uuid,
          suffix: suffix,
          date: dsf.date.format(new Date(), 'yyyymmdd'),
        }
        obj.relativePath = `files/${obj.date}/${obj.uuid}.${suffix}`;
        dsf.http.request(dsf.url.getWebPath("ncFile/getFileUploadToken"), {
          ossFileDir: obj.relativePath
        }, 'POST')
          .done((res) => {
            if (res.success) {
              Object.assign(obj, res.data)
              _this.initFile(file, allLength, obj, reloadId, allfiles);
            }
          })
          .error(() => { })
          .exec();
        // _this.initFile(file, allLength, reloadId);
      });
      $(this).val('');//操作结束清空input中的内容
    });
  }
  initFile(file, allLength, obj, reloadId, allfiles) {
    var token = obj.token;
    if (token == null) {
      dsf.layer.message("服务器获取token异常", false);
      return;
    }

    var uploadUrl = obj.address;
    var extraConfig = {
      timeout: 0, // 超时时间, 默认为0 超时错误可以重试上传
      concurrentRequestLimit: 6, //并发数,默认为3。注：浏览器对连接的请求资源是有限的, 比如Chrome的请求资源是6, 所以会有这样的情况, 如果并发数写10, 虽然发起了10个请求, 但是只有6个真正在上传
      retryCount: 10 //上传重试, 默认为0
      // key: key //选填，用于指定文件上传至云存储的名称，注：token中指定的key优先级较高
      // mimeType: mimeType //选填，自定义文件的MIME-Type
      // deadline: deadline //选填，文件保存期限。超过保存天数文件自动删除,单位：天。例如：1、2、3
    };
    var uploadObj = wangsu.wcsUpload(file, token, uploadUrl, extraConfig);
    allfiles[file.id] = 0;
    var _this = this;
    uploadObj.uploadProgress = function (progress) {
      console.log(allfiles);
      allfiles[file.id] = parseInt(progress.total.percent);
      const length = Object.keys(allfiles).length;
      const allPercent = Object.values(allfiles).reduce((a, b) => a + b);
      _this.percent = parseInt(allPercent / length);
      layui.use("element", function () {
        var element = layui.element;
        element.progress(`percent_${_this.id}`, _this.percent + '%');
        $(`[lay-filter=percent_${_this.id}]`).css("display", "block");
        if (_this.percent >= 100) {
          setTimeout(() => {
            $(`[lay-filter=percent_${_this.id}]`).css("display", "none");
          }, 200)
        }
      });
    };

    uploadObj.onError = function (error) {
      if (_this.$uploadFileNum == 1) {
        _this.multipleFiles = [];
      }
      _this.failed++;
      dsf.layer.message(res.message, false);
      allComplete();
    };

    uploadObj.onComplete = function (res) {
      const realFile = {
        absolutePath: obj.askUrl + '/' + obj.relativePath,
        contentType: file.type,
        id: obj.uuid,
        isCutSuccess: false,
        name: file.name.replace(`.${obj.suffix}`, ""),
        originalFileName: file.name,
        relativePath: '/' + obj.relativePath,
        size: file.size,
        success: true,
        suffix: obj.suffix,
        uploadDate: dsf.date.format(new Date(), 'yyyy-mm-dd hh:ii:ss'),
      }
      _this.isdeltbn = false;
      if (reloadId) {
        let index = _this.multipleFiles.findIndex(item => item.id === reloadId);
        _this.multipleFiles.splice(index, 1, realFile)
      } else {
        _this.multipleFiles.push(realFile);
      }
      _this.value = JSON.stringify(_this.multipleFiles);
      _this.event.trigger(FormControlEvent.VALUECHANGE, {
        ui: _this
      });
      _this.hasUpload++;
      allComplete();
    };

    const allComplete = function () {
      if (_this.hasUpload + _this.failed === allLength) {
        //上传失败的文件数量
        if (_this.failed > 0) {
          if (_this.failed == _allLength) { // 如果 上传失败的文件数量 == 上传文件的数量 则不显示全部下载按钮
            _this.$isShowDownloadBtn = false;
            dsf.layer.message("上传失败", false);
            return
          }
          dsf.layer.message("有" + _this.failed + "份文件上传失败", false);
          return;
        }
        if (_this.backUrl) {
          dsf.http.request(dsf.url.getWebPath(_this.backUrl), JSON.stringify({
            ossFileStr: _this.multipleFiles
          }), 'POST', "application/json; charset=utf-8")
            .done((res) => {
              if (res.success) {
                console.log(res);
              }
            }).error(() => { })
            .exec();
        }
      }
    }
    uploadObj.putFile(); // 开始上传
  }

  setControlId() {
    return this.id
  }
  getTextString() {
    let container = $('<table class="layui-table fileContainer mutiple" lay-skin="nob"><tbody></tbody></table>')
    if (this.value !== '' && dsf.isDef(this.value) && typeof this.value === 'string') {
      if (!this.isdeltbn && (!this.$multiple || this.$uploadFileNum == 1)) {
        container = $('<table class="layui-table fileContainer singleFile" lay-skin="nob"><tbody></tbody></table>')
        this.isdeltbn = false
      }
      var value = JSON.parse(this.value);//123
      if ($.isArray(value) && value.length > 0) {
        for (let i = 0; i < value.length; i++) {
          createUploadContent.call(this, container, value[i], value[i].id, i + 1)
        }
      }
      $('.mutiple').closest(".uploadfileBtn").css("padding-top", "38px");
      let readonlyHtml = $(container).prop("outerHTML");
      return readonlyHtml
    } else if (this.root._isDesign) {
      var tableStr = '<table class="layui-table fileContainer UploadFile readOnly" lay-skin="nob"></table>'
      return tableStr
    }
  }

  renderReady() {
    super.renderReady();
    if (this.element.find(".downLoad").length > 0) {
      let downLoadbtn = this.element.find(".downLoad");
      downLoadbtn.click(this, downLoadFn)
    }
    if (this.element.find(".previewBtn ").length > 0) {
      let previewBtn = this.element.find(".previewBtn");
      previewBtn.click(this, filePreviewFn)
    }
    $(`[lay-filter=percent_${this.id}]`).css("display", "none");
  }
  createDownLoadBtn() {
    let multipleDownBtn = ' <button class="layui-btn downLoadBtn" ds-event="downLoad">' +
      ' <span handler="btnName" ds-event="downLoad" class="btnName">' +
      ' 全部下载</span>' +
      '</button>'
    if (this.$isShowDownloadBtn && this.element) {
      this.element.find(".uploadbtn").append(multipleDownBtn)
    }
  }
  btnBindFn() {
    if (this.element) {
      if (!this.readOnly) {
        this.element.find(".delete").on("click", {
          obj: this
        }, deleteItem) //删除功能
        this.element.find(".edit").on("click", {
          obj: this
        }, editItem) //编辑名称功能
        this.element.find(".cutVedio").on("click", {
          obj: this
        }, cutFile) //视频剪切功能
      }
      let downloadBtn = this.element.find('.downLoadBtn')
      let previewBtn = this.element.find('.previewBtn')
      if (downloadBtn.length > 0) {
        downloadBtn.on("click", {
          obj: this
        }, downLoadFn)
      }
      previewBtn.length > 0 ? previewBtn.on("click", {
        obj: this
      }, filePreviewFn) : ""
      this.element.find(".moveup").on("click", moveupFn)
      this.element.find(".movedown").on("click", movedownFn)

      $(this.element.find(".moveFile")).data('data', this)
    }

  }
  createFileBox(val) {
    let container = '';
    let count = ""
    var item = $($(this).get(0)._element[0]).find(".item");
    if (item.length == 0) {
      container = $(' <table class="layui-table fileContainer" lay-skin="nob"><tbody></tbody></table>')
    } else {
      container = $($(this).get(0)._element[0]).find(".fileContainer")
    }

    if (!this.isdeltbn && (!this.$multiple || this.$uploadFileNum == 1)) {
      if (this.isDragable) {
        this.element.find('.uploadMainBtn').show();
      } else {
        this.element.find('.uploadMainBtn').hide();
      }
      container = $('<table class="layui-table fileContainer singleFile" lay-skin="nob"><tbody></tbody></table>')
      this.element.find(".uploadfileBtn").append(container)
      this.element.find('.downLoadBtn').hide()
      this.isdeltbn = false
    }

    // let isCutSuccess = true
    for (let i = 0; i < val.length; i++) {
      if (item.length > 0) {
        count = item.length
      } else {
        count = i
      }
      // let fileObj = val[i];
      // //给文件对象添加是否切片成功属性
      // if (fileObj.suffix.toLowerCase() == 'mp4') { //仅对后缀为MP4的文件进行切片处理
      //   isCutSuccess = this.videoIsCut(fileObj.id) //后台是否切片成功
      //   fileObj.isCutSuccess = isCutSuccess;
      // }

      createUploadContent.call(this, container, val[i], val[i].id, count + 1)
    }
  }

  validateInfo() {
    return {
      tipsElement: ".uploadMainBtn"
    }
  }

  notDisposeIdea() {
    return this.$classList.indexOf(this._flowUploadClass) == -1;
  }

}

function createUploadContent(container, file, id, count) {

  let filesize = computeFileSize(file.size)
  file.uploadDate = dsf.date.format(file.uploadDate, 'yyyy-mm-dd hh:ii')
  let fileType = file.suffix || file.type;
  let className = diffIcon(fileType)
  let html = '<tr id="' + id + '" class="item">' +
    ' <td  class="order" >' + count + '.</td>' +
    '<td class="textLeft filename_td" id="' + file.id + '">' +
    '<div class="fileName">' +
    '<b  class="icon midIcon ' + className + '"></b><span>' + file.name + '</span><span>.' + file.suffix +
    '</span></div>' +
    '</td>' +
    '<td class="fontpostion" >' + file.uploadDate + '</td>' +
    '<td class="blank fontpostion"width="100" >' + filesize + '</td>' +
    '<td class="operate fontpostion">' +
    '<span class="moveup iconfont moveFile" moveID ="' + id + '" title="上移">&#xe62f;</span>' +
    '<span class="movedown iconfont moveFile" moveID="' + id + '" title="下移">&#xe637;</span>' +
    '<span class="previewBtn iconfont " previewfileID ="' + id + '" title="预览">&#xeb8d;</span>' +
    '<span class="downLoad iconfont downLoadBtn" filename="' + file.name + '" downLoadkey="' + id +
    '" title="下载">&#xec22;</span>' +
    '<span class="delete iconfont" delkey="' + id + '" title="删除" >&#xe61b;</span>' +
    '<div class="upload-div">' +
    '<span class="reload iconfont" style="margin-left:7px;" title="重新上传">&#xec23;</span>' +
    '<input class="third-upload" type="file" id="reload_' + id + '" title="重新上传">' +
    '</div>' +
    '<span class="edit iconfont"  style="margin-left:7px;" delkey="' + id + '" title="修改名称">&#xe7e1;</span>' +
    '</td>' +
    '</tr>'

  $(container).append(html)
  if (this._element) {
    if (this.element.find(".fileContainer")) {
      this.element.find(".fileContainer").remove()
    }
    if (this.$multiple) {
      if (this.$uploadFileNum != 1) {
        this.element.find(".uploadfileBtn").append(container)
      }
    } else {
      this.element.find(".uploadfileBtn").append(container)
    }
    if (!this.preview) {
      $('.previewBtn').css('display', 'none')
    } else {
      $('.previewBtn').css('display', 'inline-block')
    }
  }




  // // 添加切片按钮
  // if (file.suffix.toLowerCase() == 'mp4') {
  //   if (file.isCutSuccess) {
  //     let str = '<span class="iconfont" style="margin-left:7px;"  cutID ="' + id + '" title="切片成功">&#xe670;</span>'
  //     $("#" + id).find('.operate').append(str)
  //   }
  //   //如果切片不成功
  //   if (!file.isCutSuccess) {
  //     //添加手动切片按钮
  //     let str = '<span class="iconfont cutVedio" style="margin-left:7px;"  cutID ="' + id + '" title="切片">&#xe671;</span>'
  //     $("#" + id).find('.operate').append(str)
  //   }
  // }



  if (this.element && this.element.find(".singleFile").length > 0) {
    this.element.find(".order").hide();
    $(".operate").find(".moveFile").remove()
  }
  if (this.readOnly) {
    $(".operate").find(".delete").remove()
    $(".operate").find(".moveFile").remove()
    $(".operate").find(".reload").remove()
    $(".operate").find(".edit").remove()
    $(".operate").find(".cutVedio").remove()
  }
  this.initUploader("#reload_" + id, id);
}
//编辑名称方法-现在只对class为._flowUploadClass的上传文件开放
function editItem(event) {
  let _this = event.data.obj;
  let _index = parseInt($(event.target).parent().siblings(".order").text()) - 1;
  layui.layer.open({
    title: '修改文件名称',
    content: '<form class="layui-form"><input value="' + _this.multipleFiles[_index].name +
      '" placeholder="请输入新的名称" class="layui-input"/></form>',
    yes: function (index, layero) {
      let val = layero.find('input').val();
      if (val) {
        _this.multipleFiles[_index].name = val;
        _this.value = JSON.stringify(_this.multipleFiles);
        layui.layer.close(index);
      } else {
        dsf.layer.message('名称不能为空', false);
      }
    }
  })
}
// 视频切片功能
function cutFile(event) {
  let _this = event.data.obj;
  let target = event.target;
  let fileId = $(target).attr('cutid')
  let url = dsf.url.getAbsolutePath('/slice/manual/video');
  dsf.http.request(url + '/' + fileId, {}, 'GET')
    .done((res) => {
      console.log(res)
      if (res.success) {
        $(target).html('&#xe670;')
        $(target).off('click') //切片成功后，解绑切片事件
      } else {
        dsf.layer.message('视频切片失败，请稍后再试', false)
      }
    }).error(() => { })
    .exec()
}

//单个删除方法
function deleteItem(event) {
  let _this = event.data.obj;
  let parentDom = _this.element
  _this.isdeltbn = true
  dsf.layer.confirm("确定要删除么?", () => {
    if (_this.$uploadFileNum == 1 && _this.notDisposeIdea()) {
      _this.multipleFiles = []
      $(parentDom).find(".uploadMainBtn").show()
      $(parentDom).find(".fileContainer").remove()
    } else {
      let index = parseInt($(this).parent().siblings(".order").text()) - 1;
      _this.multipleFiles.splice(index, 1)
      $(this).closest(".item").remove();
      if ($(parentDom).find(".fileContainer").find("tr").length == 0) {
        _this.element.find('.downLoadBtn').remove()
      }
    }
    _this.value = JSON.stringify(_this.multipleFiles)
  })
}
//文件预览
function filePreviewFn(event) {
  let target = event.target;
  let fileId = $(target).attr('previewfileID')
  let previewUrl = dsf.url.getWebPath('preview/file?fileId=' + fileId + '')
  window.open(previewUrl)
}
//获取配置上传文件格式

//绑定 单个文件重新上传按钮
function bindRelodBtn(id) {
  var _this = this;
  $(".uploadfileBtn").on("change", "#reload_" + id, function () {
    if ($(this).val() == '') {//如果没有选择文件则不触发
      return false;
    }
    let files = this.files;
    _this.hasSameName = false; //是否有重名
    let repeateName = ""
    //上传的文件与已上传的文件名对比
    _.forEach(_this.multipleFiles, function (val, index) {
      for (var key in files) {
        if (val.originalFileName == files[key].name) {
          _this.hasSameName = true;
          repeateName += files[key].name + " ";
        }
      }
    })
    if (_this.hasSameName) {
      dsf.layer.message("已存在文件" + repeateName + "，请修改后重新上传", false);
      layer.closeAll('loading');
      $(this).val('');
      return false;
    }
    const allLength = files.length;
    _this.hasUpload = 0;
    _this.failed = 0;
    Array.from(files).forEach(file => {
      let fileNameStr = file.name;
      let fileSuffixIndex = fileNameStr.lastIndexOf('.');
      let suffix = fileNameStr.substring(fileSuffixIndex + 1, fileNameStr.length);
      suffix = suffix.toLowerCase();
      if (!$.isEmptyObject(_this.$extsSetting) && _this.$uploadFileExts.indexOf(suffix) < 0) {
        // 选择文件中包含不支持的文件格式
        if (_this.$uploadFileExts.split("|").length >= 3) {
          dsf.layer.alert("选择文件中包含不支持的文件格式,请选择包含这些格式的文件：" + _this.$uploadFileExts.split('|').join(','), {
            icon: 5
          }, function (index) {
            dsf.layer.close(index);
          })
        } else {
          dsf.layer.message("选择文件中包含不支持的文件格式,请选择包含这些格式的文件：" + _this.$uploadFileExts.split('|').join(','), false);
        }
        $(this).val('');
        return false
      }
      _this.initFile(file, allLength, suffix, id);
    });
    $(this).val('');//操作结束清空input中的内容
  });
}
//全部下载方法
function downLoadFn(event) {
  let _this = null;
  let paramZipname = "";
  let paramID = "";
  if (event.data.obj) {
    _this = event.data.obj;
  } else {
    _this = event.data //只读时的数据
  }

  let singleFile = event.target;
  let downLoadkey = $(singleFile).attr('downLoadkey');
  let singlefileName = $(singleFile).attr('filename')

  let fileIds = []
  //单文件下载
  if (downLoadkey) {
    paramID = downLoadkey + "^" + singlefileName
  } else {
    //多文件下载
    for (let i = 0; i < _this.multipleFiles.length; i++) {
      let id = _this.multipleFiles[i].id;
      let name = _this.multipleFiles[i].name;
      let file = id + "^" + name
      fileIds.push(file);
    }
    paramID = fileIds.join(",")
  }
  if (fileIds.length > 0) {
    paramZipname = _this.$zipFileName
  }
  let url = dsf.url.getWebPath('file/download')
  $('<form action=' + url + ' method="get">' + // action请求路径及推送方法
    '<input type="text" name="files" value="' + paramID + '"/>' + // 文件id
    '<input type="text" name="zipName" value="' + paramZipname + '"/>' + // 文件名称
    '</form>')
    .appendTo('body').submit().remove();
}
//根据文件上传类型 配对文件图标
function diffIcon(fileType) {
  let className = ''
  if (fileType.indexOf("do") > -1) {
    className = "Word"
  }
  if (fileType.indexOf("excel") > -1 || fileType.indexOf("sheet") > -1 || fileType.indexOf("xl") > -1) {
    className = "Excel"
  }
  if (fileType.indexOf("pn") > -1) {
    className = "png"
  }
  if (fileType.indexOf("plain") > -1 || fileType.indexOf("tx") > -1) {
    className = "txt"
  }
  if (fileType.indexOf("zi") > -1) {
    className = "zip"
  }
  if (fileType.indexOf("jpe") > -1) {
    className = "jpg"
  }
  if (fileType.indexOf("pdf") > -1) {
    className = "pdf"
  }
  return className
}

function computeFileSize(fileSize) {
  let filesizeUnit = ""
  //1048576
  if (parseInt(fileSize) > 1050000) {
    filesizeUnit = (fileSize / Math.pow(1024, 2)).toFixed(2) + "M";
  } else {
    filesizeUnit = (fileSize / Math.pow(1024, 1)).toFixed(2) + "K";
  }
  return filesizeUnit
}
//获取文件大小
function getFileSize(data) {
  let fileSize = parseInt(data)
  if (data.indexOf("M") > -1 || data.indexOf("m") > -1) {
    fileSize = parseInt(data) * 1024
  }
  return fileSize
}

function moveupFn(evt) {
  let target = evt.target;
  let moveTargetID = $(target).attr("moveID");
  let data = $(this).data("data")
  let fileArray = data.multipleFiles;
  for (let i = 1; i < fileArray.length; i++) {
    if (fileArray[i].id == moveTargetID) {
      let temp = fileArray[i - 1];
      fileArray[i - 1] = fileArray[i];
      fileArray[i] = temp;
      data.value = JSON.stringify(fileArray);
      return;
    }
  }
}

function movedownFn(evt) {
  let target = evt.target;
  let moveTargetID = $(target).attr("moveID");
  let data = $(this).data("data")
  let fileArray = data.multipleFiles;
  for (let i = 0; i < fileArray.length - 1; i++) {
    if (fileArray[i].id == moveTargetID) {
      let temp = fileArray[i + 1];
      fileArray[i + 1] = fileArray[i];
      fileArray[i] = temp;
      data.value = JSON.stringify(fileArray);
      return;
    }
  }
}


