import { updateUserNameMetaData } from '../../../../core/metadata';
import { SystemUser } from './SystemUser';
import { map } from '../../../../decorator/controlmap';

@map('更新人名字', 'dsf.updateusername', 'UpdateUserName')
export class UpdateUserName extends SystemUser {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "修改人"
    this.$metadata = updateUserNameMetaData.call(this);
  }

  init() {
    super.init();
    this.caption = dsf.config.kw.updateusername;
  }
}