export class Template {
    constructor(target, handler, control) {
        this._target = target;
        this._handler = handler;
        this._tempJson = null;
        controldefine(this);
        this._tempJsonStr="";
        
    }

    createControlByTemplate(dataRow, index, callback) {
        // console.time("加载行模板")
        let _this = this;
        dataRow = dataRow || {};
        dataRow[dsf.hashKey] = dataRow[dsf.hashKey] || dsf.uuid();
        if(!this._tempJsonStr){
            this._tempJsonStr=this.control.getControlJson();
        }
        this._tempJson = JSON.parse(_this._tempJsonStr);
        let idx = 0,
            templateRoot = null;
        let ctrl = Template.toControl(this._tempJson, true, ctrl => {
            let oldId=ctrl.id;
            ctrl._caption= ctrl.caption;
            if (idx == 0) {
                templateRoot = ctrl;
                ctrl.id = dsf.uuid();
                ctrl.caption = dsf.uuid();
            } else {
                ctrl.id = dsf.uuid();
                ctrl.caption = _this._target.caption + "_" + templateRoot.caption + "_" + ctrl.caption;
            }
            if (ctrl.metadata_fullcode) {
                //加载控件的默认值
                if(page._initData.data[ctrl.metadata_fullcode]){
                    ctrl.value=page._initData.data[ctrl.metadata_fullcode];
                }
                 //加载控件的数据源
                let ds = window.page._initData.dataSourceData[ctrl.metadata_fullcode];
                if (ctrl instanceof dsf.Controls.ItemsControl) {
                    if (ds) {
                        ctrl.items = ds;
                    }
                }
                if(dataRow[ctrl.metadata_fullcode]!=undefined){
                    ctrl.value = dataRow[ctrl.metadata_fullcode];
                }
            } else if (ctrl instanceof dsf.Controls.Customer) {
                ctrl._cacheKey=oldId;
                ctrl.data = dataRow;
            }
            if (callback) {
                callback(ctrl);
            }

            idx++;
        });
        // console.timeEnd("加载行模板")
        return ctrl;
    }

    static toControl(obj, hasChild, callback) {
        if (dsf.Controls[obj.ctrl_type]) {
            let control = new dsf.Controls[obj.ctrl_type]();
            $.extend(control, obj);
            control.children = [];
            if (callback) {
                callback(control, obj);
            }
            if (!!hasChild) {
                if (obj.children && obj.children.length > 0) {
                    for (let i = 0; i < obj.children.length; i++) {
                        let c = Template.toControl(obj.children[i], hasChild, callback);
                        control.children.push(c);
                    }
                }
            }
            return control;
        }
    }

    static createTemplate(target, attr, hanlder) {
        let data = {};
        let val = new Template(target, hanlder);
        Object.defineProperty(target, attr, {
            enumerable: true,
            configurable: true,
            get: function() {
                return val;
            },
            set: function(value) {
                let _v = value;
                if (typeof(value) == "string") {
                    value = JSON.parse(_v);
                }
                if (typeof(value) == "object") {
                    let temp = new Template(target, hanlder);
                    $.extend(temp, value);
                    value = temp;
                }
                val = value;
            }
        });
    }

}


function controldefine(target) {
    let control = null;
    Object.defineProperty(target, "control", {
        enumerable: true,
        configurable: true,
        get: function() {
            return control;
        },
        set: function(ctrl) {
            if (!(ctrl instanceof dsf.Controls.Control)) {
                control = Template.toControl(ctrl, true);
            } else {
                control = ctrl;
            }
            control.root = window.page; // target._target.root;
            control.parentElement = target._handler;
            control.parent = target._target;
            // target._tempJson=JSON.stringify(control);
        }
    })
}