const dom = require("../../templates/UploadImg.ejs");
import { FormControl } from '../../../../baseControls';
import { relyFiles } from '../../../../core/relyfiles';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { photoMetaData } from '../../../../core/metadata';
import { map } from '../../../../decorator/controlmap';

@map('图片上传', 'dsf.uploadimg', 'UploadImg')
@isSupportDataPost(true)
@relyFiles([
    'res/libs/cropper/croppers.js',
    'res/libs/cropper/cropper.js'
])
export class UploadImg extends FormControl {
    //<table class="layui-table imgContainer" lay-skin="nob"><tbody></tbody></table>
    constructor(id, isPart) {
        super(id, isPart);
        this.$btnName = "图片上传";
        this.$showBtnName = true;
        this.label = "图片上传"
        this.$showLabel = true;
        this.$multiple = true;
        this.$metadata = photoMetaData.call(this, 500);
        this.multipleImage = [];
        this.$uploadFileExts = "";//允许上传文件类型
        this.$uploadFileNum = "2";
        this.$maxFileSize = "";
        this.$zipFileName = "";//打包文件名
        this.$isCutPic = true;
        this.$aspectRatio = "";
        this.$error_tipsPosition = "right"
    }


    set btnName(value) {
        this.$btnName = value
    }

    get btnName() {
        return this.$btnName
    }
    set showBtnName(value) {
        this.$showBtnName = value
        if (!value) {
            this.addClass("hideName")
        } else {
            this.removeClass("hideName")
        }
    }
    get showBtnName() {
        return this.$showBtnName
    }

    set value(val) {
        if (!val) {
            val = "";
        }
        super.value = val;
        if (typeof val === 'string') {
            if (val) {
                val = JSON.parse(val);
                this.multipleImage = val;
            }
        }
        if (_.isArray(val)) {
            if (!this.readOnly) {
                if (this.element && this.element.find(".imgContainer")) {
                    this.element.find(".imgContainer").remove()
                }
                this.createFileBox(val)
            } else {
                this.getTextString()
                if (val.length > 1) {
                    this.createDownLoadBtn()
                }
            }
            if (this.visible) {
                this.btnBindFn()
            }

        }
    }
    get value() {
        return super.value
    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
    }

    renderContext() {
        super.renderContext();

        if (this._handlers.btnName) {
            this._handlers.btnName.html(this.btnName);
        }
        if (this._handlers.label) {
            this._handlers.label.html(this.$label);
        }
    }
    renderReady() {
        super.renderReady()
        this.initEvent()
    }
    initEvent() {
        let that = this;
        that.headersParam = dsf.getCookie("XSRF-TOKEN") || ""
        if (!that.readOnly) {
            layui.element.init();
            layui.upload.render({
                elem: '#ui_' + that.id, // 文件选择
                accept: "images",
                multiple: that.$multiple,
                number: parseInt(that.$uploadFileNum),
                headers: { 'X-XSRF-TOKEN': that.headersParam },
                acceptMime: 'image/*',
                url: dsf.url.getWebPath('file/upload/'),
                auto: true, // 设置不自动提交
                exts: geExts(that.$uploadFileExts),
                size: getFileSize(that.$maxFileSize),
                before: function (obj) {
                    layer.load(); //上传loading
                },
                allDone: function (obj) { //当文件全部被提交后，才触发
                    layer.closeAll('loading');
                    that.boundImg(that.multipleImage, obj)
                    if (that.element.find(".downLoadBtn").length > 0) {
                        that.element.find(".downLoadBtn").remove()
                    }
                    //多张文件上传且文件数量>1时，创建全部下载按钮
                    if (that.$multiple && that.$uploadFileNum > 1) {
                        that.createDownLoadBtn();
                        that.btnBindFn();
                    } else if (that.$multiple && that.$uploadFileNum == 1) {
                        if (that.$isCutPic) {
                            cropperFn.call(that, null, that.multipleImage[0])
                        }
                    }

                    if (obj.aborted > 0) {
                        dsf.layer.message("有" + obj.aborted + "张图片上传失败", false)
                    } else {
                        dsf.layer.message("上传成功", true)
                    }
                },
                done: function (res) {
                    if (that.$uploadFileNum == 1) {
                        that.multipleImage = []
                        if (!res.success) {
                            that.multipleImage['success'] = res.success;
                            layer.layer.message(res.message, false);
                            return
                        }
                    }
                    res.data[0].success = res.success;
                    that.multipleImage.push(res.data[0]);
                    if (!that.$multiple) {
                        if (that.$isCutPic) {
                            cropperFn.call(that, null, res.data[0])
                        } else {
                            that.value = JSON.stringify(that.multipleImage)
                        }
                        let obj = { total: 1 };
                        layer.closeAll('loading');
                        that.boundImg(that.multipleImage, obj);
                    }
                    that.event.trigger(FormControlEvent.VALUECHANGE, { ui: that });
                },
                error: function (res) {
                    dsf.layer.message("上传失败", false);
                    layer.closeAll('loading');
                }
            });
        } else {
            if (that.element.find(".imgContainer")) {
                that.element.find(".imgContainer").remove()
            }
        }
    }
    setControlId() {
        return this.id
    }
    getTextString() {
        let container = $('<div class=" imgContainer" ></div>')
        if (this.value) {
            var value = JSON.parse(this.value)
            for (let i = 0; i < value.length; i++) {
                createUploadContent.call(this, container, value[i], value[i].id, i + 1)
            }
            let readonlyHtml = $(container).html()

            return readonlyHtml
        }
    }
    boundImg(multipleImage, obj) {
        let that = this;
        let imgArrLen = multipleImage.length;
        if (that.$uploadFileNum > 0) {
            let startIndex = parseInt(imgArrLen) - parseInt(obj.total) - parseInt(obj.total);
            if (startIndex != -1) {
                if (that.$uploadFileNum < multipleImage.length) {
                    for (let i = 0; i <= obj.total; i++) {
                        let data = multipleImage[imgArrLen - i - 1]
                        multipleImage.splice(startIndex + i, 1, data)
                    }
                    multipleImage.length = that.$uploadFileNum
                }
            } else {
                for (let k = 0; k <= obj.total; k++) {
                    let data = multipleImage[imgArrLen - k - 1]
                    if (data) {
                        multipleImage.splice(k, 1, data)
                    }
                }
            }

        }

        if (that.$uploadFileNum == "0") { that.$uploadFileNum = 1000000 }
        if (multipleImage.length > that.$uploadFileNum) {
            multipleImage.length = that.$uploadFileNum
        }
        that.value = JSON.stringify(multipleImage)
    }
    renderReady() {
        super.renderReady();
        if (this.element.find(".downLoad").length > 0) {
            let downLoadbtn = this.element.find(".downLoad");
            downLoadbtn.click(this, downLoadFn)
        }
    }
    createDownLoadBtn() {
        let multipleDownBtn = ' <button class="layui-btn downLoadBtn downLoad" ds-event="downLoad" id="downloadAll" style="float: right;">' +
            ' <span handler="btnName" ds-event="downLoad" class="btnName">' +
            ' 全部下载</span>' +
            '</button>'
        this.element.find(".uploadfileBtn").prepend(multipleDownBtn)
    }
    deleteDownLoadAllBtn() {
        let count = setInterval(function () {
            if ($('.imgContainer').length > 0) {
                $("#downloadAll").remove();
                clearInterval(count)
            }
        }, 1000)
    }
    createFileBox(val) {
        let container = '';
        let count = "";
        var item = _.isNull($(this).get(0)._element) ? [] : $($(this).get(0)._element[0]).find(".item")
        if (item.length == 0) {
            container = $(' <div class=" imgContainer"></div>')
        } else {
            container = this.element.find(".imgContainer")
        }
        $(".showImgEdit").length > 0 && $(".showImgEdit:not(.photoEdit)").remove()
        for (let i = 0; i < val.length; i++) {
            if (item.length > 0) {
                count = item.length
            } else {
                count = i
            }
            createUploadContent.call(this, container, val[i], val[i].id, count + 1)
        }
    }
    btnBindFn() {
        //非只读模式是绑定删除功能、下载功能
        // console.log('this.readOnly', this.readOnly)
        // console.log('this.element', this.element)
        if (this.element) {
            //绑定图片放大
            this.element.find(".sizeUp").on("click", { obj: this }, sizeUp)
            this.element.find(".sizeUp").hover(function () {
                $(this).append(mask);
                $(this).find(".mask").fadeIn()
            }, function () {
                $(this).find('.mask').remove()
                $(this).find(".mask").fadeOut()
            })

            //绑定图片排序事件
            this.element.find('.moveleft').on("click", moveleftFn);
            this.element.find('.moveright').on("click", moverightFn)
            $(this.element.find('.moveImg')).data("data", this);

            let downloadBtn = this.element.find('.downLoadBtn')
            if (downloadBtn.length > 0) {
                downloadBtn.on("click", { obj: this }, downLoadFn)
            }
        }
        if (!this.readOnly && !_.isNull(this.element)) {
            // if (!this.readOnly && _.isNull(!this.element)) {
            this.element.find(".delete").on("click", { obj: this }, deleteItem)//删除功能
            $(this.element.find(".delete")).data("data", this)
            // 绑定图片剪裁事件
            this.element.find(".cut").on("click", cropperFn);
            $(this.element.find('.cut')).data("data", this);
        }

        //为图片绑定hover状态样式
        let mask = "<div style='position:absolute;background-color:rgba(0,0,0,.4);top:0;left:0;bottom:0;right:0;text-align:center;cursor:pointer' class='mask'><span class='iconfont' style='color:white;font-size: 20px; padding: 15px; border-radius: 50%; background-color: rgba(255,255,255,.3);display: inline-block;margin: 21px auto;'>&#xec14;</span></div>"

    }

    validateInfo() {
        return {
            tipsElement: ".layui-btn.upload"
        }
    }
}

function createUploadContent(container, file, id, count) {
    // if (file.relativePath.indexOf("dsfa") < 0) {
    let relativePath =dsf.config.staticPath? dsf.config.staticPath+file.relativePath:dsf.url.getWebPath(file.relativePath);
    let defaultcover = "../../../res/dsf_style/img/coverdefault.png"
    // }else{

    // }
    file.uploadDate = dsf.date.format(file.uploadDate, 'yyyy-mm-dd HH:mm')
    let html = '<dl class="pic" id="' + file.id + '">' +
        '<dt class="img sizeUp" id="img_' + file.id + '">' +
        '<img src="' + relativePath + '" relativePath="' + file.relativePath + '" onerror=\'javascript:this.src="' + defaultcover + ';onerror=null\'/>' +
        '<dt>' +
        '<dd class="title">' +
        '<div>' + count + '.</div>' +
        '<input class="ImgName" value=' + file.name + ' disabled>' +
        '<span>.' + file.suffix + '</span>' +
        '<div class="operateBox">' +
        '<span class="moveleft moveImg iconfont"  title="左移" moveID = "' + id + '">&#xe630;</span>' +
        '<span class="moveright moveImg iconfont" title="右移" moveID = "' + id + '">&#xe634;</span>' +
        '<span class="downLoad iconfont downLoadBtn" filename="' + file.name + '"  downLoadkey="' + id + '" title="下载">&#xec22;</span>' +
        '<span class="delete iconfont" delkey="' + id + '" title="删除">&#xe61b;</span>' +
        '<span class="cut iconfont" cutkey="' + id + '" title="裁剪" id="cut_' + id + '"  >&#xe693;</span>' +
        '<span class="reload iconfont" style="margin-left:7px;" id="reload_' + id + '" title="重新上传">&#xec23;</span>' +
        '</div>' +
        '</dd>' +
        '</dl>'

    $(container).append(html)

    if (this._element) {
        this.element.find(".uploadfileBtn").append(container)
        if (!this.$multiple || this.$uploadFileNum == 1) {
            $(".operateBox").find(".moveImg").remove();
            $(".operateBox").find(".cut").remove();
        }
        if (!this.$isCutPic) {
            $(".operateBox").find(".cut").remove()
        }
    }
    if (this.readOnly) {
        $(".operateBox").find(".delete").remove()
        $(".operateBox").find(".moveImg").remove()
        $(".operateBox").find(".reload").remove()
        $(".operateBox").find(".cut").remove()
    }
    bindRelodBtn.call(this, id);
    createImgEditor(id)
    $("img").on("error", () => {
        this.src = "../../../res/dsf_style/img/coverdefault.png";
        this.onerror = null
    })

}
// 删除
function deleteItem(event) {
    console.log(111)
    let delFile = event.target;
    let _that = event.data.obj;
    let parentDom = _that.element;
    let delKey = $(delFile).attr('delKey')
    // let that= event.data.obj
    let that = $(this).data("data");
    let imgContainer = that.element.find(".imgContainer")

    dsf.layer.confirm("确定要删除么?", () => {
        if ($(imgContainer).find(".item").length == 1) {
            $(imgContainer).remove()
            that.element.find('.downLoadBtn').remove()
            that.multipleImage = [];
        } else {
            for (let i = 0; i < that.multipleImage.length; i++) {
                if (that.multipleImage[i].id == delKey) {
                    that.multipleImage.splice(i, 1)
                }
            }
            $("#" + delKey).remove();
            if ($(parentDom).find(".imgContainer").find("dl").length == 0) {
                that.element.find('#downloadAll').remove()
            }
        }
        that.value = JSON.stringify(that.multipleImage)
    })
}
//图片放大
function sizeUp() {
    let path = $(this).find('img').attr("src");
    if ($('body:has(.bigImgDom)')) {
        $(".bigImgDom").remove()
    }
    let bigImgDome = '<div class="bigImgDom">' +
        ' <div class="singleImgContainer">' +
        '<img src="' + path + '" alt="">' +
        ' </div>' +
        '</div>'
    $("body").append(bigImgDome)
    $(".bigImgDom").on("click", function () {
        $(this).remove()
    })
}
//绑定 单个文件重新上传按钮
function bindRelodBtn(id) {
    let that = this
    layui.use(['upload', 'element'], function () {
        var upload = layui.upload,
            element = layui.element;
        element.init();
        upload.render({
            elem: '#reload_' + id + '',
            accept: 'images',
            multiple: false,
            acceptMime: 'image/*',
            url: dsf.url.getWebPath('file/upload/'),
            headers: { 'X-XSRF-TOKEN': that.headersParam },
            auto: true, // 设置不自动提交
            exts: geExts(that.$uploadFileExts),
            size: getFileSize(that.$maxFileSize),
            before: function (obj) {
                layer.load(); //上传loading
            },
            choose: function () {
                console.log("choose")
            },
            done: function (res) {
                res.data[0].success = res.success;
                if (!that.$multiple || (that.$multiple && that.$uploadFileNum == 1)) {
                    if (that.$isCutPic) {
                        createImgEditor(res.data[0].id)
                        cropperFn.call(that, null, res.data[0], true)
                    } else {
                        let index = parseInt($($(this).get(0))[0].elem.parent().siblings().get(0).textContent) - 1
                        that.multipleImage.splice(index, 1, res.data[0])
                        that.value = JSON.stringify(that.multipleImage)
                    }
                }
                else {
                    let index = parseInt($($(this).get(0))[0].elem.parent().siblings().get(0).textContent) - 1
                    that.multipleImage.splice(index, 1, res.data[0])
                    that.value = JSON.stringify(that.multipleImage)
                }
                layer.closeAll('loading');
            },
            error: function (index) {
                dsf.layer.message("上传失败", false);
                layer.closeAll('loading');
            }
        });
    });
}
//文件下载
function downLoadFn(event) {
    let that = null;
    let paramZipname = "";
    let paramID = "";
    if (event.data.obj) {
        that = event.data.obj;
    } else {
        that = event.data //只读时的数据
    }
    let singleFile = event.target;
    let downLoadkey = $(singleFile).attr('downLoadkey')
    let singlefileName = $(singleFile).attr('filename')

    let fileIds = []
    //单图片下载
    if (downLoadkey) {
        paramID = downLoadkey + "^" + singlefileName
    } else {
        //多图片下载
        for (let i = 0; i < that.multipleImage.length; i++) {
            let id = that.multipleImage[i].id;
            let name = that.multipleImage[i].name;
            let file = id + "^" + name
            fileIds.push(file);
        }
        paramID = fileIds.join(",")
    }
    if (fileIds.length > 0) {
        paramZipname = that.$zipFileName
    }
    let url = dsf.url.getWebPath('file/download')
    $('<form action=' + url + ' method="get">' +  // action请求路径及推送方法
        '<input type="text" name="files" value="' + paramID + '"/>' + // 文件路径
        '<input type="text" name="zipName" value="' + paramZipname + '"/>' + // 文件名称
        '</form>')
        .appendTo('body').submit().remove();
}
//图片左移
function moveleftFn(evt) {
    let target = evt.target;
    let moveTargetID = $(target).attr("moveID");
    let data = $(this).data("data");
    console.log("data", data);
    let imgArray = data.multipleImage;
    for (let i = 1; i < imgArray.length; i++) {
        if (imgArray[i].id == moveTargetID) {
            let temp = imgArray[i - 1];
            imgArray[i - 1] = imgArray[i];
            imgArray[i] = temp;
            data.value = JSON.stringify(imgArray);
            return;
        }
    }
}
//图片右移
function moverightFn(evt) {
    let target = evt.target;
    let moveTargetID = $(target).attr("moveID");
    let data = $(this).data("data");
    console.log("data", data);
    let imgArray = data.multipleImage;
    for (let i = 0; i < imgArray.length - 1; i++) {
        if (imgArray[i].id == moveTargetID) {
            let temp = imgArray[i + 1];
            imgArray[i + 1] = imgArray[i];
            imgArray[i] = temp;
            data.value = JSON.stringify(imgArray);
            return;
        }
    }
}
