function cropperFn(evt, data, isreload) {
    console.log('重新上传')
    let that = this;
    let img = {};
    let file = data ? that : $(that).data("data");
    console.log("file", file);
    let ratioWidth = file.$aspectRatio.split(':')[0]
    let ratioHeight = file.$aspectRatio.split(':')[1]
    let aspectRatio = ratioWidth / ratioHeight
    let id = data ? data.id : $(evt.target).attr("cutkey");
    let elem = data ? '#img_' + id : '#cut_' + id + ''
    if (!data) {
        $.each(file.multipleImage, (i, obj) => {
            if (obj.id == id) {
                img = obj
            }
        })
    } else {
        img = data
    }
    let imgurl =  dsf.config.staticPath? dsf.config.staticPath+img.relativePath:dsf.url.getWebPath(img.relativePath);
    let filename = img.originalFileName;
    let imgtype = img.contentType;
    layui.config({
        base: '/dsfa/res/libs/cropper/' //layui自定义layui组件目录
    }).use(['cropper', 'croppers'], function () {
        var $ = layui.jquery;
        var croppers = layui.croppers;
        //创建一个头像上传组件
        croppers.render({
            elem: elem
            , aspectRatio: aspectRatio
            , autoCropArea: "1"
            , area: '800px'  //弹窗宽度
            , filename: filename
            , id: id
            , url: dsf.url.getWebPath('file/upload/')  //图片上传接口返回和（layui 的upload 模块）返回的JOSN一样
            , imgurl: imgurl
            , imgtype: imgtype
            , done: function (data) { //上传完毕回调
                if (isreload) {
                    file.multipleImage.splice(0, 1, data[0]);
                } else {
                    $.each(file.multipleImage, function (i, obj) {
                        if (obj.name == data[0].name) {
                            file.multipleImage.splice(i, 1, data[0]);
                        }
                    })
                }

                file.value = JSON.stringify(file.multipleImage)
            }
        });

    });
}
//返回格式化后的文件大小
function computeFileSize(fileSize) {
    let filesizeUnit = ""
    if (parseInt(fileSize) > 1050000) {
        filesizeUnit = (fileSize / Math.pow(1024, 2)).toFixed(2) + "M";
    } else {
        filesizeUnit = (fileSize / Math.pow(1024, 1)).toFixed(2) + "K";
    }
    return filesizeUnit
}
//获取文件大小
function getFileSize(data) {
    let fileSize = parseInt(data)
    if (data.indexOf("M") > -1) {
        fileSize = parseInt(data) * 1024
    }
    return fileSize
}
//获取配置上传文件格式
function geExts(exts) {
    let formatExt = ""
    if (exts.indexOf("*") > -1) {
        formatExt = ''
    } else {
        formatExt = exts.split(",").join("|")
    }
    return formatExt
}
