const dom = require("../../templates/Card.ejs");
import { LayoutControl, Container } from '../../../../baseControls';
import { CardEvent } from '../../../../core/ControlEvent';
import { ButtonPlugin } from '../../../../pulgins/buttons';
import { map } from '../../../../decorator/controlmap';

@map('卡片', 'dsf.card', 'Card')
export class Card extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$width = 200;
    this._checked = false;
    this.$checkabled = false;
    // this.$buttonBar=ButtonPlugin.ButtonBar();
    this.$showButtonBar = false;
  }

  set width(val) {
    this.$width = val;
    this.resize();
  }
  get width() {
    return this.$width;
  }

  initTemplate() {
    return dom(this);
  }

  set checked(value) {
    if (this._checked != value) {
      this._checked = value;
    }
    if (this.element) {
      $("#check_" + this.id).prop("checked", this._checked);
      this.checked ? this.element.addClass("checked") : this.element.removeClass("checked");
    }
  }
  get checked() {
    return this._checked;
  }

  set checkabled(value) {
    this.$checkabled = value;
  }
  get checkabled() {
    return this.$checkabled;
  }

  initEvent() {
    let _this = this;
    this.element.on("click", function(evt) {
      if (_this.$checkabled) {
        _this.checked = !_this.checked;
        _this.checked ? _this.element.addClass("checked") : _this.element.removeClass("checked");
        _this.event.trigger(CardEvent.CHECKED, _this);
      }
    });
  }

  createElement() {
    super.createElement();
    // if (!this._isRender && this.root._isDesign && this.children.length <= 0) {
    //     let content = this.root.createControl(Container, this.id + "content", true);
    //     content.addClass("no_padding");
    //     content.addClass("ds_card_content")
    //     this._addChild(content, null, "#" + this.id);
    // }
  }

  set showButtonBar(value) {
    this.$showButtonBar = value;
    if (this.element) {
      (value) ? this.element.addClass("showbuttonbar"): this.element.removeClass("showbuttonbar");
    }

  }

  get showButtonBar() {
    return this.$showButtonBar;
  }

  render() {
    super.render();
    $("#check_" + this.id).prop("checked", this._checked);
    this.checked ? this.element.addClass("checked") : this.element.removeClass("checked");
    (this.showButtonBar) ? this.element.addClass("showbuttonbar"): this.element.removeClass("showbuttonbar");
  }

  renderContext() {
    super.renderContext();
    this.element.css("width", this.$width);
  }

  resize() {
    if (this.element) {
      this.element.css("width", this.$width);
    }

  }
}