
import { isSupportDataPost } from '../../../../core/postDecorator';
import * as ButtonPlugin from '../../../../pulgins/buttons';
import {DataChoice} from "./DataChoice";
import { Control } from '../../../../baseControls'
import {map} from  '../../../../decorator/controlmap';

@map('部门人员','dsf.ouaselect','OuaSelect')
@isSupportDataPost(true)
export class OuaSelect extends DataChoice {
    constructor(id, isPart) {
        super(id, isPart);
        this.label = "部门人员选择";
        // tab显示
        this.tabs = ['framework'];
        // 可选择类型
        this.types = "";
        // 是否可排序
        this.canSort = false;
        // 显示类型
        this.showType = "user";
        // 组织架构仅仅显示子机构
        this.showSubDept = false;
        this.$dialogUrl = null;
        // 点击时是否选择子节点
        this.chkboxType = false;
    }

    init(){
        this.$dialogUrl = "/dsfa/oua/views/select.html";
    }
    
    createElement() {
        let ctrl = new Control;
        ctrl.createElement.call(this);
        if (!this.readOnly) {
            let buttonArg = this.$dialogUrl + ";" + this.$dialogTitle + ";" + (this.$dialoSize.split(",").join(";")) + ";" + this.$dialogHeight;
            let button = ButtonPlugin.createButton("人员选择", "system_selector_list_dialog", "icon-Magnifier", "auxiliary", 2, null, true, buttonArg);
            if (this._buttonBar.buttons.length <= 0) {
                this._buttonBar.buttons.push(button);
            }
            ButtonPlugin.renderButtons(this, this._handlers.searchBox, this._buttonBar, null, null, "small");
        }
    }
}