function getAllowReturnValueControl() {
  let ctrls = [];
  this.ControlsForEach((v) => {
    if (v._allowReturnValue) {
      ctrls.push(v);
      return false;
    }
  }, false);
  if (ctrls.length <= 0) {
    return null;
  } else {
    let ctrl = ctrls[0];
    return ctrl;
  }
}

function returnValue(value) {
  let v = null;
  if (value != undefined) {
    v = value;
    this.returnValue = v;
  } else {
    return v;
  }
}

let ayncTotal = 0; //统计异步请求数量
let isOver = 0; // 统计异步已经完成情况
//获取数据字典
function getDataDict(page, callback) {
  let data = [];
  let controls = {};
  page.ControlsForEach((ctrl) => {
    let md = ctrl.metadata;
    if (md && md.dataSource) {
      if (md.dataSource.type == "dict") {
        data.push({
          key: ctrl.id,
          dictId: md.dataSource.code,
        });
        controls[ctrl.id] = ctrl;
      } else if (md.dataSource.type == "db") {
        ayncTotal++;
        controls[ctrl.id] = ctrl;
        getDsFromDb(md.dataSource.code, ctrl, callback);
      } else if (md.dataSource.type == "static") {
        ctrl.items = md.dataSource.code;
      }
    }
  });
  if (data.length > 0) {
    ayncTotal++;
    let args = {
      dicts: JSON.stringify(data),
    };
    dsf.http
      .request(dsf.url.getWebPath("dict/data"), args, "GET")
      .done((res) => {
        if (res.success && res.data) {
          for (let k in res.data) {
            let items = [];
            res.data[k].forEach((o) => {
              let item = {
                text: o.text,
                value: o.value,
              };
              items.push(item);
            });
            controls[k].items = items;
          }
        }
      })
      .always(() => {
        isOver++;
        if (ayncTotal == isOver) {
          callback & callback();
        }
      })
      .exec();
  }
  if (ayncTotal == isOver) {
    callback & callback();
  }
}

function getDsFromDb(rmId, ctrl, callback) {
  dsf.http
    .request(
      dsf.UrlSetting.dbSource,
      {
        rmId: rmId,
      },
      "GET"
    )
    .done(function(response) {
      console.log(response);
      ctrl.items = response.data;
    })
    .always(() => {
      isOver++;
      if (ayncTotal == isOver) {
        callback & callback();
      }
    })
    .exec();
}

//refreshTarget,args,isSilent, callback
function save(options) {
  let refreshTarget = options.refreshTarget || "opener";
  let info = options.info;
  let isSilent = options.isSilent || false;
  let isCloseWindow = options.isCloseWindow || false;
  let callback = options.callback;
  let message = options.message;
  let isRefreshPage = options.isRefreshPage || false;
  let isReadOnly = options.isReadOnly || false;
  let isTemporaryStorage = options.isTemporaryStorage;
  let _this = this;
  let loadingIndex = dsf.layer.loadding();
  _this.endAllEditControl();
  let saveReault = false;
  let auditState = 1;
  let queue = dsf.queue();
  let _data = {};
  //检测所有控件中保存前执行的操作
  _this.ControlsForEach((control) => {
    if (control.saveBeforeAction) {
      queue.step(function(def, v) {
        control.saveBeforeAction(def, v, options);
      });
    }
  });

  queue.step((def, v) => {
    _this.addData = {};
    if (_this.event.has(PageEvent.SAVEBEFORE)) {
      _this.event.trigger(PageEvent.SAVEBEFORE, { ui: _this, args: info }, def);
    } else {
      def.resolve();
    }
  });
  queue.step((def, v) => {
    let controls = _this.getPostControls();
    let scope = _this.getControlsData();
    //非暂存处理
    if (!isTemporaryStorage) {
      let result = _this.getValidateResult(scope, scope, controls);
      //显示验证错误的组件提示
      if (result.errorControls.length) {
        _.each(result.errorControls, (ctrl) => {
          ctrl.validateError();
        });
      }
      //验证成功的组件如果原先存在错误则取消改错误
      if (result.successControls.length) {
        _.each(result.successControls, (ctrl) => {
          ctrl.validateError();
        });
      }
      if (!result.success) {
        _this.event.trigger(PageEvent.VALIDATEERROR, {
          ui: _this,
          data: result,
        });
        if (result.errorControls) {
          let first = result.errorControls[0];
          if (first) {
            let el = first.element;
            if (first.getErrorPostElement) {
              el = first.getErrorPostElement();
            }
            if (el.length > 0) {
              el.get(0).scrollIntoView({ behavior: "smooth" });
            }
          }
          _.each(result.errorControls, (ctrl) => {
            ctrl.validateError();
          });
          dsf.layer.message("未填写完整或不符合要求，请检查", false);
        }
        def.reject();
        return;
      }
      //触发热审开始事件,调用execAudit组件（如果页面中有该组件）
      execAudit.call(_this);
      // if(this._auditInfo&&this._auditInfo.)
      def.resolve();
    } else {
      //如果是暂存将审核状态强行设置成成当前状态*10
      if (this._auditInfo) {
        this._auditInfo.value.state = this._auditInfo.value.state * 10;
      }
      def.resolve();
    }
  });

  //保存请求
  queue.step((def, v) => {
    Action.form_save(_this, (err, data, response) => {
      const defaultEvent = () => {
		_data = data;
        if (err) {
          if (!isSilent) {
            let msg = dsf.prompt.savefail;
            if (message) {
              msg = message + "失败";
            }
            if (data.state == "20001") {
              dsf.layer.message(msg, false);
            } else {
              dsf.layer.message(data.message, false);
            }
          }
          def.reject();
        } else {
          _this.loadData(data);
          if (this._auditInfo) {
            let state = parseInt(this._auditInfo.value.state);
            if (state < 0) {
              dsf.layer.alert(
                "数据已为您暂存,但审核存在问题请检查!",
                { icon: 7 },
                function() {
                  _this._auditInfo.showDetail();
                }
              );
            } else if (state > 0) {
              if (!isSilent) {
                let msg = dsf.prompt.savesuccess;
                if (message) {
                  msg = message + "成功";
                }
                dsf.layer.message(msg, true);
              }
            }
          } else {
            if (!isSilent) {
              let msg = dsf.prompt.savesuccess;
              if (message) {
                msg = message + "成功";
              }
              if (response.state == "20000") {
                dsf.layer.message(msg, true);
              } else {
                dsf.layer.message(response.message, true);
              }
              // dsf.layer.message(msg, true);
            }
          }
          def.resolve(data);
        }
      };
      if (page.onFormButtonSaveAfter) {
        page.onFormButtonSaveAfter({ def, response, next: defaultEvent });
      } else {
        defaultEvent();
      }
    });
  });

  queue.step((def, v) => {
    if (_this.event.has(PageEvent.SAVEAFTER)) {
      _this.event.trigger(PageEvent.SAVEAFTER, { ui: _this, args: info }, def);
    } else {
      def.resolve();
    }
  });

  queue.step((def, v) => {
    if (window[refreshTarget]) {
      try {
        _this.refreshParent(refreshTarget);
      } catch (ex) {
        dsf.error("未能成功刷新父页面");
      }
    }
    def.resolve();
    saveReault = true;
  });

  queue.catch(function() {
    saveReault = false;
  });

  queue.finally(function() {
    callback ? callback(saveReault,_data) : dsf.noop();
    _this.event.trigger(PageEvent.SAVECOMPLATE, {
      ui: _this,
      args: info,
      data: _this._data,
      saveResult: saveReault,
    });
    if (isCloseWindow && saveReault) {
      try {
        window.setTimeout(function() {
          _this.close();
          dsf.layer.close(loadingIndex);
        }, 2000);
      } catch (ex) {
        dsf.error(ex);
        dsf.layer.close(loadingIndex);
      }
    } else if (!isCloseWindow && saveReault && isRefreshPage) {
      window.setTimeout(function() {
        _this.refreshSelf(isReadOnly);
        dsf.layer.close(loadingIndex);
      }, 2000);
    } else {
      dsf.layer.close(loadingIndex);
    }

    //重新更新按钮
    page.element.find("[ctrl_type=ButtonBar]").each(function(i) {
      let el = $(this);
      let ctrl = el.data("Object");
      if (ctrl) {
        ctrl.renderButtons();
      }
    });
  });

  queue.exec();
}

function execAudit(isShowResult) {
  if (this._auditInfo) {
    this._auditInfo.exec();
    return this._auditInfo.value;
  }
  return null;
}

function showAuditDetail() {
  if (dsf.isDef(this._auditInfo) && dsf.isDef(this._auditInfo.value)) {
    let state = this._auditInfo.value.state;
    state = parseInt(state);
    if (state < 0) {
      this._auditInfo.showDetail();
    }
  }
}

function createDataAttrs(page) {
  let attrs = {};
  attrs["$$key"] = page._data.$$key;
  let controls = {};
  page.ControlsForEach((control) => {
    if (control.oneToMany || control._isFormControl) {
      controls[control.metadata_fullcode] = control;
      return false;
    }
  });
  for (let k in controls) {
    attrs[k] = undefined;
  }
  page._data = dsf.platform.modelFactory(attrs);
}
