import dom from "../../templates/TableLayout.ejs";
import rowdom from "../../templates/TableLayoutRow.ejs";
import celldom from "../../templates/TableLayoutCell.ejs";
import { LayoutControl, Container } from "../../../../baseControls";
import { TableLayoutEditor } from '../../../../editor/TableLayoutEditor'
import { map } from '../../../../decorator/controlmap';

@map('表格布局', 'dsf.tablelayout', 'TableLayout')
export class TableLayout extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = TableLayoutEditor;
    this._matrix = [];
    this.columns = [];
    this.$minRowHeight = 57;
    this.$isOuterPadding = true;
    this.$borderShow = true;
    // this.$paddingShow = true;
    this.$fixedLayout = false;
  }

  initTemplate() {
    return dom(this);
  }
  createElement() {
    super.createElement();
    if (!this._isRender) {
      if (this.root._isDesign) {
        if (this.children.length <= 0) {
          for (var i = 0; i < 4; i++) {
            let tableRow = new TableLayoutRow(null, true);
            this._addChild(tableRow, null, "tbody");
            for (let n = 0; n < 4; n++) {
              let tableCell = new TableLayoutCell(null, true);
              tableRow._addChild(tableCell, null, "#" + tableRow.id);
            }
          }
        }
        if (this.columns.length == 0) {
          for (var i = 0; i < 4; i++) {
            this.columns.push({
              "width": "25",
              "fixed": true
            });
          }

        }
      }
    }
  }
  renderContext() {
    if (!this.$borderShow) {
      this.addClass("no_border");
    } else {
      this.removeClass("no_border");
    }
    if (this.$fixedLayout) {
      this.addClass("table_fixed");
    } else {
      this.removeClass("table_fixed");
    }
    super.renderContext();
    if (dsf.isDef(this.$paddingShow)) {
      this.$paddingShow ? this.removeClass("no_padding") : this.addClass("no_padding");
    }

    this.refreshTableHead();
  }

  renderReady() {
    super.renderReady();
    Parser.call(this);
  }

  refreshTableHead() {
    refreshTableHead.call(this);
  }

  getRow(index) {
    return this.children[index];
  }
  addRow(index, isEmpty) {
    let row = new TableLayoutRow(null, true);
    row.table = this;
    this.addChild(row, index, "tbody");
    if (!isEmpty) {
      let rowSpaned = {};
      for (let i = 0; i < this.columns.length; i++) {
        let _matrix_row = this._matrix[index];
        if (_matrix_row) {
          let cell = _matrix_row[i];
          if (cell) {
            let mindex = cell.attr("matrix_idx").split(",");
            let rowIndex = parseInt(mindex[0]);
            let rowSpan = parseInt(cell.attr("rowspan")) || 1;
            if (rowSpan > 1 && (index != rowIndex)) {
              let c = cell.data("Object");
              if (!rowSpaned[c.id]) {
                c.rowSpan++;
                c.setRowSpan(c.rowSpan);
                rowSpaned[c.id] = c;
              }
            } else {
              row.addCell();
            }
          } else {
            row.addCell();
          }
        } else {
          row.addCell();
        }
      }

    }
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
    }
  }
  addColumn(index, isParser) {
    let matrix = this._matrix;
    let colSpaned = {};
    let head_tr = this._handlers.table.children("THEAD").children("TR");
    let head_cells = head_tr.children("TD");
    for (let i = 0; i < matrix.length; i++) {
      let row = matrix[i];
      let cell = row[index];
      let tableRow = this.getRow(i);
      if (cell) {
        let mindex = cell.attr("matrix_idx").split(",");
        let cellIndex = parseInt(mindex[1]);
        let colSpan = parseInt(cell.attr("colspan")) || 1;
        if (colSpan > 1 && (index != cellIndex)) {
          let c = cell.data("Object");
          if (!colSpaned[c.id]) {
            c.colSpan++;
            c.setColSpan(c.colSpan);
            colSpaned[c.id] = c;
          }
        } else {
          tableRow.addCell(index);
        }
      } else {
        tableRow.addCell();
      }
    }
    let head_td = head_cells.eq(index);
    let head_new_td = $("<TD new='true'>");
    if (head_td.length > 0) {
      head_td.before(head_new_td);
    } else {
      head_tr.append(head_new_td);
    }
    if (isParser) {
      this.execParser();
    }
  }
  removeRow(index) {
    let tableRow = this.getRow(index);
    if (tableRow) {
      let rowSpaned = {};
      let i = 0;
      while (i < this.columns.length) {
        let cell = this._matrix[index][i];
        if (cell) {
          let mindex = cell.attr("matrix_idx").split(",");
          let rowIndex = parseInt(mindex[0]);
          let rowSpan = parseInt(cell.attr("rowspan")) || 1;
          let colSpan = parseInt(cell.attr("colspan")) || 1;
          if (rowSpan > 1) {
            let c = cell.data("Object");
            if (!rowSpaned[c.id]) {
              c.rowSpan--;
              if (c.rowSpan < 1) {
                c.rowSpan = 1;
              }
              c.setRowSpan(c.rowSpan);
              rowSpaned[c.id] = c;
            }
            if (index == rowIndex) {
              let nextCell = getNextCell.call(this, index + 1, c);
              let nextRow = this.getRow(index + 1);
              if (nextRow) {
                let newCell = null;
                if (nextCell) {
                  let index = nextRow.children.indexOf(nextCell);
                  newCell = nextRow.addCell(index);

                } else {
                  newCell = nextRow.addCell();
                }
                newCell.setRowSpan(c.rowSpan);
                newCell.setColSpan(c.colSpan);
              }
            }
          }
          i += colSpan;
        } else {
          break;
        }
      }
      tableRow.remove();
    }
    this.execParser();
  }
  removeColumn(index) {
    let colSpaned = {};
    let n = 0;
    while (n < this._matrix.length) {
      var row = this.getRow(n);
      let cell = this._matrix[n][index];
      if (cell) {
        let mindex = cell.attr("matrix_idx").split(",");
        let cellIndex = parseInt(mindex[1]);
        let colSpan = parseInt(cell.attr("colspan")) || 1;
        let rowSpan = parseInt(cell.attr("rowspan")) || 1;
        if (colSpan > 1) {
          let c = cell.data("Object");
          if (!colSpaned[c.id]) {
            c.colSpan--;
            if (c.colSpan < 1) {
              c.colSpan = 1;
            }
            c.setColSpan(c.colSpan);
            colSpaned[c.id] = c;
          }
        } else {
          let ctrl = cell.data("Object");
          ctrl.remove();
        }
        n += rowSpan;
      } else {
        break;
      }
    }

    var head_cells = this._handlers.table.children("THEAD").children("TR").children("TD");
    head_cells.eq(index).remove();

    this.execParser();
    this.refreshTableHead();
  }

  mergeCells(cells, rowSpan, colSpan) {
    mergeCells.call(this, cells, rowSpan, colSpan);
  }
  splitCells(cell) {
    splitCells.call(this, cell);
  }

  execParser() {
    Parser.call(this);
  }
}



export class TableLayoutRow extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    // this.id=this.table.id+"_"+this.id;
    this.selectabled = false;
    this._index = 0;
    this._table = null;
    this._desingerClass = null;
    this._dropIgnore = true;
    this.height = "57px";
  }

  get table() {
    return this._table;
  }
  set table(val) {
    this._table = val;
  }



  initTemplate() {
    return rowdom(this);
  }
  renderContext() {
    super.renderContext();
    this.element.attr("rowindex", this.index);
  }

  renderReady() {
    super.renderReady();
  }
  addCell(index) {
    if (index == undefined) {
      index = this.children.length;
    }
    let cell = new TableLayoutCell(null, true);
    this.addChild(cell, index);
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
    }
    return cell;
  }

  getHeight() {
    return this.element.height();
  }
  setHeight(val) {
    if (!isNaN(val)) {
      if (val < 10) {
        val = "57px";
      }
    }
    this.element.height(val);
    this.height = this.element.height() + "px";
    // this.children("TD").height(this.element.height());
  }
}

export class TableLayoutCell extends Container {
  constructor(id, isPart) {
    super(id, isPart);
    // this.id=this.table.id+"_"+this.id;
    this.selectabled = false;
    this._index = 0;
    this._desingerClass = null;
    // this._dropIgnore = true;
    this.$noPadding = true;
    this.width = null;
    this.rowSpan = 1;
    this.colSpan = 1;
    this.align = "left";
    this.vAlign = "middle";
  }

  initTemplate() {
    return celldom(this);
  }

  createElement() {
    var el = super.createElement();
    this.addClass("no_padding");
    return el;
  }

  renderContext() {
    super.renderContext();
    this.addStyle("text-align", this.align);
    this.addStyle("vertical-align", this.vAlign);
    // this.element.css("text-align", this.align);
    // this.element.css("vertical-align", this.vAlign);
  }

  setRowSpan(rowSpan) {
    this.rowSpan = rowSpan;
    if (this.element) {
      this.element.attr("rowspan", rowSpan);
    }
  }

  setColSpan(colSpan) {
    this.colSpan = colSpan;
    if (this.element) {
      this.element.attr("colspan", colSpan);
    }
  }
}



//将table解析成矩阵数组
function Parser() {
  let matrix = this._matrix = [];
  var tbody = this._handlers.table.children("tbody");
  var rows = tbody.children("tr");
  // let isInit = false;

  for (let i = 0; i < rows.length; i++) {
    matrix[i] = [];
  }
  for (let i = 0; i < rows.length; i++) {
    let cells = rows.eq(i).children("TD");
    let cellPos = 0;
    for (let n = 0; n < cells.length; n++) {
      let cell = cells.eq(n);
      let rowSpan = parseInt(cell.attr("rowspan")) || 1;
      let colSpan = parseInt(cell.attr("colspan")) || 1;

      for (let k1 = 0; k1 < colSpan; k1++) {
        while (matrix[i][cellPos]) {
          cellPos++;
        }
        if (k1 == 0) {
          cell.attr("matrix_idx", i + "," + cellPos);
          cell.attr("row-index", i);
          cell.attr("cell-index", cellPos)
        }
        for (let k = 0; k < rowSpan; k++) {
          matrix[i + k][cellPos] = cell;
        }
      }
    }
  }
  // if (this.columns.length == 0) {
  //     // isInit = true;
  //     for (let i = 0; i < matrix.length; i++) {
  //         for (var n = 0; n < matrix[i].length; n++) {
  //             var c = matrix[i][n];
  //             var colSpan = parseInt(c.attr("colspan")) || 1;
  //             // var rowSpan = parseInt(c.attr("rowspan")) || 1;
  //             if (colSpan == 1) {
  //                 if (!this.columns[n]) {
  //                     this.columns[n] = {
  //                         width: (c.get(0).style.width || "auto"),
  //                         fixed: c.get(0).style.width ? true : false
  //                     }
  //                 }
  //             }
  //         }
  //     }
  // } 
  var head_cells = this._handlers.table.children("THEAD").children("TR").children("TD");
  this.columns = [];
  for (let i = 0; i < head_cells.length; i++) {
    let head_cell = head_cells.eq(i);
    let fixed = head_cell.attr("fixed") == "true" ? true : false;
    let col = {
      fixed: fixed,
      width: fixed ? parseFloat(head_cells.get(i).style.width) : "auto",
    };
    if (head_cell.attr("new") == "true") {
      col.new = true;
    }
    this.columns.push(col)
  }
  var total = 100;
  var sum = 0,
    arr = [];
  for (let i = 0; i < this.columns.length; i++) {
    let c = this.columns[i];
    if (c.fixed) {
      sum += parseFloat(c.width);
    } else {
      arr.push(c);
    }
  }
  //做一次四舍五入避免产生99.9999999%的情况
  sum = parseInt(sum.toFixed(0));
  //如果固定宽度已经占满100 % 则从按比例平均分配,一般在添加列的时候会进入
  if (sum >= 100 && arr.length > 0) {
    let newSize = 100 / this.columns.length;
    for (let i = 0; i < this.columns.length; i++) {
      let c = this.columns[i];
      if (!c.new) {
        c.width = c.width * (sum - newSize) / 100;
      } else {
        c.width = newSize
      }
      c.fixed = true;
    }
  }
  //如果列宽不够,一般在删除列的时候进入
  else if (sum > 0 && sum < 100 && arr.length == 0) {
    let s = 0;
    for (let i = 0; i < this.columns.length; i++) {
      let c = this.columns[i];
      c.width = c.width * 100 / sum;
      c.fixed = true;
    }
  }
  //如果宽度有存在列宽是自适应的则从自适应的列宽中分配
  else {
    let surplus = total - sum;
    for (let i = 0; i < arr.length; i++) {
      arr[i].width = surplus / arr.length;
      arr[i].fixed = true;
    }
  }
}

function refreshTableHead() {
  let thead = this._handlers.table.children("THEAD");
  thead.html("");
  let tr = $("<TR>");
  for (let i = 0; i < this.columns.length; i++) {
    let td = $("<TD fixed='" + this.columns[i].fixed + "' style='height:0px'>");
    td.width(this.columns[i].width + "%");
    td.appendTo(tr);
  }
  tr.appendTo(thead);

}

function mergeCells(cells) {
  let maxRow = -1;
  let minRow = 99999;
  let maxCell = -1
  let minCell = 99999;
  for (let i = 0; i < cells.length; i++) {
    let cell = $(cells[i])
    let indexArr = cell.attr("matrix_idx").split(",");
    let rIndex = parseInt(indexArr[0]);
    let cIndex = parseInt(indexArr[1]);
    let rIndex1 = rIndex + (parseInt(cell.attr("rowspan")) || 1) - 1;
    let cIndex1 = cIndex + (parseInt(cell.attr("colspan")) || 1) - 1;
    if (rIndex < minRow) {
      minRow = rIndex;
    }
    if (rIndex1 > maxRow) {
      maxRow = rIndex1;
    }
    if (cIndex < minCell) {
      minCell = cIndex;
    }
    if (cIndex1 > maxCell) {
      maxCell = cIndex1;
    }
  }
  let rowSpan = maxRow - minRow + 1;
  let colSpan = maxCell - minCell + 1;
  let cellMain = $(cells[0]);
  let cellControl = cellMain.data("Object");
  cellControl.setRowSpan(rowSpan);
  cellControl.setColSpan(colSpan);
  for (let i = 1; i < cells.length; i++) {
    let cell = $(cells[i]);
    let control = cell.data("Object");
    control.remove();
  }
  this.execParser();
}

function splitCells(cells) {
  for (let i = 0; i < cells.length; i++) {
    let cell = $(cells[i]);
    let m_index = cell.attr("matrix_idx").split(",");
    let r_index = parseInt(m_index[0]);
    let c_index = parseInt(m_index[1]);
    let rowSpan = parseInt(cell.attr("rowspan")) || 1;
    let colSpan = parseInt(cell.attr("colspan")) || 1;
    if (rowSpan > 1 || colSpan > 1) {
      for (let n = r_index; n < (r_index + rowSpan); n++) {
        let r = this._matrix[n];
        let tableRow = this.getRow(n);
        let nextCellIndex = c_index + colSpan;
        let mark = false;
        while (!mark) {
          var nc = this._matrix[n][nextCellIndex];
          if (!nc) {
            break;
          }
          if (nc.parent().data("Object") != tableRow) {
            nextCellIndex++;
          } else {
            break;
          }
          if (nextCellIndex >= this._matrix[n].length) {
            break;
          }
        }
        let nextCell = this._matrix[n][nextCellIndex];
        for (let k = c_index; k < (c_index + colSpan); k++) {
          let c = r[k];
          if (n != r_index || k != c_index) {
            if (nextCell) {
              let index = tableRow.children.indexOf(nextCell.data("Object"));
              tableRow.addCell(index);
            } else {
              tableRow.addCell();
            }
          }
        }
      }
    }
    let ctrl = cell.data("Object");
    ctrl.setColSpan(1);
    ctrl.setRowSpan(1);
    this.execParser();
  }
}


function getNextCell(rIndex, cell) {
  let mIndex = cell.element.attr("matrix_idx").split(",");
  let colSpan = parseInt(cell.element.attr("colspan")) || 1;
  let rowIndex = parseInt(mIndex[0]);
  let cellIndex = parseInt(mIndex[1]) + colSpan;
  let tableRow = this.getRow(rIndex);
  let nextCell = null;
  for (var i = cellIndex; i < this._matrix[rIndex].length; i++) {
    let row = this._matrix[rIndex];
    var nc = row[i].data("Object");
    if (tableRow != nc.parent) {
      continue;
    } else {
      nextCell = nc;
      break;
    }
  }
  return nextCell;
}