import { Container } from './Container';
import { map } from '../../decorator/controlmap';

@map('HTML元素', 'dsf.htmlelement', 'HtmlElement')
export class HtmlElement extends Container {
  constructor(htmlText, isPart) {
    super(null, isPart);
    this.html = htmlText;
    this.isContainer = true;
    this.$innerHTML = "";
  }


  initTemplate() {
    return this.html;
  }
  createElement() {
    super.createElement();
    // this.element = $(this.html);
    if (!this.isContainer) {
      this.element.removeClass("ds_container");
    }
  }
  renderContext() {
    super.renderContext();
    if (this.innerHTML) {
      this.element.html(this.innerHTML)
    }

  }
  set innerHTML(value) {
    this.$innerHTML = value;
    if (this.element) {
      this.element.html(value);
    }
  }
  get innerHTML() {
    return this.$innerHTML;
  }

}