const dom = require("../../templates/FormFill.ejs");
import { FormControl } from "../../../../baseControls";
import { FormFillMetaData } from '../../../../core/metadata'
import { isSupportDataPost } from "../../../../core/postDecorator";
import {map} from  '../../../../decorator/controlmap';

const inputMinWidth = 60;
const inputMaxWidth = 300;
const placeholder = /\(\)|（）/gi;


@map('填空','dsf.formfill','FormFill')

@isSupportDataPost(true)
export class FormFill extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = FormFillMetaData.call(this);
        //值
        this.$value = "";
    }

    init() {
        super.init();
        let v = this.$value;
        if (this.$metadata && this.$metadata.valueAttributes.length == 1) {
            this.$value = v||"";
        } else if (this.$metadata && this.$metadata.valueAttributes.length > 1) {
            this.$value = {};
            for (let i = 0; i < this.$metadata.valueAttributes.length; i++) {
                let va = this.$metadata.valueAttributes[i];
                this.$value[va.code] = v[va.code]||"";
            }
        }
        v = null;
    }

    initTemplate() {
        return dom(this);
    }
    render() {
        super.render();
    }
    renderContext() {
        let _this = this;
        super.renderContext();
        let content = this.getContentHtml();
        if (this._handlers.content) {
            this._handlers.content.html("")
            this._handlers.content.append(content);
        }
        loadData.call(this, this.$value)
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this.renderContext();
        }
    }

    set value(value) {
        this.$value = value;
        loadData.call(this, value);
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
    }

    get value() {
        return this.$value;
    }

    getContentHtml() {
        // let reg = /\(\)|（）/gi;
        let count = 1;
        let content = ""
        let _this = this;
        if (this.questionBody) {
            let str = this.questionBody.replace(placeholder, function(a, b, c) {
                let key = "text_" + (count);
                let html = "";
                if (!_this.readOnly) {
                    html = "<input type='text' placeholder='请输入' class='filltext' index='" + count + "' autocomplete='off' name='" + key + "'/>";
                } else {
                    html = "<span class='filltext' index='" + count + "'  name='" + key + "'></span>";
                }
                count++;
                return html;
            });
            content = str;
        } else {
            content = "请配置填空内容";
        }
        return content;
    }

    resize() {
        super.resize();
    }

    initEvent() {
        let _this = this;
        super.initEvent();
        this.element.on("input", "input.filltext", function(evt) {
            let input = $(evt.target);
            inputReSize.call(_this, input);
            let content = input.val();
            if (_this.$metadata && _this.$metadata.valueAttributes.length == 1) {
                _this.$value = content;
            } else if (_this.$metadata && _this.$metadata.valueAttributes.length > 1) {
                if (!_this.$value || typeof(_this.$value) != "object") {
                    _this.$value = {};
                }
                _this.$value[input.attr("name")] = content;
            }
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this })
        });
        this.element.on("change.audit", "input.filltext", (evt)=> {
            this.commitAudit();
        })
    }

    createMetaData() {
        let m = super.createMetaData();
        if (m) {
            let meta = m.md;
            meta.valueAttributes = [];
            let inputs = this.element.find("input.filltext");
            inputs.each(function(i, el) {
                meta.valueAttributes.push({
                    "name": "文本" + (i + 1),
                    "code": "text_" + (i + 1),
                    "type": { text: "文本", value: "string" },
                    "length": "100",
                    "defaultValue": null,
                    "unit": null
                });
            })
            return m;
        }
        return null;
    }

    getTextString(){
        let idx=0;
        let arr=[];
        let content=""
        if(typeof(this.value)=="object"){
            for(let k in this.value){
                arr.push(this.value[k]||"");
            }
        }else{
            arr.push(this.value);
        }
        if (this.questionBody) {
            let str = this.questionBody.replace(placeholder, function(a, b, c) {
                let html = arr[idx];
                idx++;
                return html;
            });
            content = str;
        }
        return content;
    }
}

function loadData(value) {
    let tagname = "input";
    if (this.readOnly) {
        tagname = "span";
    }
    if (this.element) {
        if (typeof(value) == "string") {
            let input = this.element.find(tagname + "[name='text_1']");
            if (tagname == "input") {
                input.val(value);
                inputReSize.call(this, input);
            } else {
                input.text(value);
            }
        } else if (typeof(value) == "object") {
            for (let k in value) {
                if (this.element) {
                    let input = this.element.find(tagname + "[name='" + k + "']");
                    if (tagname == "input") {
                        input.val(value[k]);
                        inputReSize.call(this, input);
                    } else {
                        input.text(value[k]);
                    }
                    
                }
            }
        }
    }

}



function inputReSize(input) {
    let content = input.val();
    this._handlers.fontsize.html(content);
    let width = this._handlers.fontsize.width();
    if (width < inputMinWidth) {
        width = inputMinWidth;
    } else if (width > inputMaxWidth) {
        width = inputMaxWidth;
    }
    input.css("width", width + "px");
}