const dom = require("../../templates/Label.ejs");
import { Text } from '../../../../baseControls'
import { map } from '../../../../decorator/controlmap';

@map('文本', 'dsf.label', 'Label')
export class Label extends Text {
  constructor(id, isPart) {
    super(id, isPart);
    this.$htmlFor = "";
    this.$value = "文本标签";
    this.$useVdom = true;
    this.textAlign = "";
    this.fontFamily = "";
    this._editting = false;
    this.$required = false;
  }
  get htmlFor() {
    return this.$htmlFor;
  }
  set htmlFor(value) {
    this.$htmlFor = value;
    this.domUpdate();
  }
  set value(value) {
    super.value = value;
    this.domUpdate();
  }
  get value() {
    return super.value;
  }

  initTemplate() {
    return "<div></div>";
  }


  initTemplate() {
    return dom(this);
  }

  inserted() {
    if (this._root._isDesign) {
      this.element.off("dblclick");
      this.element.on("blur")
      this.element.on('dblclick', '.ds_control_design', () => {
        this._editting = true;
        this.domUpdate();
        this.element.find(".contenteditable").focus();
      })
      this.element.on("blur", ".contenteditable", (evt) => {
        this._editting = false;
        this.value = evt.target.innerHTML;
        this.domUpdate();
      })
    }
  }
}