const dom = require("../../templates/DataChoice.ejs");
import { ItemsControl } from '../../../../baseControls'
import { DataChoiceMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';
import * as ButtonPlugin from '../../../../pulgins/buttons';
import { FormControlEvent } from "../../../../core/ControlEvent";
import {map} from  '../../../../decorator/controlmap';
import { relyFiles } from "../../../../core/relyfiles";

@map('数据选择','dsf.datachoice','DataChoice')
@relyFiles([
    'res/libs/tagsinput/js/typeahead.bundle.js',
    'res/libs/tagsinput/js/tagsinput.min.js'
])
@isSupportDataPost(true)
export class DataChoice extends ItemsControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$placeholder = "请输入";
        this.label = "数据选择";
        this.value = [];
        this.$metadata = DataChoiceMetaData.call(this, 100);
        this.$dialogUrl = ""; //"http://192.168.1.122:8081/dsfa/dsfa/rm/views/rmlist.html?pid=e31357e71e2e43d5b1205fccdcd9d83b&ppath=";
        this.$dialoSize = "1000px,600px";
        // this.$dialogHeight = "600px";
        this.$dialogTitle = "请选择";
        this._buttonBar = ButtonPlugin.ButtonBar();
        this.maxTags = "";
        this._isTargetFormValueChange = true;
    }

    get label() {
        return super.label;
    }
    set label(value) {
        super.label = value;
    }

    set value(value) {
        if (value == undefined || value == null) {
            value = [];
        }
        if (typeof(value) == "string") {
            if (!value) {
                value = [];
            }
        }
        if (!$.isArray(value)) {
            value = [value];
        }
        let vcopy = value.slice(0);
        this._isTargetFormValueChange = false;
        this.clearTags(false);
        for (let i = 0; i < vcopy.length; i++) {
            let v = vcopy[i];
            if (JSON.stringify(v) != "{}") {
                if ((this.maxTags && i < parseInt(this.maxTags || 0)) || !this.maxTags) {
                    this.addTag(v);
                }
            }
        }
        this._isTargetFormValueChange = true;
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
    }
    get value() {
        return this.$value;
    }

    set placeholder(value) {
        this.$placeholder = value;
        if (this._handlers.input) {
            this._handlers.input.attr("placeholder", value);
        }
    }
    get placeholder() {
        return this.$placeholder;
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        if (!this.readOnly) {
            let buttonArg = this.$dialogUrl + ";" + this.$dialogTitle + ";" + (this.$dialoSize.split(",").join(";")) + ";" + this.$dialogHeight;
            let button = ButtonPlugin.createButton("选择", "system_datachoice_list_dialog", "icon-Magnifier", "auxiliary", 2, null, true, buttonArg);//返回弹出框属性参数
            if (this._buttonBar.buttons.length <= 0) {
                this._buttonBar.buttons.push(button);
            }
           
            ButtonPlugin.renderButtons(this, this._handlers.searchBox, this._buttonBar, null, null, "small");
        }

    }
    renderContext() {
        super.renderContext();
        if (this.disabled) {
            if (this._handlers.input) {
                this._handlers.input.prop("disabled", true);
            }
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
    }

    renderReady() {
        // let _this = this;
        super.renderReady();
    }
    renderComplete() {
        let _this = this;
        super.renderComplete();
        let trigger = _.debounce(function() {
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
            if(_this._handlers.input){
                _this._handlers.input.trigger("change");
            }
            _this.commitAudit();
        }, 200);

        if (this._handlers.input) {
            this._handlers.input.tagsinput({
                itemValue: 'value',
                itemText: 'text',
                freeInput: true,
                triggerChange:false,
                maxTags: this.maxTags || undefined
                    // typeaheadjs: {
                    //     // name: 'cities',
                    //     displayKey: 'text',
                    //     source:function(){
                    //         return [{item:"id"},{}]
                    //     }
                    // }
            });
            _this._isTargetFormValueChange = false;
            for (let i = 0; i < this.$value.length; i++) {
                this._handlers.input.tagsinput("add", this.$value[i]);
            }
            _this._isTargetFormValueChange = true;
            this.element.find(".ds_tagsinput>input").prop("readonly", true);

            this._handlers.input.on("itemAdded", evt => {
                _this.$value = _this._handlers.input.tagsinput('items');
                if (_this._isTargetFormValueChange) {
                    trigger();
                }
            });
            this._handlers.input.on("itemRemoved", evt => {
                _this.$value = _this._handlers.input.tagsinput('items');
                if (_this._isTargetFormValueChange) {
                    trigger();
                }
            });
            // this.value=this.value;
        }
        // this.event.on(DataChoiceEvent.OPENBEFORE,function(args,q){
        //     debugger;
        //     window.setTimeout(function(){
        //         alert('d')
        //         q.resolve(true);
        //     },1000)
        // });
        // this.event.on(DataChoiceEvent.OPENBEFORE,function(args,next){
        //     alert("c")
        //     next(true)
        // })
        // this.event.on(DataChoiceEvent.OPENBEFORE,function(args,next){
        //     alert("d")
        //     next(true)
        // })
    }

    clearTags(isTrigger) {
        if (this._handlers.input) {
            this._handlers.input.tagsinput('removeAll');
        }
        this.$value = [];
        if (isTrigger != false) {
            this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
            this.commitAudit();
        }

    }
    addTag(val) {
        if (this._handlers.input) {
            this._handlers.input.tagsinput('add', { "value": val.value, "text": val.text });
        } else {
            let result = this.$value.filter((v, i) => {
                if (v.value == val.value) {
                    v = val;
                    return true;
                }
                return false;
            });
            if (result.length <= 0) {
                this.$value.push(val);
            }
        }
    }
    remove() {
        if (this._handlers.input) {
            this._handlers.input.tagsinput('destroy');
        }
        super.remove();
    }

    getTextString(split) {
        let arr = [];
        for (let i = 0; i < this.value.length; i++) {
            arr.push(this.value[i].text);
        }
        return arr.join(",")
    }

    getValueString(split) {
        let arr = [];
        for (let i = 0; i < this.value.length; i++) {
            arr.push(this.value[i].value);
        }
        return arr.join(split || ",");
    }
}