const dom = require("../../templates/NavTree.ejs");
import { Tree } from '../other/Tree';
import { PageEvent } from '../../../../core/ControlEvent';
import { Action } from '../../../../core/pageAction';
import { TreeMetaData } from '../../../../core/metadata';
import { express } from '../../../../core/express';

import { map } from '../../../../decorator/controlmap';

@map('导航树', 'dsf.navtree', 'NavTree')
export class NavTree extends Tree {

  constructor(id, isPart) {
    super(id, isPart);

    this.$label = "标题";

    this.ztreeClass = "arrowsTree";

    this.pId = "";

    this.globalId = "";

    this.maxLevel = "";

    this.$metadata = TreeMetaData.call(this);

    // 查询条件
    this.$searchInfo = [];

    this.$defaultOrder = "";

    //浏览范围
    this.$browseScope = {
      "scope": "2",
      "unit": []
    }


    // 数据源类型
    this.metaDataType = 1;
    // 数据源元数据
    this.chooseMetaData = {};
    // 数据源自定义接口
    this.sql = null;
    // 异步数据源类型
    this.async_metaDataType = 0;
    // 异步数据源元数据
    this.async_chooseMetaData = {};
    // 异步数据源自定义接口
    this.async_sql = null;
  }
  initDesign() {
    this._zNodes = [{
      id: 1,
      pId: 0,
      open: "true",
      _name: "公文",
      children: [
        { id: 11, pId: 1, _name: "发文" },
        { id: 12, pId: 1, _name: "收文" },
        { id: 110100000000, pId: 1, _name: "签报" },
      ]
    }, {
      id: 2,
      pId: 0,
      open: "true",
      _name: "报销",
      children: [
        { id: 21, pId: 2, _name: "日常报销" },
        {
          id: 22,
          pId: 2,
          open: "true",
          _name: "项目报销",
          children: [
            { id: 221, pId: 22, _name: "内部项目" },
            { id: 222, pId: 22, _name: "外部项目" }
          ]
        }
      ]
    }]
  }
  initTemplate() {
    return dom(this);
  }
  set label(value) {
    this.$label = value;
    this._handlers.title.text(value);
  }
  get label() {
    return this.$label;
  }
  set defaultOrder(value) {
    this.$defaultOrder = value;
  }
  get defaultOrder() {
    return this.$defaultOrder;
  }
  set rootId(value) {
    this.pId = value;
  }
  get rootId() {
    return this.pId;
  }
  renderData() {
    let _this = this;
    if (!_this.root._isDesign) {
      if (_this.maxLevel && (_this.defaultOpenSeries || 0) * 1 > (_this.maxLevel || 0) * 1) {
        _this.defaultOpenSeries = _this.maxLevel;
      }
      loadData.call(_this);
    }
  }
  loadData(data) {
    this._zNodes = data;
    if (this.setting.async.enable) {
        this.setting.async = {
          enable: true,
          url: dsf.UrlSetting.tree_load_async,
          otherParam: {
            metaFullCode: this.metadata_fullcode,
            pageName: this.root.$name,
            namespace: this.root.nameSpace,
            maxLevel: this.maxLevel
          },
          type: "get",
          autoParam: ["_id=pid"],
          dataFilter: this.asyncDataFilter.bind(this)
        }
    }
    super.initTree();
  }

  createMetaData() {
	let controlCode = this.$caption;
	this.metadata.code = controlCode;
	this.metadata.name = this.metadata.name || this.label;
	this.metadata.level = 0;
	let key = this.root.scope;
	
	if(this.async_metaDataType * 1===1 && this.async_chooseMetaData.id){
	  this.metadata.id = this.async_chooseMetaData.at + '.' + controlCode;
	  this.metadata.at = this.async_chooseMetaData.at;
	  key = this.metadata.at.split('.').join('_');
	}else{
		let ns = this.root.scope;
		this.metadata.id = ns.replace(/\_/g, '.') + "." + controlCode;
		let path = ns.replace(/\_/g, '.');
		this.metadata.at = path;
	}
	key += "." + controlCode;
	this.metadata_fullcode = key;
	
	return { "key": this.metadata_fullcode, "md": this.metadata };
  }

  changeMetaDataType() {
    $.fn.zTree.destroy(this.id + '_tree');
    loadData.call(this);
  }
}

//数据加载
function loadData() {
  let metaDataType = this.metaDataType * 1;
  // 元数据组 || 自定义接口
  if ((metaDataType === 2 && (this.chooseMetaData.id || this.chooseMetaData.rmId)) || (metaDataType === 3 && this.sqlUrl)) {
    let layerIndex_action = dsf.layer.loadding();
    let _this = this;
    /**
     * dbSource：数据源获取树
     * getTreeByName： 元数据获取树
     * treeSelector： 自己写的方法
     */
    let action = metaDataType === 2 ? (this.chooseMetaData.TabNum == 1 ? 'dbSource' : 'getTreeByName') : 'treeSelector';
    if (Action[action]) {
      let exp = dsf.Express;
      let url = this.sqlUrl ? exp.replace(this.sqlUrl) : "";
      let param = {
        id: this.chooseMetaData.id,
        url: url,
        rmId: this.chooseMetaData.rmId,
        self: this,
        pageName: this.root.$name,
        namespace: this.root.nameSpace
      }
      if (this.setting.async.enable) {
        param.openLevel = (!this.defaultOpenSeries || this.defaultOpenSeries <= 1) ? 1 : this.defaultOpenSeries;
      }
      Action[action](param, (err, data) => {
        if (err) {
          dsf.layer.message(dsf.prompt.loaddatafail, false);
        } else {
          _this.loadData(data);
        }
        setTimeout(function() {
          dsf.layer.close(layerIndex_action);
        }, 1000)
      });
    } else {
      dsf.layer.message("接口地址不存在", 5);
    }
  } else {
    let param = {
      pid: this.pId,
      metaFullCode: this.metadata_fullcode,
      pageName: this.root.$name,
      namespace: this.root.nameSpace,
      globalIdValue: this.globalId,
      $searchInfo: this.$searchInfo,
      maxLevel: this.maxLevel,
      $defaultOrder: this.$defaultOrder
    }
    if (this.setting.async.enable) {
      param.openLevel = (!this.defaultOpenSeries || this.defaultOpenSeries <= 1) ? 1 : this.defaultOpenSeries;
    }

    Action.tree_load(param, (err, data) => {
      if (err) {
        dsf.layer.message(dsf.prompt.loaddatafail, false);
      } else {
        this.loadData(data);
      }
    });
  }
}