const dom = require("../../templates/Datepicker.ejs");
import {
    FormControl
} from '../../../../baseControls'
import {
    DateMetaData
} from '../../../../core/metadata'
import {
    isSupportDataPost
} from '../../../../core/postDecorator';

import {map} from  '../../../../decorator/controlmap';

@map('日期','dsf.datepicker','Datepicker')

@isSupportDataPost(true)
export class Datepicker extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        let d = new Date();
        this.$label = "";
        this.$showLabel = true;
        this.$showBottom = true;
        this.$timeFormat = "1";
        this.$metadata = DateMetaData.call(this);
        this.$chooseType = "date"
        this.lable = "日期选择"
        this.$hourStep = '10';
        this.$isShowNow = false;
		this.isZodiac=false;//是否通过生肖选择日期，仅供移动端使用
		this.isInput = false;//是否输入，仅供移动端使用
    }
    set value(val) {
        if (val != null && val != undefined && val != "") {
            this.$value = val;
            // let timeFormat = this.timeFormat.toLowerCase()
            // if (this.$chooseType == "datetime") {
            //     timeFormat = timeFormat + ' hh:ii'
            // } else if (this.$chooseType == "datetime_s") {
            //     timeFormat = timeFormat + ' hh:ii:ss'
            // }
            if (val) {
                let format_d = getFormatDateValue.call(this, val, this.timeFormat);
                if (this._handlers.readonlyBlock) {
                    this._handlers.readonlyBlock.text(this.getTextString());
                }
                if (this._handlers.picker) {
                    this._handlers.picker[0].value = format_d;
                }
            } else {
                this._handlers.picker[0].value = ""
            }
        }
    }
    get value() {
        return this.$value
    }
    set label(value) {
        this.$label = value;
    }
    get label() {
        return this.$label;
    }

    get timeFormat() {
        let formatDir = {
            1: 'yyyy-MM-dd',
            2: 'yyyy年MM月dd日',
            3: 'yyyy年MM月',
            4: 'M月d日',
            5: 'yyyy年'
        }
        let format = formatDir[this.$timeFormat]
        return format
    }

    set showLabel(value) {
        this.$showLabel = value;
        if (!value) {
            this.addClass("hideLabel")
        } else {
            this.removeClass("hideLabel")
        }
    }
    get showLabel() {
        return this.$showLabel;
    }

    get defaultTime() {
        let d = new Date();
        let month = null;
        let date = d.getDate();
        let defaultTime = ""
        let nowMonth = parseInt(d.getMonth() + 1);
        let nowDate = parseInt(d.getDate())
        month = formatNumber(nowMonth);
        date = formatNumber(nowDate);
        if (this.$chooseType == 'month') {
            this.$showBottom = true;
            if (this.$timeFormat == 2 || this.$timeFormat == 4) {
                this.$timeFormat = 3;
            }
            defaultTime = d.getFullYear() + '-' + month
        } else {
            defaultTime = d.getFullYear() + '-' + month + '-' + date;
        }
        return defaultTime
    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
    }

    setMin (date){
        if(date&&this.$dateCtrl) this.$dateCtrl.config.min = {
            year: date.getFullYear(),
            month: date.getMonth(),
            date: date.getDate(),
            hours: date.getHours(),
            minutes: date.getHours(),
            seconds: date.getSeconds()
        }
    }

    setMax (date){
        if(date&&this.$dateCtrl) this.$dateCtrl.config.max = {
            year: date.getFullYear(),
            month: date.getMonth(),
            date: date.getDate(),
            hours: date.getHours(),
            minutes: date.getHours(),
            seconds: date.getSeconds()
        }
    }

    renderContext() {
        // this.value = "2019-09-03 00:00:00"
        super.renderContext();
        let format_d = getFormatDateValue.call(this, this.value, this.timeFormat);
        if (this._handlers.readonlyBlock) {
            this._handlers.readonlyBlock.text(this.getTextString());
        }
        if (this._handlers.picker) {
            this._handlers.picker[0].value = format_d;
        }

        if (this._handlers.label) {
            this._handlers.label.html(this.$label)
        }
        if (this._handlers.picker) {
            if (this.readOnly) {
                $(this._handlers['picker'][0]).attr("disabled", 'disabled')

            } else {
                $(this._handlers['picker'][0]).removeAttr("disabled")
            }
        }

    }
    initEvent() {
        let that = this;
        changeDateTimeStyle.call(that) //“日期时间”类型时，修改时间样式，根据定时器找到dom

        if (!this.$metadata.defaultValue) this.$metadata.defaultValue = this.defaultTime
        if (!this.readOnly) {
            let format_d = getFormatDateValue.call(this, that.value, this.timeFormat)
            this.$dateCtrl = layui.laydate.render({
                elem: '#d_' + that.id,
                value: format_d,
                isInitValue: true,
                type: that.$chooseType,
                calendar: that.$calendar,
                showBottom: that.$showBottom,
                trigger: 'click',
                min: that.$isShowNow ? that.minDate() : '1900-1-1',
                format: that.$chooseType == 'datetime' ? that.timeFormat + ' HH:mm' : that.$chooseType == "datetime_s" ? that.timeFormat +
                    'HH:mm:ss' : that.timeFormat,
                position: 'fixed',
                ready: function(date) {
                    console.log(date)
                    if (that.$isShowNow) {
                        var d = new Date()

                        this.$dateCtrl.config.min = {
                            year: d.getFullYear(),
                            month: d.getMonth(),
                            date: d.getDate(),
                            hours: d.getHours(),
                            minutes: d.getHours(),
                            seconds: d.getSeconds()
                        }
                    }

                    changeDateTimeStyle.call(that)
                },
                done: function(value, date, endDate) {
                    let wholeVal = date.year + '-' + date.month + '-' + date.date + " " + date.hours + ":" + date.minutes + ":00"
                    that.$value = dsf.date.format(wholeVal, 'yyyy-mm-dd hh:ii:ss')
                    that.event.trigger(FormControlEvent.VALUECHANGE, {
                        ui: that
                    });
                    that.commitAudit();
                }
            });
        } else {
            this._handlers.readonlyBlock.text(this.getTextString());
        }

    }
    renderReady() {
        super.renderReady();
    }
    getTextString(split) {
        return getFormatDateValue.call(this, this.value, this.timeFormat);
    }
    setControlId() {
        return this.id
    }
    minDate() {
        let now = new Date()
        return now.getFullYear() + '-' + (now.getMonth() + 1) + '-' + now.getDate()

    }
}

function formatNumber(n) {
    n = n.toString()
    return n[1] ? n : '0' + n
}


function getFormatDateValue(d, format) {
    let timeFormat = this.timeFormat.toLowerCase();
    if (this.$chooseType == "datetime") {
        timeFormat = timeFormat + ' hh:ii'
    } else if (this.$chooseType == "datetime_s") {
        timeFormat = timeFormat + ' hh:ii:ss'
    }
    if (d) {
        return dsf.date.format(d, timeFormat)
    }
    return d;
}

function changeDateTimeStyle() {
    let _this = this;
    if (_this.$chooseType == 'datetime') {
        if (this.$timeInter) {
            let timeInterval = this.$timeInter
            var minHour = $.trim(timeInterval.split("-")[0])
            var maxHour = $.trim(timeInterval.split("-")[1])
        }
        _this.count = window.setInterval(function() {
            if ($("body").find(".laydate-time-show").length > 0) {
                // console.log(count)
                var showtime = $($(".laydate-time-list li ol")[1]).find("li");
                var showhour = $($(".laydate-time-list li ol")[0]).find("li")
                for (var i = 0; i < showtime.length; i++) {
                    var t00 = parseInt(showtime[i].innerText);
                    var step = parseInt(_this.$hourStep)
                    if (t00 % step != 0) {
                        showtime[i].remove()
                    }
                }
                for (var k = 0; k < showhour.length; k++) {
                    var h00 = parseInt(showhour[k].innerText);
                    minHour = parseInt(minHour);
                    maxHour = parseInt(maxHour);
                    if (h00 < minHour || h00 > maxHour) {
                        // showhour[k].remove()
                        $(showhour[k]).css({
                            "pointer-events": "none",
                            "color": "#ddd"
                        })
                    }
                }
                $($(".laydate-time-list li ol")[2]).find("li").remove(); //清空秒
            }
        }, 800)
    }
}