//加载数据行
function renderDataRow(rowData, index) {
  // console.time("datagrid加载数据")
  let _this = this;
  let row = this.$tableTemplate.createControlByTemplate(rowData, index);
  if (rowData._id != undefined) {
    row.id = "row_" + rowData._id;
  }
  this.addChild(row, null, "datagrid_body_tobdy");

  row.element.data("data", rowData);
  row.element.attr("row_index", index);
  row.element.attr("data", 1);
  let rowHeight = row.element.outerHeight();
  row.element.css("height", rowHeight);

  // 兼容老版本的没有宽度样式的代码
  row.element.find(".ds_datagrid_data_col").each(function(i, el) {
    $(el).children().removeAttr("style");
  });

  let td = row.element.find(".ds_datagrid_operate_cell");
  let div = td.children("div");
  let buttons = ButtonPlugin.renderButtons(this, div, this.$rowbuttonBar, rowData, "row", "small");
  buttons.addClass("nowrap");

  let checkboxId = "check_" + row.id;
  //锁头锁列
  let ftr = $("<tr row_index='" + index + "' data='1'/>");
  ftr.data("data", rowData);

  if (this.$checkboxColumn) {
    let td = $("<td class='ds_datagrid_check_cell'><div style='width:" + (this.$checkboxColumn.width + "px") +
      "'><input id='" + checkboxId + "' value='" + (rowData ? rowData._id : "") +
      "' class='rowcheckbox' lay-filter='" + checkboxId + "' type='checkbox' name='" + this.id +
      "' lay-skin='primary' /></div></td>");
    this.$checkboxColumn.hide == "1" ? td.addClass("ds_hide") : td.removeClass("ds_hide");
    ftr.append(td);
  }
  if (this.$indexColumn) {
    let rowIndex = (index + 1) + (_this.$limit * (_this._curr - 1));
    let td = $("<td class='ds_datagrid_index_cell no_padding '><div class='ds_datagrid_index_centext ellipsis'>" + (
      rowIndex) + "</div></td>");
    this.$indexColumn.hide == "1" ? td.addClass("ds_hide") : td.removeClass("ds_hide");
    ftr.append(td);
  }

  ftr.css("height", rowHeight);
  // if (this.$showCheckBox) {
  //     let td = "<td class='ds_datagrid_check_cell'><input id='" + checkboxId + "' value='" + (rowData ? rowData._id : "") + "' class='rowcheckbox' lay-filter='" + checkboxId + "' type='checkbox' name='" + this.id + "' lay-skin='primary' /></td>";
  //     ftr.append(td);
  //     ftr.css("height", row.element.outerHeight())
  // }
  this._handlers.fx_left_body_tobdy.append(ftr);

  let rtr = $("<tr  row_index='" + index + "' data='1'/>");
  if (this.$operateColumn) {
    let td = $("<td></td>");
    td.addClass("ds_datagrid_operate_cell");
    this.$operateColumn.hide == "1" ? td.addClass("ds_hide") : td.removeClass("ds_hide");
    let div = $("<div></div>").appendTo(td);
    div.css("width", this.$operateColumn.width - 1);

    let buttons = ButtonPlugin.renderButtons(this, div, this.$rowbuttonBar, rowData, "row", "small");
    buttons.addClass("nowrap");
    div.css("text-align", this.$operateColumn.bodyAilgn);
    this.$operateColumn.hide == "1" ? td.addClass("ds_hide") : td.removeClass("ds_hide");
    rtr.append(td);
    rtr.css("height", rowHeight)
  }

  this._handlers.fx_right_body_tobdy.append(rtr);
  this._rows.push(row);

  if (rowData.$$checked) {
    $("#" + checkboxId).prop("checked", true);
  }
  layui.form.on("checkbox(check_" + row.id + ")", obj => {
    rowData.$$checked = obj.elem.checked;
    checkBoxChecked.call(this, rowData, true);
  });

  this.event.trigger(DataGridEvent.ROWRENDER, {
    "ui": this,
    "row": row,
    "fixed_left": ftr,
    "rightrow": rtr,
    "data": rowData
  });

  let enter = function() {
    ftr.addClass("hover");
    rtr.addClass("hover");
    row.element.addClass("hover");
  }
  let leave = function() {
    ftr.removeClass("hover");
    rtr.removeClass("hover");
    row.element.removeClass("hover");
  }
  ftr.hover(enter, leave);
  ftr.hover(enter, leave)
  row.element.hover(enter, leave)
  return row;
}

function renderDataCard(rowData, index, row, marginLeft) {
  let _this = this;
  let card = this.$cardTemplate.createControlByTemplate(rowData, index);
  if (rowData._id != undefined) {
    card.id = "card_" + rowData._id;
  }
  // console.time("卡片创建");
  card.addStyle("margin-left", marginLeft);
  card.addStyle("max-width", "100%");
  card.checkabled = !(_this.$checkboxColumn.hide == "1");
  card.checked = !!rowData.$$checked;
  row.addChild(card);
  card.element.data("data", rowData);
  let _data = _this._cardConfig.data;
  if (this.$rowbuttonBar.buttons.length > 0 && this.$operateColumn.hide != "1") {
    card.showButtonBar = true;
    let _rowData = _data[index];
    if (_this._currentShowType == 'card' && !_this.cardShowPag) {
      _rowData = _this._cardConfig.data[index];
    } else if (_this._currentShowType == 'card') {
      _rowData = _data[index];
    }
    let buttons = ButtonPlugin.renderButtons(this, card._handlers.buttonbars, this.$rowbuttonBar, _rowData, "row",
      "big");
    buttons.addClass("nowrap");
  } else {
    card.showButtonBar = false;
  }
  card.event.on(CardEvent.CHECKED, evt => {
    rowData.$$checked = evt.checked;
    checkBoxChecked.call(this, rowData, true);
  });
  this._cards.push(card);
  // console.timeEnd("卡片创建")
  return card
}

