//监听操作栏目
function watchoperateCell() {
  let borderSize = 1;
  let hasScroll_Y = getScrollWidth.call(this); //(this._handlers.datagrid_body_tobdy.get(0).offsetHeight - this._handlers.datagrid_body.get(0).clientHeight) > 0;
  // let scrollHeight = 0;
  // if (hasScroll_Y) {
  //     scrollHeight = hasScroll_Y
  // }
  let op_cell = this._handlers.datagrid_head_tobdy.find(".ds_datagrid_operate_cell");
  if (op_cell.length > 0) {
    let outerWidth = this._handlers.wrap.width() - borderSize;
    let pos = op_cell.position().left + op_cell.width();
    if (pos > outerWidth) {
      this._handlers.datagrid_fixed_right.show();
      this._handlers.datagrid_fixed_right.css("right", hasScroll_Y - borderSize);
    } else {
      this._handlers.datagrid_fixed_right.hide();
    }
  }
}


//重新加载数据
function loadData() {
  let _this = this;
  if (!_this.customGetData) {
    let q = dsf.queue(true);
    q.step((def, v) => {
      _this._cardConfig.loading = true;
      Action.list_load(_this, (err, data, res) => {
        _this._cardConfig.loading = false;
        if (err) {
          let message = err.code == '20001' ? dsf.prompt.loaddatafail : err.message;
          dsf.layer.message(message, false);
          def.reject();
        } else {
          _this.loadData(data, res);
          def.resolve();
        }
      });
    });
    q.step((def, v) => {
      Action.list_count(_this, (err, data) => {
        if (err) {
          let message = err.code == '20001' ? dsf.prompt.loaddatafail : err.message;
          dsf.layer.message(message, false);
        } else {
          _this.count = parseInt(data.count);
        }
        _this.renderCustomerOrderBy();
      });
      def.resolve();
    })
    q.exec();
  } else {
    _this.getDataSource();
  }

}

