function checkBoxChecked(data, isSingleValidate) {
  let _this = this;
  if (isSingleValidate && this.$isSingleChecked) {
    //如果是单选，先清空以前所有的选项
    let _data = $.isArray(data) ? data : [data];
    let index = _.findIndex(_data, o => o.$$checked);
    if (index >= 0) {
      _.each(this._checkedRows, o => {
        o.$$checked = false;
        delete this._checkedRows[o._id]
        //列表勾选清空
        let rowCheckBox = $("#check_row_" + o._id);
        rowCheckBox.prop("checked", o.$$checked);
        //卡片勾选清空
        let card = _this.root.getControlById("card_" + o._id);
        if (card) {
          card.checked = o.$$checked;
        }
        //概览列表清空
        let itemCheckBox = $("#check_item_" + o._id);
        itemCheckBox.prop("checked", o.$$checked);
      });
    }

  }
  //同步选择框
  watchCheckedRow.call(this, data);
  let count = 0
  let _data = this._currentShowType=="card" ? this._cardConfig.data : this._data;
  for (let i = 0; i < _data.length; i++) {
    if (_data[i].$$checked) {
      count++;
    }
  }
  if (_data && _data.length > 0) {
    _data.length == count ? this.element.find("input.checkall").prop("checked", true) : this.element.find(
      "input.checkall").prop("checked", false);
    _data.length == count ? $("#check_" + this.id + "_card_all").prop("checked", true) : $("#check_" + this.id +
      "_card_all").prop("checked", false);
    _data.length == count ? $("#check_" + this.id + "_imglist_all").prop("checked", true) : $("#check_" + this.id +
      "_imglist_all").prop("checked", false);
  }
  dsf.UI.render("checkbox", true);
  // layui.form.render("checkbox");
  refreshCheckedNumer.call(this);
}

