//监听选中
function watchCheckedRow(data) {
  if (!data) {
    return;
  }
  data = $.isArray(data) ? data : [data];
  for (let i = 0; i < data.length; i++) {
    let d = data[i];
    let rowCheckBox = $("#check_row_" + d._id)
    if (rowCheckBox.length > 0) {
      rowCheckBox.prop("checked", d.$$checked);
    }
    let itemCheckBox = $("#check_item_" + d._id)
    if (itemCheckBox.length > 0) {
      itemCheckBox.prop("checked", d.$$checked);
    }

    let card = this.root.getControlById("card_" + d._id);
    if (card) {
      card.checked = d.$$checked
    }
    // let item = this.root.getControlById("item_" + d._id);
    if (d.$$checked) {
      this._checkedRows[d._id] = d;
    } else {
      delete this._checkedRows[d._id];
    }
  }
  dsf.UI.render("checkbox", true);
}

