function setColumnWidth(index, width, totalWidth, callback) {
  var style = this._handlers.colStyle.get(0);
  var sheet = style.sheet || style.styleSheet || {};
  var rules = sheet.cssRules || sheet.rules;
  var cssName = "." + this._classStart + index;
  // var total=this._handlers.outer.width() - 3;
  for (var i = 0; i < rules.length; i++) {
    var rule = rules[i];
    if (rule.selectorText != cssName) {
      continue;
    }
    if (width.toString().indexOf("%") > 0) {
      let w = totalWidth * (parseFloat(width) / 100);
      rule.style.width = parseFloat(w - 1) + "px";
      return w;
    } else {
      rule.style.width = parseFloat(width - 1) + "px";
      return width;
    }
  }
}

function getScrollWidth(type) {
  type = type || "vertical";
  let datagridBody = this._handlers.datagrid_body.get(0);
  let width = 0;
  //计算滚动条厚度
  if (type == "vertical" && datagridBody.scrollHeight > datagridBody.clientHeight) {
    //如果内容大于高度则有滚动条
    width = datagridBody.offsetWidth - datagridBody.clientWidth;
  } else if (type == "horizontal" && datagridBody.scrollWidth > datagridBody.clientWidth) {
    width = datagridBody.offsetHeight - datagridBody.clientHeight;
  }
  return width;
}


function getUrlParams(name) { // 不传name返回所有值，否则返回对应值
  var url = window.location.search;
  if (url.indexOf('?') == 1 || url == '') return;
  url = url.substr(1);
  url = url.split('&');
  var name = name || '';
  var nameres;
  // 获取全部参数及其值
  for (var i = 0; i < url.length; i++) {
    var info = url[i].split('=');
    var obj = {};
    obj[info[0]] = decodeURI(info[1]);
    url[i] = obj;
  }
  // 如果传入一个参数名称，就匹配其值
  if (name) {
    for (var i = 0; i < url.length; i++) {
      for (const key in url[i]) {
        if (key == name) {
          nameres = url[i][key];
        }
      }
    }
  } else {
    nameres = url;
  }
  // 返回结果
  return nameres;
}
