const dom = require("../../templates/DisposeIdea.ejs");
import {
	map
} from '../../../../decorator/controlmap';
import {
	TextBox
} from '../Form/TextBox';

@map('处理意见', 'dsf.disposeidea', 'DisposeIdea')
export class DisposeIdea extends TextBox {
	constructor(id, isPart) {
		super(id, isPart);
		this.$allowPost = false;
		this.$metadata = null;
		this.uploadCtrl = null;
		this._uploadCaption = 'ds_disposeIdea_uploadFile';

		this._sPID = dsf.url.queryString('sPID') || '';
		this._sCurLinkID = dsf.url.queryString('sCurLinkID') || '';
	}

	initTemplate() {
		this.$readOnly = false;
		return dom(this);
	}

	renderComplete() {
		super.renderComplete();
		let _this = this;
		if (!this.root._isDesign) {
			if (!this._sPID || !this._sCurLinkID) {
				this.visible = false;
				if (!page.preview) {
					return
				}
			}
			bindTempChange.call(this);
			bindUpload.call(this);
			this.root.event.on(PageEvent.GetFlowProcess, datas => {
				for (let i = datas.length - 1; i >= 0; i--) {
					let data = datas[i];
					if (data.linkid == _this._sCurLinkID && data.pid == _this._sPID) {
						if (data.STATUS != 0 && data.STATUS != 1) {
							// 应处理的环节
							this.visible = false;
							this._root.event.on(PageEvent.READY, () => {
								this._root.element.find('[ds-event="system_flow_sendBack"]').hide();
								this._root.element.find('[ds-event="system_flow_send"]').hide();
							});
							break;
						}
						if (data.opinionatts) {
							let opinionatts = JSON.parse(data.opinionatts);
							_this.value = opinionatts.Content;
							_this.uploadCtrl.value = opinionatts.Attachments || [];
							break;
						}
					}
				}
			})
		}
	}

	saveBeforeAction(def, v, opts) {
		if (opts.btnType === 'flowSend' || !this.visible) {
			def.resolve();
		} else {
			let _this = this;
			let param = {
				sPID: _this._sPID,
				sCurLinkID: _this._sCurLinkID,
				sOpinion: {
					'Content': _this.value,
					'Attachments': []
				}
			}
			if (this.uploadCtrl) {
				let datas = this.uploadCtrl.multipleFiles;
				_.each(datas, (data) => {
					param.sOpinion.Attachments.push(data);
				})
			}
			param.sOpinion = JSON.stringify(param.sOpinion);
			dsf.http.request(dsf.url.getWebPath('wfr/opinion'), param, 'get')
				.done(res => {
					console.log(res)
					if (res.success) {
						def.resolve();
					} else {
						dsf.layer.message(res.message || (_this.label || '处理意见') + '异常', false)
						def.reject();
					}
				})
				.error(res => {
					dsf.layer.message((_this.label || '处理意见') + '异常', false)
					def.reject();
				})
				.exec();
		}
	}
}

function bindTempChange() {
	let _this = this;
	let $tempBtn = _this._handlers.tempBtn;
	if ($tempBtn) {
		let $tempUl = _this._handlers.tempUl;
		dsf.http.request(dsf.url.getWebPath('wfr/getOpinionKeyWord'), {}, 'get')
			.done(res => {
				if (res.success && res.data.length > 0) {
					let temp = '';
					_.each(res.data, (li) => {
						temp += '<li title="' + li.key_word + '">' + li.key_word + '</li>';
					})
					$tempUl.html(temp);
					$tempBtn.on('click', (evt) => {
						$tempBtn.closest('.btns').toggleClass('showTemp');
					})
					$tempUl.on('click', 'li', (_evt) => {
						_this.value = $(_evt.target).attr('title');
						$tempUl.closest('.btns').toggleClass('showTemp');
					})
				} else {
					$tempUl.hide();
				}
			})
			.error(res => {
				$tempUl.hide();
			})
			.exec();
	}
}

function bindUpload() {
	let _this = this;
	if (!_this.uploadCtrl) {
		_this.uploadCtrl = new dsf.Controls.UploadFile(_this.id + '_disposeIdea_uploadFile', false);
		_this.uploadCtrl.label = '';
		_this.uploadCtrl.$allowPost = false;
		_this.uploadCtrl.showLabel = _this.showLabel;
		_this.uploadCtrl.readOnly = _this.readOnly;
		_this.uploadCtrl.addClass('ds_disposeIdea_uploadFile');
		if (_this.tbNoPadding) {
			_this.uploadCtrl.addClass('needTop');
		}
		_this.parent.addChild(_this.uploadCtrl, _this.index + 1);
	}
	if (this._handlers.uploadBtn) {
		this._handlers.uploadBtn.on('click', (evt) => {
			$('#uf_' + _this.id + '_disposeIdea_uploadFile').trigger("click");
		})
	}
}
