import { Control } from '../../../../baseControls';
import { ControlEditor } from '../../../../editor/ControlEditor';
import { map } from '../../../../decorator/controlmap';
let cache = {};

@map('HTML', 'dsf.customer', 'Customer')
export class Customer extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$htmlTemplate = "<div></div>";
    this._data = null;
    this._cacheKey = "";
    this._isCustomerControl = true;
  }
  initTemplate() {
    if (!this.$htmlTemplate || this.root._isDesign) {
      return "<div></div>";
    }
    try {
      let t = null;
      if (this._cacheKey) {
        if (!cache[this._cacheKey]) {
          t = ejs.compile(this.$htmlTemplate);
          cache[this._cacheKey] = t;
        } else {
          t = cache[this._cacheKey];
        }
      } else {
        t = ejs.compile(this.$htmlTemplate);
      }
      return t({ "data": this._data || {} });
    } catch (ex) {
      return "<div>" + ex.message + "</div>"
    }

  }

  set data(value) {
    this._data = value;
    if (this.element) {
      if (this.$htmlTemplate || this.root._isDesign || !this._data) {
        this.render();
      }
    }

  }

  createElement() {
    super.createElement();
  }

  render() {
    // console.time("创建模板");
    super.render();
    // console.timeEnd("创建模板");
  }
}