const dom = require("../../templates/SystemFormControl.ejs");
import { FormControl } from "../../../../baseControls";
import { isSupportDataPost } from '../../../../core/postDecorator';
import { map } from '../../../../decorator/controlmap';

@map('系统用户', 'dsf.systemuser', 'SystemUser')
@isSupportDataPost(false)
export class SystemUser extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
  }

  initTemplate() {
    return dom(this);
  }

  set value(value) {
    super.value = value;
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(value)
    }
  }
  get value() {
    return super.value;
  }

  getTextString() {
    return this.value;
  }
  getValueString() {
    return this.value;
  }
}