const dom = require("../../templates/CheckBox.ejs");
import { ItemsControl } from '../../../../baseControls';
import { FormControlEvent } from '../../../../core/ControlEvent'
import { isSupportDataPost } from '../../../../core/postDecorator';
import { map } from '../../../../decorator/controlmap';

@map('多选框', 'dsf.checkbox', 'CheckBox')

@isSupportDataPost(true)
export class CheckBox extends ItemsControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.label = "多选框";
        this.maxChooseNum = null;
        // this.value = [];

        this.$showModel = "none";
        this.$placeholder = "请输入";
        this.$readOnlyShowText = "text"
    }

    set value(value) {
        if (value == undefined || value == null) {
            value = [];
        }
        if (!$.isArray(value)) {
            value = [value];
        }
        this.$value = [];
        for (let i = 0; i < value.length; i++) {
            let v = value[i];
            if (typeof(v) == "string" || typeof(v) == "number") {
                for (let i = 0; i < this._items.length; i++) {
                    if (this._items[i].value == v) {
                        this.$value.push(this._items[i]);
                    }
                }
            } else if (typeof(v) == "object") {
                for (let i = 0; i < this._items.length; i++) {
                    let o = this._items[i];
                    if (o.value == v.value) {
                        if (v.attach_text) {
                            o.attach_text = v.attach_text;
                        }
                        this.$value.push(o);
                    }
                }
            }
        }
        if (this.$value.length <= 0) {
            this.$value = value;
        }
        if (this.itemsBox) {
            let result = "";
            for (var i = 0; i < this.$value.length; i++) {
                let o = this.$value[i];
                this.itemsBox.find("input[value='" + o.value + "']").prop("checked", true);

                if (o.value == "else") {
                    let attachInput = this._itemsBox.find("div.q_other>input");
                    attachInput.val(o['attach_text']);
                }
                result += o.value;
            }
            renderCheckBox.call(this);
            if (this.showModel == "text" && this._handlers.input) {
                this._handlers.input.val(result);
            }
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }

    }
    get value() {
        if (!this.$value) {
            this.$value = [];
        }
        let _this = this;
        if (_this.$value instanceof Array) {
            _this.$value.forEach(function(o, i) {
                if (o.value == "else") {
                    if (_this._itemsBox) {
                        o.attach_text = _this._itemsBox.find("div.q_other>input").val();
                    }
                }
            });
        }

        return _this.$value;
    }

    set showModel(val) {
        this.$showModel = val;
        if (this.element) {
            this.render();
        }
    }
    get showModel() {
        return this.$showModel;
    }

    set placeholder(value) {
        this.$placeholder = value;
        if (this._handlers.input) {
            this._handlers.input.attr("placeholder", value);
        }
    }
    get placeholder() {
        return this.$placeholder;
    }

    set readOnlyShowText(val) {
        this.$readOnlyShowText = val;
        if (this.element) {
            this.render();
        }
    }
    get readOnlyShowText() {
        return this.$readOnlyShowText;

    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
        this._itemsBox = this._handlers.inputbox;
    }

    initEvent() {
        let _this = this;
        if (this.showModel == "text") {
            if (this._handlers.input) {
                this._handlers.input.off("change")
                this._handlers.input.on("change", function(evt) {
                    var val = _this._handlers.input.val();
                    val = syncItemsChecked.call(_this, val);
                    _this._handlers.input.val(val);
                    _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                    this.commitAudit();
                });
            }
        } else {
            layui.form.on('checkbox(' + this.id + ')', function(data) {
                let checked = _this.element.find("input:checked");
                if (!!_this.maxChooseNum && data.elem.checked) {
                    if (checked.length > _this.maxChooseNum * 1) {
                        data.elem.checked = false;
                        data.othis.removeClass('layui-form-checked');
                        dsf.layer.message("最多只能选择" + _this.maxChooseNum + "个", false);
                        return;
                    }
                }
                _this.value = [];
                if (checked.length > 0) {
                    let arr = [];
                    checked.each((i, el) => {
                        arr.push($(el).val());
                    });
                    _this.value = arr;
                }
                _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this,clickItem:{value:data.value,isCheck:data.elem.checked} });
                _this.commitAudit();
            });
        }
        this.element.off("input", ".q_other>input[type=text]")
        this.element.off("change", ".q_other>input[type=text]")

        this.element.on("input", ".q_other>input[type=text]", evt => {
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });
        this.element.on("change", ".q_other>input[type=text]", evt => {
            this.commitAudit();
        });
    }

    renderContext() {
        super.renderContext();
        this._handlers.label.html(this.label);
        if (this.showModel == "text" && this._handlers.input) {
            let v = syncItemsChecked.call(this, _.map(this.value, "value").join(""));
            this._handlers.input.val(v);
        }
    }
    renderReady() {
        super.renderReady();
        renderCheckBox.call(this);

    }

    renderItems() {
        super.renderItems();
        if (this.element) {
            if (this.root._isDesign && this.items.length <= 0) {
                for (let i = 0; i < 2; i++) {
                    let value = (i + 1);
                    let op = $("<input type='checkbox' " + (this.disabled ? "disabled" : "") + " value='" + value + "' lay-filter='" + this.id + "' title='选项" + value + "' name='" + name + "[" + value + "]' lay-skin='primary'/>");
                    this._itemsBox.append(op);
                }
                if (this.isOther) {
                    this._itemsBox.append("<input type='checkbox' lay-skin='primary' " + (this.disabled ? "disabled" : "") + " lay-filter='" + this.id + "' title='其他' />");
                }
            } else {
                //判断items中是否已经存在其他如果没有则追加一个
                let otherItem = null;
                let index = _.findIndex(this.items, { "value": "else" });
                if (index >= 0) {
                    otherItem = this.items[index];
                    this.items.splice(index, 1);
                }
                if (this.isOther) {
                    this.items.push(otherItem || {
                        "text": "其他",
                        "value": "else",
                        "attach_text": ""
                    });
                }

                for (let i = 0; i < this.items.length; i++) {
                    let item = this.items[i];
                    let name = this.name || this.id;
                    let isCheck = false;
                    for (let n = 0; n < this.value.length; n++) {
                        if (typeof(this.value) == "string" || typeof(this.value) == "number") {
                            if (this.value[n] == item.value) {
                                this.value[n] = item;
                                isCheck = true;
                                break;
                            }
                        } else if (typeof(this.value) == "object") {
                            if (this.value[n].value == item.value) {
                                this.value[n] = item;
                                isCheck = true;
                                break;
                            }
                        }
                    }
                    let op = $("<input type='checkbox' " + (this.disabled ? "disabled" : "") + " value='" + item.value + "' lay-filter='" + this.id + "' title='" + item.text + "' name='" + name + "[" + item.value + "]' " + (isCheck ? "checked" : "") + " lay-skin='primary'/>");
                    this._itemsBox.append(op);
                    if (item.value == "else") {
                        let val = $.isArray(this.value) ? this.value : [this.value];
                        let result = _.find(val, { "value": val.value });
                        this._itemsBox.append('<div class="q_other"><input type="text"></div>');
                        if (this.value.value == "else") {
                            this._itemsBox.find(".q_other>input").val(result ? result.attach_text : "");
                        }
                    }
                }
            }
            renderCheckBox.call(this);
        }

    }
    getTextString(split) {
        let arr = [];
        for (let i = 0; i < this.value.length; i++) {
            arr.push(this.value[i].text);
        }
        return arr.join(split || "、")
    }

    getValueString(split) {
        let arr = [];
        for (let i = 0; i < this.value.length; i++) {
            arr.push(this.value[i].value);
        }
        return arr.join(split || "、");
    }
}

function syncItemsChecked(val) {
    var arr = [];
    this.value = [];
    for (let i = 0; i <= val.length; i++) {
        var char = val[i];
        let result = _.find(this.items, o => o.value == char);
        if (result) {
            let d = _.find(arr, o => o.value == result.value);
            if (!d) {
                arr.push(result);
            }
        }
    }
    this.value = arr;
    return _.map(arr, "value").join("");
}

function renderCheckBox() {
    if (this.showModel != "text") {
        dsf.UI.render("checkbox", true);
    }
}