const mmtype = {
   "1": { value: "1", text: "基础元数据" },
   "2": { value: "2", text: "系统元数据" },
   "3": { value: "3", text: "业务元数据" }
}
const vattType = {
   "string": { text: "文本", value: "string" },
   "date": { text: "日期", value: "date" },
   "number": { text: "数字", value: "number" },
   "object": { text: "对象", value: "object" },  
   "time": { text: "时间", value: "time" },
   "long": { text: "大对象", value: "longObject" }
}


function getControlMap(target) {
   return {
      text: window._controlMap.className[target.ctrl_type].name,
      value: window._controlMap.className[target.ctrl_type].code
   }
}

let createValidate = function (code, config, model) {
   return {
      "code": code || null,
      "config": config || {
         "express": "",
         "isNumber": "0",
         "max": "",
         "min": "",
         "precision": "",
         "required": false
      },
      "model": model || "base"
   }
}


function TextMetaData(length, defaultValue) {
   length = length || 100;
   let controls = $.extend({}, getControlMap(this));
   let strLength = length / 4; //UTF8MB4占用汉字4个字节
   let code = {
      "pseudocode": "dsf_validate(!isOverLength(currentValue," + strLength + "),\"不能大于" + strLength + "个字符\");",
      "java": "dsf_validate(!isOverLength(currentValue," + strLength + "),\"不能大于" + strLength + "个字符\");",
      "javascript": "dsf_validate(!isOverLength(currentValue," + strLength + "),\"不能大于" + strLength + "个字符\");"
   };
   let config = {
      "express": "",
      "isNumber": "0",
      "max": strLength,
      "min": "",
      "precision": "",
      "required": false
   };
   let model = "base";
   return {
      "id": "",
      "name": "",
      "code": "",
      "type": mmtype[3],
      "at": "",
      "currentControl": controls,
      "controls": [controls],
      "validate": createValidate(code, config, model),
      "defaultValue": null,
      "valueAttributes": [{
         "name": "文本",
         "code": "text",
         "type": $.extend({}, vattType["string"]),
         "length": length,
         "defaultValue": defaultValue || null,
         "unit": null,
         "encrypt": false

      }]
   };
}

