import { Control } from '../../../../baseControls';
const dom = require("../../templates/ButtonBar.ejs");
import { ControlEditor } from '../../../../editor/ControlEditor';
// import {Action} from '../../core/action/pageAction';
import * as ButtonPlugin from '../../../../pulgins/buttons';
import {map} from  '../../../../decorator/controlmap';

@map('按钮组','dsf.buttonbar','ButtonBar')
export class ButtonBar extends Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.$align = "left";
        this.$buttonBar = ButtonPlugin.ButtonBar();
    }
    initTemplate() {
        return dom(this)
    }

    createElement() {
        super.createElement();
        if (!window.opener && !this.root._isDesign) {
            let close = this.element.find("[ds-event=close]");
            close.addClass("hidden")
        }
    }

    initEvent() {
        super.initEvent();
    }

    renderContext() {
        let _this = this;
        super.renderContext();
        this.element.css("text-align", this.$align);
        if (this.root._isDesign) {
            _this.renderButtons();
        } else {
            this.root.event.on(PageEvent.READY, function() {
                _this.renderButtons();
            })
        }
    }
    renderButtons() {
        ButtonPlugin.renderButtons(this, this._handlers.buttonBox, this.$buttonBar);
    }
}