const dom = require("../../templates/UEditor.ejs");
import { FormControl } from '../../../../baseControls';
import { UeditorMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';;
import { relyFiles } from '../../../../core/relyfiles';
import { map } from '../../../../decorator/controlmap';

@map('富文本', 'dsf.ueditor', 'UEditor')
@relyFiles([
    'res/libs/uEditor/js/ueditor.config.js',
    'res/libs/uEditor/js/ueditor.all.min.js'
])
@isSupportDataPost(true)
export class UEditor extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$metadata = UeditorMetaData.call(this);
        this.photoArray = []
        this.$value = ""
        this.$richTxtHeight = "400"
        this._editor = null;
        this._eidtorId = "";
        this.label = "富文本";
        this.editor = ""
    }
    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
        this._eidtorId = "ueditor_" + this.id;
    }
    renderContext() {
        super.renderContext();
        if (!this.$readOnly) {
            this.renderEditor();
        }
        if (this._handlers.ueditor) {
            if (this.$showLabel) {
                this._handlers.ueditor.addClass("hasLable")
            } else {
                this._handlers.ueditor.removeClass("hasLable")
            }
        }

    }
    set value(val) {
        this.$value = val;
        if (JSON.stringify(val) != "{}" && val) {
            if (this._handlers.readonlyBlock) {
                this._handlers.readonlyBlock.html(this.getTextString())
            }
            if (this._handlers.ueditor) {
                $(this.element.closest('.layui-tab-item')).css("overflow-x", 'hidden');
                let height = $(this.element.closest('.layui-tab-item')).height();
                let count = setInterval(() => {
                    this.editor.ready(() => {
                        if (height) {
                            this.editor.setHeight(height - 140);
                        }
                        this.editor.setContent(val)
                        clearInterval(count)
                    })
                })

            }
        }
    }
    get value() {
        return this.$value;
    }
    initEvent() {
        let that = this;
        let editor = null;
        var count = setInterval(function () {
            if ($("#edui_fixedlayer").css("z-index") < 0) {
                $("#edui_fixedlayer").css("z-index", 9)
            }
        }, 800)
        if (!this.$readOnly) {
            try {
                if (UE.browser.ie) {
                    editor = this.editor = UE.getEditor(this._eidtorId, { toolbars: window.UEDITOR_CONFIG.iEtoolbars });
                } else {
                    editor = this.editor = UE.getEditor(this._eidtorId, { toolbars: window.UEDITOR_CONFIG.toolbars });
                }

                UE.registerUI('autostyle', function (editor, uiName) {
                    //注册按钮执行时的command命令，使用命令默认就会带有回退操作
                    editor.registerCommand(uiName, {
                        execCommand: function () {
                            editor.setContent(that.$value.replace(/<p><br\/><\/p>/g, ""), false);
                            editor.setContent(that.$value.replace(/&nbsp;/g, ""), false);

                            // 全选
                            editor.execCommand('selectall');
                            // 清除格式
                            editor.execCommand('removeformat');
                            // 文字大小
                            editor.execCommand('fontsize', '20px');
                            // 字体样式
                            editor.execCommand('fontfamily', '仿宋');
                            // 段落格式
                            editor.execCommand('Paragraph', 'p');
                            //p标签缩进
                            editor.execCommand('indent');
                            // 行距
                            editor.execCommand('lineheight', 1.75);
                        }
                    });
                    //创建一个button
                    var btn = new UE.ui.Button({
                        //按钮的名字
                        name: uiName,
                        //提示
                        title: '自动排版',
                        //添加额外样式，指定icon图标，这里默认使用一个重复的icon
                        cssRules: 'background-position:-640px -40px;',
                        //点击时执行的命令
                        onclick: function () {
                            editor.execCommand(uiName);
                        }
                    });
                    return btn;

                });
                editor.ready(function () {
                    var id = editor.ui.id;
                    var style = document.createElement('style');
                    style.innerHTML = '#{id}_imagescale,#{id}_imagescale_cover{display:none !important;}'.replace(/{id}/g, id);
                    document.head.appendChild(style);
                    editor.addListener('blur', function (e) {
                        that.$value = editor.getContent()
                    })
                })
            } catch (error) {
                console.log("初始化失败")
            }
        }

    }
    getTextString() {
        if ($.isEmptyObject(this.value)) {
            return "";
        } else {
            let html = filterXSS(this.value, dsf.xssOptions);
            // let html = xss.process(this.value);
            return html;
        }
    }

    renderEditor() {
        let height = this.$richTxtHeight - 90;
        try {
            if (this._editor) {
                this._editor.destroy()
                // this._editor.reset();
                this._editor = null;
            }
            this._handlers.ueditor.html("")
        } catch (ex) {
            this._handlers.ueditor.html("")
            console.log(ex)
        } finally {
            let editorSj = "<script id='" + this._eidtorId + "' type='text/plain' class='editorContent'></script>"
            if (this._handlers.ueditor) {
                this._handlers.ueditor.html(editorSj)
            }
        }
        if (this.root && this.root._isDesign) {
            if (!this.$readOnly) {
                try {
                    this._editor = UE.getEditor(this._eidtorId, {
                        'readonly': true,
                    });
                } catch (error) {
                    dsf.layer.message("请重拖富文本控件", 8)
                    console.log("请重拖富文本控件", error)
                }
            }

            var heightUeditor = parseInt(this.$richTxtHeight) + 12
        }
        if (this._handlers.ueditor) {
            $(this._handlers.ueditor[0]).height(heightUeditor);
        }
    }

}