import { updateTimeMetaData } from '../../../../core/metadata';
import { SystemTime } from "./SystemTime";
import { map } from '../../../../decorator/controlmap';

@map('更新时间', 'dsf.updatetime', 'UpdateTime')
export class UpdateTime extends SystemTime {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "修改时间";
    this.$metadata = updateTimeMetaData.call(this);
  }

  init() {
    super.init();
    this.caption = dsf.config.kw.updatetime;
  }
}