const dom = require("../../templates/Block.ejs");
const subtitleDom = require("../../templates/SubTitle.ejs");
// import { childrenData } from "../../decorator/childrenData";
import { isSupportDataPost } from "../../../../core/postDecorator";
import { LayoutControl } from "../../../../baseControls";
import {map} from  '../../../../decorator/controlmap';

@map('块','dsf.block','Block')
@isSupportDataPost(true)
export class Block extends LayoutControl {
    constructor(id,isPart){
        super(id, isPart);
        this.$label = "";
        this.$scopeLevel=0;
    }

   
    set label(value) {
        this.$label = value;
        if (this.element) {
            let dom = this.renderTitle();
            this._handlers.title.html(dom);
        }
    }
    get label() {
        return this.$label;
    }

    initTemplate(){
        return dom(this);
    }   
    renderTitle() {
        return subtitleDom({ title: this.$label });
    }
}