import { Title3 } from '../Text/Title3';
import { map } from '../../../../decorator/controlmap';

@map('页签', 'dsf.navposition', 'NavPosition')
export class NavPosition extends Title3 {
  constructor(id, isPart) {
    super(id, isPart);
    this.$value = "页签";
    this.showWeight = true;
    this.$visible = false;
    this.textAlign = "text-center";
  }
}