const dom = require("../templates/Container.ejs");
import { Control } from './Control';
import { Question } from "./Question";
import { ExamSubject } from './ExamSubject'
import { map } from '../../decorator/controlmap';

@map('容器', 'dsf.container', 'Container')
export class Container extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.children = [];
    this.selectabled = false;
    this.$showPadding = false;
    this._isContainerControl = true;
  }


  initTemplate() {
    return dom();
    // let template=ejs.compile(dom)
    // return template(this);
  }
  addChild(control, index) {
    control._parent = this;
    control.parentElement = "#" + this.id;

    if (index === undefined && index === null) {
      this.children.push(control);
    } else {
      if (this.children[index]) {
        this.children.splice(index, 0, control);
      } else {
        this.children.push(control);
      }
    }
    var qIndex = 0;

    for (let i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
      if (this.isDesign) {
        if (this.children[i] instanceof Question || this.children[i] instanceof ExamSubject) {
          // this.children[i].questionIndex="Q"+(qIndex);
          this.children[i].questionIndex = ++qIndex;
          // if ('$indexInExam' in this.children[i]) {
          //     this.children[i].indexInExam = qIndex;
          // }
        }
      }
    }
    if (this._root) {
      control._root = this._root;
      if (!control.$caption) {
        control.caption = control.ctrl_type.toLowerCase() + (++(control.root.$serial));
      }
    }
    control.render();
  }

  _addChild(control, index) {
    control._parent = this;
    control.parentElement = "#" + this.id;
    if (this._root) {
      control._root = this._root;
      if (!control.$caption) {
        control.caption = control.ctrl_type + (++(control.root.$serial));
      }
    }
    if (index === undefined && index === null) {
      this.children.push(control);
    } else {
      if (this.children[index]) {
        this.children.splice(index, 0, control);
      } else {
        this.children.push(control);
      }
    }
    var qIndex = 0;
    for (let i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
      if (this.isDesign) {
        if (this.children[i] instanceof Question || this.children[i] instanceof ExamSubject) {
          this.children[i].questionIndex = ++qIndex;
          // if ('$indexInExam' in this.children[i]) {
          //     this.children[i].indexInExam = qIndex;
          // }
        }
      }
    }
  }

  childAllow(callback) {
    if (callback) {
      return callback();
    }
    return true;
  }

  remove() {
    this.emptyChild();
    super.remove();
  }

  removeChild(control, removeElement) {
    control._parent = null;
    let index = this.children.indexOf(control);
    if (index >= 0) {
      this.children.splice(index, 1);
      if (removeElement != false) {
        control.element.remove();
      }
    }
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
    }
  }

  renderContext() {
    super.renderContext();
    this.addClass("ds_container");
  }

  emptyChild() {
    for (var i = this.children.length - 1; i >= 0; i--) {
      this.children[i].remove();
    }
  }

  renderReady() {
    super.renderReady();
  }
  renderChild() {
    // console.time("创建子节点"+this.id+"_"+this.ctrl_type)
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].root = this.root;
      this.children[i].parent = this;
      this.children[i].index = i;
      if (!this.children[i].caption) {
        this.children[i].caption = this.children[i].ctrl_type + (++(this.root.$serial));
      }
      this.children[i].render();
    }
  }
  render() {
    super.render();
  }

  resize() {
    super.resize();
    if (this.children) {
      this.children.forEach(v => {
        v.resize();
      })
    }
  }

  ControlsForEach(callback, isSelf) {
    let result = true;
    if (isSelf != false) {
      result = callback(this);
    }
    if (result != false && this.children) {
      for (var i = 0; i < this.children.length; i++) {
        let c = this.children[i];
        if (c.ControlsForEach) {
          c.ControlsForEach(callback);
        } else {
          callback(c)
        }
      }
    }
  }
}