import { Page } from './Page'
const mainDom = require('../../templates/ExamPage.ejs')
const infoDom = require('../../templates/ExamInfo.ejs')
const resultDom = require('../../templates/ExamResult.ejs')
import { map } from '../../../../decorator/controlmap'
import { PageEvent } from '../../../../core/ControlEvent'
import { relyFiles } from '../../../../core/relyfiles'
import { Action } from '../../../../core/pageAction'
// 当前考试不区分选答题
@map('考试页面', 'dsf.exampage', 'ExamPage')
export class ExamPage extends Page {
  constructor(id, isPart) {
    super(id, isPart)
    this.$viewSplit = '0px,250px'
    this.$pageType = 'exam'
    this.headHeight = 0
    this.footHeight = 0
    this.$hasHeader = false
    this.$hasFooter = false
    this.$pageWidth = '1170px'
    this.$headfootwidth = 'same'
    this.$fit = 0
    this.$caption = 'ExamPage'
    this._logic = []
    this.$hasHeader = false
    // 是否启用计时功能
    this.$openTime = false
    this._useTime = new Date()
    // this._timeIndices = 0;
    this._examTimer = null
    this._examId = ''
    this._examSubjectCount = 0
    this._currAnswered = 0
    this._examStatus = false
    this.isExamSubjectLoaded = false

    //试卷信息
    this._examData = {}
    //考生答卷答案信息
    this._examAnswer = null
    //考试结果
    this._examResult = null
    //考试分数
    this._examScore = null
    // 提交考试的按钮 是否可显
    this.allowTime = 0
    // 是不是已经提交的状态
    this._examState = 0
    // 考生暂存数据
    this._examAnswerData = null
    // 定时器问题
    this._whether_pop = null
    this._examStateData =['未考试', '待阅卷', '已阅卷', '考试中', '待主观题阅卷']
  }

  initTemplate() {
    return mainDom(this)
  }

  createElement() {
    this.headHeight = 0
    this.footHeight = 0
    this.$hasHeader = false
    this.$hasFooter = false
    this.$pageWidth = '1170px'
    this.$viewSplit = '0px,300px'
    this.$pageType = 'exam'
    this.$title = '考试'
    super.createElement()
    this._handlers.north.css('display', 'none')
    this.disableWestEdit()
  }

  render(el) {
    super.render(el)
    this.topBottom = 'split_big'
  }

  renderContext() {
    this.addClass('ds_exam_page')
    super.renderContext()
  }

  renderComplete() {
    //创建考试倒计时器
    this.createExamTimer()
    super.renderComplete()
  }
  initEvent() {
    this.event.on(PageEvent.READY, (args) => {
      //题目全部加载完成
      if (args.ui.isExamSubjectLoaded) {
        //如果_examAnswer属性没有数据则表示第一次打开试卷开始考试
        if (!args.ui._examAnswer) {
          this.startExam()
        } else {
          this._examTimer.render()
        }
      }
    })
  }

  disableWestEdit() {
    this.children[3]._dropIgnore = true
  }

  createExamTimer() {
    let time = this.element.find('div[caption=WestView]')
    time.html('')
    let tools = $("<div class='ds_exam_timer'></div>")
    time.append(tools)
    this._examTimer = createExamTimer(tools.get(0), this)
    this._examTimer.render()
  }

  //开始考试
  startExam() {
    this._startTime = new Date()
    // createExamReady(3, () => {
    //     !this._isView && this._examTimer.timing();
    // });
    // 获取弹窗注意事项及是否弹窗 在 startExam  判断
    let u = dsf.url.queryString('u')
    let e = dsf.url.queryString('e')
    dsf.http
      .request(
        dsf.url.getWebPath('exam/handler/getAttention'),
        { u: u, e: e },
        'GET'
      )
      .done((res) => {
        let data = res.data
        this._whether_pop = data.whether_pop
        if (data && data.whether_pop == '1') {
          createExamReadyDialog(data, () => {
            !this._isView && this._examTimer.timing()
          })
        } else {
          !this._isView && this._examTimer.timing()
        }
      })
      .error((err) => {
        callback & callback(err, null)
      })
      .exec()

    // !this._isView && this._examTimer.timing();
  }

  //读取数据
  queryData(isFirstRender) {
    let _this = this
    let s = dsf.url.queryString('sId') || ''
    let u = dsf.url.queryString('u')
    let e = dsf.url.queryString('e')
    let a = dsf.url.hashString('a') || ''
    if (!this.isDesign) {
      let q = dsf.queue(true)
      q.step((def, v) => {
        //获取试卷
        getExamInfo.call(this, u, e, a, s, (err, res) => {
          if (err) {
            def.reject('获取试卷信息出错')
          } else {
            let data = res.data
            if (data && !$.isEmptyObject(data)) {
              this._examData = data
              this.allowTime = data.allowTime // 毫秒数
              this._examState = data.state
              this._examAnswer = data.answer || null
              this._examAnswerData = data.data || null
              this._data.$$key = data.answerId
              let ns = (data.namespace || '').split('.')
              this.context.B = ns[0]
              this.context.M = ns.slice(1).join('.')
              this.$name = data.pageName || ''
              // 添加切换窗口 当前页为考试
              if (_this.$title === '考试' && !_this._examAnswer) {
                let isChange = 0
                $(document).on('visibilitychange', () => {
                  if (document.hidden && document.visibilityState == 'hidden') {
                    isChange++
                    if (isChange > 5000) {
                      page.formSave()
                    } else {
                      // layer.open({
                      //   title: '温馨提示',
                      //   content:
                      //     '考生跳出答卷页面次数不能超过5次，否则会保存并自动交卷，当前跳出次数为' +
                      //     isChange +
                      //     '次。',
                      // })
                      // if (isChange === 1 && _this._whether_pop == '1') {
                      //   !_this._isView && _this._examTimer.timing()
                      // }
                    }
                  }
                })
              }
              def.resolve(data)
            } else {
              def.reject(res.message)
            }
          }
        })
      })
      q.step((def, v) => {
        loadExamSubject(this, v)
        def.resolve()
      })
      q.step((def, v) => {
        // 如果试卷有考生答案 当前状态是已经提交过
        if (this._examAnswer) {
          loadAnswer.call(this, this._examAnswer)
          getExamResult.call(this, false, (err, res) => {
            def.resolve()
          })
        } else if (this._examAnswerData) {
          loadAnswer.call(this)
          def.resolve()
        } else {
          def.resolve()
        }
      })
      q.catch((v) => {
        dsf.layer.message(v, false)
      })
      q.finally((e, v) => {
        if (isFirstRender) {
          _this.event.trigger(PageEvent.INITED, { ui: _this })
          // console.log("INITED");
          _this.event.trigger(PageEvent.LOADBEFORE, { ui: _this })
          // console.log("LOADBEFORE");
          _this.event.trigger(PageEvent.LOADED, { ui: _this })
        }
        _this.event.trigger(PageEvent.READY, { ui: _this })
      })
      q.exec()
    }
  }

  //考试题目状态发生变化
  stateChange(ctrl) {
    //更新答题卡
    this._examTimer.updateCard()
    //更新答题进度
    this._examTimer.updateProgress()
  }

  toSubject(index) {
    // alert(index);
    let ctrl = this.getControlByQIndex(index)
    if (document.body.scrollIntoView) {
      ctrl.element.get(0).scrollIntoView({ behavior: 'smooth' })
    }
  }

  //题目是否被打标签
  isSubjectMarked(qindex) {
    let ctrl = this.getControlByQIndex(qindex)
    if (ctrl._isMark) {
      return ctrl._isMark
    }
    return false
  }

  //题目是否回答正确
  isSubjectRight(qindex) {
    let ctrl = this.getControlByQIndex(qindex)
    return ctrl.isRight()
  }

  //获取问卷答题进度
  getAnsweredCount() {
    let num = 0
    for (var i = 0; i < this._examSubjectCount; i++) {
      if (isAnswered(i + 1)) {
        num++
      }
    }
    return num
  }

  //通过提序获取题目组件
  getControlByQIndex(qindex) {
    let caption = 'Q' + (qindex + 1000).toString().substr(1)
    let ctrl = page.getControl(caption)
    return ctrl
  }

  formSave(options, callback) {
    let defaultOptions = {
      refreshTarget: 'opener',
      info: '',
      callback: callback,
      isSilent: false,
      isCloseWindow: false,
      isRefreshPage: false,
    }
    let ops = $.extend({}, defaultOptions, options)
    save.call(this, ops)
  }
}

//分钟转秒
function minutesToSeconds(m) {
  let currentDate = new Date()
  var endDate = new Date(currentDate.getTime() + m * 60 * 1000)
  var totalSeconds = parseInt((endDate - currentDate) / 1000)
  return totalSeconds
}

//倒记时
function TimeDown(totalSeconds) {
  if (!totalSeconds) {
    return '00:00:00'
  }
  //天数
  // var days = Math.floor(totalSeconds / (60 * 60 * 24));
  //取模（余数）
  var modulo = totalSeconds % (60 * 60 * 24)
  //小时数
  var hours = Math.floor(modulo / (60 * 60))
  modulo = modulo % (60 * 60)
  //分钟
  var minutes = Math.floor(modulo / 60)
  //秒
  var seconds = modulo % 60
  //输出到页面
  hours = ((hours || 0) + 100).toString().substr(1)
  minutes = ((minutes || 0) + 100).toString().substr(1)
  seconds = ((seconds || 0) + 100).toString().substr(1)
  return hours + ':' + minutes + ':' + seconds
}

//创建考试计时器工具条
let clearId
let countDown = 0 // 在固定时间内提交暂存
function createExamTimer(el, page, seconds) {
  let zero = '00:00:00'
  let subjects = []
  let myScroll = null
  seconds = seconds || 0
  let posting = false
  let data = {
    subjects: subjects,
    isTiming: true,
    page: page,
    getTime: function() {
      return seconds <= 0 ? zero : TimeDown(seconds)
    },
    getAnsweredCount: function() {
      return page.getAnsweredCount() + '/' + page._examSubjectCount
    },
    isAnswered: function(item) {
      return isAnswered(item.questionIndex)
    },
    isSubjectMarked: function(item) {
      return page.isSubjectMarked(item.questionIndex)
    },
    isSubjectRight: function(item) {
      return page.isSubjectRight(item.questionIndex)
    },
    scrollTo: function(item) {
      page.toSubject(item.questionIndex)
    },
    getAllowSubmit() {
      if (page.isDesign || page._isView == 1) {
        return false
      }
      if ($.isEmptyObject(page._examData)) {
        return false
      }
      if (page._examAnswer) {
        return false
      }
      // 控制按钮是否显示
      if (page.allowTime > 0) {
        return false
      }
      return true
    },
    post: function() {
      if (!this.getAllowSubmit()) {
        return
      }
      if (!posting && page.allowTime === 0 && page._examState === 3) {
        //验证题目是否全部做完
        let noAnswered = [],
          listId = ''
        for (let i = 0; i < page._examSubjectCount; i++) {
          let ctrl = page.getControlByQIndex(i + 1)
          if (!ctrl._answered) {
            listId += ctrl.$questionIndex + '、'
          }
          !ctrl._answered && noAnswered.push(ctrl)
        }
        let message = '是否现在交卷?'
        if (noAnswered.length) {
          if (noAnswered.length == page._examSubjectCount) {
            message = '请填写全部题目！'
          } else {
            message = '请填写 ' + listId.slice(0, -1) + ' 题！'
          }
          obj.setIsTiming(false)
          layer.confirm(message, {
            title: '提醒',
            closeBtn: false,
            btn: ['确定'],
            btnAlign: 'c',
            yes: function(index) {
              obj.setIsTiming(true)
              layer.close(index)
            },
          })
          return false
        }
        //暂停计时器
        obj.setIsTiming(false)
        layer.confirm(message, {
          title: '提醒',
          btn: ['确定', '取消'],
          btnAlign: 'c',
          yes: function() {
            posting = true
            page.formSave({
              callback: function() {
                posting = false
              },
            })
          },
          end: function() {
            //启动计时器
            obj.setIsTiming(true)
          },
        })
      }
    },
  }
  let iRender = dsf.vdom({
    template: infoDom(),
    el: el,
    data: data,
    updated: function(oldVnode, vnode) {},
  })
  let obj = {
    render: function() {
      iRender.render()
    },
    timing() {
      clearId = window.setInterval(() => {
        if (!data.isTiming) {
          return
        }
        seconds--
        // 控制提交按钮的显示
        if (page.allowTime === 0 && page._examState === 3) {
          $('.ds_exam_post').removeClass('disabled')
        } else {
          page.allowTime--
        }
        // 300秒后自动暂存
        if (++countDown === 30) {
          saveExamHold(page)
        }
        if (seconds < 0) {
          seconds = 0
        }
        iRender.render()
        if (seconds < 30 && seconds > 1) {
          layer.msg('请注意考试时间还剩余' + seconds + '秒', {
            icon: 7,
            offset: 't',
            anim: 6,
            time: 1000,
          })
        }
        if (seconds == 0) {
          window.clearInterval(clearId)
          //时间到，强制交卷
          page.formSave({
            isSilent: true,
          })
        }
      }, 1000)
    },
    setIsTiming(v) {
      data.isTiming = v
      iRender.render()
    },
    setCard(subs) {
      data.subjects = subs
      iRender.render()
      let elm = page.element.find('.ds_exam_card_box').get(0)
      if (myScroll) {
        myScroll.destroy()
        myScroll = null
      }
      if (elm.childNodes.length > 0) {
        myScroll = new IScroll(elm, {
          snap: true,
          fadeScrollbars: true,
          interactiveScrollbars: true,
          mouseWheel: true,
          scrollbars: true,
        })
      }
      // subjectCard.update();
    },
    setTime(s) {
      if (dsf.isDef(s) && !isNaN(s)) {
        seconds = s
        iRender.render()
      }
    },
    updateCard() {
      iRender.render()
      // subjectCard.update();
    },
    updateProgress() {
      iRender.render()
      // progress.update();
    },
  }
  return obj
}

// 考试答卷信息暂存接口
function saveExamHold(_this) {
  let url = dsf.url.getWebPath('exam/score/saveExamHold')
  let data = _.mapKeys(_this.getPostData(), function(value, key) {
    return key.split('.')[1]
  })
  let args = {
    table: _this.nameSpace.replace(/\./g, '_'),
    answerId: _this._data.$$key,
    data: data,
  }
  dsf.http
    .request(
      url,
      JSON.stringify(args),
      'POST',
      'application/json;charset=utf-8'
    )
    .done(function(response) {
      if (response.success && response.state == 20000) {
        layer.msg('自动暂存成功', {
          icon: 1,
          offset: '30px',
        })
      } else {
        dsf.layer.message('暂存失败！', false)
      }
    })
    .error(function(response) {
      dsf.layer.message('暂存失败！', false)
    })
    .always(function() {
      countDown = 3
    })
    .exec()
}

//  创建考试倒计时注意事项
function createExamReadyDialog(data, readyComplete) {
  var i = data.time
  var interval
  layer.confirm('考试注意事项', {
    title: '考试注意事项',
    closeBtn: false,
    offset: ['200px'],
    area: '500px',
    btnAlign: 'c',
    move: false,
    shade: 0.8,
    anim: 1, //0-6的动画形式，-1不开启
    btn: [i + 's后可确定'], //按钮
    content: data.caution || '',
    success: function(layero, index) {
      $('.layui-layer-btn0').css({
        backgroundColor: '#FBFBFB',
        color: '#C9C9C9',
        border: '1px solid #e6e6e6',
      })
      var fn = function() {
        i--
        $('.layui-layer-btn0').text(i + 's后可确定')
      }
      interval = setInterval(function() {
        fn()
        if (i === 0) {
          $('.layui-layer-btn0')
            .css({
              backgroundColor: '#1E9FFF',
              color: '#fff',
              border: '1px solid #1E9FFF',
            })
            .text('确定')
          clearInterval(interval)
        }
      }, 1000)
    },
    yes: function(index) {
      if (i <= 0) {
        readyComplete && readyComplete()
        layer.close(index)
        clearInterval(interval)
      }
    },
  })
}

//创建考试准倒数321
function createExamReady(n, readyComplete) {
  let layer = $('body').find('.ds_exam_ready_layer') // $("<div class='ds_exam_ready_layer'></div>");
  if (layer.length <= 0) {
    layer = $("<div class='ds_exam_ready_layer'></div>")
    $('body').append(layer)
  }
  let clearId = null
  let isClose = false
  let vd = dsf.vdom.create('div', {
    class: () => ['ds_exam_ready_layer', isClose ? 'hide' : ''],
    children: () => {
      return (
        n >= 0 &&
        dsf.vdom.create('div', {
          class: ['ds_exam_ready_timer'],
          children: () => [
            n == 0 && dsf.vdom.create('span', { children: '开始答题' }),
            n != 0 &&
              dsf.vdom.create('div', { class: ['num'], children: () => n }),
            n != 0 && dsf.vdom.create('span', { children: '准备开始' }),
          ],
        })
      )
    },
  })

  vd.render(layer.get(0))
  clearId = window.setInterval(function() {
    n--
    isClose = n < 0
    vd.update()
    if (isClose) {
      window.clearInterval(clearId)
      readyComplete && readyComplete()
    }
  }, 1000)
}

let qNum = 0
//加载试题
function loadExamSubject(page, data) {
  if (!page.isDesign) {
    //绑定试卷名称
    page.getControl('title').value = data.name
    $('.exam-remark').html(data.remark)
    // 添加
    let card = []
    for (let i = 0; i < data.questions.length; i++) {
      let question = initQuestionData(data.questions[i], page, data, i + 1)
      let controls = createQuestionControl(question)
      controls.forEach((ctrl) => page.children[0].addChild(ctrl))
      card.push(question)
      page._examSubjectCount += question.subjects.length
    }
    //绑定考试时间
    // page._timeIndices = data.duration; minutesToSeconds(data.duration)
    // 考试时间 直接传秒
    page._examTimer.setTime(parseInt(data.duration))
    //绑定答题卡
    page._examTimer.setCard(card)
  }
  page._examTimer.updateProgress()
  page.isExamSubjectLoaded = true
}

//初始化试题数据
function initQuestionData(question, page, data, index) {
  let obj = {
    index: index,
    title: '',
    ctor: null,
    subjects: [],
  }
  let title = '',
    isQuestionRandom = false,
    isOptionsRandom = false
  switch (question.type) {
    case 'radio':
      title = '单选题'
      isQuestionRandom = data.random.question == '1'
      isOptionsRandom = data.random.item == '1'
      obj.ctor = dsf.getControlClassForCode('dsf.exam.radio')
      break
    case 'checkbox':
      title = '多选题'
      isQuestionRandom = data.random.question == '1'
      isOptionsRandom = data.random.item == '1'
      obj.ctor = dsf.getControlClassForCode('dsf.exam.checkbox')
      break
    case 'input':
      title = '填空题'
      isQuestionRandom = data.random.question == '1'
      obj.ctor = dsf.getControlClassForCode('dsf.exam.fill')
      break
    case 'judge':
      title = '判断题'
      isQuestionRandom = data.random.question == '1'
      obj.ctor = dsf.getControlClassForCode('dsf.exam.trueorfalse')
      break
    case 'subjective':
      title = '主观题'
      isQuestionRandom = data.random.question == '1'
      obj.ctor = dsf.getControlClassForCode('dsf.exam.subjective')
      break
  }
  let total = ''
  if (question.score && question.score.total) {
    total = question.score.total
  }
  obj.title =
    dsf.Math.toChinesNum(index) +
    '、' +
    title +
    (total ? ' (共' + total + '分)' : '')

  let arr = []
  for (let i = 0; i < question.subjects.length; i++) {
    let s = question.subjects[i]
    let sub = {}
    sub.id = s.id
    sub.questionIndex = ''
    sub.questionBody = s.content || ''
    sub.prompt = s.prompt
    sub.column =
      dsf.isDef(s.column) && !isNaN(s.column) ? parseInt(s.column) : 1
    sub.fontNum = s.fontNum
    if (s.items && s.items.length) {
      sub.realItems = s.items.slice(0)
      sub.items = isOptionsRandom ? randomSort(s.items) : s.items.slice(0)
    }
    let key = page.scope
    let ns = key
    let code = sub.id
    key += '.' + code
    let path = ns.replace(/\_/g, '.')
    sub.metadata = {
      id: ns.replace(/\_/g, '.') + '.' + code,
      code: code,
      at: path,
      name: sub.questionBody,
      level: 0,
    }
    sub.metadata_fullcode = key
    sub.answer = []
    sub.analysisContent = ''
    arr.push(sub)
  }
  //如果随机排序
  arr = isQuestionRandom ? randomSort(arr) : arr
  arr.forEach((sub, i) => {
    sub.questionIndex = ++qNum
  })
  obj.subjects = arr
  return obj
}

function createQuestionControl(data) {
  let controls = []
  let titleCtrlClass = dsf.getControlClassForCode('dsf.title3')
  let titleCtrl = new titleCtrlClass()
  titleCtrl.value = data.title
  titleCtrl.showWeight = true
  controls.push(titleCtrl)
  for (let i = 0; i < data.subjects.length; i++) {
    let s = data.subjects[i]
    let examSubject = new data.ctor(s.id, false)
    examSubject.questionIndex = s.questionIndex
    examSubject.questionBody = s.questionBody
    examSubject.$prompt = s.prompt
    if ('colNum' in examSubject) {
      let column =
        dsf.isDef(s.column) && !isNaN(s.column) ? parseInt(s.column) : 1
      examSubject.colNum = column
    }
    if ('items' in examSubject && s.items && s.items.length) {
      //将真实顺序保存到_realItems;
      let ritems = _.map(s.realItems, (item) => {
        return {
          text: item.text,
          value: item.value,
          img: item.img,
        }
      })
      examSubject._realItems = ritems || []
      //按配置需要将如果试卷配置了选项乱序则调用randomSort乱序排列
      let items = _.map(s.items, (item) => {
        return {
          text: item.text,
          value: item.value,
          img: item.img,
        }
      })
      examSubject.items = items || []
    }
    if ('$chatLength' in examSubject) {
      examSubject.$chatLength = s.fontNum
    }
    examSubject.readOnly = page._isView == 1
    examSubject.$metadata = $.extend(examSubject.$metadata, s.metadata)
    examSubject.metadata_fullcode = s.metadata_fullcode
    controls.push(examSubject)
  }
  return controls
}

//随机排序
function randomSort(arr) {
  arr = arr.slice(0)
  var brr = []
  var num = arr.length
  for (var i = 0; i < num; i++) {
    var temp = parseInt(Math.random() * (num - i))
    brr.push(arr[temp])
    arr.splice(temp, 1)
  }
  arr = null
  return brr
}

//是否回答
function isAnswered(questionIndex) {
  let ctrl = page.getControlByQIndex(questionIndex)
  return ctrl && ctrl._answered
}

function save(options) {
  let _this = this
  let refreshTarget = options.refreshTarget || 'opener'
  let queue = dsf.queue()
  let info = options.info
  let saveReault = true
  let callback = options.callback || dsf.noop
  let isSilent = options.isSilent || false
  //保存请求
  queue.step((def, v) => {
    Action.exam_save(this, (err, data) => {
      if (err) {
        if (!isSilent) {
          let msg = data.state == '20001' ? '试卷提交失败' : data.message
          dsf.layer.message(msg, false)
        }
        def.reject()
      } else {
        this.loadData(data)
        def.resolve(data)
      }
    })
  })
  queue.step((def, v) => {
    //获取考试结果
    let waitIndex = layui.layer.msg('正在批阅中,请勿关闭窗口', {
      icon: 16,
      shade: 0.01,
      time: 0,
    })
    getExamResult.call(_this, true, (err, res) => {
      if (err) {
        dsf.layer.close(waitIndex)
      } else {
        dsf.layer.close(waitIndex)
        showExamInfo.call(_this, res && res.data ? res.data : {}, () => {})
      }
    })
    window.location.href = '#a=' + _this._examData.answerId
  })
  queue.step((def, v) => {
    if (this.event.has(PageEvent.SAVEAFTER)) {
      this.event.trigger(PageEvent.SAVEAFTER, { ui: this, args: info }, def)
    } else {
      def.resolve()
    }
  })

  queue.step((def, v) => {
    if (window[refreshTarget]) {
      try {
        this.refreshParent(refreshTarget)
      } catch (ex) {
        dsf.error('未能成功刷新父页面')
      }
    }
    def.resolve()
    saveReault = true
  })

  queue.catch(function() {
    saveReault = false
  })
  queue.finally(function() {
    callback ? callback(saveReault) : dsf.noop()
  })
  queue.exec()
}

function getExamInfo(u, e, a, s, callback) {
  //获取试卷
  dsf.http
    .request(
      dsf.url.getWebPath('exam/handler/getExamInfo'),
      { u: u, e: e, a: a, s: s },
      'GET'
    )
    .done((response) => {
      callback & callback(null, response)
    })
    .error((err) => {
      callback & callback(err, null)
    })
    .exec()
}

//获取考试批阅结果
function getExamResult(isWait, callback) {
  let _this = this
  let url = dsf.url.getWebPath('exam/score/findExamResultByAnswerId')
  dsf.http
    .request(url, { answerId: _this._data.$$key }, 'GET')
    .done((res) => {
      dsf.warn(res)
      if (res.state == 20000) {
        let data = res.data
        _this._examResult = {
          ys: data.ys,
          isPass: data.isPass,
          examScore: data.examScore,
          statusValue: data.statusValue,
        }
        callback && callback(null, res)
      } else if (res.state == '20001') {
        if (isWait) {
          //服务器未返回结果时候再次请求知道请求道结果为止
          window.setTimeout(() => {
            getExamResult.call(_this, true, callback)
          }, 1000)
        } else {
          callback && callback(res, null)
        }
      }
    })
    .error((res) => {
      dsf.warn(res)
      callback && callback(res)
    })
    .always(() => {})
    .exec()
}

function showExamInfo(data, callback) {
  let _this = this
  let resultIndex = dsf.layer.openHTMLView("<div class='exam_result'></div>", {
    type: 0,
    area: ['400px', '470px'],
    title: '考试结果',
    closeBtn: 0,
    success: function(layero, index) {
      callback && callback()
      let el = layero.find('.exam_result')
      createContent.call(_this, el)
    },
  })
  function createContent(el) {
    dsf.vdom({
      template: resultDom(this),
      el: el.get(0),
      data: {
        ys: data.ys,
        isPass: data.isPass,
        statusValue: data.statusValue,
        examScore: data.examScore,
        close: function() {
          _this.close()
        },
        reExam: function() {
          window.location.href =
            window.location.pathname + window.location.search
        },
        lookAnswer: function() {
          dsf.layer.close(resultIndex)
          let s = dsf.url.queryString('sId') || ''
          let u = dsf.url.queryString('u') || ''
          let e = dsf.url.queryString('e') || ''
          let a = _this._data.$$key

          getExamInfo.call(_this, u, e, a, s, (err, res) => {
            if (!res.data || !res.data.answer) {
              return
            }
            _this._examState = res.data.state
            _this._examAnswer = res.data.answer
            _this._examTimer.render()
            _this._examData = res.data
            loadAnswer.call(_this)
          })
        },
      },
    })
    // 关闭时间
    _this._examTimer.setIsTiming(false)
    window.clearInterval(clearId)
    // 移除监听事件
    $(document).off('visibilitychange')
  }
}

//加载考生答题
function loadAnswer() {
  let rightAnswer = this._examAnswer
  let postAnswer = this._examData ? this._examData.data : {}
  //将考生回答的答案赋值给各个组件
  for (let k in postAnswer) {
    let pa =  _.isNull(postAnswer[k]) || _.isEmpty(postAnswer[k]) ? '' : postAnswer[k]
    // 以下处理key 排序问题 {text_1: "低排放", text_3: "高效率", text_2: "低能耗"}
    let ordered = {}
    if (_.isObject(pa)) { 
      Object.keys(pa)
      .sort()
      .forEach((key) => {
        ordered[key] = pa[key]
      })
    }
    let el = $("[ds-data-bind='" + k + "']")
    let ctrl = el.data('Object')
    if (ctrl) {
      ctrl.$readOnly = this._examState !== 3
      // 以下是全题型回显数据
      if (_.has(pa, 'parse') || _.has(pa, 'value') || ordered) {
        // 主观题是字符串 其它是对象 
        if( ctrl.ctrl_type == "ExamSubjective"){
          ctrl.setValue(pa)
        }else{
          ctrl.setValue(ordered)
        }
        ctrl.setAnalysis(pa.parse || '')
        ctrl.setAnswer(_.map(pa.values, 'value'))
      }
    }
  }
  //将正确答案加载给各个组件
  for (let k in rightAnswer) {
    let el = $("[ds-data-bind='" + k + "']")
    let ctrl = el.data('Object')
    let ra = rightAnswer[k]
    if (ctrl) {
      ctrl.$readOnly = true
      ctrl.setAnalysis(ra.parse || '')
      let v = _.map(ra.values, 'value')
      ctrl.setAnswer(v)
    }
  }

  if (this._examState !== 3) {
    // 关闭时间
    this._examTimer.setIsTiming(false)
    window.clearInterval(clearId)
    // 移除监听事件
    $(document).off('visibilitychange')
    $('.ds_exam_post').addClass('disabled')
  }
}
