import { relyFiles } from "../../../../core/relyfiles";

const dom = require("../../templates/RemoteSearch.ejs");
import { ItemsControl } from '../../../../baseControls';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControlEvent } from '../../../../core/ControlEvent';
import { map } from '../../../../decorator/controlmap';
@relyFiles([
  'res/libs/xm-select.js'
])
@map('远程搜索', 'dsf.remotesearch', 'RemoteSearch')
@isSupportDataPost(true)
export class RemoteSearch extends ItemsControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "远程搜索";
    this.maxChooseNum = 0;
    this.$placeholder = "请选择";
    this.$readOnlyShowText = "text";
    this.selectEle = '', this.relativeEle = '';
    this.isViewTxt = null;
    this.current = "";   //用户当前选择项
    this.selectarr = "";   //用户选择后,全部选择项
    this.requestUrl = '';//远程搜索接口
    this.$relativeBoxObj = {
      value: "dept",
      caption: ""
    }
    this.$distance = '';//两个box间距,支持任何形式
    this.$isShowRelativeBox = false;
    this.isshowDelIcon = true //是否显示方块删除图标
  }

  get items() {
    return this._items;
  }
  set items(value) {
    this._items = [];
    if ($.isArray(value)) {
      if (value[0] == undefined || value[0].value != "") {
        value.splice(0, 0, { "text": "", "value": "" });
      }
      for (let i = 0; i < value.length; i++) {
        let isRender = i == value.length - 1 ? true : false;
        this.addItem(value[i], i, isRender);
      }
    }
  }


  set placeholder(value) {
    this.$placeholder = value;
    if (this._handlers.selects) {
      this.renderItems()
    }
  }
  get placeholder() {
    return this.$placeholder;
  }

  set readOnlyShowText(val) {
    this.$readOnlyShowText = val;
    if (this.element) {
      this.render();
    }
  }
  get readOnlyShowText() {
    return this.$readOnlyShowText;
  }
  set relativeBoxObj(val) {
    this.$relativeBoxObj = val;
    if (this.element) {
      this.render()
    }
  }
  get relativeBoxObj() {
    return this.$relativeBoxObj
  }

  set distance(val) {
    let a = val.trim().toLowerCase()
    if (a && /^-?(\d+\.\d+|[1-9]\d*|0)$/.test(a)) { //仅数字
      this.$distance = a + 'px'
    } else if (/^-?(\d+\.\d+|[1-9]\d*|0)(px|%)$/.test(a)) { // 正确的已%或者'px'结尾的数字
      this.$distance = a
    } else {
      dsf.layer.message('间距属性填写有误，仅支持数字、百分比或者"数字+px"的形式', false)
    }
  }
  get distance() {
    return this.$distance
  }

  initTemplate() {
    return dom(this);
  }
  createElement() {
    super.createElement();
    this._itemsBox = this._handlers.selects;
  }

  renderContext() {
    // logIn()
    super.renderContext();
    this._handlers.label.html(this.label);
    if (this.disabled) {
      if (this._handlers.selects) {
        this._handlers.selects.prop("disabled", true);
      }
      this.$isshowDelIcon = true
    } else {
      this.$isshowDelIcon = false
    }

  }


  set value(value) {
    if (value == undefined || value == null) {
      value = [];
    }
    if (!$.isArray(value)) {
      value = [value];
    }
    let isView = dsf.url.queryString('isview') === '1' ? true : false;
    if (isView) {
      this.$value = value;
      if (this._handlers && this._handlers.selects) {
        this._handlers.selects.css({ 'padding': '9px', 'color': '#333' }).html(this.getTextString(','))
      } else {
        this.isViewTxt = this.getTextString(',');
      }
      return
    }

    this.$value = [];
    for (let i = 0; i < value.length; i++) {
      let v = value[i];
      if (typeof (v) == "string" || typeof (v) == "number") {
        for (let i = 0; i < this._items.length; i++) {
          if (this._items[i].value == v) {
            this.$value.push(this._items[i]);
          }
        }
      } else if (typeof (v) == "object") {
        for (let i = 0; i < this._items.length; i++) {
          let o = this._items[i];
          if (o.value == v.value) {
            if (v.attach_text) {
              o.attach_text = v.attach_text;
            }
            this.$value.push(o);
          }
        }
      }
    }
    if (this.$value.length <= 0) {
      this.$value = value;
    }
    if (this.itemsBox && this.selectEle) {
      this.selectEle.setValue(this.value);
      let relativeEle = this._root.getControl(this.relativeBoxObj.caption)
      if(relativeEle && $.isArray(this.selectarr)){
        let realtiveValArr=[];
        if(this.selectarr.length>0){
          this.selectarr.map(val => {
            realtiveValArr.push(val[this.relativeBoxObj.value]);
          })
        }
        relativeEle.selectEle.update({data:realtiveValArr})
        relativeEle.selectEle.setValue(realtiveValArr);
        relativeEle.value = realtiveValArr
      }
    }
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(this.getTextString(","));
    }
  }
  get value() {
    if (!this.$value) {
      this.$value = [];
    }
    let _this = this;
    if (_this.$value instanceof Array) {
      _this.$value.forEach(function (o, i) {
        if (o.value == "else") {
          if (_this._itemsBox) {
            o.attach_text = _this._itemsBox.find("div.q_other>input").val();
          }
        }
      });
    }
    return _this.$value;
  }

  renderReady() {
    super.renderReady();
    (this.isViewTxt != null && this._handlers.selects) && (this._handlers.selects.css({
      'padding': '9px',
      'color': '#333'
    }).html(this.isViewTxt), this.isViewTxt = null);
  }

  renderItems() {
    if (!this.readOnly) {
      super.renderItems();
      this.renderSelect();
    }
  }

  renderSelect() {
    if (this.element && this._handlers.selects) {
      Object.prototype.toString.call(this.value) !== '[object Array]' && (this.value = []);
      let _this = this;
      // 可选的远程所有框
      _this.selectEle = xmSelect.render({
        el: '#' + this.ctrl_type + this.id,
        template({item,sles,name,value}){
          let temp = item[_this.relativeBoxObj.value]?item.text  + '<span style="position: absolute; right: 10px; color: #8799a3">'+item[_this.relativeBoxObj.value].text+'</span>' :item.text
          return temp
        },
        tips: this.placeholder,
        language: 'zn',
        filterable: true,
        remoteSearch: this.disabled ? false : true,
        theme: {
          color: '#ff7200',
        },
        prop: {
          name: 'text',
          value: 'value',
        },
        model: {
          label: {
            type: 'block',
            block: {
              //是否显示删除图标
              showIcon: this.isshowDelIcon
            }
          }
        },
        disabled: this.disabled,
        initValue: this.value,//默认值
        max: this.maxChooseNum || 0,
        autoRow: true,//自动换行
        maxMethod(seles, item) {
          layer.msg(`最多只能选择${seles.length}条`, { icon: 5 });
        },
        on({ arr, change, isAdd }) {
          //arr:  当前多选已选中的数据
          //change, 此次选择变化的数据,数组
          //isAdd, 此次操作是新增还是删除
          _this.current = change;
          _this.selectarr = arr;
          // _this.value = arr;
          _this.value  = changeObjInArr(arr);
          typeof _this.onSelectTrigger === 'function' && _this.onSelectTrigger(arr, change, isAdd);
        },
        remoteMethod: (val, cb, show) => {
          //这里如果val为空, 则不触发搜索
          if (!val) {
            return cb([]);
          }
          dsf.http.request(dsf.url.getWebPath(dsf.Express.replace(_this.requestUrl)), { keywords: val }, 'Get')
            .done(response => {
              if (response.state == 20000) {
                cb(response.data)
              } else {
                cb([])
              }
            })
            .error(response => {
              cb([])
            })
            .exec();
        }
      })
    }
  }

  renderComplete() {
    super.renderComplete();
  }

  //描述组件的验证信息
  validateInfo() {
    return {
      tipsElement: ".layui-input-block"
    }
  }

  getTextString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].name ? this.value[i].name : this.value[i].text ? this.value[i].text : '');
    }
    return arr.join(split || "、")
  }

  getValueString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].value);
    }
    return arr.join(split || "、");
  }
}

function changeObjInArr(items) {
  let arr = [];
  if (items.length > 0) {
    items.forEach(function (item) {
      (item.text && item.value !== '') && arr.push({
        text: item.text,
        value: item.value
      });
    })
  }
  console.log('arr', arr)
  return arr
}

