const dom = require("../../templates/UploadPhoto.ejs");
import { FormControl } from '../../../../baseControls';
import { photoMetaData } from '../../../../core/metadata';
import { isSupportDataPost } from '../../../../core/postDecorator';
// const imageUrl = require('../../../../assets/themes/img/photodefault.jpg');
import {map} from  '../../../../decorator/controlmap';

@map('照片上传','dsf.uploadphoto','UploadPhoto')
@isSupportDataPost(true)
export class UploadPhoto extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.btnName = "上传照片";
        this.$metadata = photoMetaData.call(this, 500);
        this.photoArray = []
        this.$imgWidth = "180";
        this.$imgHeight = "230";
        this.$isStretch = ""; //是否拉伸
        this.label = "上传照片";
        this.$value = "";
        this.$defaultImg = "1";
        this.$hasPadding = "1"
        this.$hasBorder = "1";
        this.$isCutPic = true;
        this.$aspectRatio = "2:3"
        this.$maxFileSize ="2"
        this.$error_tipsPosition="right";
        this.$isShowTips=true;
        this.$tipsPx=""

    }
    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
    }
    renderContext() {
        let imageUrl = {
            1: require('../../../../assets/themes/img/photodefault.jpg'),
            2: require('../../../../assets/themes/img/coverdefault.png')
        }
        super.renderContext();

        if (!this.readOnly) {
            this.element.css("cursor", "pointer").attr("title", "点击上传照片");
        } else if(!this.root._isDesign){
            this.element.css('pointer-events', 'none')
        }
        if (this.$imgWidth) {
            this.element.css("width", this.$imgWidth + "px");
        }
        if (this.$imgHeight) {
            this.element.css("height", this.$imgHeight + "px");
        }

        let photoBoxElem = this._handlers.photoBox 
        !parseInt(this.$hasPadding) ? photoBoxElem.addClass("no_padding") : photoBoxElem.removeClass('no_padding');
        if (!this.root._isDesign) {
            !parseInt(this.$hasBorder) ? this.element.addClass("no_border") : this.element.removeClass('no_border')
        }

        if (this.isDesign) {
            // if (!this.value.relativePath) {
            this._handlers.photoImg.attr("src", dsf.url.getWebPath("res/dsf_styles/" + imageUrl[this.$defaultImg]));
            // }
        } else if ($.isEmptyObject(this.value) || !this.value ) {
            this._handlers.photoImg.attr("src", dsf.url.getWebPath("res/dsf_styles/" + imageUrl[this.$defaultImg]));
        } else {
            let src = '';
            let url=""
            if(this._handlers.photoImg){
                src = this._handlers.photoImg.attr("src");
            }
            typeof this.value === 'string' && (this.value=JSON.parse(this.value))
            if (this.value && $.isArray(this.value) && this.value.length > 0) {
                url =  dsf.config.staticPath? dsf.config.staticPath+this.value[0].relativePath :dsf.url.getWebPath(this.value[0].relativePath);
                if (src != url) {
                    $("#photo_" + this.id).attr('src', url)
                }
            } 
        }
		if(Object.prototype.toString.call(this.$tipsPx.remove) === '[object Function]'){
			this.$tipsPx.remove()
		} 
		if(this.$isShowTips){
			addTips.call(this)
		}
			
        createImgEditor(this.id)
    }
    get imgWidth() {
        return this.$imgWidth
    }
    set imgWidth(value) {
        this.$imgWidth = value;
        if (this.element) {
            this.element.css("width", this.$imgWidth + "px");
        }
    }

    get imgHeight() {
        return this.$imgHeight;

    }
    set imgHeight(value) {
        this.$imgHeight = value;
        if (this.element) {
            this.element.css("height", this.$imgHeight + "px");
        }
    }

    set value(val) {
        if (!val) { val = "" }
        super.value = val;
        if (typeof val === 'string') {
            if (val && val != '[]') {
                val = JSON.parse(val);
                if ($.isArray(val) && val.length > 0) {
                    if (this.element && this.element.find("#photo_" + this.id)) {
                        let src= dsf.config.staticPath? dsf.config.staticPath+val[0].relativePath:dsf.url.getWebPath(val[0].relativePath);
                        $("#photo_" + this.id).attr('src', src)
                    }
					if(!this.$isShowTips){
						(Object.prototype.toString.call(this.$tipsPx.remove)==='[object Function]') && this.$tipsPx.remove()
					}
                } else {
                    return;
                }

            }
        }
    }
    get value() {
        return super.value;
    }
    setControlId() {
        return this.id
    }
    initEvent() {
        let that = this;
		that.headersParam = dsf.getCookie("XSRF-TOKEN")||""
        if (!this.readOnly) {
            layui.use(['upload', 'element'], function () {
                var upload = layui.upload,
                    element = layui.element;
                element.init();
                upload.render({
                    // elem: '#uploadPhoto', // 文件选择
                    elem: that.element.get(0),
                    accept: that.$uploadFileType,
                    multiple: that.$multiple,
					headers:{'X-XSRF-TOKEN': that.headersParam},
                    acceptMime: 'image/*',
                    url: dsf.url.getWebPath('file/upload/'),
                    auto: true, // 设置不自动提交
                    size: getFileSize(that.$maxFileSize),
                    before: function (obj) {
                        layer.load(); //上传loading
                    },
                    choose: function (obj) {
                        obj.preview(function (index, file, result) {
                        });
                    },
                    done: function (res) {
						if(res.success){
							if (that.$isCutPic) {
							    cropperFn.call(that, res.data[0])
							} else {
							    that.photoArray.push(res.data[0])
							    that.value = JSON.stringify(that.photoArray);
							}
							// layer.msg(res.message);
							layer.closeAll('loading');
							that.photoArray = [];
							that.event.trigger(FormControlEvent.VALUECHANGE, { ui: that });
						}else{
                            layer.closeAll('loading');
							layer.msg(res.message)
						}
                       
                    },
                    error: function (res) {
                        layer.msg(res.message || '上传失败');
                        layer.closeAll('loading');
                    }
                });
            });
        }

    }

     //描述组件的验证信息
     validateInfo() {
        return {
            tipsElement:".photoBox"
        }
    }
}
function createImgEditor(id) {
    var html = "<link rel=\"stylesheet\" href=\"/dsfa/res/libs/cropper/cropper.css\">\n" +
        "<div class=\"layui-fluid showImgEdit photoEdit\" style=\"display: none;padding-right: 0px;\" id=\"imgEdit_" + id + "\">\n" +
        "    <div class=\"layui-row layui-col-space15\">\n" +
        "        <div class=\"layui-col-xs10\">\n" +
        "            <div class=\"readyimg\" style=\"height:450px;\">\n" +
        "                <img src=\"\" style=\"width:100%;height:100%\" >\n" +
        "            </div>\n" +
        "        <div class=\"row\" style=\"text-align:center;\">\n" +
        "            <button class=\"layui-btn layui-btn-fluid\" cropper-event=\"confirmSave\" type=\"button\"> 确定</button>\n" +
        "            <button type=\"button\" class=\"layui-btn\" cropper-event=\"reset\" >重置</button>\n" +
        "        </div>\n" +
        "        </div>\n" +
        "        <div class=\"layui-col-xs2\">\n" +
        "            <div><button type=\"button\" class=\"layui-btn \" cropper-event=\"rotate\" data-option=\"-15\" title=\"Rotate -90 degrees\"> 向左旋转</button></div>\n" +
        "            <div><button type=\"button\" class=\"layui-btn \" cropper-event=\"rotate\" data-option=\"15\" title=\"Rotate 90 degrees\"> 向右旋转</button></div>\n" +
        "            <div><button type=\"button\" class=\"layui-btn\" cropper-event=\"scaleSmall\"  title=\"右镜像\">右镜像</button></div>\n" +
        "            <div><button type=\"button\" class=\"layui-btn \" cropper-event=\"scaleBig\" title=\"左镜像\">左镜像</button></div>\n" +
        "            <div><button type=\"button\" class=\"layui-btn \" cropper-event=\"zoomBig\" title=\"放大图片\">放大</button></div>\n" +
        "            <div><button type=\"button\" class=\"layui-btn \"cropper-event=\"zoomSmall\"  title=\"缩小图片\">缩小</button></div>\n" +

        "        </div>\n" +
        "    </div>\n" +
        "    <div class=\"layui-row layui-col-space15\">\n" +
        "    </div>\n" +
        "</div>\n" +
        "</div>";
    $('body').append(html);
}
function cropperFn(img) {
    let _this = this;
	let ratioWidth="",ratioHeight="",aspectRatio=""
	if(_this.$aspectRatio){
		ratioWidth = _this.$aspectRatio.split(':')[0]
		ratioHeight = _this.$aspectRatio.split(':')[1]
		aspectRatio = ratioWidth/ratioHeight
	}else{
		aspectRatio = (_this.$imgWidth)/(_this.$imgHeight)
	}
 
    let imgurl = dsf.config.staticPath? dsf.config.staticPath+img.relativePath :dsf.url.getWebPath(img.relativePath);
    let filename = img.originalFileName;
	let imgtype = img.contentType;
    let id = _this.id;
    layui.config({
        base: '/dsfa/res/libs/cropper/' //layui自定义layui组件目录
    }).use(['cropper', 'croppers'], function () {
        var $ = layui.jquery;
        var croppers = layui.croppers;
        //创建一个头像上传组件
        croppers.render({
            elem: "#photo_" + id
            , aspectRatio:aspectRatio
            , autoCropArea:1
            , area: '800px'  //弹窗宽度
            , filename: filename
            , id: id
			, imgtype:imgtype
            , url: dsf.url.getWebPath('file/upload/')  //图片上传接口返回和（layui 的upload 模块）返回的JOSN一样
            , imgurl: imgurl
            , done: function (data) { //上传完毕回调
                _this.photoArray.push(data[0]);
                _this.value = JSON.stringify(_this.photoArray);
            }
        });

    });
}
//获取文件大小
function getFileSize(data) {
    let fileSize = parseInt(data)
    data = data.toString().toLowerCase();
    if (data.indexOf("m") > -1 || data.indexOf("mb") > -1) {
        fileSize = parseInt(data) * 1024
    }
    return fileSize
}
function addTips(){
    let $tipsPx = this.$tipsPx=$("<div style='position:relative;bottom:30px;text-align: center'>");
    let str = `长 * 宽：${this.$imgWidth}px * ${this.$imgHeight}px`;
    $tipsPx.html(str);
    this._handlers.photoBox.append($tipsPx)
}