const dom = require("../../templates/SystemFormControl.ejs");
import { deletedMetaData } from '../../../../core/metadata';
import { FormControl } from '../../../../baseControls';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { map } from '../../../../decorator/controlmap';

@map('删除状态', 'dsf.deletedstatus', 'DeletedStatus')
@isSupportDataPost(false)
export class DeletedStatus extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "删除状态"
    this.$metadata = deletedMetaData.call(this);
  }

  set value(value) {
    super.value = value;
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(valueFormatter(super.value));
    }
  }
  get value() {
    return super.value;
  }

  initTemplate() {
    return dom(this)
  }

  init() {
    super.init();
    this.caption = dsf.config.kw.deleted;
  }
  getValueString() {
    return valueFormatter(this.value);
  }
  getValueString() {
    return valueFormatter(this.value);
  }
}

function valueFormatter(val) {
  if (val == "1") {
    return "是";
  } else if (val == "0") {
    return "否"
  } else {
    return "";
  }
}