const dom = require("../../templates/CheckNode.ejs");
import { isSupportDataPost } from "../../../../core/postDecorator";
import { LayoutControl } from "../../../../baseControls";
import { Action } from "../../../../core/pageAction";
import { returnSelectedValue } from "../../../../decorator/ReturnSelectedData";
import { map } from "../../../../decorator/controlmap";

@map("组织架构选择", "dsf.checknode", "CheckNode")
@returnSelectedValue()
@isSupportDataPost(true)
export class CheckNode extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);

    this.tabs = [];

    /**
     * common：常用(没做)
     * unit 本部门
     * group 小组(没做)
     * department 本单位
     * framework 组织架构-组织架构的选人启用的异步请求showLevel判断接口
     */
    this._tabsExplain = {
      common: {
        user: "",
        dept: "",
      },
      unit: {
        user: "getUserByCurDept",
        dept: "getUserByCurDept",
      },
      group: {
        user: "",
        dept: "",
      },
      department: {
        user: "getUserByCurUnit",
        dept: "getDeptByCurUnit",
      },
      framework: {
        user: "getUserByOrg",
        dept: "getDeptByOrg",
      },
    };

    this._value = [];

    // 常用
    this._common = {
      data: [],
    };
    // 本部门
    this._unit = {
      data: [],
      treeObj: null,
      searchTreeObj: null,
    };
    // 小组
    this._group = {
      data: [],
    };
    // 本单位
    this._department = {
      data: [],
      treeObj: null,
      searchTreeObj: null,
    };
    // 组织架构
    this._framework = {
      data: [],
      treeObj: null,
      searchTreeObj: null,
    };

    // 搜索出来的值
    this.searchNode = [];

    // 是否可排序
    this.sort = false;

    // 是否显示复选框
    this.showCheckbox = false;
    /**
     * 选择类型
     * 0代表部门
     * 1代表人
     */
    this.types = "1";

    /**
     * 显示人员还是部门
     * user 人员
     * dept 部门
     */
    this.showType = "user";

    // 可选择的最大长度
    this.maxLength = null;

    // 组织架构的显示层级0为显示子机构，不填为显示全部
    this._showLevel = 0;
    // 组织架构仅仅显示子机构
    this.showSubDept = false;

    // 优化
    this._loading = null;
    this._loading_length = 0;

    // 点击时是否选择子节点
    this.chkboxType = false;
    this.defaultOpenSeries = 1;
  }

  set _tabs(v) {
    this.tabs = v;
  }
  get _tabs() {
    return this.tabs;
  }

  set _sort(v) {
    this.sort = v;
  }
  get _sort() {
    return this.sort;
  }

  set _showCheckbox(v) {
    this.showCheckbox = v;
  }

  get _showCheckbox() {
    return this.showCheckbox;
  }

  set _showType(v) {
    this.showType = v;
  }
  get _showType() {
    return this.showType;
  }

  set _types(v) {
    this.types = v;
  }
  get _types() {
    return this.types;
  }

  set value(v) {
    this._value = v;
    this.uploadChooseList();
    this.showCheckbox && this.checkedInit();
  }
  get value() {
    return this._value;
  }

  set _showSubDept(v) {
    this.showSubDept = v;
  }
  get _showSubDept() {
    return this.showSubDept;
  }

  set _chkboxType(v) {
    this.chkboxType = v || false;
  }
  get _chkboxType() {
    return this.chkboxType;
  }

  get treeSet() {
    const ct = this.chkboxType ? "" : "ps";
    const callback = this.showCheckbox
      ? {
          onCheck: this.zTreeOnCheck.bind(this),
        }
      : {
          onClick: this.zTreeOnClick.bind(this),
        };
    return {
      check: {
        enable: this.showCheckbox,
        chkStyle: "checkbox",
        chkboxType: { Y: ct, N: ct },
      },
      view: {
        selectedMulti: false,
        showIcon: false,
        showLine: false,
        fontCss: this.getFontCss.bind(this),
      },
      data: {
        key: {
          children: "children",
          name: "_name",
        },
      },
      callback,
    };
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    super.createElement();

    let _this = this;

    // 搜索
    this._handlers.search.on("click", function(e) {
      _this.search();
    });
    // 回车搜索
    this._handlers.search_input.on("keyup", function(e) {
      let keycode = window.event ? e.keyCode : e.which;
      if (keycode == 13) {
        _this.search();
      }
    });
    // 刷新
    this._handlers.search_clear.on("click", function(e) {
      _this._handlers.search_input.val("");
      _this.search();
    });
    // 清空
    this._handlers.empty.on("click", function() {
      _this._handlers.chooseList.html("");
      _this._handlers.chooseNum.html(0);
      _this._value = [];
      if (_this.showCheckbox) {
        _this._unit.treeObj && _this._unit.treeObj.checkAllNodes(false);
        _this._department.treeObj && _this._department.treeObj.checkAllNodes(false);
        _this._framework.treeObj && _this._framework.treeObj.checkAllNodes(false);
      }
    });
    // 删除
    this._handlers.chooseList.on("click", ".closeIcon", function() {
      let i = $(this)
        .closest(".item")
        .index();
      _this._value.splice(i, 1);
      _this.uploadChooseList();
      if (_this.showCheckbox) {
        const id = $(this)
          .parent()
          .attr("id");
        [_this._unit.treeObj, _this._department.treeObj, _this._framework.treeObj].forEach(treeObj => {
          if (treeObj) {
            const selectNodes = treeObj.getCheckedNodes(true);
            const index = selectNodes.findIndex(it => it._id === id);
            index !== -1 && treeObj.checkNode(selectNodes[index], false, false);
          }
        });
      }
    });
    // 上移
    this._handlers.chooseList.on("click", ".icon-shang", function() {
      let index = $(this)
        .closest(".item")
        .index();

      if (index == 0) {
        return;
      } else {
        let _temp = _this._value[index];
        _this._value[index] = _this._value[index - 1];
        _this._value[index - 1] = _temp;
      }

      _this.uploadChooseList();
    });
    // 下移
    this._handlers.chooseList.on("click", ".icon-xia", function() {
      let maxL = _this._value.length;
      let index = $(this)
        .closest(".item")
        .index();

      if (index + 1 == maxL) {
        return;
      } else {
        let _temp = _this._value[index];
        _this._value[index] = _this._value[index + 1];
        _this._value[index + 1] = _temp;
      }

      _this.uploadChooseList();
    });
  }

  search() {
    let v = this._handlers.search_input.val();
    this.updateNodes(false);

    if (v == "" || !v) {
      if (this._handlers.tree_unit_search) {
        // 本部门
        this._handlers.tree_unit.show();
        this._handlers.tree_unit_search.hide();
      }
      if (this._handlers.tree_department_search) {
        // 本单位
        this._handlers.tree_department.show();
        this._handlers.tree_department_search.hide();
      }
      if (this._handlers.tree_framework_search) {
        // 组织架构
        this._handlers.tree_framework.show();
        this._handlers.tree_framework_search.hide();
      }
      return;
    }

    this.searchNode = [];
    if (this._framework.treeObj) {
      this._handlers.tree_framework.hide();
      this._handlers.tree_framework_search.show();

      let searchNode = this._framework.treeObj.getNodesByParamFuzzy("_name", v);
      this.searchNode = searchNode;
      this.searchTree(this._framework.searchTreeObj, "tree_framework_search", searchNode);
    }
    if (this._unit.treeObj) {
      this._handlers.tree_unit.hide();
      this._handlers.tree_unit_search.show();

      let searchNode = this._unit.treeObj.getNodesByParamFuzzy("_name", v);
      this.searchNode = this.searchNode.concat(searchNode);
      this.searchTree(this._unit.searchTreeObj, "tree_unit_search", searchNode);
    }
    if (this._department.treeObj) {
      this._handlers.tree_department.hide();
      this._handlers.tree_department_search.show();

      let searchNode = this._department.treeObj.getNodesByParamFuzzy("_name", v);
      this.searchNode = this.searchNode.concat(searchNode);
      this.searchTree(this._department.searchTreeObj, "tree_department_search", searchNode);
    }
    // this.updateNodes(true);
  }
  searchTree(treeObj, treeId, searchNode) {
    let _searchNode = $.extend(true, [], searchNode);

    $.fn.zTree.destroy(treeId);

    for (let i in _searchNode) {
      let _treeNode = _searchNode[i];
      _treeNode.children = [];
      _treeNode.highlight = true;
      _treeNode.isParent = !!_treeNode.isParent;

      let parentNode = this.getParentSite(_treeNode, treeObj, true);
      if (i == 0) {
        treeObj = $.fn.zTree.init($("#" + treeId), this.treeSet, [parentNode]);
      } else {
        treeObj.addNodes(treeObj.getNodesByParam("_id", parentNode._id, null)[0], parentNode.children, true);
      }
    }
    if (_searchNode.length == 0) {
      $("#" + treeId).html(
        "<div style='text-align:center;padding:20px'><img style='width:40%;max-width:162px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"
      );
    }
  }
  getParentSite(_treeNode, treeObj, isFirst) {
    if (_treeNode._id) {
      let hasNode = !treeObj || isFirst ? [] : treeObj.getNodesByParam("_id", _treeNode._id, null);
      if (hasNode && hasNode.length > 0) {
        return _treeNode;
      } else {
        let p = _treeNode.getParentNode() ? $.extend(true, {}, _treeNode.getParentNode()) : null;
        if (p) {
          p.children.length = 1;
          p.children[0] = _treeNode;
          return this.getParentSite(p, treeObj);
        } else {
          return _treeNode;
        }
      }
    }
  }
  updateNodes(highlight) {
    for (let i in this.searchNode) {
      this.searchNode[i].highlight = highlight;
      if (this._framework.searchTreeObj) {
        this._framework.searchTreeObj.updateNode(this.searchNode[i]);
      }
      if (this._unit.searchTreeObj) {
        this._unit.searchTreeObj.updateNode(this.searchNode[i]);
      }
      if (this._department.searchTreeObj) {
        this._department.searchTreeObj.updateNode(this.searchNode[i]);
      }
    }
  }
  checkedInit() {
    const ids = this._value.map(it => it._id);
    [this._unit.treeObj, this._department.treeObj, this._framework.treeObj].forEach(treeObj => {
      if (treeObj) {
        const allNodes = treeObj.transformToArray(treeObj.getNodes());
        ids.forEach(id => {
          const index = allNodes.findIndex(it => it._id === id);
          index !== -1 && treeObj.checkNode(allNodes[index], true, false);
        });
      }
    });
  }
  rerenderTree() {
    if (this._handlers.unit.css("display") !== "none" && this._unit.treeObj) {
      this._unit.treeObj.destroy();
      const formatData = Array.isArray(this._unit.data) ? this._unit.data : [this._unit.data];
      formatChecked(formatData, this._value, !this.showCheckbox);
      this._unit.data = formatData;
      this._unit.treeObj = $.fn.zTree.init($("#tree_unit"), this.treeSet, this._unit.data);
      expandTree(this._unit.treeObj, this.defaultOpenSeries);
    }
    if (this._handlers.department.css("display") !== "none" && this._department.treeObj) {
      this._department.treeObj.destroy();
      const formatData = Array.isArray(this._department.data) ? this._department.data : [this._department.data];
      formatChecked(formatData, this._value, !this.showCheckbox);
      this._department.data = formatData;
      this._department.treeObj = $.fn.zTree.init($("#tree_department"), this.treeSet, this._department.data);
      expandTree(this._department.treeObj, this.defaultOpenSeries);
    }
    if (this._handlers.framework.css("display") !== "none" && this._framework.treeObj) {
      const isAsync = this.showType == "user" && (this.showSubDept == true ? true : false);
      const treeSet = isAsync
        ? {
            async: {
              enable: true,
              url: dsf.UrlSetting.getUserByDept,
              type: "get",
              autoParam: ["_id=deptID"],
              dataFilter: this.asyncDataFilter.bind(this),
            },
          }
        : {};
      Object.assign(treeSet, this.treeSet);
      this._framework.treeObj.destroy();
      const formatData = Array.isArray(this._framework.data) ? this._framework.data : [this._framework.data];
      formatChecked(formatData, this._value, !this.showCheckbox);
      this._framework.data = formatData;
      this._framework.treeObj = $.fn.zTree.init($("#tree_framework"), treeSet, this._framework.data);
      if (!isAsync) {
        expandTree(this._framework.treeObj, this.defaultOpenSeries);
      }
    }
  }
  renderReady() {
    super.renderReady();
    this.renderDom();
  }
  renderDom() {
    this._handlers.common.hide();
    this._handlers.unit.hide();
    this._handlers.group.hide();
    this._handlers.department.hide();
    this._handlers.framework.hide();

    this._handlers.common_c.hide();
    this._handlers.unit_c.hide();
    this._handlers.group_c.hide();
    this._handlers.department_c.hide();
    this._handlers.framework_c.hide();

    this._handlers.tree_unit_search.hide();
    this._handlers.tree_department_search.hide();
    this._handlers.tree_framework_search.hide();

    this.element.find(".layui-this").removeClass("layui-this");
    this.element.find(".layui-show").removeClass("layui-show");

    if (this.root._isDesign) {
      for (let i in this.tabs) {
        this._handlers[this.tabs[i]].show();
        if (i == 0) {
          this._handlers[this.tabs[i]].addClass("layui-this");
          this._handlers[this.tabs[i] + "_c"].addClass("layui-show");
        }
      }
    }

    this.root.event.on(PageEvent.READY, evt => {
      this._loading = dsf.layer.loadding();
      for (let i in this.tabs) {
        this._handlers[this.tabs[i]].show();
        if (i == 0) {
          this._handlers[this.tabs[i]].addClass("layui-this");
          this._handlers[this.tabs[i] + "_c"].addClass("layui-show");
        }
      }
      this.loadTreeUnit();
      this.loadTreeDepartment();
      this.loadTreeFramework();
    });
  }

  getFontCss(treeId, treeNode) {
    return !!treeNode.highlight ? { color: "#EB6025", "font-weight": "bold" } : { color: "#333", "font-weight": "normal" };
  }
  zTreeOnCheck(event, treeId, treeNode) {
    let nodes = $.fn.zTree.getZTreeObj(treeId).transformToArray(treeNode);
    const parentNode = [];
    let temp = treeNode;
    while (temp) {
      const tempNode = temp.getParentNode();
      temp = tempNode;
      temp && parentNode.push(temp);
    }
    nodes = [...parentNode, ...nodes];
    nodes.forEach(item => {
      if (item.checked) {
        if (!this._value.some(it => it._id === item._id)) {
          this._value.push(item);
        }
      } else {
        const index = this._value.findIndex(it => it._id === item._id);
        index !== -1 && this._value.splice(index, 1);
      }
      if (this.maxLength && this._value.length > this.maxLength) {
        this._value.splice(0, 1);
        $.fn.zTree.getZTreeObj(treeId).checkNode(item, false, false);
      }
      this.uploadChooseList();
    });
  }
  zTreeOnClick(event, treeId, treeNode) {
    let elem = this._handlers.chooseList;
    if (elem.find("#" + treeNode._id).length == 0) {
      if (this.chkboxType) {
        this._value.push(treeNode);
      } else {
        treeNode = $.fn.zTree.getZTreeObj(treeId).transformToArray(treeNode);
        for (let i in treeNode) {
          if (this.isCanChooseType(treeNode[i]._type) && elem.find("#" + treeNode[i]._id).length == 0) {
            treeNode[i]._getParentNode = treeNode[i].getParentNode();
            this._value.push(treeNode[i]);
          }
          if (this.maxLength && this._value.length > this.maxLength) {
            this._value.splice(0, 1);
          }
        }
      }
      this.uploadChooseList();
    } else {
      console.log("您已经选择过了");
    }
  }

  isCanChooseType(treeNodeType) {
    if (this.types && this.types != "") {
      if (!$.isArray(this.types)) {
        this.types = this.types.split(",");
      }
      for (let i in this.types) {
        if (this.types[i] == treeNodeType) {
          return true;
        }
      }
      return false;
    } else {
      return true;
    }
  }
  uploadChooseList() {
    let elem = this._handlers.chooseList;
    elem.html("");
    for (let i in this._value) {
      let item = this._value[i];
      let sortIcon = "";
      if (this.sort) {
        sortIcon = "<i class='iconfont icon-shang'></i><i class='iconfont icon-xia'></i>";
      }
      elem.append(
        "<li class='item " +
          (this.sort ? "canSort" : "") +
          "' id='" +
          item._id +
          "'>" +
          (i * 1 + 1) +
          "." +
          item._name +
          sortIcon +
          " <i class='closeIcon iconfont icon-guanbi1'></li>"
      );
    }
    this._handlers.chooseNum.html(this._value.length);
  }

  loadTreeUnit() {
    if (this._handlers.unit.css("display") == "none") {
      return;
    } else {
      this._loading_length++;
      this._handlers.tree_unit.show();
      loadUnit.call(this);
    }
  }
  loadTreeDepartment() {
    if (this._handlers.department.css("display") == "none") {
      return;
    } else {
      this._loading_length++;
      this._handlers.tree_department.show();
      loadDepartment.call(this);
    }
  }

  loadTreeFramework() {
    if (this._handlers.framework.css("display") == "none") {
      return;
    } else {
      this._loading_length++;
      this._handlers.tree_framework.show();
      loadFramework.call(this);
    }
  }

  asyncDataFilter(treeId, parentNode, responseData) {
    if (responseData.data.children && responseData.data.children.length > 0) {
      responseData.data = [responseData.data];
      loadFramework_async(responseData.data, true);
      return responseData.data[0];
    }
    return null;
  }
}

function expandTree(tree, defaultOpenSeries) {
  const nodes = tree.getNodes();
  const fn = nodes => {
    for (let i in nodes) {
      if (parseInt(defaultOpenSeries) - 1 >= nodes[i].level) {
        tree.expandNode(nodes[i], true);
        if (nodes[i].children && nodes[i].children.length) {
          fn(nodes[i].children);
        }
      }
    }
  };
  if (defaultOpenSeries > 0) {
    fn(nodes);
  } else if (defaultOpenSeries < 0) {
    tree.expandAll(true);
  }
}

function formatChecked(data, chos, removeCheck = false) {
  data.forEach(item => {
    if (removeCheck) {
      delete item.checked;
    } else {
      item.checked = chos.some(it => it._id === item._id);
    }
    item.children && item.children.length && formatChecked(item.children, chos, removeCheck);
  });
}

function loadUnit() {
  Action[this._tabsExplain.unit[this.showType]]({}, (err, data) => {
    if (err) {
      dsf.layer.message(dsf.prompt.loaddatafail, false);
    } else {
      const formatData = Array.isArray(data) ? data : [data];
      this.showCheckbox && formatChecked(formatData, this._value);
      if (this.showCheckbox) {
        formatChecked(formatData, this._value);
      }
      this._unit.data = formatData;
      this._unit.treeObj = $.fn.zTree.init($("#tree_unit"), this.treeSet, this._unit.data);
      expandTree(this._unit.treeObj, this.defaultOpenSeries);
    }
    if (this._loading_length == 1) {
      this._loading_length = 0;
      dsf.layer.close(this._loading);
    } else {
      this._loading_length--;
    }
  });
}

function loadDepartment() {
  Action[this._tabsExplain.department[this.showType]]({}, (err, data) => {
    if (err) {
      dsf.layer.message(dsf.prompt.loaddatafail, false);
    } else {
      const formatData = Array.isArray(data) ? data : [data];
      this.showCheckbox && formatChecked(formatData, this._value);
      if (this.showCheckbox) {
        formatChecked(formatData, this._value);
      }
      this._department.data = formatData;
      this._department.treeObj = $.fn.zTree.init($("#tree_department"), this.treeSet, this._department.data);
      expandTree(this._department.treeObj, this.defaultOpenSeries);
    }
    if (this._loading_length == 1) {
      this._loading_length = 0;
      dsf.layer.close(this._loading);
    } else {
      this._loading_length--;
    }
  });
}

function loadFramework() {
  let treeSet = this.treeSet;
  // 组织架构人员如果不是开启的全部就启用异步加载
  let async = this.showType == "user" && (this.showSubDept == true ? true : false);

  let UrlSetting = this._tabsExplain.framework[this.showType];
  let param = {};

  if (async) {
    treeSet.async = {
      enable: true,
      url: dsf.UrlSetting.getUserByDept,
      type: "get",
      autoParam: ["_id=deptID"],
      dataFilter: this.asyncDataFilter.bind(this),
    };
    UrlSetting = "getUserByOrg_async";
    param = {
      sExplanLevel: this._showLevel,
    };
  } else if (this.showType == "dept") {
    param = {
      sExplanLevel: this._showLevel,
    };
  }
  Action[UrlSetting](param, (err, data) => {
    if (err) {
      dsf.layer.message(dsf.prompt.loaddatafail, false);
    } else {
      if (async) {
        if (!Array.isArray(data)) {
          data = [data];
        }
        loadFramework_async.call(this, data);
      }
      const formatData = Array.isArray(data) ? data : [data];
      this.showCheckbox && formatChecked(formatData, this._value);
      if (this.showCheckbox) {
        formatChecked(formatData, this._value);
      }
      this._framework.data = formatData;
      this._framework.treeObj = $.fn.zTree.init($("#tree_framework"), treeSet, this._framework.data);
      if (!async) {
        expandTree(this._framework.treeObj, this.defaultOpenSeries);
      }
    }
    if (this._loading_length == 1) {
      this._loading_length = 0;
      dsf.layer.close(this._loading);
    } else {
      this._loading_length--;
    }
  });
}

function loadFramework_async(nodes, noParent) {
  for (let i in nodes) {
    let node = nodes[i];
    let children = node.children;
    if (children && children.length > 0) {
      node.open = true;
      loadFramework_async(children, noParent);
    } else if (!noParent && children && children.length == 0) {
      delete node.children;
      node["isParent"] = "true";
    } else {
      node.open = true;
    }
  }
}
