function getSuperFilterData(filter) {
  var queryData = {};
  if (filter) {
    for (var i = 0; i < filter.length; i++) {
      var f = filter[i];
      var data = f.data;
      var code = null;
      if (data.valueAttributes.length > 1) {
        var va = {};
        data.valueAttributes.forEach(function (o) {
          va[o.code] = o.code;
        })
        if (va.value != undefined) {
          code = f.data.code + "_" + va.value;
        } else if (va.sdate != undefined && va.edate != undefined) {
          code = [f.data.code + "_" + va.sdate, f.data.code + "_" + va.edate];
        }
      }
      if (!code) {
        code = f.data.code;
      }
      if (data.queryType == "enum_multi" || data.queryType == "multi_select") {
        if (data.enumItems && data.enumItems.operator == "range") {
          f.value.forEach(function (v) {
            let arr = v.value.split(";")
            arr.forEach(function (v, i) {
              queryData[code + "_" + (i + 1)] = v;
            });
          });
        } else if (data.enumItems && data.enumItems.operator == "in") {
          let value = [];
          f.value.forEach(function (v) {
            let arr = v.value.split(";");
            arr.forEach(function (v, i) {
              value.push(v);
            });
          });
          queryData[code] = value;
        } else if (data.enumItems.operator == "like" || data.enumItems.operator == "slike" || data.enumItems.operator == "elike") {
          let value = [];
          f.value.forEach(function (v) {
            let arr = v.value.split(";");
            arr.forEach(function (v, i) {
              value.push(v);
            });
          });
          queryData[code] = value.join(" ")
        } else {
          let value = [];
          f.value.forEach(function (v) {
            let arr = v.value.split(";");
            arr.forEach(function (v, i) {
              value.push(v);
            });
          })
          queryData[code] = value;
        }
      } else if (data.queryType == "datetime") {
        //单个日期字段
        if (typeof (code) == "string") {
          queryData[code + "_1"] = f.value[0].value[0] + " 00:00:00 ";
          queryData[code + "_2"] = f.value[0].value[1] + " 23:59:59";
        }
        //日期区间 
        else if ($.isArray(code)) {
          queryData[code[0]] = f.value[0].value[1] + " 23:59:59";
          queryData[code[1]] = f.value[0].value[0] + " 00:00:00 ";
        }
      } else if (data.queryType == "text") {
        queryData[code] = f.value[0].value;
      }

    }
  }
  return queryData;
}

export default{
  getSuperFilterData
}