const dom = require("../../templates/UpDownLayout.ejs");
import { LayoutControl } from '../../../../baseControls';
import { Container } from "../../../../baseControls";
import { map } from '../../../../decorator/controlmap';

@map('上下布局', 'dsf.updownlayout', 'UpDownLayout')
export class UpDownLayout extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$viewSplit = "50%,50%";
    this._upElement = null;
    this._downElement = null;
    this.hasPadding = true;
  }
  initTemplate() {
    return dom(this);
  }
  createElement() {
    var el = super.createElement();
    if (!this._isRender && this.root._isDesign) {
      if (this.children.length <= 0) {
        for (var i = 0; i < 2; i++) {
          var container = new Container(this.id + "_" + i, true);
          this._addChild(container, null);
          if (i == 0) {
            container.addClass(["up"]);
            this._upElement = container;
          } else {
            container.addClass(["down"]);
            this._downElement = container;
          }
        }
      }
    }
    return el;
  }
  resize() {
    let _h = this.element.height();
    let _d = this.$viewSplit.split(",");
    let _seting = false;
    if (_d && _d[0] && _d[0] != 'auto') {
      _seting = true;
      let _up = this.element.find('.up');
      _up.css('height', _d[0]);
      this.element.find('.down').css('height', _h - _up.height() - 1);
    }
    if (!_seting && _d && _d[1] && _d[1] != 'auto') {
      let _down = this.element.find('.down');
      _down.css('height', _d[1]);

      this.element.find('.up').css('height', _h - _down.height() - 1);
    }
    super.resize();
  }
  renderPadding() {
    if (this.$hasPadding) {
      this._upElement.removeClass("no_padding");
      this._downElement.removeClass("no_padding");
    } else {
      this._upElement.addClass(["no_padding"]);
      this._downElement.addClass(["no_padding"]);
    }

  }
}