  //修改选项
  changeFilters(data) {
    let search = [];
    for (let i = 0; i < data.length; i++) {
      let s = data[i];
      let va = s.valueAttributes;
      let code = null;
      //复杂元数据有超过1个属性
      if (va.length > 1) {
        let v = {};
        va.forEach(function(o) {
          v[o.code] = o.code;
        });
        //枚举型数据
        if (v.text != undefined && v.value != undefined) {
          code = s.code + "_" + v.value;
        } else if (v.sdate != undefined && v.edate != undefined) {
          code = [s.code + "_sdate", s.code + "_edate"];
        }
      }
      if (!code) {
        code = s.code;
      }
      if (s.queryType == "enum_multi") {
        let operator = (s.enumItems) ? s.enumItems.operator : (s.dataSource ? s.dataSource.operator : 'eq');
        //区间为单选
        if (operator == "range") {
          let item1 = {
            code: code,
            operator: "gteq",
            valueKey: code + "_1",
            pCode: s.pCode || ''
          }
          let item2 = {
            code: code,
            operator: "lteq",
            valueKey: code + "_2",
            pCode: s.pCode || ''
          }
          search.push(item1);
          search.push(item2);
        }
        //多选
        else if (operator == "in" || operator == "eq" || operator == "like" || operator == "slike" || operator == "elike") {
          let item = {
            code: code,
            operator: (operator == "in" || operator == "eq") ? "in" : operator,
            valueKey: code,
            pCode: s.pCode || ''
          }
          search.push(item);
        }
      } else if (s.queryType == "datetime") {
        if (typeof(code) == "string") {

          let item1 = {
            code: code,
            operator: "gteq",
            valueKey: code + "_1",
            pCode: s.pCode || ''
          }
          let item2 = {
            code: code,
            operator: "lteq",
            valueKey: code + "_2",
            pCode: s.pCode || ''
          }
          //后端暂不支持复杂查询
          // item.items.push(item1);
          // item.items.push(item2);
          search.push(item1);
          search.push(item2);
        } else if ($.isArray(code)) {
          let item1 = {
            code: code[0],
            operator: "lteq",
            valueKey: code[0],
            pCode: s.pCode || ''
          }
          let item2 = {
            code: code[1],
            operator: "gteq",
            valueKey: code[1],
            pCode: s.pCode || ''
          }
          // item.items.push(item1);
          // item.items.push(item2);
          search.push(item1);
          search.push(item2);
        }
      }
    }
    return search;
  }

