const dom = require("../../templates/Select.ejs");
import { ItemsControl } from '../../../../baseControls';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControlEvent } from '../../../../core/ControlEvent';
import {map} from  '../../../../decorator/controlmap';

@map('下拉框','dsf.select','Select')
@isSupportDataPost(true)
export class Select extends ItemsControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.label = "选择框";
        this.$allowMulti = false;
        // this.$isEmptry = true;
        // this.value=0;
    }


    get items() {
        return this._items;
    }
    set items(value) {
        this._items = [];
        if ($.isArray(value)) {
            if (value[0] == undefined || value[0].value != "") {
                value.splice(0, 0, { "text": "", "value": "" });
            }
            for (let i = 0; i < value.length; i++) {
                let isRender = i == value.length - 1 ? true : false;
                this.addItem(value[i], i, isRender);
            }
        }
    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
        this._itemsBox = this._handlers.select;
    }

    renderContext() {
        super.renderContext();
        this._handlers.label.html(this.label);
        if (this.disabled) {
            if (this._handlers.select) {
                this._handlers.select.prop("disabled", true);
            }
        }
    }

    get value() {
        return super.value;
    }
    set value(value) {
        super.value = value;
        //如果是空对象或者
        if (value && $.isEmptyObject(value) && value.value != undefined && value.text != undefined) {
            this.$value.text = "";
            this.$value.value = "";
            this.$value = value;
        }
        if (this.itemsBox) {
            if (value && value.value != undefined && value.text != undefined) {
                let isExist = this.items.filter(v => {
                    return v.value == value.value;
                });
                if (isExist.length == 0) {
                    this._items.push(this.$value)
                    this.items = this._items;
                }
            }
            let val = (this.value == null || this.value == undefined) ? "" : this.value.value;
            this.itemsBox.val(val);
            dsf.UI.render("select", true);
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }

    }

    renderReady() {
        let _this = this;
        super.renderReady();

        //这段很影响性能
        //判断是否在子表中，如果是需要增加selectopen属性强制将ellipsis样式的overflow设置成overflow: visible否则下拉框无法展开
        let cell = this.element.closest(".ds_sub_table_cell_context");
        if (!this.readOnly) {
            dsf.UI.render("select", true);

            if (cell.length > 0) {
                if (cell.hasClass("ellipsis")) {
                    cell.attr("selectopen", "1");
                }
            }
        } else {
            cell.removeAttr("selectopen", "1");
        }

        layui.form.on('select(' + this.id + ')', function(data) {
            $(data.elem).val(data.value);
            let isChange = data.value != _this.value;
            _this.value = data.value;
            if (isChange) {
                _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
                if (_this.itemsBox) {
                    _this.itemsBox.trigger("change", { ui: _this });
                }
                _this.commitAudit();
            }
        });
    }

    renderItems() {
        if (!this.readOnly) {
            super.renderItems();
            if (this.element) {
                let isExist = false;
                for (let i = 0; i < this.items.length; i++) {
                    let item = this.items[i];
                    let selected = null;
                    if (this.value) {
                        selected = this.value.value == item.value;
                        if (selected) {
                            isExist = true;
                        }
                    }
                    let op = $("<option value='" + item.value + "' " + (selected ? "selected" : "") + ">" + item.text + "</option>");
                    this._itemsBox.append(op);
                }
                if (!isExist) {
                    if (this.value && (this.value.value != undefined && this.value.text != undefined)) {
                        this._items.push(this.value);
                        let op = $("<option value='" + this.value.value + "'  selected='selected'>" + this.value.value + "</option>");
                        this._itemsBox.append(op);
                    } else {
                        this.value = this.items[0];
                    }
                }
                // layui.form.render("select");
                dsf.UI.render("select", true);
            }
        }

    }

     //描述组件的验证信息
     validateInfo(){
        return {
            tipsElement:".layui-input-block"
        }
    }
}