import { FormControlEvent } from '../../core/ControlEvent';
import { FormControl } from './FormControl';
import { map } from '../../decorator/controlmap';

@map('考试题基类', 'dsf.examsubject', 'ExamSubject')

export class ExamSubject extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    // this._desingerClass = ControlEditor;
    this.$value = null;
    this.$label = "";
    this.$useVdom = true;
    //是否只读
    this.$readOnly = false;
    this.$required = false;
    //题目真实顺序
    this.$questionIndex = 1;
    this.$indexInExam = 1;
    this.$questionBody = "";
    this._isMark = false;
    this.$prompt = "";
    this.$answer = [];
    this.$analysis_content = '';
    this._answered = false;
    this._isExamControl = true;
  }

  set label(value) {
    this.$label = value;
  }

  get label() {
    return this.$label;
  }


  set value(value) {
    this.$value = value;
  }

  get value() {
    return this.$value;
  }


  set readOnly(value) {
    this.$readOnly = value;
    this.domUpdate();
  }

  get readOnly() {
    return this.$readOnly;
  }

  set visible(value) {
    this.$visible = value;
    this.domUpdate();
  }
  get visible() {
    return this.$visible;
  }


  set questionIndex(value) {
    this.$questionIndex = value;
    let v = (this.$questionIndex + 1000).toString().substr(1);
    this.caption = "Q" + v;
    this.domUpdate();
  }
  get questionIndex() {
    return this.$questionIndex;
  }

  set indexInExam(value) {
    this.$indexInExam = value;
    this.domUpdate();
  }
  get indexInExam() {
    return this.$indexInExam;
  }

  get questionBody() {
    return this.$questionBody
  }

  set questionBody(value) {
    this.$questionBody = value;
    this.domUpdate();
  }


  set metadata(value) {
    super.metadata = value;
  }

  get metadata() {
    return super.metadata;
  }


  commit() {
    if (this.root) {
      this.root.stateChange(this);
    }
  }

  doMark() {
    this._isMark = !this._isMark;
    this.domUpdate();
    this.commit();
  }

  showPrompt() {
    let _this = this;
    layer.open({
      title: false,
      closeBtn: 0,
      resize: false,
      content: '<pre class="exam-msg-tip">' + _this.$prompt + '</pre>',
      area: ["1000px", '500px']
    });
  }

  //获取标准答案
  getAnswer() {
    return this.$answer;
  }

  setAnswer(value) {
    this.$answer = value || [];
    this.$answer = $.type(this.$answer) == 'array' ? this.$answer : [this.$answer];
    // this.update()
    this._viewRender.render();
    this.commit();
  }

  setAnalysis(value) {
    this.$analysis_content = value;
    this._viewRender.render();
  }

  getTextString() {
    return "";
  }

  getValueString(split) {
    return this.value;
  }

  createMetaData() {
    if (this.metadata) {
      if (!this.$isFromMetaData) {
        let key = this.root.scope;
        let controlCode = this.$caption;
        let ns = key;
        key += "." + controlCode;
        this.metadata.code = controlCode;
        this.metadata.id = ns.replace(/\_/g, '.') + "." + controlCode;
        let path = ns.replace(/\_/g, '.');
        this.metadata.at = path;
        // this.metadata.name = this.metadata.name || this.$questionBody;
        this.metadata.name = this.$questionBody;
        this.metadata_fullcode = key;
        this.metadata.level = 0;
        return { "key": this.metadata_fullcode, "md": this.metadata };
      } else {
        let index = this.metadata.id.lastIndexOf(".");
        let key = this.metadata.id.substring(0, index).replace(/\./g, "_") + "." + this.metadata.id.substr(index + 1);
        this.metadata_fullcode = key;
        this.metadata.level = 0;
        return { "key": this.metadata_fullcode, "md": this.metadata };
      }
    }
    return null;
  }


}