const dom = require("../../templates/Iframe.ejs");
import { Control } from '../../../../baseControls';
import { ControlEditor } from '../../../../editor/ControlEditor';
import { express } from '../../../../core/express';
import { map } from '../../../../decorator/controlmap';

@map('网页视图', 'dsf.iframe', 'Iframe')
export class Iframe extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.$rmiframeUrl = ''
    this._desingerClass = ControlEditor;
    this.$lazyLoad = false;
    this._isLoaded = false;
    this.$showPadding = false;
  }

  set rmiframeUrl(value) {
    this.$rmiframeUrl = value;
  }
  get rmiframeUrl() {
    return this.$rmiframeUrl
  }

  initTemplate() {
    return dom(this);
  }
  createElement() {
    super.createElement();
  }

  renderContext() {
    super.renderContext();
    if (!this._isRender && !this.root._isDesign) {
      if (!this.$lazyLoad) {
        this.loadView();
      }
    }
  }

  loadView() {
    // let exp = dsf.Express;
    // let v = exp.replace(this.rmiframeUrl);
    let v = dsf.Express.replace(this.rmiframeUrl)
    v = dsf.url.getAbsolutePath(v);
    v = dsf.url.analysis(v)
    this._handlers.iframe.attr('src', v)
    this._isLoaded = true;
  }

  resize() {
    this.element.css("height", "100%")
    this._handlers.iframe.css("height", "100%")
    this._handlers.iframe.css("width", "100%");

    super.resize();
  }
}