import dome from '../../templates/NormalComment.ejs';
import { ControlEditor } from "../../../../editor/ControlEditor";
import { NewsDetailEvent } from '../../../../core/ControlEvent';
import { Control } from "../../../../baseControls";
import { Template } from '../../../../core/template';
import { normalCommentMetaData } from "../../../../core/metadata";
import * as Controls from '../controls';
import * as ButtonPlugin from '../../../../pulgins/buttons';

import { map } from '../../../../decorator/controlmap';
const baseIndent = 60;
@map("评论", 'dsf.normalcomment', 'NormalComment')
export class NormalComment extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$Msgtitle = "评论";
    this.$metadata = normalCommentMetaData.call(this);
    this.$firstCommentNum = "1"
    this.$replyAreaTop = 'top';
    this.$pageSize = '4'; //一级分页 每页条数
    this.$childPageSize = "3"; //子级分页每页条数
    this.$orderWay = "up"; //排序方式
    this.$orderType = "time"; //排序类型
    this.$businessType = "kc_pl";
    this.$buttonBar = ButtonPlugin.ButtonBar();
    this.$customerOption = {}
    this.pageNo = 1;
    this.childPageNo = 1;
    this.businessId = '';
    this.pageTotal = "";
    this.MsgNum = "0"
    this.ywTitle = "";
    this.subComTextUp = true;
    this.commentImgarr = [];
    this.isOwn = 0;
    this.tagDictId = ""
    this.qqfaceRes = dsf.url.getWebPath('res/libs/qqFace/arclist/')
    this.$readOnly = false;
    this.firstlevelPlaceholder = '请输入提问内容'

    this.backgroundColor = null

    //   创建一个评论项模板
    Template.createTemplate(this, '$commentTemplate', "main_content");
    console.log(this.$commentTemplate)
    jQuery.fn.extend({
      setCaret: function () {
        // if(!$.browser.msie) return; 
        var initSetCaret = function () {
          var textObj = $(this).get(0);
          textObj.caretPos = document.selection.createRange().duplicate();
        };
        $(this).click(initSetCaret).select(initSetCaret).keyup(initSetCaret);
      },
      insertAtCaret: function (textFeildValue) {
        var textObj = $(this).get(0);
        var str = textFeildValue.replace(/\[em_([0-9]*)\]/g, '<img src="' + dsf.url.getWebPath('/res/libs/qqFace/arclist/$1.gif') + '" border="0" />');
        if (textObj.innerHTML && textObj.innerHTML != '请输入提问内容' && $(this).children('span').length == 0) {
          textObj.innerHTML += str
        } else {
          textObj.innerHTML = str
        }
        $("#show").html(textObj.innerHTML);
      }
    });
    var interval;
    jQuery.event.special.contentchange = {
      setup: function () {
        var self = this,
          $this = $(this),
          $originalContent = $this.text();
        interval = setInterval(function () {
          if ($originalContent != $this.text()) {
            $originalContent = $this.text();
            jQuery.event.dispatch.call(self, { type: 'contentchange' });
          }
        }, 100);
      },
      teardown: function () {
        clearInterval(interval);
      }
    };
    document.onkeydown = function (e) {
      if (e.keyCode == 8) {
        if ($("#firstComment").get(0).innerText.length == 1) {
          $("#firstComment").html(' ')
        }
      }
    }
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-16 11:09:27
   * @LastEditors: OBKoro1
   * @LastEditTime: 颜色值
   */
  setColor() {
    var pattern = /^#[0-9a-fA-F]{6}$/
    if (!this.backgroundColor.match(pattern)) {
      alert('请输入正确的16进制颜色值')
      return
    }
    this._handlers.bannerColor.css({
      backgroundColor: this.backgroundColor,
    })
  }


  set readOnly(val) {
    this.$readOnly = val
    this.loadCommentData()
  }
  get readOnly() {
    return this.$readOnly
  }
  set customerOption(val) {
    if (_.isPlainObject(val)) {
      this.$customerOption = val
    } else {
      dsf.layer.message("用户自定义参数格式错误")
    }

  }
  get customerOption() {
    return this.$customerOption
  }
  set msgNum(val) {
    if (!$.isEmptyObject(this._handlers)) {
      this._handlers.MsgNum.html("（" + val + "）")
    }
    this.$msgNum = val
  }
  get msgNum() {
    return this.$msgNum
  }
  set firstCommentNum(val) {
    // document.getElementById("msgTitle-data").innerHTML=val;
    this.$firstCommentNum = val
  }
  get firstCommentNum() {
    return this.$firstCommentNum
  }
  set businessType(val) {
    this.$businessType = val
  }
  get businessType() {
    return this.$businessType
  }
  set replyAreaTop(val) {
    this.$replyAreaTop = val
  }
  get replyAreaTop() {
    return this.$replyAreaTop
  }
  set Msgtitle(val) {
    this.$Msgtitle = val
  }
  get Msgtitle() {
    return this.$Msgtitle
  }
  set pageSize(val) {
    this.$pageSize = parseInt(val)
  }
  get pageSize() {
    return this.$pageSize
  }
  set childPageSize(val) {
    this.$childPageSize = parseInt(val)
  }
  get childPageSize() {
    return this.$childPageSize
  }
  set orderWay(val) {
    this.$orderWay = val
  }
  get orderWay() {
    return this.$orderWay
  }
  set orderType(val) {
    this.$orderType = val
  }
  get orderType() {
    return this.$orderType
  }


  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    if (this.root._isDesign) {
      if (!this.$commentTemplate.control) {
        let trCtrl = new Controls.HtmlElement("<DIV></DIV>", true);
        trCtrl.addClass("no_padding");
        this.$commentTemplate.control = trCtrl;
      }
    }
    this.commentContent = this._handlers.main_content; //评论内容父元素DIV
    this.msgNum = this._handlers.MsgNum.html(); // 评论数量
    this.imgBox = this._handlers.imgBox //一级评论 图片容器
    this.wordNum = this._handlers.wordNum;
    this.searchQ = this._handlers.searchQ;
    this.replyArea_wrap = this._handlers.replyArea_wrap;
    this.tempContainer = this._handlers.tempContainer
  }


  renderContext() {
    this._handlers.msgTitle.html(this.Msgtitle);
    console.log(this.$metadata.dataSource)
    this.tagDictId = this.$metadata.dataSource && this.$metadata.dataSource.code
  }
  initEvent() {
    console.log("this.$buttonBar", this.$buttonBar)
    this.businessId = dsf.url.queryString('id');
    this.ywTitle = dsf.Base64.decode(dsf.url.queryString('ywTitle'));
    this.ywUrl = dsf.Base64.decode(dsf.url.queryString('ywUrl'));
    this.pLID = dsf.url.queryString('dsfaCommentId')
    let _this = this;
    //    评论图片上传
    uploadImg.call(this);
    this.commentContent.html()
    this.loadCommentData()
    this.addqqFace($('.emotion'), {
      id: 'facebox',
      assign: 'firstComment',
      path: _this.qqfaceRes //表情存放的路径
    })
    // 一级评论提交
    $(".replyBtnOrg").bind("click", { "class": this }, this.submitFn)
    $(".searchbtn").bind("click", { "class": this }, this.searchfn)
    // 监听可编辑首级div的 文本输入
    $("#firstComment").html(_this.firstlevelPlaceholder);
    $("#firstComment").on("focus", function () {
      if ($("#firstComment").html() == _this.firstlevelPlaceholder) {
        $("#firstComment").html("")
      }
    })
    $("#firstComment").on("blur", function () {
      if ($("#firstComment").html() == '') {
        $("#firstComment").html(_this.firstlevelPlaceholder)
      }
    })
    $("#firstComment").bind('contentchange', function (e) {
      let str = $(e.currentTarget).get(0).innerText
      let num = str.length
      _this.wordNum.html(num + '/100')
      if (num > 100) {
        $(e.currentTarget).text(str.substring(0, 100))
      }
    })
    // $("#firstComment").on("focus",function(){
    //     $("#replyBtn").bind("click", { "class": _this }, _this.submitFn)
    // })
  }


  renderReady() {
    super.renderReady();
  }

  renderComplete() {
    super.renderComplete();
    if ($.isEmptyObject(this.customerOption)) {
      this.customerOption = {}
    }
  }
  searchfn(e) {
    let _this = e.data.class;
    let args = {
      pageNo: 1,
      pageSize: _this.pageSize,
      childPageNo: 1,
      childPageSize: _this.childPageSize,
      keywords: $(".searchQ").val(),
    }
    _this.loadCommentData(args)
  }
  loadCommentData(params, isloadMore) {
    console.log("this.customerOption", this.customerOption)
    let defaultParam = {
      pageNo: this.pageNo,
      pageSize: this.pageSize,
      childPageNo: this.childPageNo,
      childPageSize: this.childPageSize,
      keywords: "",
      businessType: this.businessType,
      businessId: this.businessId,
      orderWay: this.orderWay,
      orderType: this.orderType,
      btnPara: createBtnParam.call(this) || '',
      paraKey: dsf.url.queryString('paraKey'),
      isOwn: this.isOwn ? 1 : 0,
      tagDictId: this.tagDictId,
      dsfaCommentId: this.pLID

    }
    let args = $.extend(defaultParam, params)
    let url = dsf.url.getWebPath('dsfa/platform/comment/queryComment');
    // let url = 'http://192.168.0.31:8080/dsfa/dsfa/platform/comment/queryComment'
    let _this = this;
    dataRequst.call(this, url, args, 'get', function (args) {
      console.log(args)
      let data = args.data;
      let commentArr = data.comment;
      _this.pageTotal = data.total;
      if (!isloadMore) {
        _this.commentContent.html('');
        _this.renderPagination();
      }
      _(commentArr).forEach((val, index, arr) => {
        _this.createDom(val);
      })
      _this.msgNum = data.total;
    })
  }

  loadSubComment(pid) {
    let param = {
      childPageNo: this.childPageNo,
      childPageSize: this.childPageSize,
      businessType: this.businessType,
      businessId: this.businessId,
      pId: pid,
      btnPara: createBtnParam.call(this) || ''
    }
    let url = dsf.url.getWebPath('dsfa/platform/comment/queryChildComment');
    let _this = this;
    dataRequst.call(this, url, param, 'get', function (args) {
      console.log(args);
      let data = args.data;
      if (args.data.length > 0) {
        _(data).forEach((val, index, arr) => {
          _this.createDom(val, true);
        })
      } else {
        $('#loadmore_' + pid).html("已经到底啦。。");
        $('#loadmore_' + pid).off("click")
      }

    })
  }
  //    生成评论item的Dom 元素
  createDom(data, isSub) {
    let tempClass = data.treeinfoLevel == 2 ? "retractNum subLevel" : data.treeinfoLevel > 2 ? "doubleRetractNum subLevel" : ''
    // let displayNone = (!this.isShowHashTag && 'displayNone') || (data.treeinfoLevel >= 2 && 'displayNone')
    let isSubRShow = !isSub ? "displayNone" : "";
    let visibilityH = data.childList && data.childList.length > 0 ? 'visibilityV' : 'visibilityH';
    let userName = !isSub ? data.dsCreateUserName : data.bplrText;
    let isShowDel = dsf.getCookie('user_id') === data.dsCreateUserId ? "" : "displayNone";
    let isSelf = dsf.getCookie('user_id') === data.dsCreateUserId && !isSub ? "isSelf" : ''
    let str = "";
    str = '<div class="item_warp ' + tempClass + ' " handler="item_wrap" id="' + data.dsfaCommentId + '" commentLevel="' + data.treeinfoLevel + '">' +
      '<div class="item" handler="item">' +
      '<div class="content_left">' +
      '<div class="head_icon">' +
      '<img src="" alt="" id="headIcon_' + data.dsfaCommentId + '">' +
      ' </div>' +
      '<div class="tags">' +

      ' </div>' +
      '</div>' +
      '<div class="content_right">' +
      ' <div class="content_right_top">' +
      '<div class="user_name_wrap ' + isSelf + '" handler="user_name_wrap">' +
      '<span class="user_name ' + isSubRShow + '">' + data.dsCreateUserName + '</span>' +
      '<span class="' + isSubRShow + '"> 回复 </span>' +
      '<span class="user_name">' + userName + '</span>' +
      '</div>' +
      '<div class="operate_wrap">' +
      // '<div  class="'+isSelf+' alter">修改</div>' +
      '<div class="delbtn ' + isShowDel + '" id="delbtn_' + data.dsfaCommentId + '">删除</div>' +
      '</div>' +
      '</div>' +
      '<div class="theme_wrap" handler="theme_wrap">' +
      '<div class="theme_content">' + data.plnr + '</div>' +
      // '<div class="theme_title ' + displayNone + '" id="ywTitle_' + data.dsfaCommentId + '">#' + data.ywTitle + '#</div>' +
      '</div>' +
      '<div class="img_container" id="img_container_' + data.dsfaCommentId + '">' +

      '</div>' +
      '<div class="content_right_bottom">' +
      '<div class="teas_btn_area">' +
      '<div class="sys_btn_area" id="sys_btn_area_' + data.dsfaCommentId + '"></div>' +
      '<div class="subreply_icon_wrap">' +
      '<i class="icon subreply_icon" id="subreply_icon_' + data.dsfaCommentId + '" ></i><span class="' + ((data.childNum == 0 || dsf.isUnDef(data.childNum)) && "displayNone") + '" style="position:relative;top:2px"> ' + data.childNum + ' </span>' +
      '</div>' +
      '</div>' +
      '<div class="info">' +
      '<div class="toggle_btn ' + visibilityH + ' "  id="toggle_btn_' + data.dsfaCommentId + '"><span>收起</span> <i class="iconfont icon-shang1"></i></div>' +
      '<div class="time">' + data.showTime + '</div>' + //dsf.date.format(data.dsCreateTime, 'yyyy-mm-dd') 
      '</div>' +
      '</div>' +
      '</div>' +
      '<div class="subreply_box_wrap" id="subreply_box_wrap_' + data.dsfaCommentId + '" isDown = "false">' +
      '<div class="subreply_box">' +
      '<div  class="textareaStyle textarea" id="subComment_' + data.dsfaCommentId + '" contenteditable="true"></div>' +
      '<i class="icon emoji_icon subEmoji" id="subemoji_' + data.dsfaCommentId + '"></i>' +
      '</div>' +
      '<div class="subRelybtn commiteBtn btn" id="sub_btn_' + data.dsfaCommentId + '">提交</div>' +
      '</div>' +
      '</div>' +
      '</div>'

    $('#tempContainer').empty();
    let $containerDom = '',
      appendWay = "";
    if (isSub === undefined || isSub == '') {
      $containerDom = this.commentContent
      appendWay = 'append'
    } else {
      $containerDom = $('#' + data.treeinfoPid)
      appendWay = 'after'
    }
    cusrtomerDom.call(this, $containerDom, str, appendWay, data);
    let themeObjStr = $('<div class="theme_title ' + (data.treeinfoLevel >= 2 && 'displayNone') + '" id="ywTitle_' + data.dsfaCommentId + '">#' + data.ywTitle + '#</div>');
    if (this.isShowHashTag && data.ywTitle) {
      $('#' + data.dsfaCommentId + ' .theme_content').after(themeObjStr)
    }
    let _this = this
    if (dsf.isDef(data.childList) && $.isArray(data.childList) && data.childList.length > 0) {

      _(data.childList).forEach((val, index) => {
        _this.createDom(val, true);
        if (data.childList.length < data.childNum && index == data.childList.length - 1) {
          let str = '<div class="loadmore" id = "loadmore_' + data.dsfaCommentId + '">显示更多<i class="iconfont icon-shuangjiantouxia"></i></div>'
          $('#' + val.dsfaCommentId + ">.item").append(str);
          let _self = _this
          $('#loadmore_' + val.treeinfoPid).on("click", function () {
            _self.childPageNo++;
            _self.loadSubComment(val.treeinfoPid)
          })
        }
      })
      $("#" + data.dsfaCommentId + ">.item").addClass("noneborder")
    }
    _this.img_container = $('#img_container_' + data.dsfaCommentId) //评论内容的图片容器
    if (!_this.readOnly) {
      $('#toggle_btn_' + data.dsfaCommentId).bind("click", { id: data.dsfaCommentId }, _this.toggleSubComment) //展开
      $('#subreply_icon_' + data.dsfaCommentId).bind("click", { id: data.dsfaCommentId, name: data.dsCreateUserName, "class": _this }, _this.addDom) //显示隐藏子回复框
      $('#delbtn_' + data.dsfaCommentId).bind("click", { id: data.dsfaCommentId, "class": _this }, _this.deleDom) //评估删除
      $('#sub_btn_' + data.dsfaCommentId).bind("click", { "id": data.dsfaCommentId, "class": _this, 'data': data }, _this.submitFn) //自回复按钮
      $('#ywTitle_' + data.dsfaCommentId).on("click", () => { window.parent.location.href = dsf.url.getWebPath(data.ywUrl) })
      let placeHolder = $('<span>回复:' + data.dsCreateUserName + '</span>')
      $("#subComment_" + data.dsfaCommentId).html(placeHolder)
      $("#subComment_" + data.dsfaCommentId).on("focus", function () { if ($(this).html() == placeHolder[0].outerHTML) $(this).html('') })
      $("#subComment_" + data.dsfaCommentId).on("blur", function () { if ($(this).html() == '') $(this).html(placeHolder) })
      $("#subComment_" + data.dsfaCommentId).bind("contentchange", (e) => {
        $("#subreply_box_wrap_" + data.dsfaCommentId).css("height", "auto");
        let htmlstr = $(e.currentTarget).html()
        if (htmlstr && htmlstr != placeHolder) {
          $("#sub_btn_" + data.dsfaCommentId).css("background", "#c62f26");
        } else {
          $("#sub_btn_" + data.dsfaCommentId).css("background", "#B2B2B2")
        }

      })
      $('#headIcon_' + data.dsfaCommentId).attr('src', dsf.url.getWebPath('oua/getRedisUserPhoto?userId=' + data.dsCreateUserId + '&r=' + Math.random())) // 用户头像请求
    } else {
      _this.replyArea_wrap.addClass("displayNone")
      $('.teas_btn_area').addClass("visibilityH")
      $('.operate_wrap').addClass("displayNone")
    }


    $("#sys_btn_area_" + data.dsfaCommentId).find("");
    var dom = $("#sys_btn_area_" + data.dsfaCommentId)
    _this.renderButtons(dom)
    _this.renderButtonsNum(dom, data.btnNumMap)
    // 自回复框中表情
    _this.addqqFace($('#subemoji_' + data.dsfaCommentId + ''), {
      id: 'subqqfacebox_' + data.dsfaCommentId,
      assign: 'subComment_' + data.dsfaCommentId + '',
      path: _this.qqfaceRes
    })
    // 首级评论图片渲染
    if (data.img !== "" && dsf.isDef(data.img)) {
      console.log(data.img);
      createImgDom.call(this, data.img);
      $('#img_container_' + data.dsfaCommentId + ' img').bind("click", {}, function (e) {
        // console.log(parent);

        // var photos = JSON.parse(data.img).map(item => {
        //   return {
        //     src: dsf.url.getWebPath(item.relativePath)
        //   }
        // });
        // console.log(photos);
        // parent.window.resetHeight();
        // const viewer = new Viewer($('#img_container_' + data.dsfaCommentId)[0], {
        //   viewed() {
        //     // viewer.zoomTo(1);
        //   },
        // });
        dsf.openUrl(1, e.target.src);
        // layer.photos({
        //   // photos: { "data": photos },
        //   photos: '#img_container_' + data.dsfaCommentId,
        // });
      });
    }
    $('#headIcon_' + data.dsfaCommentId).on('error', function (event) {
      var $img = $(event.currentTarget);
      $img.attr("src", dsf.url.getWebPath("res/dsf_styles/themes/img/default.png"))
      this.onerror = null; //控制不要一直跳动 
    });
    window.parent && window.parent.loadHeight && window.parent.loadHeight(true);
  }
  addDom(e) {
    let id = e.data.id;
    let name = e.data.name;
    let isDownAttr = $("#subreply_box_wrap_" + id).attr("isDown");
    $("#subreply_box_wrap_" + id).css("height", "40px")
    if (!JSON.parse(isDownAttr)) {
      $(document).find('[class="subreply_box_wrap"]').slideUp("slow").attr("isDown", false)
      $("#subreply_box_wrap_" + id).slideDown("slow");
      $("#subreply_box_wrap_" + id).attr("isDown", !JSON.parse(isDownAttr))
      $("#subreply_box_wrap_" + id).css("display", "flex");
    } else {
      $("#subreply_box_wrap_" + id).slideUp("slow")
      $("#subreply_box_wrap_" + id).attr("isDown", !JSON.parse(isDownAttr))
      $(document).find('[class="subreply_box_wrap"]').attr("isDown", false)
    }
    let placeHolder = $('<span>回复:' + name + '</span>')
    $("#subComment_" + id).on("focus", function () { if ($(this).html() == placeHolder[0].outerHTML) $(this).html('') })
    $("#subComment_" + id).on("blur", function () { if ($(this).html() == '') $(this).html(placeHolder) })
    $("#subComment_" + id).bind("contentchange", (e) => {
      $("#subreply_box_wrap_" + id).css("height", "auto");
      let htmlstr = $(e.currentTarget).html()
      if (htmlstr && htmlstr != placeHolder) {
        $("#sub_btn_" + id).css("background", "#c62f26");
      } else {
        $("#sub_btn_" + id).css("background", "#B2B2B2")
      }

    })
  }
  deleDom(e) {
    deleDom.call(this, e)
  }
  toggleSubComment(e) {
    let id = e.data.id;
    let $spanText = $(this).find('span')
    if ($spanText.text() == '收起') {
      $spanText.text('展开')
      $(this).find("i").attr("class", "iconfont icon-xia1");
      $(this).closest('.item').removeClass("noneborder")
    } else {
      $spanText.text('收起')
      $(this).find("i").attr("class", "iconfont icon-shang1");
      $(this).closest('.item').addClass("noneborder")
    }

    $('#' + id).nextUntil('[commentlevel=1]').slideToggle("normal");
  }
  submitFn(e) {
    console.log("submitFn", e)
    let dataID = '',
      subParam = {},
      _this = "",
      data = "";
    if (dsf.isDef(e) && e.data) {
      dataID = e.data.id;
      _this = e.data.class;
      data = e.data.data
    }
    if (dataID) {
      subParam = {
        dsfaCommentId: '',
        treeinfoPid: dataID,
        plnr: $('#subComment_' + dataID).html()
      }
    }
    if (_this.imgBox.html().length == 0) {
      _this.commentImgarr = [];
    }
    let url = dsf.url.getWebPath('dsfa/platform/comment/addOrRefreshComment')
    let defaultparam = {
      dsfaCommentId: '',
      treeinfoPid: '',
      plnr: $('.firstComment').html() == _this.firstlevelPlaceholder ? "" : $('.firstComment').html(),
      ywlxValue: _this.businessType,
      ywid: _this.businessId,
      ywTitle: _this.ywTitle,
      img: JSON.stringify(_this.commentImgarr),
      btnPara: createBtnParam.call(_this) || '',
      ywUrl: _this.ywUrl
    }
    let args = $.extend(defaultparam, subParam)
    console.log(args)
    dataRequst(url, args, 'post', function (args) {
      console.log(args)
      _this.createDom(args.data, dataID ? true : '');
      if (dataID) {
        let isDownAttr = $("#subreply_box_wrap_" + dataID).attr("isDown")
        $("#subreply_box_wrap_" + dataID).slideUp("slow")
        $("#subreply_box_wrap_" + dataID).attr("isDown", !JSON.parse(isDownAttr))
        $(document).find('[class="subreply_box_wrap"]').attr("isDown", false)
        $('#subComment_' + dataID).empty().html("回复：" + data.dsCreateUserName)
      } else {
        $('#firstComment').empty();
        _this.commentImgarr = []
        _this.imgBox.empty();
      }
      _this.changeMsgNum("jia");
      _this.pageTotal++
      _this.renderPagination();
    }, function (response) {
      // _this.commentImgarr = [];
      // _this.imgBox.empty();
      dsf.layer.message(response.message, false)
    })
  }
  addqqFace(dom, options) {
    qqface.call(this, dom, options)
  }
  changeMsgNum(type) {
    let html = this._handlers.MsgNum.html(),
      num = parseInt(html.substring(html.length - 1, 1)),
      msgNum = ''
    if (type == "jian") {
      msgNum = num - 1;
    } else {
      msgNum = num + 1;
    }
    this.msgNum = msgNum;
  }
  renderPagination() {
    let id = 'comment_page';
    var laypage = layui.laypage;
    let _this = this;
    //执行一个laypage实例
    laypage.render({
      "elem": id,
      "count": _this.pageTotal,
      "limit": parseInt(_this.pageSize),
      "curr": _this.pageNo,
      "layout": ['prev', 'page', 'next', 'count'],
      "prev": "<i class='iconfont icon-left'></i>",
      "next": "<i class='iconfont icon-right'></i>",
      "jump": (obj, first) => {
        if (!first) {
          //如果pageSize发生变化
          _this.pageSize = obj.limit;
          _this.pageNo = obj.curr;
          // _this._groups = obj.groups;
          _this.pageTotal = obj.count;
          _this.loadCommentData();
        }
      }
    });
  }
  renderButtons(dom) {
    ButtonPlugin.renderButtons(this, dom, this.$buttonBar, {}, "", "small");
  }
  renderButtonsNum(dom, data) {
    _(this.$buttonBar.buttons).forEach((val) => {
      dom.find("[dstag='" + val.cate + "']>span").text(data[val.cate].num)
      if (data[val.cate].isDo) {
        dom.find("[dstag='" + val.cate + "']>i").removeClass().addClass("iconfont " + val.activeIcon)
      } else {
        dom.find("[dstag='" + val.cate + "']>i").removeClass().addClass("iconfont " + val.icon)
      }
    })

  }
}

function createBtnParam() {
  let btnArr = [],
    btn = []
  let _this = this;
  var btnObj = {}
  _(_this.$buttonBar.buttons).forEach((val, index, arr) => {
    let obj = {};
    btnObj = {};
    let argsywlx = val.actionArgs.split(";")[0]
    obj.name = val.cate;
    obj.ywlx = argsywlx;
    btn.push(obj);
    btnObj.level = "-1";
    btnObj.btn = btn;

  })
  btnArr.push(btnObj)
  return JSON.stringify(btnArr)
}

