// 上传图片
function uploadImg() {
  var upload = layui.upload;
  this.headersParam = dsf.getCookie("XSRF-TOKEN") || ""
  let _this = this,
    files = []
  _this.commentImgarr = [];
  var uploadListIns = upload.render({
    elem: '#uploadImg',
    accept: 'images',
    multiple: true,
    acceptMime: 'image/*',
    url: dsf.url.getWebPath('file/upload/'),
    headers: { 'X-XSRF-TOKEN': _this.headersParam },
    auto: false, // 设置不自动提交,
    bindAction: "#replyBtn",
    choose: function (obj) {
      layer.load(); //上传loading
      $(".replyBtnOrg").unbind("click")
      obj.preview(function (index, file, result) {
        files = obj.pushFile();
        let imgWrap = $('<div><img src="' + result + '" alt=""></div>');
        imgWrap.addClass('closeBtn').append($('<i class="iconfont icon-icon2">'))
        _this.imgBox.append(imgWrap)
        imgWrap.find('.icon-icon2').on('click', function () {
          // $("#replyBtn").addClass("replyBtnOrg").removeClass('replyBtn_hasImg');
          delete files[index]; //删除对应的文件
          imgWrap.remove();
          uploadListIns.config.elem.next()[0].value = ''; //清空 input file 值，以免删除后出现同名文件不可选
        });
      });
      layer.closeAll('loading')
    },
    done: function (res, index, upload) {
      console.log(res)
      if (res.success) {
        _this.commentImgarr.push(res.data[0])
        let e = {
          data: {
            class: _this
          }
        }

        // $("#replyBtn").addClass("replyBtn_hasImg").removeClass('replyBtnOrg');
        _this.submitFn(e)
        _(files).forEach((val, index) => {
          delete files[index]
        })
        $(".replyBtnOrg").bind("click", { "class": _this }, _this.submitFn);
      } else {
        console.log(res.message)
      }

      layer.closeAll('loading'); //关闭loading
    },
    allDone: function (obj) {
      console.log(obj)
    },
    error: function (index, upload) {
      layer.closeAll('loading'); //关闭loading
    }
  });
}
