// 数据请求封装方法
function dataRequst(url, args, queryway, scallback, erroCallback) {
  let loadding = dsf.layer.loadding();
  dsf.http.request(url, args, queryway, scallback, erroCallback)
    .done(function (response) {
      console.log(response)
      if (response.success) {
        if (scallback) scallback(response)
      } else {
        if (erroCallback) erroCallback(response)

      }
    })
    .error(function (err) {

      dsf.layer.message("请求失败,请稍后再试", false)
    })
    .always(function () {
      dsf.layer.close(loadding);
    }).exec();
}

function qqface(dom, options) {
  var defaults = {
    id: 'facebox',
    path: 'face/',
    assign: 'content',
    tip: 'em_'
  };
  var option = $.extend(defaults, options);
  var assign = $('#' + option.assign);
  var id = option.id;
  var path = option.path;
  var tip = option.tip;

  if (assign.length <= 0) {
    console.log('缺少表情赋值对象。');
    return false;
  }

  dom.click(function (e) {
    var strFace, labFace;
    $("[id*='facebox']").hide();
    if ($('#' + id).length <= 0) {
      strFace = '<div id="' + id + '" style="position:absolute;display:none;z-index:1000; background:#fff" class="qqFace">' +
        '<table border="0" cellspacing="0" cellpadding="0"><tr>';
      for (var i = 1; i <= 75; i++) {
        labFace = '[' + tip + i + ']';
        strFace += '<td><img src="' + path + i + '.gif" onclick="$(\'#' + option.assign + '\').setCaret();$(\'#' + option.assign + '\').insertAtCaret(\'' + labFace + '\');" /></td>';
        if (i % 15 == 0) strFace += '</tr><tr>';
      }
      strFace += '</tr></table></div>';
    }
    dom.parent().append(strFace);
    var offset = dom.position();
    var top = offset.top + dom.outerHeight();
    var outerparentWidth = dom.parent().parent().width();;
    // 若不延迟，则无法获取表情table 的宽度
    setTimeout(() => {
      if (outerparentWidth - offset.left < $('#' + id).width()) {
        $('#' + id).css('left', offset.left - 234);
      } else {
        $('#' + id).css('left', offset.left);
      }

      if ($('.ds_Normalcomment ').height() - dom.offset().top < $('#' + id).height()) {
        $('#' + id).css('top', -124);
      } else {
        $('#' + id).css('top', top);
      }
      $('#' + id).show();
    }, 200)
    e.stopPropagation();
  });

  $(document).click(function () {
    $('#' + id).hide();
    $('#' + id).remove();
  });
}
/**
 * 二次开发,若有自定义属性，就生成自定义Dom；则生成原始评论代码
 * @param {Object} $containerDom jquery对象，需添加元素的父级元素 
 * @param {String} str 生成的原始dom字符串 
 * @param {String} appendWay 兼容父级评论（append）和子集评论（after）使用不同方法渲染到页面
 * @param {Object} rowData 当前行数据
 */
function cusrtomerDom($containerDom, str, appendWay, rowData) {
  $('#tempContainer').append(str)
  let obj = $.extend({}, defaultOption, this.$customerOption);
  let domstr = obj.format($('#tempContainer'), rowData);
  let id = rowData.dsfaCommentId;
  $containerDom[appendWay](domstr.html());
  $('#tempContainer').empty(str);

  if (rowData.isShowBtn != false) {
    if (obj.buttonbar && obj.buttonbar.length > 0) {
      let $btnBox = $("#" + id).find('.operate_wrap')
      let buttonbarArr = obj.buttonbar
      _(buttonbarArr).forEach((val) => {
        if (val.btnValue == 'delbtn') {
          val.isShow = dsf.getCookie('user_id') === rowData.dsCreateUserId ? true : false
        }
        // let isShowDel = val.isShow ? "" : 'displayNone'
        let btnstr = "";
        let customerClass = val.btnCls.join(" ")
        btnstr = '<div class="' + customerClass + ' " id="' + val.btnValue + '_' + id + '">' + val.btnText + '</div>';
        $btnBox.append(btnstr);
        $('#' + val.btnValue + '_' + id).on("click", { "data": rowData, "id": id, "class": this }, val.handler)
      })
    }
  }
}
var deleDom = function (e) {
  dsf.layer.confirm("确定要删除么?", () => {
    let id = e.data.id
    let _this = e.data.class;
    let url = dsf.url.getWebPath('dsfa/platform/comment/delComment')
    let args = {
      commentId: id
    };
    dataRequst(url, args, 'post', function (args) {
      console.log(args)
      let subLevelArr = $("#" + id).nextAll('.subLevel');
      _(subLevelArr).forEach((val) => {
        if ($(val).attr('commentLevel') > $("#" + id).attr('commentLevel')) {
          $(val).remove()
        }
      })
      $("#" + id + "").remove();
      _this.changeMsgNum("jian");
      _this.pageTotal--
      _this.renderPagination();
      window.parent && window.parent.loadHeight && window.parent.loadHeight(true);
    })
  });
}
var defaultOption = {
  format: function (rowDom, rowData) {
    return rowDom
  },
  buttonbar: [{
    btnText: '',
    btnCls: [],
    isShow: true,
    handler: new Function()
  }]
}