const dom = require("../../templates/Row.ejs");
import { LayoutControl, Container } from '../../../../baseControls';
import { map } from '../../../../decorator/controlmap';

@map('一行三列', 'dsf.row_1_3', 'Row_1_3')
export class Row_1_3 extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$showPadding = false;
  }
  initTemplate() {
    return dom(this);
  }
  createElement() {
    var el = super.createElement();
    if (!this._isRender && this.root._isDesign) {
      if (this.children.length <= 0) {
        for (var i = 0; i < 3; i++) {
          var container = new Container(this.id + "_" + i, true);
          this._addChild(container, null, "row");
          container.addClass(["layui-col-md4", "ds_column"]);
        }
      }
    }
    return el;
  }
}