const dom = require("../../templates/TreeSelector.ejs");
import { isSupportDataPost } from '../../../../core/postDecorator';
import { LayoutControl } from '../../../../baseControls';
import { Action } from '../../../../core/pageAction';
import { express } from '../../../../core/express';
import { map } from '../../../../decorator/controlmap';
/**
 * 数据结构
 * [
	children:[{}]
	_name
	_id
	treeinfo_pid 以及treeinfo的数据
 ]
 * 
 */
@map('树选择', 'dsf.treeselector', 'TreeSelector')
@isSupportDataPost(true)
export class TreeSelector extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);

    this._value = [];

    // 数量上限
    this.maxLength = null;

    // 是否可排序
    this.sort = false;
    // 是否支持复选框
    this.showCheckbox = false;

    // 能选择的类型
    this.types = "";

    // 搜索出来的值
    this._searchNode = [];

    // 0为接口，1为元数据
    this.metaDataType = 1;

    // 接口值
    this.sqlUrl = null;
    // 选择的元数据
    this.chooseMetaData = {};

    this.typeStyle = "list";

    this.chooseTreeObj = null;

    // 列表时单节点选择
    this.chooseOneNode = true;

    // 启用tab
    this.useTab = false;
    // tab配置
    this.tabOpts = [];

    this.activeOpts = {};
    this._trees = [];
    this.defaultOpenSeries = 1;
  }

  set _sort(v) {
    // 设置是否可排序
    this.sort = v;
  }
  get _sort() {
    return this.sort;
  }

  set _showCheckbox(v) {
    this._showCheckbox = v;
  }

  get _showCheckbox() {
    return this.showCheckbox;
  }

  get _treeObj() {
    const self = this;
    const tree = _.find(self._trees, it => {
      return it.id === this.activeOpts.id || it.id === 'single';
    })
    return tree.tree;
  }

  set _types(v) {
    // 设置选择条件
    this.types = v;
  }
  get _types() {
    return this.types;
  }

  set _useTab(v) {
    this.useTab = v;
  }

  get _useTab() {
    return this.useTab;
  }

  set _tabOpts(v) {
    this.tabOpts = v;
  }

  get _tabOpts() {
    return this.tabOpts;
  }

  set value(v) {
    // 设置选中值
    this._value = v;
    this.showCheckbox && this.checkedInit();
    // this.loadChooseData();
  }
  get value() {
    return this._value;
  }

  set _maxLength(v) {
    //设置数量上限
    this.maxLength = v;
  }
  get _maxLength() {
    return this.maxLength;
  }

  get treeSet() {
    const ct = this.chooseOneNode ? '' : 's';
    const callback = this.showCheckbox ? {
      onCheck: this.zTreeOnCheck.bind(this),
      beforeCheck: this.beforeCheck.bind(this),
    } : {
      onClick: this.zTreeOnClick.bind(this),
    };
    return {
      check: {
        enable: this.showCheckbox,
        chkStyle: 'checkbox',
        chkboxType: { "Y": ct, "N": ct }        
      },        
      view: {
        selectedMulti: false,
        showIcon: false,
        showLine: false,
        fontCss: this.getFontCss.bind(this)
      },
      data: {
        key: {
          children: "children",
          name: "_name",
          url: ""
        }
      },
      callback,     
    }
  }

  initTemplate() {
    return dom(this);
  }

  renderEvent() {
    let _this = this;

    this._handlers.search.on('click', function(e) {
      // 搜索
      _this.search();
    });
    this._handlers.search_input.on('keyup', function(e) {
      // 回车搜索
      let keycode = window.event ? e.keyCode : e.which;
      if (keycode == 13) {
        _this.search();
      }
    });
    this._handlers.search_clear.on('click', function(e) {
      // 刷新数据
      _this._handlers.search_input.val("");
      _this.search();
    });
    this._handlers.empty.on('click', function() {
      // 清空选中值
      _this._value = [];

      _this._handlers.chooseList.html("");

      _this._handlers.chooseTree.html("");
      $.fn.zTree.destroy(this.id + "_chooseTree");

      _this._handlers.chooseLength.html(0);
      if (_this.showCheckbox) {
        _this._trees.forEach(({ tree }) => {
          tree.checkAllNodes(false);
        });
      }
    });
    this._handlers.chooseList.on('click', '.closeIcon', function() {
      // 删除选中值
      let i = $(this).closest('.item').index();
      _this._value.splice(i, 1);
      _this.uploadChooseList();
      if (_this.showCheckbox) {
        const id = $(this).parent().attr('id');
        _this._trees.forEach(({ tree }) => {
          const selectNodes = tree.getCheckedNodes(true);
          const index = selectNodes.findIndex(it => it._id === id);
          index !== -1 && tree.checkNode(selectNodes[index], false, false);
        });
      }
    });
    this._handlers.chooseList.on('click', '.icon-shang', function() {
      // 上移排序
      let index = $(this).closest('.item').index();
      if (index == 0) {
        return
      } else {
        let _temp = _this._value[index];
        _this._value[index] = _this._value[index - 1];
        _this._value[index - 1] = _temp;
      }
      _this.uploadChooseList();

    });
    this._handlers.chooseList.on('click', '.icon-xia', function() {
      // 下移排序
      let maxL = _this._value.length;
      let index = $(this).closest('.item').index();
      if (index + 1 == maxL) {
        return
      } else {
        let _temp = _this._value[index];
        _this._value[index] = _this._value[index + 1];
        _this._value[index + 1] = _temp;
      }
      _this.uploadChooseList();
    });
    this._handlers['layui-tab-title'].on('click', '.tab-pane', function(ev) {
      const target = $(ev.target || ev.srcElement);
      const id = target.attr('handler').replace('tab-pane-', '');
      const item = _this.tabOpts.find(it => it.id === id);
      const { types, metaDataType, chooseMetaData, sqlUrl, chooseOneNode } = _this;
      const opts = Object.assign({
        types,
        metaDataType,
        chooseMetaData,
        sqlUrl,
        chooseOneNode,
      }, item);
      if (target.hasClass('layui-this')) {
        return;
      }
      _this.activeOpts = opts;
      if (!target.attr('loaded')) {
        _this.loadData(target);
      } else {
        _this._handlers.search.trigger('click');
      }
    });
  }

  renderReady() {
    super.renderReady();
    this.renderEvent();
    this.toggleComponent();
    this.root.event.on(PageEvent.READY, evt => {
      if (this.useTab) {
        this.initTab();
        this.loadChooseData();
      } else {
        this.loadData();
        this.loadChooseData();
      }
    });
  }
  loadChooseData() {
    const target = this.useTab ? this.activeOpts : this;
    if (target.typeStyle == 'tree') {
      this.uploadChooseTree();
    } else {
      this.uploadChooseList();
    }
  }
  formatChecked(data, chos, removeCheck = false) {
    data.forEach(item => {
        if (removeCheck) {
            delete item.checked;
        } else {
            item.checked = chos.some(it => it._id === item._id);            
        }
        item.children && item.children.length && this.formatChecked(item.children, chos, removeCheck);
    });
  }  
  loadData(element) {
    const option = this.useTab ? this.activeOpts : this;
    if ((option.metaDataType && (option.chooseMetaData.id || option.chooseMetaData.rmId)) || (option.metaDataType == 0 && option.sqlUrl)) {
      let layerIndex_action = dsf.layer.loadding();
      let _this = this;
      let action = parseInt(option.metaDataType) ? (option.chooseMetaData.TabNum == 1 ? 'dbSource' : 'getTreeByName') : 'treeSelector';
      if (Action[action]) {
        let exp = dsf.Express;
        let url = option.sqlUrl ? exp.replace(option.sqlUrl) : "";
        let param = {
          id: option.chooseMetaData.id,
          url: url,
          rmId: option.chooseMetaData.rmId,
          pageName: this.root.$name,
          namespace: this.root.nameSpace,
        }
        Action[action](param, (err, data) => {
          if (err) {
            dsf.layer.message(dsf.prompt.loaddatafail, false);
          } else {
            let el = _this._handlers.tree;
            if (_this.useTab) {
              el = _this._handlers.tab.find(`#tree-${option.id}`);
            }
            this.showCheckbox && this.formatChecked(data, this._value);
            const tree = $.fn.zTree.init(el, this.treeSet, data);
            _this._trees.push({
              id: _this.useTab ? option.id : 'single',
              data,
              tree,
            });
            this.expandTree(tree);
            element && element.attr('loaded', true);
            _this._handlers.search.trigger('click');
          }
          setTimeout(function() {
            dsf.layer.close(layerIndex_action);
          }, 1000)
        });
      } else {
        dsf.layer.message("接口地址不存在", 5);
      }
    }
  } 
  search() {
    const tree = _.find(this._trees, it => {
      return it.id === this.activeOpts.id || it.id === 'single';
    });
    if(tree && tree.tree) {
      const v = this._handlers.search_input.val().replace(/\s|\n/m, '');
      const nodes = tree.tree.transformToArray(tree.tree.getNodes());
      const treeId = tree.tree.setting.treeId;
      if (v) {
        this.updateNodes(false);
        this.searchNode = this._treeObj.getNodesByParamFuzzy('_name', v);
        const temp = [];
        const fn = node => {
          temp.push(node);
          const pn = node.getParentNode();
          pn && fn(pn);
        }
        this.searchNode.forEach(n => fn(n));
        this.updateNodes(true);
        tree.tree.hideNodes(nodes);
        tree.tree.showNodes(temp);
        if (!this.searchNode.length) {
          $("#" + treeId).append($("<div class='tips' style='text-align:center;padding:20px'><img style='width:40%;max-width:162px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"));        
        } else {
          $("#" + treeId).find('.tips').remove();
          tree.tree.selectNode(this.searchNode[0], false, false);
        }
      } else if(!v) {
        tree.tree.showNodes(tree.tree.transformToArray(tree.tree.getNodes()));
        this.updateNodes(false);
        $("#" + treeId).find('.tips').remove();
      }      
    }
  }
  getFontCss(treeId, treeNode) {
    return (!!treeNode.highlight) ? { color: "#EB6025", "font-weight": "bold" } : { color: "#333", "font-weight": "normal" };
  }
  updateNodes(highlight) {
    for (let i in this.searchNode) {
      this.searchNode[i].highlight = highlight;
      this._treeObj.updateNode(this.searchNode[i]);
    }
  }
  beforeCheck(treeId, treeNode) {
    if (!this.isCanChooseNode(treeNode)) {
      return false;
    }
  }
  zTreeOnCheck(event, treeId, treeNode) {
    const target = this.useTab ? this.activeOpts : this;
    if (target.typeStyle == "tree") {
      let _treeNode = $.extend(true, {}, treeNode);
      if (this._value.length == 0) {
        this._value.push(this.getParent(_treeNode, false));
        this.uploadChooseTree();
      } else {
        let parentNode = this.getParentSite(_treeNode);
        if (parentNode._id == _treeNode._id) {
          let p = this.chooseTreeObj.getNodesByParam("_id", parentNode._id, null)[0];
          if (!p) {
            this.chooseTreeObj.addNodes(p, parentNode, true);
            this.chooseTreeObj.expandNode(parentNode, true);
          } else {
            this.chooseTreeObj.removeChildNodes(p);
            for (let i in parentNode.children) {
              this.chooseTreeObj.addNodes(p, parentNode.children[i], true);
            }
            this.chooseTreeObj.expandNode(p, true);
          }

        } else {
          let parent = this.chooseTreeObj.getNodesByParam("_id", parentNode._id, null)[0];
          this.chooseTreeObj.addNodes(parent, parent ? parentNode.children : parentNode, true);
        }

        this.uploadChooseLength();
      }
    } else {
      let nodes = $.fn.zTree.getZTreeObj(treeId).transformToArray(treeNode);
      const parentNode = [];
      let temp = treeNode;
      while (temp) {
          const tempNode = temp.getParentNode();
          temp = tempNode;
          temp && parentNode.push(temp);
      }
      nodes = [ ...parentNode, ...nodes];
      nodes.forEach(item => {
        if (item.checked) {
          if (!this._value.some(it => it._id === item._id)) {
            this._value.push(item);
          }
        } else {
          const index = this._value.findIndex(it => it._id === item._id);
          index !== -1 && this._value.splice(index, 1);
        }
        if (this.maxLength && (this._value.length > this.maxLength)) {
          this._value.splice(0, 1);
          this._treeObj.checkNode(item, false, false);
        }    
        this.uploadChooseList();    
      });
    }
  }
  zTreeOnClick(event, treeId, treeNode) {
    const target = this.useTab ? this.activeOpts : this;
    if (target.typeStyle == "tree") {
      let _treeNode = $.extend(true, {}, treeNode);
      if (this._value.length == 0) {
        this._value.push(this.getParent(_treeNode, false));
        this.uploadChooseTree();
      } else {
        let parentNode = this.getParentSite(_treeNode);
        if (parentNode._id == _treeNode._id) {
          let p = this.chooseTreeObj.getNodesByParam("_id", parentNode._id, null)[0];
          if (!p) {
            this.chooseTreeObj.addNodes(p, parentNode, true);
            this.chooseTreeObj.expandNode(parentNode, true);
          } else {
            this.chooseTreeObj.removeChildNodes(p);
            for (let i in parentNode.children) {
              this.chooseTreeObj.addNodes(p, parentNode.children[i], true);
            }
            this.chooseTreeObj.expandNode(p, true);
          }

        } else {
          let parent = this.chooseTreeObj.getNodesByParam("_id", parentNode._id, null)[0];
          this.chooseTreeObj.addNodes(parent, parent ? parentNode.children : parentNode, true);
        }

        this.uploadChooseLength();
      }
    } else {
      let elem = this._handlers.chooseList;
      if (elem.find("#" + treeNode._id).length == 0) {
        if (target.chooseOneNode * 1) {
          if (this.isCanChooseNode(treeNode) && elem.find("#" + treeNode._id).length == 0) {
            this._value.push(treeNode);
          }
          if (this.maxLength && (this._value.length > this.maxLength)) {
            this._value.splice(0, 1);
          }
        } else {
          treeNode = $.fn.zTree.getZTreeObj(treeId).transformToArray(treeNode);
          for (let i in treeNode) {
            if (this.isCanChooseNode(treeNode[i]) && elem.find("#" + treeNode[i]._id).length == 0) {
              this._value.push(treeNode[i]);
            }
            if (this.maxLength && (this._value.length > this.maxLength)) {
              this._value.splice(0, 1);
            }
          }
        }

        this.uploadChooseList();
      } else {
        console.log("您已经选择过[" + treeNode._name + ']')
      }
    }
  }

  isCanChooseNode(treeNode) {
    const target = this.useTab ? this.activeOpts : this;
    if (target.types && target.types != "") {
      return dsf.Express.eval(target.types, treeNode);
    } else {
      return true;
    }
  }

  uploadChooseList() {
    let elem = this._handlers.chooseList;
    elem.html("");
    for (let i in this._value) {
      let item = this._value[i];
      let sortIcon = "";
      if (this.sort) {
        sortIcon = "<i class='iconfont icon-shang'></i><i class='iconfont icon-xia'></i>";
      }
      elem.append("<li class='item " + (this.sort ? 'canSort' : '') + "' id='" + item._id + "'>" + (i * 1 + 1) + "." + item._name + sortIcon + " <i class='closeIcon iconfont icon-guanbi1'></li>");
    }
    this.uploadChooseLength();
  }

  uploadChooseLength() {
    // 更新选中长度
    let num = 0;
    const opts = this.useTab ? this.activeOpts : this;
    if (opts.typeStyle == "tree") {
      this._value = this.chooseTreeObj.transformToArray(this.chooseTreeObj.getNodes());
    }
    num = this._value.length;
    this._handlers.chooseLength.html(num);
  }


  changeTypeStyle() {
    const opts = this.useTab ? this.activeOpts : this;
    this._value = [];
    if (opts.typeStyle == "tree") {
      this._handlers.chooseList.html("");
    } else {
      this._handlers.chooseTree.html("");
      $.fn.zTree.destroy(this.id + "_chooseTree");
    }
    this._handlers.chooseLength.html('0');
    this.rerenderTree();
  }
  getParent(_treeNode) {
    let p = _treeNode.getParentNode() ? $.extend(true, {}, _treeNode.getParentNode()) : null;
    if (p) {
      p.children.length = 1;
      p.children[0] = _treeNode;
      return this.getParent(p);
    } else {
      return _treeNode;
    }
  } 
  getParentSite(_treeNode) {
    if (_treeNode._id) {
      let hasNode = this.chooseTreeObj.getNodesByParam("_id", _treeNode._id, null);
      if (hasNode && hasNode.length > 0) {
        return _treeNode;
      } else {
        let p = _treeNode.getParentNode() ? $.extend(true, {}, _treeNode.getParentNode()) : null;
        if (p) {
          p.children.length = 1;
          p.children[0] = _treeNode;
          return this.getParentSite(p)
        } else {
          return _treeNode;
        }
      }
    }
  }
  uploadChooseTree() {
    let _this = this;
    const treeSet = { check: {} };
    Object.assign(treeSet, this.treeSet);
    _this.chooseTreeObj = $.fn.zTree.init(_this._handlers.chooseTree, treeSet, _this._value);
    _this.chooseTreeObj.expandAll(true);
    _this.uploadChooseLength();
  }
  chooseTreeOnClick(event, treeId, treeNode) {
    this.chooseTreeObj.removeNode(treeNode);
    this.uploadChooseLength();
  }
  changeUseTab() {
    this._handlers.empty.trigger('click');
    this.toggleComponent();
    if (!this.useTab) {
      this.activeOpts = {};
    }
  }
  toggleComponent() {
    this._handlers.tree.toggle(!this.useTab);
    this._handlers.tab.toggle(this.useTab);
  }
  checkedInit() {
      const ids = this._value.map(it => it._id);
      this._trees.forEach(({ tree }) => {
        if (tree) {
          const allNodes = tree.transformToArray(tree.getNodes());
          ids.forEach(id => {
              const index = allNodes.findIndex(it => it._id === id);
              index !== -1 && tree.checkNode(allNodes[index], true, false);  
          });                      
        }
      })      
  }  
  rerenderTree() {
    try{
      this._trees.forEach((item) => {        
        const { tree, id, data } = item;
        const { treeId } = tree.setting;
        tree.destroy(); 
        this.formatChecked(data, this._value, !this.showCheckbox);
        const newTree = $.fn.zTree.init($(`#${treeId}`), this.treeSet, data);
        this.expandTree(newTree);
        item.data = data;
        item.tree = newTree;  
      });      
    }catch(e){
      throw new Error(e);
    }
  }
  expandTree(tree) {
    const nodes = tree.getNodes();
    const defaultOpenSeries = this.useTab ? this.activeOpts.defaultOpenSeries : this.defaultOpenSeries;
    const fn = nodes => {
      for (let i in nodes) {
        if (parseInt(defaultOpenSeries) - 1 >= nodes[i].level) {
          tree.expandNode(nodes[i], true);
          if (nodes[i].children && nodes[i].children.length) {
            fn(nodes[i].children);
          }
        }
      }  
    }
    if(defaultOpenSeries > 0) {
      fn(nodes);
    } else if(defaultOpenSeries < 0) {
      tree.expandAll(true);
    }
  }
  initTab() {
    const render = () => {
      let tabTitles = '';
      let tabItems = '';
      this.tabOpts.forEach((tab, index) => {
        const handler = `tab-pane-${tab.id}`;
        tabTitles += `<li class="tab-pane" handler="${handler}">${tab.name}</li>`;
        tabItems += `<div handler="tab-item-${tab.id}" class="layui-tab-item">
                    <ul class="ztree" handler='tree-${tab.id}' id='tree-${tab.id}'></ul>
                </div>`;
      });
      this._handlers['layui-tab-title'].empty();
      this._handlers['layui-tab-content'].empty();
      this._handlers['layui-tab-title'].append(tabTitles);
      this._handlers['layui-tab-content'].append(tabItems);
      this._handlers['layui-tab-title'].find('.tab-pane:eq(0)').trigger('click');
    }
    if (this.root._isDesign) {
      render();
    }
    this.root.event.on(PageEvent.READY, evt => {
      render();
    })
  }
}
