const dom = require("../../templates/FlowInfo.ejs");

import {
	map
} from '../../../../decorator/controlmap';
import {
	FormControl
} from '../../../../baseControls';
import {
	FlowInfoMetaData
} from '../../../../core/metadata';
import {
	isSupportDataPost
} from '../../../../core/postDecorator';

@map('流程信息', 'dsf.flowinfo', 'FlowInfo')
@isSupportDataPost(true)

export class FlowInfo extends FormControl {
	constructor(id, isPart) {
		super(id, isPart);
		this.visible = false;
		this.$caption = "wfinfo";
		this.$metadata = FlowInfoMetaData.call(this);
		this.chooseFlow = {};
		this.$value = {
			"wf_id": "",
			"wf_name": ""
		};
		// 用于参数记录
		this._RequestID = null;
		// 事项名称
		this.eventName = null;
		// 环节设置
		this.linkData = null;
	}

	initTemplate() {
		return dom(this);
	}
	set value(value) {
		if (value != undefined) {
			if (typeof(value) == "string") {
				this.$value.wf_id = value;
			} else {
				this.$value = {
					wf_id: value.ID,
					wf_name: value.name
				};
			}
		}
	}
	get value() {
		return this.$value;
	}
	initEvent() {
		let _this = this;
		// 监听表单数据提交前
		this.root.event.on(PageEvent.POSTDATABEFORE, evt => {
			_this.$value = {
				wf_id: "",
				wf_name: ""
			}
			if (_this.chooseFlow.ID) {
				_this.$value.wf_id = _this.chooseFlow.ID;
			}
			if (_this.chooseFlow.name) {
				_this.$value.wf_name = _this.chooseFlow.name;
			}
		});
	}
	setChooseFlow() {
		// 选择流程
		this._handlers.input.val(this.chooseFlow.name || "");
	}
	linkSetChooseFlow() {
		this.setChooseFlow();
		this._toolRight.find(".LinkSet .ds_button").click();
	}
	getSendBackLink(args) {
		let loadingIndex = dsf.layer.loadding();
		let param = {
			sPID: args[0] || null,
			sCurLinkID: args[1] || null
		}
		dsf.http.request(dsf.url.getWebPath('wfr/getSendBackLink'), param, 'post')
			.done(res => {
				if (res.success && res.data && res.data.BackLinks) {
					let BackLinks = res.data.BackLinks;
					if (BackLinks.length == 1) {
						this.sendBack(args, BackLinks[0].ID);
					} else {
						chooseBackNode.call(this, BackLinks, args);
					}
				} else {
					dsf.layer.message(res.data.Message || '退回异常', false);
				}
			})
			.error(res => {
				dsf.layer.message('退回异常', false);
			})
			.always(() => {
				dsf.layer.close(loadingIndex);
			})
			.exec();
	}
	sendBack(args, id, layerIndexs) {
		let _this = this;
		let area = [(args[2] || "300px"), (args[3] || "280px")];
		layui.layer.open({
			title: '退回原因',
			content: '<form class="layui-form"><textarea name="desc" placeholder="请输入退回原因" class="layui-textarea"></textarea></form>',
			skin: 'flowinfo-dialog sendBackTxt',
			area: area,
			zIndex: layui.layer.zIndex,
			yes: function(index, layero) {
				layer.setTop(layero); 
				let val = layero.find('textarea').val();
				if (val) {
					let loadingIndex = dsf.layer.loadding();
					let param = {
						sPID: args[0] || null,
						sCurLinkID: args[1] || null,
						sReason: layero.find('textarea').val() || null,
						sBackLinkID: id
					}
					dsf.http.request(dsf.url.getWebPath('wfr/sendBack'), param, 'post')
						.done(res => {
							if (res.success && res.data && res.data.Code == '21000') {
								_.forEach(layerIndexs, (layer) => {
									if (layer.index !== undefined) {
										dsf.layer.close(layer.index, true)
									} else {
										layui.layer.close(layer);
									}
								})
								dsf.layer.message('退回成功', true);
								layui.layer.close(index);
								_this.root.close('1500');
								_this.event.trigger(flowCtrlEvent.changeState, {
									data: res.data,
									type: '退回'
								})
							} else {
								if (res.data.Code == '93003') {
									layui.layer.close(index);
								}
								dsf.layer.message(res.data.Message || '退回异常', false);
							}
						})
						.error(res => {
							dsf.layer.message('退回异常', false);
						})
						.always(() => {
							dsf.layer.close(loadingIndex);
						})
						.exec();
				}
			}
		});
	}
	flowSend() {
		// 流程发送按钮
		let id = this.chooseFlow.dsfa_rm_id;
		if (id) {
			// 开始发送
			let _this = this,
				loadingIndex = dsf.layer.loadding(),
				url = "wfr/startSend",
				param = {
					sWFID: id,
					sObjectID: page._data._id,
					sObjectName: this.eventName ? page.getControl(this.eventName) ? page.getControl(this.eventName).value : '' : '',
					sCurNodeID: "",
					sExInfos: ""
				};

			//继续发送
			if (dsf.url.queryString('sPID')) {
				url = 'wfr/send';
				param = {
					sPID: dsf.url.queryString('sPID'),
					sCurLinkID: dsf.url.queryString('sCurLinkID') || '',
					sExInfos: ""
				}
			}

			//发送时有处理意见
			let DisposeIdeaDom = $('[ctrl_type="DisposeIdea"]');
			if (DisposeIdeaDom.length > 0) {
				let DisposeIdeaCtrl = DisposeIdeaDom.data('Object');
				param.sOpinion = {
					'Content': DisposeIdeaCtrl.value,
					'Attachments': []
				}
				if (DisposeIdeaCtrl.uploadCtrl) {
					let datas = DisposeIdeaCtrl.uploadCtrl.multipleFiles;
					_.each(datas, (data) => {
						param.sOpinion.Attachments.push(data);
					})
				}
				param.sOpinion = JSON.stringify(param.sOpinion);
			}
      
      let config = {
        param : param,
        url: url
      }
      
      if(this.event.has(flowCtrlEvent.setSendConfig)){
        // 可以通过二次开发修改发送的接口的参数
        this.event.trigger(flowCtrlEvent.setSendConfig, { ui: this, config: config });
      }

			dsf.http.request(dsf.url.getWebPath(config.url), config.param, 'post')
				.done(response => {
					flowSend.call(this, response, []);
				})
				.error(response => {
					dsf.layer.message("发送异常", false);
					this._RequestID = null;
				})
				.always(() => {
					dsf.layer.close(loadingIndex);
				})
				.exec();
		} else {
			dsf.layer.message("请先配置流程信息控件的'选择流程'", false);
		}
	}
}

// 选择退回节点
function chooseBackNode(data, args, layerIndexs) {
	let _this = this,
		lineHtml = "";
	layerIndexs = [];
	_.forEach(data, (d, index) => {
		lineHtml += `<div id='${d.ID}'>${d.NodeName}-${d.LinkUser.RUserName}</div>`
	})
	if (lineHtml) {
		lineHtml = "<div class='chooseSendLine'>" + lineHtml + "</div>";
		layui.layer.open({
			type: 1,
			title: "请选择要退回的环节：",
			skin: 'flowinfo-dialog content-no-padding button_auxiliary sendBack',
			area: '300px;',
			btn: ['取消'],
			btnAlign: 'c',
			content: lineHtml,
			move: false,
			success: function(layero, index) {
				$(layero.find('.chooseSendLine')).on('click', 'div', function(evt) {
					$(layero.find(".choosed")).removeClass('choosed');
					$(this).addClass('choosed');
					layerIndexs.push(index);
					_this.sendBack(args, $(this).attr("id"), layerIndexs);
				})
			}
		});
	}
}

function flowSend(response, layerIndexs) {
	if (response.state == 20000) {
		let data = response.data;
		this._RequestID = data.RequestID;
		if (data.Code == 20000 || data.Code == 20001 || data.Code == 20003 || data.Code == 20004 || data.Code == 20005) {
			// 发送成功 || 发送到汇总节点 || 发送到汇总环节并激活汇总环节 || 办结当前节点 || 办结当前节点，并办结整个流程
			directlySend.call(this, data);
			this.root.close('3000');
			this.event.trigger(flowCtrlEvent.changeState, {
				data: data,
				type: '发送'
			})
		} else if (data.Code == 81000) {
			// 选择发送节点
			chooseSendNode.call(this, data, layerIndexs);
		} else if (data.Code == 82000) {
			// 树选择
			treeChoose.call(this, data, layerIndexs);
		} else {
			let msg = null,
				code = data.Code;
			switch (code) {
				case 20006:
					msg = "流程已被销毁"
					break;
				case 20007:
					msg = "流程已被强制办结"
					break;
				case 91000:
					msg = "无后续可发送节点"
					break;
				case 92000:
					msg = "无可选的发送对象"
					break;
				case 92001:
					msg = "该环节只允许发送给一人，但是必选项超过一个"
					break;
				case 92002:
					msg = "未找到继承环节"
					break;
				case 92003:
					msg = "对象超出可发送范围"
					break;
				case 92004:
					msg = "路径超出可发送范围"
					break;
				case 93000:
					msg = "该事项已被处理"
					break;
				case 93001:
					msg = "保存流转情况信息失败"
					break;
				case 93002:
					msg = "保存流转环节信息失败"
					break;
				case 93003:
					msg = "该文件已被其他人签收"
					break;
				case 94001:
					msg = "与分支不能设置办结节点"
					break;
				case 95001:
					msg = "没有可回收的环节"
					break;
				case 95002:
					msg = "回收环节已接收或已处理，无法回收"
					break;
				case 95003:
					msg = "未填写退回原因"
					break;
				case 99000:
					msg = "获取数据锁失败"
					break;
			}
			dsf.layer.message(msg || '未知流程类型发送', false);
		}
	} else {
		this._RequestID = null;
		dsf.layer.message("发送异常", false);
	}
}
// 直接完成发送
function directlySend(data) {
	let userHtml = "",
		_this = this;

	if (data.Code == 20000) {
		_.forEach(data.Links, (line, index) => {
			if (line.Status == 0 && line.LinkUser) {
				let linkUser = line.LinkUser;
				let type = line.LinkUser.Type;
				if (type == 1) {
					// 直接选人
					userHtml += "<span>" + linkUser.UserName + "</span>";
				} else if (type == 2) {
					// 部门+角色
					userHtml += "<span>" + linkUser.DeptName + "-" + linkUser.RoleName + "</span>";
				} else if (type == 3) {
					// 岗位
					userHtml += "<span>" + linkUser.JobName + "</span>";
				} else if (type == 4) {
					// 人+关系
					userHtml += "<span>" + linkUser.UserName + "-" + linkUser.RelationName + "</span>";
				}
			}
		})
		layui.layer.open({
			type: 1,
			title: "流程已发送到以下人员：",
			skin: 'flowinfo-dialog',
			area: '300px;',
			id: _this._RequestID,
			time: 3000,
			btn: ['好的'],
			btnAlign: 'c',
			content: "<div class='userbox'></div><div>页面将在<span  class='timebox'>3</span>秒钟后自动关闭</div>",
			success: function(layero) {
				let timebox = layero.find('.timebox'),
					userbox = layero.find('.userbox'),
					time = 3;

				setInterval(() => {
					$(timebox).html(--time);
				}, 1000)

				$(userbox).html(userHtml);
			},
			end: function() {
				_this.event.trigger('confirmClosed', {
					ui: _this
				})
			}
		});
	} else {
		let msg = '发送成功',
			code = data.Code;
		switch (code) {
			case 20004:
				msg = "文件已办结"
				break;
			case 20005:
				msg = "文件已办结"
				break;
		}

		layui.layer.open({
			type: 1,
			title: "提示",
			skin: 'flowinfo-dialog',
			area: '300px;',
			id: _this._RequestID,
			time: 3000,
			btn: ['好的'],
			btnAlign: 'c',
			content: "<div class='userbox'><span>" + msg +
				"</span></div><div>页面将在<span  class='timebox'>3</span>秒钟后自动关闭</div>",
			success: function(layero) {
				let timebox = layero.find('.timebox'),
					time = 3;

				setInterval(() => {
					$(timebox).html(--time);
				}, 1000)
			},
			end: function() {
				_this.event.trigger('confirmClosed', {
					ui: _this
				})
			}
		});
	}

}

// 选择发送节点
function chooseSendNode(data, layerIndexs) {
	let _this = this,
		lineHtml = "",
		id = _this._RequestID;

	if (data.SendParams) {
		_.forEach(data.SendParams.Lines, (line, index) => {
			lineHtml += "<div id='" + line.LineID + "'>" + line.Name + "</div>"
		})
	}
	if (lineHtml) {
		lineHtml = "<div class='chooseSendLine'>" + lineHtml + "</div>";
		layui.layer.open({
			type: 1,
			title: "请选择要发送的环节：",
			skin: 'flowinfo-dialog content-no-padding button_auxiliary',
			area: '300px;',
			id: id,
			btn: ['取消'],
			btnAlign: 'c',
			content: lineHtml,
			move: false,
			success: function(layero, index) {
				$(layero.find('.chooseSendLine')).on('click', 'div', function(evt) {
					$(layero.find(".choosed")).removeClass('choosed');
					$(this).addClass('choosed');
					let param = {
						sRequestID: id,
						sLineID: $(this).attr("id")
					};
					layerIndexs.push(index);
					flowSendNextRequest.call(_this, "wfr/sendToLine", param, layerIndexs);
				})
			}
		});
	}
}
//树选择——一对多,多对多
function treeChoose(data, layerIndexs) {
	let _this = this;
	dsf.layer.openDialog({
		title: "请选择办理人",
		content: dsf.url.getWebPath("dsfa/pd/views/flowSendTreeChoose.html"),
		skin: 'flowinfo-dialog content-no-padding treeChoose',
		area: ['900px', '600px'],
		args: data,
		move: false,
		btn: [{
			"text": "确定",
			"handler": function(index, layero) {
				let frame = layero.find("iframe"),
					win = frame.get(0).contentWindow;
				if (win) {
					let result = win.getDialogResult();
					if (result) {
						layerIndexs.push({
							index: index
						});
						flowSendNextRequest.call(_this, "wfr/sendToReceivers", {
							sRequestID: _this._RequestID,
							sReceivers: result
						}, layerIndexs);
					}
					return false
				}
			}
		}, {
			"text": "取消",
			"handler": function(index, layero) {

			}
		}]
	})
}

function flowSendNextRequest(url, param, layerIndexs) {
	let _this = this,
		loadingIndex = dsf.layer.loadding();

	dsf.http.request(dsf.url.getWebPath(url), param, 'post')
		.done(response => {
			if (response.state == 20000) {
				let time = 0;
				if (response.data.Code == 20000) {
					_.forEach(layerIndexs, (layer) => {
						if (layer.index !== undefined) {
							dsf.layer.close(layer.index, true)
						} else {
							layui.layer.close(layer);
						}
					})
					time = 300;
				}
				setTimeout(() => {
					flowSend.call(_this, response, layerIndexs);
					dsf.layer.close(loadingIndex);
				}, time);
			} else {
				dsf.layer.message("发送异常", false);
				_this._RequestID = null;
			}
		})
		.error(response => {
			dsf.layer.message("发送异常", false);
			_this._RequestID = null;
		})
		.always(() => {
			if (!_this._RequestID) {
				dsf.layer.close(loadingIndex);
			}
		})
		.exec();
}
