import { Container } from "./Container";

import { map } from '../../decorator/controlmap';

@map('模板基类', 'dsf.template', 'Template')
export class Template extends Container {
  static toControl(obj, hasChild, callback) {
    if (dsf.Controls.Template) {
      let control = new dsf.Controls.Template();
      $.extend(true, control, obj);
      control.children = [];
      if (callback) {
        callback(control, obj);
      }
      if (!!hasChild) {
        if (obj.children && obj.children.length > 0) {
          for (let i = 0; i < obj.children.length; i++) {
            let c = Template.toControl(obj.children[i], hasChild);
            control.children.push(c);
          }
        }
      }
      return control;
    }
  }
  static createTemplate(target, attrs) {
    for (let i = 0; i < attrs.length; i++) {
      function fn(attr) {
        let key = "_" + attr;
        let val = null;
        Object.defineProperty(target, attr, {
          enumerable: true,
          configurable: true,
          get: function() {
            if (target.root && target.root._isDesign) {
              if (typeof(val) == "object" && !(val instanceof dsf.Controls.Template)) {
                val = Template.toControl(val)
              }
            }
            return val;
          },
          set: function(value) {
            val = new Template(null, true);
          }
        });
      }
      fn(attrs[i])
    }
  }
}


export class RepeatTemplate extends Template {
  constructor(id, tagName, isPart) {
    super(id, isPart);
    this.tagName = tagName;
  }


  initTemplate() {
    return "<" + this.tagName + "></" + this.tagName + ">";
  }
  createElement() {
    if (this.root._isDesign) {
      super.createElement();
    }

  }

  renderContext() {
    if (this.root._isDesign) {
      super.renderContext();
    }
  }

}