const dom = require("../../templates/QsInfo.ejs");
import { FormControl } from '../../../../baseControls'
import { QsInfoMetaData } from '../../../../core/metadata';
import { PageEvent } from '../../../../core/ControlEvent';
import { isSupportDataPost } from '../../../../core/postDecorator';
import {map} from  '../../../../decorator/controlmap';
@map('问卷信息','dsf.qsinfo','QsInfo')
@isSupportDataPost(true)
export class QsInfo extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$metadata = QsInfoMetaData.call(this);
        this.$value = {
            status_text:'未发布',   //已发布
            status_value: '0'       //1
        };
        this.$caption = "qainfo";
    }

    initTemplate() {
        return dom(this);
    }

    set value(value) {
        if (value != undefined) {
            if (typeof(value) == "object"){
                this.$value.status_text = value.text;
                this.$value.status_value = value.value;
            } else{
                this.$value.status_value = value;
                if(value.toString().length>1){
                    console.error('qainfo的value 只能是0或者1');
                }
            }
            if (this._handlers.readOnlyLabel) {
                this._handlers.readOnlyLabel.text(this.$value.status_text);
            }
        }
    }
    get value() {
        return this.$value;
    }
}