import { relyFiles } from "../../../../core/relyfiles";

const dom = require("../../templates/Selects.ejs");
import { ItemsControl } from '../../../../baseControls';
import { isSupportDataPost } from '../../../../core/postDecorator';
import { FormControlEvent } from '../../../../core/ControlEvent';
import { map } from '../../../../decorator/controlmap';
@relyFiles([
  'res/libs/xm-select.js'
])
@map('下拉多选', 'dsf.selects', 'Selects')
@isSupportDataPost(true)
export class Selects extends ItemsControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.label = "下拉多选";
    this.maxChooseNum = 0;
    this.$placeholder = "请选择";
    this.$readOnlyShowText = "text";
    this.selectEle = "";
    this.isViewTxt = null;
    this.current = "";   //用户当前选择项
    this.selectarr = "";   //用户选择后,全部选择项
  }

  get items() {
    return this._items;
  }
  set items(value) {
    this._items = [];
    if ($.isArray(value)) {
      if (value[0] == undefined || value[0].value != "") {
        value.splice(0, 0, { "text": "", "value": "" });
      }
      for (let i = 0; i < value.length; i++) {
        let isRender = i == value.length - 1 ? true : false;
        this.addItem(value[i], i, isRender);
      }
    }
  }


  set placeholder(value) {
    this.$placeholder = value;
    if (this._handlers.selects) {
      this.renderItems()
    }
  }
  get placeholder() {
    return this.$placeholder;
  }

  set readOnlyShowText(val) {
    this.$readOnlyShowText = val;
    if (this.element) {
      this.render();
    }
  }
  get readOnlyShowText() {
    return this.$readOnlyShowText;

  }

  initTemplate() {
    return dom(this);
  }
  createElement() {
    super.createElement();
    this._itemsBox = this._handlers.selects;
  }

  renderContext() {
    super.renderContext();
    this._handlers.label.html(this.label);
    if (this.disabled) {
      if (this._handlers.selects) {
        this._handlers.selects.prop("disabled", true);
      }
    }
  }


  set value(value) {
    if (value == undefined || value == null) {
      value = [];
    }
    if (!$.isArray(value)) {
      value = [value];
    }
    let isView = dsf.url.queryString('isview') === '1' ? true : false;
    if (isView) {
      this.$value = value;
      if (this._handlers && this._handlers.selects) {
        this._handlers.selects.css({ 'padding': '9px', 'color': '#333' }).html(this.getTextString(','))
      } else {
        this.isViewTxt = this.getTextString(',');
        this._handlers.readOnlyLabel && this._handlers.readOnlyLabel.css({
          'padding': '9px',
          'color': '#333'
        }).html(this.isViewTxt);
      }
      return
    }

    this.$value = [];
    for (let i = 0; i < value.length; i++) {
      let v = value[i];
      if (typeof (v) == "string" || typeof (v) == "number") {
        for (let i = 0; i < this._items.length; i++) {
          if (this._items[i].value == v) {
            this.$value.push(this._items[i]);
          }
        }
      } else if (typeof (v) == "object") {
        for (let i = 0; i < this._items.length; i++) {
          let o = this._items[i];
          if (o.value == v.value) {
            if (v.attach_text) {
              o.attach_text = v.attach_text;
            }
            this.$value.push(o);
          }
        }
      }
    }
    if (this.$value.length <= 0) {
      this.$value = value;
    }
    if (this.itemsBox && this.selectEle) {
      this.selectEle.setValue(this.value);
    }
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(this.getTextString(","));
    }
  }
  get value() {
    if (!this.$value) {
      this.$value = [];
    }
    let _this = this;
    if (_this.$value instanceof Array) {
      _this.$value.forEach(function (o, i) {
        if (o.value == "else") {
          if (_this._itemsBox) {
            o.attach_text = _this._itemsBox.find("div.q_other>input").val();
          }
        }
      });
    }

    return _this.$value;
  }

  renderReady() {
    super.renderReady();
    (this.isViewTxt != null && this._handlers.selects) && (this._handlers.selects.css({
      'padding': '9px',
      'color': '#333'
    }).html(this.isViewTxt), this.isViewTxt = null);
  }

  renderItems() {
    if (!this.readOnly) {
      super.renderItems();
      this.renderSelect();
    }
  }

  renderSelect() {
    if (this.element && this._handlers.selects) {
      //判断元数据还是请求数据
      let arr = [];
      if (this.$metadata.dataSource && this.$metadata.dataSource.type === "static") {
        arr = changeObjInArr(this.$metadata.dataSource.code)
      } else {
        arr = changeObjInArr(this._items)
      }
      Object.prototype.toString.call(this.value) !== '[object Array]' && (this.value = []);
      let _this = this;
      _this.selectEle = xmSelect.render({
        el: '#' + this.ctrl_type + this.id,
        tips: this.placeholder,
        language: 'zn',
        theme: {
          color: '#c9c9c9',
        },
        data: arr,
        disabled: this.disabled,
        initValue: this.value,//默认值
        max: this.maxChooseNum || 0,
        toolbar: {
          show: true,
          list: [
            {
              'name': '全选',
              'icon': 'xm-iconfont xm-icon-quanxuan',
              method(data) {
                if (data.length > _this.maxChooseNum && _this.maxChooseNum != 0) {
                  layer.msg(`最多只能选择` + _this.maxChooseNum + `条`, { icon: 5 });
                } else {
                  _this.selectEle.setValue(data);
                  typeof _this.onSelectTrigger === 'function' && _this.onSelectTrigger(data);
                }
              }
            },
            'CLEAR',
            {
              'name': '反选',
              'icon': 'xm-iconfont xm-icon-fanxuan',
              method(data) {
                if ((data.length - _this.selectEle.getValue().length) > _this.maxChooseNum && _this.maxChooseNum != 0) {
                  layer.msg(`最多只能选择` + _this.maxChooseNum + `条`, { icon: 5 });
                } else {
                  let arrtotle = [];
                  let arr1 = data;
                  let arr2 = _this.selectEle.getValue();
                  let ar1 = arr1.filter(function (n) {
                    return arr2.indexOf(n) == -1
                  });
                  let ar2 = arr2.filter(function (n) {
                    return arr1.indexOf(n) == -1
                  });
                  arrtotle = ar1.concat(ar2);
                  _this.selectEle.setValue(arrtotle);
                  typeof _this.onSelectTrigger === 'function' && _this.onSelectTrigger(data);
                }
              }
            },
          ]
        },
        maxMethod(seles, item) {
          layer.msg(`最多只能选择${seles.length}条`, { icon: 5 });
        },
        on({ arr, change, isAdd }) {
          //arr:  当前多选已选中的数据
          //change, 此次选择变化的数据,数组
          //isAdd, 此次操作是新增还是删除
          _this.current = change;
          _this.selectarr = arr;
          _this.value = arr;
          console.log(arr)
          typeof _this.onSelectTrigger === 'function' && _this.onSelectTrigger(arr, change, isAdd);
        }
      })
    }
  }

  renderComplete() {
    super.renderComplete();
  }

  //描述组件的验证信息
  validateInfo() {
    return {
      tipsElement: ".layui-input-block"
    }
  }

  getTextString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].name ? this.value[i].name : this.value[i].text ? this.value[i].text : '');
    }
    return arr.join(split || "、")
  }

  getValueString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].value);
    }
    return arr.join(split || "、");
  }
}

function changeObjInArr(items) {
  let arr = [];
  if (items.length > 0) {
    items.forEach(function (item) {
      (item.text && item.value !== '') && arr.push({
        name: item.text,
        value: item.value
      });
    })
  }
  return arr
}
