const dom = require("../../templates/Section.ejs");
import { LayoutControl, Container } from '../../../../baseControls';
import { map } from '../../../../decorator/controlmap';

@map('页面段落', 'dsf.section', 'Section')
export class Section extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$marginTop = false;
    this.$marginBottom = false;
    this.$marginLeft = false;
    this.$marginRight = false;
    this.$paddingTop = true;
    this.$paddingBottom = true;
    this.$paddingLeft = true;
    this.$paddingRight = true;
    this.$showModel = 'none';
    this.$shadow = false;
    this.$marginSize = "small";
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    var el = super.createElement();
    if (!this._isRender && this.root._isDesign) {
      if (this.children.length <= 0) {
        var container = new Container(this.id + "_" + "context", true);
        this._addChild(container, null, "section");
      }
    }
    return el;
  }

  renderBackground() {
    this.children[0].background = this.background;
  };

  renderContext() {
    super.renderContext();
    if (this._isRender) {
      this.$marginTop ? this.addClass("has_m_top") : this.removeClass("has_m_top");
      this.$marginBottom ? this.addClass("has_m_bottom") : this.removeClass("has_m_bottom");
      this.$marginLeft ? this.addClass("has_m_left") : this.removeClass("has_m_left");
      this.$marginRight ? this.addClass("has_m_right") : this.removeClass("has_m_right");
      this.$paddingTop ? this.removeClass("no_p_top") : this.addClass("no_p_top");
      this.$paddingBottom ? this.removeClass("no_p_bottom") : this.addClass("no_p_bottom");
      this.$paddingLeft ? this.removeClass("no_p_left") : this.addClass("no_p_left");
      this.$paddingRight ? this.removeClass("no_p_right") : this.addClass("no_p_right");
      this.$showModel == "full" ? this.addClass("full") : this.removeClass("full");
      this.$shadow ? this.addClass("shadow") : this.removeClass("shadow");
      this.removeClass("big");
      this.removeClass("small");
      this.removeClass("medium");
      this.addClass(this.$marginSize);
    }

  }

  resize() {
    if (this.$showModel == "full") {
      // let h=this.children[0].element.parent().innerHeight();
      // this.children[0].element.css("height",h)
    }
    super.resize();
  }
}