const dom = require("../../templates/Numeration.ejs");
import {
	TextBox
} from './TextBox';
import {
	map
} from '../../../../decorator/controlmap';

@map('编号', 'dsf.numeration', 'Numeration')
export class Numeration extends TextBox {
	constructor(id, isPart) {
		super(id, isPart);
		this.$showBtn = false;
		this.$rule = {};
		this.$btnIcon = null;
	}
	set showBtn(v) {
		this.$showBtn = v;
		let box = this._handlers.inputBox;
		if (v) {
			box.addClass('showbtn');
		} else {
			box.removeClass('showbtn');
		}
	}
	get showBtn() {
		return this.$showBtn;
	}
	set rule(v) {
		this.$rule = v;
		this.$metadata.ruleId = v['dsfa_number_rule.dsfa_number_rule_id'];
	}
	get rule() {
		return this.$rule;
	}
	set btnIcon(v) {
		this.$btnIcon = v;
		let getValueDom = this._handlers.getValue;
		if (getValueDom) {
			getValueDom.attr('class','iconfont '+(v || 'icon-bianjisekuai'));
		}
	}
	get btnIcon() {
		return this.$btnIcon;
	}
	initTemplate() {
		return dom(this);
	}
	initEvent() {
		let getValueDom = this._handlers.getValue;
		if (getValueDom) {
			getValueDom.on('click', () => {
				if (this._root.preview) {
					dsf.layer.message('预览界面不支持该操作', false);
				} else {
					setValue.call(this);
				}
			})
		}
	}
	saveBeforeAction(def, v) {
		if (!this.$value && (!this.$showBtn || (this.$metadata.validate && this.$metadata.validate.config && this.$metadata.validate.config.required))) {
			setValue.call(this, def);
		} else {
			def.resolve();
		}
	}
}

function setValue(def) {
	let _this = this,
		loader = null,
		text = "编号";
	if (!def) {
		loader = dsf.layer.loadding();
	} else {
		text = this.$caption + '编号';
	}
	dsf.http.request(dsf.url.getWebPath("number/get/" + this.$metadata.ruleId), {}, "GET")
		.done(res => {
			if (res.success) {
				_this.value = res.data.value;
			} else {
				dsf.layer.message(res.message || text + '异常', false);
			}
		})
		.error(res => {
			dsf.layer.message(text + '异常', false);
		})
		.always(() => {
			if (def) {
				def.resolve();
			} else {
				dsf.layer.close(loader);
			}
		})
		.exec();
}
