const dom = require("../../templates/Block.ejs");
const subtitleDom = require("../../templates/SubTitle.ejs");
// import { childrenData } from "../../decorator/childrenData";
import { isSupportDataPost } from "../../../../core/postDecorator";
import { LayoutControl } from "../../../../baseControls";
import { oneToMany } from "../../../../decorator/oneToMany";
import {map} from  '../../../../decorator/controlmap';

@map('子块','dsf.subblock','SubBlock')
@isSupportDataPost(true)
@oneToMany
export class SubBlock extends LayoutControl {
    constructor(id,isPart){
        super(id, isPart);
        this.$label = "";
        this.$scopeLevel=1;
    }

    get dataKey() {
        return "_id";
    }
    get scope() {
        return this.root.scope + "_" + this.metadata.code;
    }
    set label(value) {
        this.$label = value;
        if (this.element) {
            let dom = this.renderTitle();
            this._handlers.title.html(dom);
        }
    }
    get label() {
        return this.$label;
    }

    initTemplate(){
        return dom(this);
    }   


    renderTitle() {
        return subtitleDom({ title: this.$label });
    }
}