const mainDom = require("./templates/customerOrderBy.ejs");

let sorts = ["", "asc", "desc"];


function render(data, container, rendered, submitCallback, heightChange) {
    let iRender,
        html = mainDom(),
        el = container.get(0),
        height = 0,
        isDesign = page.isDesign;
    // data = $.extend(true, {}, data);
    iRender = dsf.vdom({
        template: html,
        data: {
            items: data.items,
            total: 0,
            hide: data.hide,
            isDesign: isDesign,
            selectedItem: selectedItem,
            getDescriptions: function(item) {
                let nextSortType = getNextSortType(item);
                let s = nextSortType;
                let str = "";
                if (s) {
                    str = "点击后按" + item.aliasName;
                    str += (s == "asc") ? "升序" : "降序"
                } else {
                    str = "取消" + item.aliasName + "排序";
                }
                item.des=str;
                return str;
            }
        },
        inserted: (vnode, renderer) => {
            callHeightChange(vnode.elm);
            rendered && rendered(renderer)
        },
        updated: (oldVnode, vnode) => {
            callHeightChange(vnode.elm);
        }
    });
    iRender.addToElem(el);

    function selectedItem(item) {
        let nextSortType = getNextSortType(item);
        item.sortType = nextSortType;
        iRender.render();
        submitCallback && submitCallback();
    }

    function getNextSortType(item) {
        let type = item.sortType || "";
        let currIndex = sorts.indexOf(type);
        let nextIndex = ++currIndex
        if (nextIndex > sorts.length - 1) {
            nextIndex = 0;
        }
        return sorts[nextIndex];
    }

    function callHeightChange(elm) {
        heightChange && heightChange()
    }
}

function update() {

}

export {
    render,
    update
}