import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from "../../../../editor/ControlEditor";
import { ChartControl } from '../../../../baseControls/controls/ChartControl';

@map("柱状图", 'dsf.piechart', 'PieChart')
export class PieChart extends ChartControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.height = '319px';
    this.label = "饼状图";
    this.isrevseXY = true;
    this.chartType = 'pie'
    this.chartColor = '#c23531,#2f4554, #61a0a8, #d48265, #91c7ae,#749f83,  #ca8622, #bda29a,#6e7074, #546570, #c4ccd3';
    this.isCricle = false
  }

  get label() {
    return super.label;
  }
  set label(value) {
    super.label = value;
  }

  renderContext() {
    super.renderContext();
  }
  setOption() {
    super.setOption();
    let customerOption = {
      tooltip: {
        trigger: 'item'
      },
      legend: {
        type: "scroll"
      },
      xAxis: {
        show: false
      },
      yAxis: {
        show: false
      },
      series: [
        {
          radius: this.isCricle ? ['65%', '90%'] : '90%',
          center: ['50%', '50%'],
          data: this.rebuildseriesData(),
          avoidLabelOverlap: false,
          label: {
            show: this.isCricle ?false:true,
            position: this.isCricle ?'center':'top'
          },
          emphasis: {
            itemStyle: {
              shadowBlur: 10,
              shadowOffsetX: 0,
              shadowColor: 'rgba(0, 0, 0, 0.5)'
            },
            label: {
              show: true,
              fontSize: '30',
              fontWeight: 'bold'
            }
          },
          labelLine: {
            show: this.isCricle ? false : true
          }
        }
      ]
    }
    let option = $.extend(true, {}, this.defalutOption, customerOption);
    console.log(option)
    this.chart.setOption(option)
  }
  rebuildseriesData() {
    let seriesData = [], obj = {}, temp = '';
    _(this.chartData.xAxis).forEach((item, index) => {
      obj.name = item;
      obj.value = this.chartData.series[0].data[index]
      obj.itemStyle = {
        color: this.chartColor.split(',')[index]
      }
      temp = JSON.stringify(obj)
      seriesData.push(JSON.parse(temp))
    })
    return seriesData
  }
}


