// import * as Controls from '../../controls/controls';

const widget = {
    toControl:function(obj, hasChild, callback) {
        if (dsf.Controls[obj.ctrl_type]) {
            let control = new dsf.Controls[obj.ctrl_type]();
            $.extend(true, control, obj);
            control.children = [];
            if (callback) {
                callback(control, obj);
            }
            if (!!hasChild) {
                if (obj.children && obj.children.length > 0) {
                    for (let i = 0; i < obj.children.length; i++) {
                        let c = this.toControl(obj.children[i], hasChild);
                        control.children.push(c);
                    }
                }
            }
            return control;
        }
    }
}

export { widget };