const dom = require("./templates/ContextMenu.ejs");

export class ContextMenu {
    static show(items, x, y) {
        ContextMenu.removeAll();
        let menuData = {
            items: items
        }
        let element = dom(menuData);
        let jqEl = $(element);
        $("body").append(jqEl);
        jqEl.children(".layui-nav-child").show();
        let menuEl = jqEl.children();

        if (menuEl.width() + x > $(".ds_page").get(0).clientWidth) {
            x = x - menuEl.width();
        }
        if (menuEl.height() + y > $(".ds_page").get(0).clientHeight) {
            y = y - menuEl.height();
        }
        jqEl.css({ "top": (y+5) + "px", "left": (x+5) + "px" });

        jqEl.on("click", "dd>a", (evt) => {
            let target = $(evt.target);
            let index = target.attr("item-index");
            if (index && items[index].handler) {
                // alert(items[index].handler)
                let result = items[index].handler.call(this);
                if (result != false) {
                    ContextMenu.removeAll();
                }
            }
        })

    }
    static removeAll() {
        $(".ds-menu").remove();
    }
}