const dom = require("../../templates/CustomerTab.ejs");
import { LayoutControl, Container } from "../../../../baseControls";
// import { ControlEditor } from "../../../../editor/ControlEditor";
import { relyFiles } from '../../../../core/relyfiles';
import { map } from '../../../../decorator/controlmap';

@map('自定义选项卡', 'dsf.customertab', 'CustomerTab')
@relyFiles([
  'res/libs/fullPage/css/jquery.fullPage.css',
  'res/libs/fullPage/scripts/jquery.fullPage.min.js',
  'res/libs/fullPage/scripts/jquery.easing.1.3.js'
])
export class CustomerTab extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.tabHeight = '100%'
    this.enableDelete = false;
    this.tabPosition = "";
    this.$showPadding = true;
    this.$tabNum = 3;
    this.$anchors = ['1','2','3'];
    this.menuStyle = 'graphical';
    this.iscontinuous = false;
    this.fullpageOption = {
      // 'sectionsColor': ['#1bbc9b', '#4BBFC3', '#7BAABE'],
      'navigation': false,
      'navigationPosition': "left",
      'anchors': ['1','2','3'],
      'menu': '#full-page-menu'
    };
    this.hasChildrenL = ''
    this.container = null;
  }

  get tabNum() {
    return this.$tabNum
  }
  set tabNum(val) {
    let menuNameArr = [];
    for (let i=0; i<val; i++) {
      menuNameArr[i] = `${i+1}`
    }
    this.fullpageOption.anchors = menuNameArr;
    this.$anchors = menuNameArr;
    this.$tabNum = val
  }

  render() {
    super.render();
    // if (this.isDesign) {
    //   super.renderReady();
    //   this.fullpageOption.navigation = false

    // } else {
    //   this.fullpageOption.navigation = true
    // }
    let _this = this;
    this.fullpageOption.afterLoad = function(anchorLink, index) {
      _this.event.trigger(Fullpage.AFTERLOAD, { ui: _this, index: index, anchorLink: anchorLink });
    }
    this.fullpageOption.onLeave = function(index, nextIndex, direction) {
      $("#full-page-menu li").eq(nextIndex-1).addClass('active').siblings().removeClass('active')
      _this.event.trigger(Fullpage.ONLEAVE, { ui: _this, index: index, nextIndex: nextIndex, direction: direction });
    }
    $("#tabcontent").fullpage(this.fullpageOption);
  }
  initTemplate() {
    return dom(this);
  }
  renderContext() {
    this.renderBox();
  }
  createElement() {
    super.createElement()
  }
  renderBox() {
    let container = null,
      hasChildrenL = this.children.length,
      newChidren = [];
    for (var i = 0; i < this.tabNum; i++) {
      let $div = $('<div>')
      this._handlers['layui-tab-content'].append($div)
      $div.addClass("section");
      $div.attr("handler", "section_" + i)

      // 导航菜单@xiexitian
      const fullPageMenu = document.getElementById('full-page-menu')
      let menuItem = document.createElement('li')
      menuItem.setAttribute('data-menuanchor',this.$anchors[i])
      let menuItemLink = document.createElement('a')
      menuItemLink.setAttribute('href',`#${this.$anchors[i]}`)
      menuItemLink.innerHTML = this.menuStyle === 'words' ? this.$anchors[i] : ''
      menuItem.appendChild(menuItemLink)
      fullPageMenu.append(menuItem)
      if (this.fullpageOption.navigationPosition === 'left') {
        fullPageMenu.style.left = '20px'
        fullPageMenu.style.right = 'unset'
      } else {
        fullPageMenu.style.left = 'unset'
        fullPageMenu.style.right = '20px'
      }

      this.createHandlers();
      // $div.attr("id", this.id + "_" + i);
      this.renderContainer(i, container, hasChildrenL, newChidren)
    }
    document.getElementById('full-page-menu').children[0].classList.add('active')
    this.children = newChidren;
  }
  renderContainer(i, container, hasChildrenL, newChidren) {
    let key = this.id + '_' + i;
    if (hasChildrenL > 0) {
      for (let j = 0; j < this.children.length; j++) {
        if (this.children[j].id == key) {
          container = this.children[j]
          break;
        }
      }
    }
    if (!container) {
      container = new Container(key, true);
      this._addChild(container, null, "section_" + i)
    }

    container.addStyle("height", "100%");
    newChidren.unshift(container);
  }
}