const dom = require("../../templates/FlowProcess.ejs");
import {
	Control
} from '../../../../baseControls';
import {
	map
} from '../../../../decorator/controlmap';
import {
	ControlEditor
} from '../../../../editor/ControlEditor';

@map('办理情况', 'dsf.flowprocess', 'FlowProcess')
export class FlowProcess extends Control {
	constructor(id, isPart) {
		super(id, isPart);
		this.caption = 'FlowProcess';
		this._desingerClass = ControlEditor;

	}
	initTemplate() {
		return dom(this);
	}
	renderComplete() {
		super.renderComplete();
		let _this = this;
		dsf.UI.render("checkbox", this.id + '_checkbox');
		layui.form.on('checkbox(' + this.id + '_checkbox)', function(data) {
			if (data.elem.checked) {
				_this.element.addClass('hideYj');
			} else {
				_this.element.removeClass('hideYj');
			}
		});
		layui.form.on('checkbox(' + this.id + '_checkbox0)', function(data) {
			if (data.elem.checked) {
				_this.element.addClass('hideNode');
			} else {
				_this.element.removeClass('hideNode');
			}
		});
		this.element.addClass('hideYj');
		this.element.addClass('hideNode');
		this.root.event.on(PageEvent.GetFlowProcess, data => {
			renderDom.call(_this, data);
		})
		if (this.root._isDesign || this.root.preview) {
			renderDom.call(_this, [{
					nodename: "拟稿",
					STATUS: 0,
					linkid: "faedda583f7742948b0714f0f17d1085",
					opinionatts: JSON.stringify({
						"Content": "同意"
					}),
					ruserid: "",
					pid: "af60e455757d48dd801d07b1538eb806",
					rusername: "平台管理员",
					rdeptname: "平台管理组",
					reachtime: "2020年01月06日 18:21:21",
					receivetime: "2020年1月2日 10:21:21"
				},
				{
					nodename: "拟稿",
					STATUS: 1,
					linkid: "faedda583f7742948b0714f0f17d1085",
					opinionatts: JSON.stringify({
						"Content": "同意"
					}),
					ruserid: "",
					pid: "af60e455757d48dd801d07b1538eb806",
					rusername: "平台管理员",
					rdeptname: "平台管理组",
					reachtime: "2020年01月06日 18:21:21",
					receivetime: "2020年1月2日 10:21:21"
				}
			]);
		}
		if (!this.root._isDesign && !dsf.url.queryString('sPID')) {
			this.visible = false;
		}

		this.element.on('click', '.downLoadBtn', (event) => {
			let paramID = "";

			let singleFile = event.target;
			let downLoadkey = $(singleFile).attr('downLoadkey');
			let singlefileName = $(singleFile).attr('filename')

			let url = dsf.url.getWebPath('file/download')
			$('<form action=' + url + ' method="get">' + // action请求路径及推送方法
					'<input type="text" name="files" value="' + (downLoadkey + "^" + singlefileName) + '"/>' + // 文件id
					'</form>')
				.appendTo('body').submit().remove();
		})
	}
}

function renderDom(datas) {
	let _this = this;
	let _temp = '';
	_.forEach(datas, (data, i) => {
		let yj = '',
			file = '';
		if (data.opinionatts) {
			let op = JSON.parse(data.opinionatts) || {};
			yj = op.Content;
			file = op.Attachments;
		}
		let icon = 'status' + data.STATUS;
		if (data.STATUS == '-31') {
			icon = 'status-3';
		} else if (data.STATUS == '-1') {
			icon = 'status-2'
		}
		_temp += "<div class='item " + (data.STATUS == '-4' ? 'unusual' : '') + " " + ((!yj && !file) ? 'noyj' : '') + "'>" +
			"			<div class='fl-box'>" +
			"				<span>" + (data.reachtime || '无数据') + "</span>" +
			"				<img class='tx' src='" + dsf.url.getWebPath('oua/getRedisUserPhoto?type=absolutePath&userId=' + data.ruserid) +
			"' onerror='javascript:this.src=\"/dsfa/res/dsf_styles/themes/workFlow/head_logo.png\"'/>" +
			"				<img class='icon' src='/dsfa/res/dsf_styles/themes/workFlow/" + icon + ".png'/>" +
			"			</div>" +
			"			<div class='fr-box'>" +
			"				<div class='des'>" +
			"					<span>处理环节：" + (data.nodename || '无数据') + "</span>" +
			"					<span>处理人：" + (data.rusername || '无数据') + "</span>" +
			"					<span>签收时间：" + (data.receivetime || '无数据') + "</span>" +
			"				</div>" +
			"				<div class='yj'>处理意见：" + ((!yj && !file) ? '无数据' : (yj || '')) +
			"</div>" + files(data.opinionatts) +
			"			</div>" +
			"	</div>"
	})
	_this._handlers.content.html(_temp);
}

function files(data) {
	data = JSON.parse(data) || {};
	let _files = '';

	_.forEach(data.Attachments, (file, count) => {
		let className = diffIcon(file.suffix || file.type);
		let filesize = computeFileSize(file.size);
		_files +=
			`<tr id='${file.id}' class='item'>
				<td  class='order ds_hide' >${count*1+1}.</td>
				<td class='textLeft' id='${file.id}'>
					<div class='fileName'>
						<b class='icon midIcon ${className}'></b>
						<span>${file.name}</span>
						<span>.${file.suffix}</span>
					</div>
				</td>
				<td class="blank fontpostion" width="100" >${filesize}</td>
				<td class="operate fontpostion" width="100">
					<span class="previewBtn iconfont" previewfileID ="${file.id}" title="预览" onclick='window.open(dsf.url.getWebPath("preview/file?fileId=${file.id}"))'>&#xeb8d;</span>
					<span class="downLoad iconfont downLoadBtn" filename="${file.name}" downLoadkey="${file.id}" title="下载">&#xec22;</span>
				</td>
			</tr>`
	})
	if (_files) {
		return `<div class='ds_uploadFile'><table class='layui-table fileContainer'><tbody>${_files}</tbody></table></div>`
	}
	return ''
}

function diffIcon(fileType) {
	let className = ''
	if (fileType.indexOf("do") > -1) {
		className = "Word"
	}
	if (fileType.indexOf("excel") > -1 || fileType.indexOf("sheet") > -1 || fileType.indexOf("xl") > -1) {
		className = "Excel"
	}
	if (fileType.indexOf("pn") > -1) {
		className = "png"
	}
	if (fileType.indexOf("plain") > -1 || fileType.indexOf("tx") > -1) {
		className = "txt"
	}
	if (fileType.indexOf("zi") > -1) {
		className = "zip"
	}
	if (fileType.indexOf("jpe") > -1) {
		className = "jpg"
	}
	if (fileType.indexOf("pdf") > -1) {
		className = "pdf"
	}
	return className
}

function computeFileSize(fileSize) {
	let filesizeUnit = ""
	//1048576
	if (parseInt(fileSize) > 1050000) {
		filesizeUnit = (fileSize / Math.pow(1024, 2)).toFixed(2) + "M";
	} else {
		filesizeUnit = (fileSize / Math.pow(1024, 1)).toFixed(2) + "K";
	}
	return filesizeUnit
}
