const dom = require("../../templates/TreeInfo.ejs");
import { FormControl } from '../../../../baseControls'
import { TreeInfoMetaData } from '../../../../core/metadata';
import { express } from "../../../../core/express";
import { PageEvent } from '../../../../core/ControlEvent';
import { isSupportDataPost } from '../../../../core/postDecorator';

import {map} from  '../../../../decorator/controlmap';

@map('树结构','dsf.treeinfo','TreeInfo')
@isSupportDataPost(true)
export class TreeInfo extends FormControl {
    constructor(id, isPart) {
        super(id, isPart);
        this.$metadata = TreeInfoMetaData.call(this);
        // this.$pid="";
        this.$pidExpress = "";
        this.$iconExpress = "";
        this.$iconMap = {};
        this.$value = {
            "pid": "",
            "icon": ""
        };
        this.$caption = "treeinfo";

    }

    initTemplate() {
        return dom(this);
    }

    set value(value) {
        if (value != undefined) {
            if (typeof(value) == "string") {
                this.$value.pid = value;
            } else {
                this.$value = {
                    pid: value.pid,
                    icon: value.icon
                };
            }
        }


    }
    get value() {
        return this.$value;
    }

    createElement() {
        super.createElement();
        this.visible = false;
    }
    initEvent() {
        let _this = this;
        // 监听表单数据提交前
        this.root.event.on(PageEvent.POSTDATABEFORE, evt => {
            if (_this.$pidExpress && page.getControl(_this.$pidExpress)) {
                v = page.getControl(_this.$pidExpress).getValueString(",");
                _this.value.pid = v;
            }
            if (_this.iconExpress && page.getControl(_this.$iconExpress)) {
                v = page.getControl(_this.$iconExpress).getValueString(",");
                if (_this.$iconMap[v2]) {
                    _this.value.icon = _this.$iconMap[v2].icon;
                }
            }
        });
    }
}