import { Page } from './Page';
import * as Controls from '../controls';
const mainDom = require("../../templates/Page.ejs");

import { map } from '../../../../decorator/controlmap';

@map('问卷页面', 'dsf.qipage', 'QIPage')
export class QIPage extends Page {
  constructor(id, isPart) {
    super(id, isPart);
    // this.$useMetaGroup = [];
    // this.$useControlsGroup = [{
    //     "code": "dsfa.basectl.text",
    //     "rm_id": "6974a69a63ce43c7b0f4a32ec01ecf81",
    //     "text": "文字"
    // },
    // // {
    // //     "code": "dsfa.basectl.button",
    // //     "rm_id": "8732107eb124474295c474427b529a75",
    // //     "text": "按钮"
    // // },
    // {
    //     "code": "dsfa.qi.ctrl.qitype",
    //     "rm_id": "1a1f8cbb36f843d294924a12d9470ac5",
    //     "text": "问卷题型"
    // }];
    this.$viewSplit = "0px,0px";
    this.$pageType = "question";
    this.$pageWidth = "1170px";
    this.$headfootwidth = "same";
    this.$fit = 0;
    this.$caption = "QIPage";
    this._logic = [];
    this.$hasHeader = false;
    // 是否启用计时功能
    this.$openTime = false;
    this._useTime = new Date();
  }

  createElement() {
    super.createElement();
    this._handlers.north.css("display", "none");
  }

  render(el) {
    super.render(el);
    this.topBottom = "";
  }

  renderReady() {
    super.renderReady();
    this.setLogicRela();
  }
  setLogicRela() {
    // 设置关联题目
    let _this = this,
      childs = page.children[0].children;
    _.forEach(childs, function(ctrl, idx) {
      ctrl.$logicRela = [];
      let v = ctrl.$logic_rela || {};
      _.forEach(v.trig, function(val, key) {
        let rela_ctrl = _this.element.find(".ds_question[data-qid=" + v.Q + "]").data("Object");
        if(rela_ctrl){
          rela_ctrl.$logicRela.push({
            Q: ctrl.$questionIndex,
            trig: v.trig
          });
        }
      })
    })
  }

    getValidateResult(scope, root, controls) {
        let returnResult = {
            success: true,
            errorControls: [],
            successControls: []
        }
        _.each(controls, ctrl => {
            //获取问卷组件且问卷组件没有被隐藏
            if (ctrl._isQuestionControl && ctrl.visible == true) {
                !ctrl._validator && (ctrl._validator = dsf.formVaildate(ctrl));
                let result = ctrl._validator.exec();
                if (result && result.errorMsg) {
                    ctrl.addError(result, "validate");
                    returnResult.errorControls.push(ctrl)
                } else {
                    //特殊验证，多选限制选择数量
                    if(ctrl['ctrl_type']=="QsCheckBox"&&ctrl['mustCheckNum']>0&&ctrl['value'].length!=ctrl['mustCheckNum']){
                      returnResult.errorControls.push(ctrl)
                    }else{
                      ctrl.removeError(result, "validate")
                      returnResult.successControls.push(ctrl)
                    }
                }
            }
        });
        if (returnResult.errorControls.length) {
            returnResult.success = false;
        }
        return returnResult;
    }

  getQA(questionIndex) {
    let q = this.element.find(".ds_question[data-qid=" + questionIndex + "]");
    return q.data("Object");
  }

  getPostData() {
    let controls = this.getPostControls();
    let postData = {};
    this.event.trigger(PageEvent.POSTDATABEFORE, this);
    for (let i = 0; i < controls.length; i++) {
      let ctrl = controls[i];
      if (!ctrl.isPostSupport) {
        continue;
      }
      if (ctrl.metadata_fullcode && ctrl.visible == true) {
        postData[ctrl.metadata_fullcode] = ctrl.value;
      } else {
        postData[ctrl.metadata_fullcode] = ctrl.getMissValue();
      }
    }
    return postData;
  }

  //问卷页面逻辑处理
  logicExec(control) {
    let qa = control;
    let qid = qa.$questionIndex;
    if (qa.logic) {
      let logic = qa.logic;
      // 跳题，获取带有逻辑触发的选项(只是单选题有跳题逻辑)
      for (let n = 0; n < logic.length; n++) {
        // 有跳题逻辑的项目配置
        let clogic = logic[n];
        // trig[0]选项的值
        let trig = clogic['trig'];
        // 跳转至的题目序号
        let relQaIndex = clogic.Q;
        // 跳转至的题目控件
        let relQa = this.getQA(relQaIndex);
        if (qa.visible == false) {
          //如果当前选项被隐藏那当前题目的所有涉及逻辑都将无效
          relQa.removeLogicMark(qid);
        } else {
          // 所有题目
          let allQa = qa['_parent']['children'];
          // 当前题目的值
          let qaValue = $.isArray(qa.value) ? qa.value : [qa.value];

          let logicMark = [];
          if (qaValue[0].value == trig[0]) {
            logicMark = [{
              "key": qid,
              "value": trig[0]
            }];
          }
          let allQa_l = allQa.length;
          let qa_index = -1;
          for (let i = 0; i < allQa_l; i++) {
            if (qa_index > -1) {
              if (logicMark.length > 0) {
                allQa[i].addLogicMark(qid, trig[0]);
              } else {
                allQa[i].removeLogicMark(qid, trig[0]);
              }
            }
            if (qa_index == -1 && allQa[i]['$caption'] == qa['$caption']) {
              qa_index = i;
            }
            if (allQa[i]['$caption'] == relQa['$caption']) {
              break;
            }
          }
        }

      }
    }
    // 关联题
    let logicRela = qa.logicRela || [];
    console.log(logicRela)
    for (let n = 0; n < logicRela.length; n++) {
      // 会影响哪些题目
      let clogic = logicRela[n];
      // 哪些选项影响
      let trig = clogic['trig'];
      // 影响的题目序号
      let relQaIndex = clogic.Q;
      // 影响的题目控件
      let relQa = this.getQA(relQaIndex);

      // 当前题目的值
      let qaValue = $.isArray(qa.value) ? qa.value : [qa.value];
      let logicMark = [];
      qaValue.forEach(function(o, i) {
        let result = _.findIndex(trig, t => t == o.value);
        if (result >= 0) {
          logicMark.push({ "key": qid, "value": o.value });
        }
      });

      if (logicMark.length > 0) {
        //打上逻辑标记
        logicMark.forEach((o, i) => {
          relQa.removeLogicMark(o.key, o.value, true);
        });
      } else {
        _.findIndex(trig, (t) => {
          relQa.addLogicMark(qid, t, true);
        });
      }

    }
  }
}
