const dom = require("../../templates/CustomList.ejs");

import {
  LayoutControl
} from "../../../../baseControls";
import {
  map
} from '../../../../decorator/controlmap';
import {
  express
} from '../../../../core/express';

@map('自定义列表', 'dsf.customlist', 'CustomList')
export class CustomList extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.title = {
      pic: 'icon-shebeiguanli' || '/dsfa/res/dsf_styles/themes/anhui/s1.png',
      text: '',
      enabled: true,
      isImage: false,
      lightCode: null,
      list: [{
          des: '类型',
          width: '25%',
          text: 'textLeft',
          ellipsis: '1',
          code: null
        },
        {
          des: '标题、描述',
          width: '25%',
          text: 'textLeft',
          ellipsis: '1',
          code: null
        },
        {
          des: '来源人/物、目的人/物',
          width: '25%',
          text: 'textLeft',
          ellipsis: '1',
          code: null
        },
        {
          des: '时间',
          width: '25%',
          text: 'textRight',
          ellipsis: '1',
          code: null
        }
      ],
      linkCode: null,
      moreUrl: ''
    }
    this.typeTabs = [];
    this.url = null;
    this.$bTNoPadding = false;
    this.$rlNoPadding = false;
    this.$lineHeight = 'split_medium';
    this.ctrlHeightType = '1';
    this.ctrlHeight = null;
    this.listStyle = false;
    this.liBBorder = false;
    this.bgColor = null;
    this._tabIndex = -1;
    this.oneTimeLoaded = false;
    this.hoverStyle = '';
  }
  initTemplate() {
    return dom(this)
  }
  set titleEnabled(v) {
    this.title.enabled = v
  }
  get titleEnabled() {
    return this.title.enabled
  }
  set titleText(v) {
    this.title.text = v
  }
  get titleText() {
    return this.title.text
  }
  set titlePic(v) {
    this.title.pic = v
  }
  get titlePic() {
    return this.title.pic
  }
  changeTitleEnabled() {
    if (!this.titleEnabled) {
      this.element.addClass('titleHide');
    } else {
      this.element.removeClass('titleHide');
    }
    this.render();
  }
  changeTitleText() {
    this._handlers.titleText.html(this.titleText)
  }
  changeTitlePic() {
    let v = this.titlePic;
    if (v.indexOf('/') != -1) {
      this.title.isImage = true;
      this.element.addClass('titleImg');
      this._handlers.titleImg.attr('src', v);
    } else {
      this.title.isImage = false;
      this.element.removeClass('titleImg');
      this._handlers.titleI.attr('class', 'pic iconfont ' + v);
    }
  }
  changeTbNoPadding() {
    if (this.$bTNoPadding) {
      this.element.addClass('tbNoPadding');
    } else {
      this.element.removeClass('tbNoPadding');
    }
  }
  changeRlNoPadding() {
    if (this.$rlNoPadding) {
      this.element.addClass('rlNoPadding');
    } else {
      this.element.removeClass('rlNoPadding');
    }
  }
  changeLineHeight() {
    this._handlers.content.attr('class', 'subTitle');
    this._handlers.content.addClass(this.$lineHeight);
  }
  changeCtrlHeightType() {
    let v = this.ctrlHeightType;
    let types = ['fix_height', 'width_content', 'width_parent'];
    let h = this.ctrlHeight || 'auto';
    _.forEach(types, (_type) => {
      this.element.removeClass(_type);
    })
    this.element.addClass(types[v]);
    if (v == '1') {
      h = 'auto';
    } else if (v == '2') {
      h = '100%'
    }
    this.element.css('height', h);
  }
  changeListStyle() {
    let v = this.listStyle;
    if (v) {
      this.element.addClass('li_dot');
    } else {
      this.element.removeClass('li_dot');
    }
  }
  changeHoverStyle() {
    let v = this.hoverStyle;
    if (v) {
      this.element.addClass(v);
    } else {
      this.element.removeClass('hover_width');
    }
  }
  changeliBBorder() {
    let v = this.liBBorder;
    if (v) {
      this.element.addClass('li_bottom_border');
    } else {
      this.element.removeClass('li_bottom_border');
    }
  }
  changeBgColor() {
    this._handlers.content.css('background-color', this.bgColor || 'transparent');
  }
  hasData(data, type) {
    for (let i = 0; i < data.length; i++) {
      if (data[i][type || 'code']) {
        return true;
      }
    }
    return false;
  }
  hasMore() {
    if (this.typeTabs.length > 0) {
      for (let i = 0; i < this.typeTabs.length; i++) {
        if (this.typeTabs[i]['moreUrl']) {
          return true;
        }
      }
    } else if (this.title.moreUrl) {
      return true;
    }
    return false;
  }
  renderContext() {
    super.renderContext();
    this.changeCtrlHeightType();
    this.changeBgColor();
  }
  renderComplete() {
    super.renderComplete();
    let _this = this;
    if (!_this.root._isDesign) {
      _this.root.event.on(PageEvent.READY, evt => {
        _this.renderList(true);
      });
    }
  }
  renderList(isRefresh, index) {
    let _this = this;
    if (_this.event.has(CustomListEvent.custom)) {
      if (_this.typeTabs.length > 0) {
        _this.typeTabs[index || (_this._tabIndex != -1 ? _this._tabIndex : 0)].loaded = false;
        tabData.call(_this, index || (_this._tabIndex != -1 ? _this._tabIndex : (_this.typeTabs.length == 0 ? undefined : 0)));
        if (index || _this._tabIndex == -1) {
          if (_this.typeTabs.length > 1) {
            _this.event.trigger(CustomListEvent.tabChange, {
              ui: _this,
              data: _this.typeTabs[index || 0],
              elem: _this._handlers['title_' + (index || 0)],
              isRefresh: isRefresh ? true : false
            });
          }
          if (!index) _this._tabIndex = 0;
        }
      } else if (_this.url) {
        loadList.call(_this, _this.url, {});
      } else {
        _this._handlers['item'].html('');
        _this.event.trigger(CustomListEvent.custom, {
          ui: _this
        }, {
          resolve: (dom) => {
            _this._handlers['item'].append(dom);
          }
        });
      }
    }
  }
  initEvent() {
    if (this.root.preview) return;
    let _this = this;
    layui.element.on('tab(tab_customlist_' + this.id + ')', function(data) {
      _this._tabIndex = data.index;
      tabData.call(_this, data.index);
      _this.event.trigger(CustomListEvent.tabChange, {
        ui: _this,
        data: _this.typeTabs[data.index],
        elem: _this._handlers['title_' + data.index]
      });
    });
    this.event.on(CustomListEvent.custom, (args, def) => {
      let _width = this.element.css('width');
      let ul = "";
      if (!args.data || (args.data.list && !args.data.list.length) || (!args.data.list && !args.data.length)) {
        ul = "<div class='design'>暂无数据</div>";
      } else if (args.data) {
        let datas = args.data.list || args.data;
        let tr_temp = args.tab ? args.tab : _this.title;
        if (_this.hasData(tr_temp.list, 'title')) {
          ul = "<ul class='contentUl listTitle'><li>";
          _.forEach(tr_temp.list, (tab, tabI) => {
            if (tab.code) {
              ul += "<div style='width:" + (tab.width || "auto") + "' class='" + tab.text + " " + (tab.ellipsis == "1" ?
                "ellipsis" : "") + "'>" + tab.title + "</div>"
            }
          });
          ul += "</li></ul>";
        }

        if (_this.hasData(tr_temp.list)) {
          ul += "<ul class='contentUl'>";

          if (args.index != undefined) {
            _this.typeTabs[args.index].data = datas;
          } else {
            _this.title.data = datas;
          }
          _.forEach(datas, (tr, trI) => {
            let linkClass = '';
            let _link = '';
            if (tr_temp.linkCode) {
              if (tr_temp.linkCode.indexOf('/') != -1) {
                _link = dsf.Express.replace(tr_temp.linkCode, tr);
                linkClass = 'hasLink';
              } else {
                _link = tr[tr_temp.linkCode];
                linkClass = _link ? 'hasLink' : '';
              }
            }

            ul += '<li class="' + linkClass + " " + (tr_temp.lightCode ? dsf.Express.eval(tr_temp.lightCode, tr) ?
              'light' : '' : '') + '" link="' + _link + '" tabIndex="' + args.index + '" linkType="' + (tr_temp.linkType ?
              dsf.Express.eval(tr_temp.linkType, tr) ? 'page' : '' : '') + '">';
            _.forEach(tr_temp.list, (tab, tabI) => {
              if (tab.code) {
                ul += "<div style='width:" + (tab.width || "auto") + "' class='" + tab.text + " " + (tab.ellipsis == "1" ?
                  "ellipsis" : "") + "'>" + tr[tab.code] + "</div>"
              }
            });
            ul += '</li>';
          })
          ul += "</ul>"
        }
      }
      args.system_elem = ul;
      if (ul && ul != "" && _this.event.events.custom.handler.length <= 1) {
        def.resolve(args.system_elem);
      }
      _this.event.trigger(CustomListEvent.loaded, $.extend(true, {
        curElem: _this._handlers['item' + (args.index != undefined ? "_" + args.index : '')]
      }, args));
    })
    this.element.off('click.li');
    this.element.off('click.more');
    this.element.on('click.li', 'ul:not(.layui-tab-title):not(.listTitle) li', function(evt) {
      let $li = $(evt.target).closest('li');
      let link = $li.attr('link');
      let liIndex = $li.index();
      console.log(liIndex);
      let tabIndex = $li.attr('tabIndex');
      let configData = _this.title;
      if (tabIndex != 'undefined') {
        configData = _this.typeTabs[tabIndex];
      }
      let data = configData.data[liIndex];
      console.log(configData);
      let opts = !link ? null : {
        title: configData.text,
        content: dsf.url.getAbsolutePath(link),
        area: ['850px', '550px']
      };
      let queue = dsf.queue();
      queue.step((def, v) => {
        if (_this.event.has(CustomListEvent.liClick)) {
          _this.event.trigger(CustomListEvent.liClick, {
            ui: _this,
            data: data,
            elem: $li,
            dialog: opts
          }, def);
        } else {
          def.resolve();
        }
      });
      queue.step((def, v) => {
        if (link) {
          if ($li.attr('linkType') === 'page') {
            dsf.layer.openWindow(dsf.url.getAbsolutePath(link));
          } else if (opts) {
            dsf.layer.openDialog(opts);
          }
        }
        def.resolve();
      });
      queue.exec();
    })
    this.element.on('click.more', '.more', () => {
      let moreUrl = dsf.Express.replace(_this.title.moreUrl || '');
      if (_this._tabIndex > -1) {
        moreUrl = dsf.Express.replace(_this.typeTabs[_this._tabIndex].moreUrl || '');
      }
      dsf.layer.openWindow(dsf.url.getAbsolutePath(moreUrl));
    })
  }
  resize() {
    super.resize();
    let pw = this.element.width();
    this.element.find('.layui-tab').eq(0).css('width', pw + 'px');
  }
}

function tabData(index) {
  let _this = this;
  let obj = this.typeTabs[index || 0];
  if (obj.loaded) {
    return
  } else {
    obj.loaded = true;
  }
  if (obj.url || _this.url) {
    loadList.call(_this, obj.url || _this.url, {
      value: obj.value
    }, obj, index);
  } else {
    _this._handlers[index === undefined ? 'item' : 'item_' + index].html("");
    _this.event.trigger(CustomListEvent.custom, {
      ui: _this,
      index: index,
      tab: obj
    }, {
      resolve: (dom) => {
        _this._handlers[index === undefined ? 'item' : 'item_' + index].append(dom);
      }
    });
  }
}

function loadList(url, param, tab, index) {
  let _this = this,
    loadingIndex = dsf.layer.loadding();

  dsf.http.request(dsf.url.getWebPath(dsf.Express.replace(url)), param, 'Get')
    .done(response => {
      if (response.state == 20000) {
        _this._handlers[index === undefined ? 'item' : 'item_' + index].html("");
        this.event.trigger(CustomListEvent.custom, {
          ui: _this,
          data: response.data,
          tab: tab,
          index: index
        }, {
          resolve: (dom) => {
            _this._handlers[index === undefined ? 'item' : 'item_' + index].append(dom);
          }
        });
      } else {
        dsf.layer.message("获取" + (tab ? tab.text : '') + "列表异常", false);
      }
    })
    .error(response => {
      dsf.layer.message("获取" + (tab ? tab.text : '') + "列表异常", false);
    })
    .always(() => {
      dsf.layer.close(loadingIndex);
      if (_this.oneTimeLoaded && index !== undefined) {
        let _next = index * 1 + 1;
        if (_this.typeTabs[_next] && !_this.typeTabs[_next].loaded) {
          _this.renderList(true, _next);
        }
      }
    })
    .exec();
}