import * as Controls from '../controls';
import { LayoutControl } from '../../../../baseControls';
import { Page } from './Page';

const mainDom = require("../../templates/Page_mobile.ejs");
import { map } from '../../../../decorator/controlmap';

@map('移动端页面', 'dsf.pagemobile', 'Page_mobile')
export class Page_mobile extends Page {
  constructor(id, isPart) {
    super(id, isPart);
    this._layoutCtrl = null;
    this.$isMobile = true;
  }

  initTemplate() {
    return mainDom(this);
  }
  createElement() {
    this._layoutCtrl = new LayoutControl;
    var el = this._layoutCtrl.createElement.call(this);
    if (!this._isRender && this.root._isDesign && this.children.length <= 0) {
      // 中
      let _center = this.createControl(Controls.Container, "CenterView", true);
      _center.addClass("no_padding");
      this._addChild(_center, null, "center");
    }
    if (!this.root._isDesign) {
      this.element.addClass("release")
    } else {
      this.element.addClass("design")
    }
    return el;
  }

  resize() {
    this._layoutCtrl.resize.call(this);
  }
}